// 🛡️ شبكة أمان: تأكد أن الدوال المساعدة الأساسية موجودة قبل أي استخدام
// (في حالة عدم تعريضها من app.js أو مشكلة في ترتيب التحميل)
(function ensureHelpers() {
    if (typeof window.$ !== 'function') {
        window.$ = id => document.getElementById(id);
    }
    if (typeof window.ov !== 'function') {
        window.ov = id => { const el = document.getElementById(id); if (el) el.classList.add('show'); };
    }
    if (typeof window.cov !== 'function') {
        window.cov = id => { const el = document.getElementById(id); if (el) el.classList.remove('show'); };
    }
    if (typeof window.toast !== 'function') {
        window.toast = (msg, type) => {
            const el = document.getElementById('toast');
            if (el) { el.textContent = msg; el.className = type || 'ok'; setTimeout(() => el.className = '', 3500); }
            else { console.log('[toast]', msg); }
        };
    }
    if (typeof window.fmt !== 'function') {
        window.fmt = n => {
            const v = parseFloat(n);
            return isNaN(v) ? '0.00' : v.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
        };
    }
    if (typeof window.cf2 !== 'function') {
        window.cf2 = (msg, cb) => {
            const yes = document.getElementById('cfYes');
            const no = document.getElementById('cfNo');
            const msgEl = document.getElementById('cfMsg');
            if (msgEl) msgEl.textContent = msg;
            if (typeof cb === 'function') {
                if (yes) yes.onclick = () => { window.cov('mCf'); cb(); };
                if (no) no.onclick = () => window.cov('mCf');
                window.ov('mCf');
            } else {
                return new Promise(resolve => {
                    if (yes) yes.onclick = () => { window.cov('mCf'); resolve(true); };
                    if (no) no.onclick = () => { window.cov('mCf'); resolve(false); };
                    window.ov('mCf');
                });
            }
        };
    }
})();

