// ── دالة العرض الرئيسية ─────────────────
window.renderChartOfAccounts = function () {
    const container = $('pg-chartofaccounts'); if (!container) return;
    // 📋 عرض كشف الأرصدة بدلاً من الشجرة إن كان مختاراً
    if (window._coaView === 'balances') { renderCoaBalanceStatement(container); return; }
    const accounts = window.chartOfAccounts || {};
    const accountsArr = Object.entries(accounts);
    const hasAccounts = accountsArr.length > 0;

    // 🛡️ حذف الشجرة بالكامل — صلاحية المدير المالي (أو المدير العام) فقط
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    const canDeleteCoa = isAdmin || isFinanceMgr;

    // إحصائيات
    const stats = { total: accountsArr.length, asset: 0, liability: 0, equity: 0, revenue: 0, expense: 0, active: 0, detail: 0 };
    accountsArr.forEach(([, a]) => {
        if (a.type) stats[a.type]++;
        if (a.active !== false) stats.active++;
        if (a.nature === 'detail') stats.detail++;
    });

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#1e8449 0%,#27ae60 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(39,174,96,.25)">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">CHART OF ACCOUNTS</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">🌳 شجرة الحسابات</h1>
                    <p style="margin:6px 0 0;font-size:12px;opacity:.95">الأساس المحاسبي لتصنيف جميع المعاملات المالية</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    <button class="btn" onclick="openCoaAccount()" style="background:white;color:#1e8449;padding:9px 16px;font-weight:700">➕ إضافة حساب</button>
                    <button class="btn" onclick="window._coaView='balances';renderChartOfAccounts()" style="background:#1a3a5c;color:white;padding:9px 16px;font-weight:700">📋 كشف الأرصدة</button>
                    <button class="btn" onclick="ov('mCoaLoadDefaults')" style="background:#f39c12;color:white;padding:9px 16px;font-weight:700">📥 ${hasAccounts ? 'مزامنة الافتراضية' : 'تحميل الافتراضية'}</button>
                    <button class="btn" onclick="resetCoaImport();ov('mCoaImport')" style="background:#8e44ad;color:white;padding:9px 16px;font-weight:700">📊 استيراد من Excel</button>
                    <button class="btn" onclick="exportCoaExcel()" style="background:rgba(255,255,255,.2);color:white;padding:9px 16px;font-weight:700;backdrop-filter:blur(10px)">📤 تصدير Excel</button>
                    ${canDeleteCoa && hasAccounts ? `<button class="btn" onclick="deleteEntireChartOfAccounts()" style="background:#c0392b;color:white;padding:9px 16px;font-weight:700" title="حذف شجرة الحسابات بالكامل لإدخال شجرة جديدة">🗑️ حذف الشجرة بالكامل</button>` : ''}
                </div>
            </div>
        </div>

        ${!hasAccounts ? `
        <!-- Empty State -->
        <div class="card" style="text-align:center;padding:60px 20px">
            <div style="font-size:80px;margin-bottom:16px">🌳</div>
            <div style="font-size:18px;font-weight:800;color:#1a3a5c;margin-bottom:8px">لا توجد حسابات بعد</div>
            <div style="font-size:13px;color:#666;margin-bottom:20px">ابدأ بتحميل الحسابات الافتراضية أو أضف حساباتك الخاصة</div>
            <div style="display:flex;gap:10px;justify-content:center;flex-wrap:wrap">
                <button class="btn b-g" onclick="ov('mCoaLoadDefaults')" style="padding:10px 20px;font-size:14px">📥 تحميل الحسابات الافتراضية (${DEFAULT_ACCOUNTS.length} حساب)</button>
                <button class="btn b-b" onclick="openCoaAccount()" style="padding:10px 20px;font-size:14px">➕ إضافة حساب يدوياً</button>
            </div>
        </div>
        ` : `
        <!-- Stats Cards -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">📊 إجمالي الحسابات</div>
                <div style="font-size:24px;font-weight:900;color:#1a3a5c">${stats.total}</div>
                <div style="font-size:10px;color:#888">${stats.detail} تفصيلي · ${stats.total - stats.detail} رئيسي</div>
            </div>
            ${Object.entries(COA_TYPES).map(([k, t]) => `
                <div style="background:${t.bg};border-radius:12px;padding:12px;border-right:4px solid ${t.color}">
                    <div style="font-size:11px;color:#666">${t.ar}</div>
                    <div style="font-size:24px;font-weight:900;color:${t.color}">${stats[k] || 0}</div>
                </div>
            `).join('')}
        </div>

        <!-- Tree View -->
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:10px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c">📋 الشجرة الكاملة</div>
                <div style="display:flex;gap:6px;flex-wrap:wrap">
                    <button class="btn" onclick="expandAllCoa()" style="background:#f0f5fa;color:#1a3a5c;padding:5px 12px;font-size:11px">📂 توسيع الكل</button>
                    <button class="btn" onclick="collapseAllCoa()" style="background:#f0f5fa;color:#1a3a5c;padding:5px 12px;font-size:11px">📁 طي الكل</button>
                    <input type="text" id="coaSearch" placeholder="🔍 ابحث برمز أو اسم..." oninput="filterCoaTree(this.value)" style="padding:6px 12px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;min-width:200px">
                </div>
            </div>
            <div id="coaTreeContainer">
                ${renderCoaTree()}
            </div>
        </div>
        `}
    `;

    // 🔄 بعد الرسم: طبّق حالة التوسيع المحفوظة (الشجرة مغلقة افتراضياً)
    setTimeout(() => { if (typeof window.applyCoaExpandState === 'function') window.applyCoaExpandState(); }, 30);
};

// ── بناء الشجرة (تكراري) ─────────────────
function renderCoaTree() {
    const accounts = window.chartOfAccounts || {};
    if (!Object.keys(accounts).length) return '';

    // تجميع الحسابات حسب النوع
    const byType = { asset: [], liability: [], equity: [], revenue: [], expense: [] };
    Object.entries(accounts).forEach(([k, a]) => {
        if (byType[a.type]) byType[a.type].push({ key: k, ...a });
    });

    // ترتيب كل نوع حسب الكود
    Object.values(byType).forEach(arr => arr.sort((a, b) => (a.code || '').localeCompare(b.code || '')));

    return Object.entries(COA_TYPES).map(([typeKey, typeInfo]) => {
        const items = byType[typeKey];
        if (!items.length) return '';

        // بناء شجرة هرمية
        const tree = buildCoaHierarchy(items);

        return `<div style="margin-bottom:18px">
            <div style="background:${typeInfo.bg};border-right:5px solid ${typeInfo.color};border-radius:10px;padding:12px;margin-bottom:8px;display:flex;justify-content:space-between;align-items:center">
                <div style="font-size:15px;font-weight:900;color:${typeInfo.color}">${typeInfo.ar}</div>
                <div style="font-size:11px;color:#666;background:white;padding:3px 10px;border-radius:6px">${items.length} حساب</div>
            </div>
            <div style="padding-right:8px">
                ${tree.map(node => renderCoaNode(node, 0, typeInfo.color)).join('')}
            </div>
        </div>`;
    }).join('');
}

// بناء البنية الهرمية
function buildCoaHierarchy(items) {
    const map = {};
    items.forEach(item => { map[item.code] = { ...item, children: [] }; });
    const roots = [];
    items.forEach(item => {
        if (item.parent && map[item.parent]) {
            map[item.parent].children.push(map[item.code]);
        } else {
            roots.push(map[item.code]);
        }
    });
    return roots;
}

// رسم عقدة واحدة
function renderCoaNode(node, level, color) {
    const hasChildren = node.children && node.children.length > 0;
    const indent = level * 24;
    const isActive = node.active !== false;
    const isHeader = node.nature === 'header';
    const balance = parseFloat(node.openingBalance) || 0;

    return `<div class="coa-node" data-code="${node.code}" data-name="${(node.nameAr || '').toLowerCase()}">
        <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;border-radius:8px;margin-bottom:2px;background:${isHeader ? '#f8fafc' : 'white'};border:1px solid ${isHeader ? '#e0e8f0' : '#f0f5fa'};margin-right:${indent}px;${!isActive ? 'opacity:.5' : ''}">
            ${hasChildren ?
            `<span onclick="toggleCoaNode('${node.code}')" style="cursor:pointer;color:${color};font-size:12px;width:18px;text-align:center" class="coa-toggle-${node.code}">▼</span>` :
            `<span style="width:18px;text-align:center;color:#ccc;font-size:10px">●</span>`
        }
            <span style="font-family:monospace;font-weight:700;color:${color};font-size:12px;min-width:50px">${node.code}</span>
            <span style="flex:1;font-size:13px;font-weight:${isHeader ? '800' : '600'};color:#1a3a5c">${node.nameAr || '-'}</span>
            ${node.nameEn ? `<span style="font-size:10px;color:#888;direction:ltr">${node.nameEn}</span>` : ''}
            ${isHeader ?
            `<span style="background:#e0e8f0;color:#1a3a5c;font-size:9px;padding:2px 6px;border-radius:4px">📁 رئيسي</span>` :
            `<span style="background:${color}22;color:${color};font-size:9px;padding:2px 6px;border-radius:4px">🔹 تفصيلي</span>`
        }
            ${balance !== 0 ? `<span style="font-size:11px;color:#27ae60;font-weight:700">${fmt(balance)} ر</span>` : ''}
            ${!isActive ? `<span style="background:#888;color:white;font-size:9px;padding:2px 6px;border-radius:4px">⏸️ غير نشط</span>` : ''}
            <div style="display:flex;gap:4px">
                ${isHeader ? `<button class="btn" onclick="addChildAccount('${node.code}')" style="background:#27ae60;color:white;padding:3px 10px;font-size:11px;font-weight:800" title="إضافة حساب فرعي تحت ${node.nameAr}">➕</button>` : ''}
                <button class="btn" onclick="editCoaAccount('${node.key}')" style="background:#2d6a9f;color:white;padding:3px 8px;font-size:10px" title="تعديل">✏️</button>
                <button class="btn" onclick="deleteCoaAccount('${node.key}')" style="background:#c0392b;color:white;padding:3px 8px;font-size:10px" title="حذف">🗑️</button>
            </div>
        </div>
        ${hasChildren ? `<div class="coa-children-${node.code}">
            ${node.children.sort((a, b) => (a.code || '').localeCompare(b.code || '')).map(child => renderCoaNode(child, level + 1, color)).join('')}
        </div>` : ''}
    </div>`;
}

// ── طي/توسيع عقدة ─────────────────
// 📂 تتبّع حالة العقد المفتوحة (حتى نُحافظ عليها بين عمليات الإضافة/التعديل)
window.coaExpandedNodes = window.coaExpandedNodes || new Set();

window.toggleCoaNode = function (code) {
    const children = document.querySelector(`.coa-children-${code}`);
    const toggle = document.querySelector(`.coa-toggle-${code}`);
    if (!children || !toggle) return;
    if (children.style.display === 'none') {
        children.style.display = '';
        toggle.textContent = '▼';
        window.coaExpandedNodes.add(code); // تذكّر أنه مفتوح
    } else {
        children.style.display = 'none';
        toggle.textContent = '◀';
        window.coaExpandedNodes.delete(code); // تذكّر أنه مغلق
    }
};

window.expandAllCoa = function () {
    document.querySelectorAll('[class*="coa-children-"]').forEach(el => el.style.display = '');
    document.querySelectorAll('[class*="coa-toggle-"]').forEach(el => el.textContent = '▼');
    // أضف كل الأكواد المفتوحة للذاكرة
    document.querySelectorAll('[class*="coa-children-"]').forEach(el => {
        const match = el.className.match(/coa-children-(\S+)/);
        if (match) window.coaExpandedNodes.add(match[1]);
    });
};

window.collapseAllCoa = function () {
    document.querySelectorAll('[class*="coa-children-"]').forEach(el => el.style.display = 'none');
    document.querySelectorAll('[class*="coa-toggle-"]').forEach(el => el.textContent = '◀');
    window.coaExpandedNodes.clear(); // مسح كل الذاكرة
};

// 🔄 إعادة تطبيق حالة الطي/التوسيع بعد إعادة الرسم
window.applyCoaExpandState = function () {
    // اطوِ كل شيء أولاً
    document.querySelectorAll('[class*="coa-children-"]').forEach(el => el.style.display = 'none');
    document.querySelectorAll('[class*="coa-toggle-"]').forEach(el => el.textContent = '◀');
    // ثم افتح فقط ما هو محفوظ
    window.coaExpandedNodes.forEach(code => {
        const children = document.querySelector(`.coa-children-${code}`);
        const toggle = document.querySelector(`.coa-toggle-${code}`);
        if (children) children.style.display = '';
        if (toggle) toggle.textContent = '▼';
    });
};

// ── البحث في الشجرة ─────────────────
window.filterCoaTree = function (query) {
    query = (query || '').toLowerCase().trim();
    const allNodes = document.querySelectorAll('.coa-node');

    // عند مسح البحث: ارجع للحالة الافتراضية (الكل ظاهر، الشجرة بحالتها المحفوظة)
    if (!query) {
        allNodes.forEach(n => n.style.display = '');
        // أعِد تطبيق حالة الطي/التوسيع
        if (typeof window.applyCoaExpandState === 'function') window.applyCoaExpandState();
        return;
    }

    // عند البحث: استراتيجية ذكية
    // 1. حدد العقد المطابقة
    // 2. أظهر كل أبائها (سلسلة الأجداد)
    // 3. أخفِ كل ما عداها

    const matchedCodes = new Set();
    const ancestorCodes = new Set();

    // 1️⃣ ابحث عن المطابقين
    allNodes.forEach(n => {
        const code = (n.getAttribute('data-code') || '').toLowerCase();
        const name = (n.getAttribute('data-name') || '').toLowerCase();
        if (code.includes(query) || name.includes(query)) {
            matchedCodes.add(n.getAttribute('data-code'));
        }
    });

    // 2️⃣ لكل عقدة مطابقة، اجمع أكواد أبائها من شجرة البيانات
    const accounts = window.chartOfAccounts || {};
    const codeToParent = {};
    Object.values(accounts).forEach(a => { codeToParent[a.code] = a.parent || ''; });

    matchedCodes.forEach(code => {
        let parent = codeToParent[code];
        while (parent) {
            ancestorCodes.add(parent);
            parent = codeToParent[parent];
        }
    });

    // 3️⃣ أخفِ/أظهر العقد
    const visibleCodes = new Set([...matchedCodes, ...ancestorCodes]);
    allNodes.forEach(n => {
        const code = n.getAttribute('data-code');
        if (visibleCodes.has(code)) {
            n.style.display = '';
        } else {
            n.style.display = 'none';
        }
    });

    // 4️⃣ افتح كل عقد الآباء (لتُظهر الأبناء المطابقين)
    visibleCodes.forEach(code => {
        const children = document.querySelector(`.coa-children-${CSS.escape(code)}`);
        const toggle = document.querySelector(`.coa-toggle-${CSS.escape(code)}`);
        if (children) children.style.display = '';
        if (toggle) toggle.textContent = '▼';
    });
};

// ── فتح مودال الحساب ─────────────────
window.openCoaAccount = function () {
    $('mCoaTitle').textContent = '➕ إضافة حساب جديد';
    $('mCoaKey').value = '';
    $('mCoaCode').value = '';
    $('mCoaType').value = '';
    $('mCoaNameAr').value = '';
    $('mCoaNameEn').value = '';
    $('mCoaParent').innerHTML = '<option value="">-- بدون حساب أب (رئيسي) --</option>';
    $('mCoaNature').value = 'detail';
    $('mCoaOpeningBalance').value = 0;
    if ($('mCoaFsRole')) $('mCoaFsRole').value = '';
    $('mCoaNotes').value = '';
    $('mCoaActive').checked = true;
    ov('mCoaAccount');
};

// ── إضافة حساب فرعي تحت حساب رئيسي محدد ─────────────────
// يُستدعى من زر ➕ بجانب كل حساب رئيسي
// يُولّد الكود تلقائياً ويُعبّئ نوع المجموعة والحساب الأب
window.addChildAccount = function (parentCode) {
    const accounts = window.chartOfAccounts || {};
    // ابحث عن الحساب الأب
    const parentEntry = Object.entries(accounts).find(([, a]) => a.code === parentCode);
    if (!parentEntry) { toast('⚠️ الحساب الأب غير موجود', 'er'); return; }
    const parent = parentEntry[1];

    // 📂 احفظ الأب وكل الأجداد كمفتوحين (حتى يبقى الموقع مرئياً بعد الإضافة)
    rememberAncestorsExpanded(parentCode);

    // 🎯 توليد الكود التلقائي للحساب الفرعي الجديد
    const nextCode = generateNextChildCode(parentCode, parent.type);

    // افتح المودال وعبّئ القيم
    $('mCoaTitle').textContent = `➕ إضافة حساب فرعي تحت: ${parent.nameAr}`;
    $('mCoaKey').value = '';
    $('mCoaCode').value = nextCode;
    $('mCoaType').value = parent.type;
    $('mCoaNameAr').value = '';
    $('mCoaNameEn').value = '';
    $('mCoaNature').value = 'detail';
    $('mCoaOpeningBalance').value = 0;
    if ($('mCoaFsRole')) $('mCoaFsRole').value = '';
    $('mCoaNotes').value = '';
    $('mCoaActive').checked = true;

    // عبّئ قائمة الحسابات الأب واختر الأب الحالي
    updateCoaParentOptions();
    setTimeout(() => {
        $('mCoaParent').value = parentCode;
        $('mCoaNameAr').focus();
    }, 50);

    ov('mCoaAccount');
};

// ── توليد الكود التالي للحساب الفرعي ─────────────────
// مثال: لو الأب "122" (البنوك) وتحته "12201", "12202" → التالي "12203"
// لو الأب "1" والأبناء "11", "12" → التالي "13"
function generateNextChildCode(parentCode, type) {
    const accounts = window.chartOfAccounts || {};
    // كل الحسابات التي أبوها = parentCode
    const siblings = Object.values(accounts)
        .filter(a => a.parent === parentCode)
        .map(a => a.code)
        .filter(c => c && c.startsWith(parentCode));

    // طول الكود الفرعي = طول الأب + رقمين على الأقل (أو 1 رقم لو الأب 1 خانة)
    const parentLen = parentCode.length;
    // افتراضياً، نضيف رقمين للأبناء (مثل 122 → 12201)
    // لكن للجذور القصيرة (1, 2, 3) نضيف رقم واحد (1 → 11)
    let childLen = parentLen + (parentLen <= 1 ? 1 : 2);

    // إذا وُجد أبناء، استخدم طولهم
    if (siblings.length) {
        const lens = siblings.map(c => c.length).filter(l => l > parentLen);
        if (lens.length) childLen = Math.min(...lens);
    }

    // استخرج الأرقام التي بعد الأب
    const suffixes = siblings
        .filter(c => c.length === childLen)
        .map(c => parseInt(c.substring(parentLen), 10))
        .filter(n => !isNaN(n));

    let nextSuffix = 1;
    if (suffixes.length) {
        nextSuffix = Math.max(...suffixes) + 1;
    }

    // عدد خانات اللاحقة
    const suffixLen = childLen - parentLen;
    const suffixStr = String(nextSuffix).padStart(suffixLen, '0');

    return parentCode + suffixStr;
}

// 📂 احفظ كود معيّن + كل أجداده كمفتوحين في الذاكرة
// مثال: لو الكود "12001" وأجداده "1200", "120", "1" → كلها تُحفظ كمفتوحة
function rememberAncestorsExpanded(code) {
    if (!code) return;
    const accounts = window.chartOfAccounts || {};
    let current = code;
    // أضف الكود نفسه أولاً
    window.coaExpandedNodes.add(current);
    // ثم تتبّع الأجداد حتى الجذر
    while (current) {
        const entry = Object.values(accounts).find(a => a.code === current);
        if (!entry || !entry.parent) break;
        window.coaExpandedNodes.add(entry.parent);
        current = entry.parent;
    }
}

// ── تعديل حساب ─────────────────
window.editCoaAccount = function (key) {
    const acc = window.chartOfAccounts?.[key]; if (!acc) return;
    // 📂 احفظ موقع الحساب وأجداده كمفتوحين (للعودة لنفس المكان بعد الحفظ)
    if (acc.parent) rememberAncestorsExpanded(acc.parent);
    $('mCoaTitle').textContent = '✏️ تعديل الحساب: ' + (acc.nameAr || '');
    $('mCoaKey').value = key;
    $('mCoaCode').value = acc.code || '';
    $('mCoaType').value = acc.type || '';
    $('mCoaNameAr').value = acc.nameAr || '';
    $('mCoaNameEn').value = acc.nameEn || '';
    $('mCoaNature').value = acc.nature || 'detail';
    $('mCoaOpeningBalance').value = acc.openingBalance || 0;
    if ($('mCoaFsRole')) $('mCoaFsRole').value = acc.fsRole || '';
    $('mCoaNotes').value = acc.notes || '';
    $('mCoaActive').checked = acc.active !== false;
    updateCoaParentOptions();
    setTimeout(() => { $('mCoaParent').value = acc.parent || ''; }, 50);
    ov('mCoaAccount');
};

// ── تحديث قائمة الحساب الأب ─────────────────
window.updateCoaParentOptions = function () {
    const type = $('mCoaType').value;
    const sel = $('mCoaParent');
    const currentKey = $('mCoaKey').value;
    sel.innerHTML = '<option value="">-- بدون حساب أب (رئيسي) --</option>';
    if (!type) return;
    const accs = Object.entries(window.chartOfAccounts || {})
        .filter(([k, a]) => a.type === type && k !== currentKey)
        .sort((a, b) => (a[1].code || '').localeCompare(b[1].code || ''));
    accs.forEach(([k, a]) => {
        const indent = '— '.repeat((a.code || '').length / 2 - 1);
        sel.innerHTML += `<option value="${a.code}">${indent}${a.code} - ${a.nameAr}</option>`;
    });
};

// ── حفظ حساب ─────────────────
window.saveCoaAccount = async function () {
    const key = $('mCoaKey').value;
    const code = $('mCoaCode').value.trim();
    const type = $('mCoaType').value;
    const nameAr = $('mCoaNameAr').value.trim();

    // التحقق
    if (!code) { toast('⚠️ رمز الحساب مطلوب', 'er'); return; }
    if (!type) { toast('⚠️ اختر المجموعة الرئيسية', 'er'); return; }
    if (!nameAr) { toast('⚠️ اسم الحساب بالعربية مطلوب', 'er'); return; }

    // التحقق من تكرار الكود
    const existing = Object.entries(window.chartOfAccounts || {}).find(([k, a]) => a.code === code && k !== key);
    if (existing) { toast('⚠️ رمز الحساب موجود مسبقاً', 'er'); return; }

    // التحقق من بداية الكود حسب النوع
    const expectedStart = COA_TYPES[type].codeStart;
    if (!code.startsWith(expectedStart)) {
        if (!await cf2(`الكود "${code}" لا يبدأ بـ "${expectedStart}" المعتاد لـ ${COA_TYPES[type].ar}. هل تريد الحفظ على أي حال؟`)) return;
    }

    const data = {
        code, type, nameAr,
        nameEn: $('mCoaNameEn').value.trim(),
        parent: $('mCoaParent').value,
        nature: $('mCoaNature').value,
        openingBalance: parseFloat($('mCoaOpeningBalance').value) || 0,
        fsRole: ($('mCoaFsRole') && $('mCoaFsRole').value) || '',
        notes: $('mCoaNotes').value.trim(),
        active: $('mCoaActive').checked,
        updatedAt: new Date().toISOString(),
        updatedBy: (typeof curU !== 'undefined' && curU?.uid) || 'system'
    };

    try {
        if (key) {
            // تحديث
            await update(ref(db, 'ledger/chartOfAccounts/' + key), data);
            // 📂 احفظ موقع الحساب المُعدَّل وأجداده كمفتوحين
            if (data.parent) rememberAncestorsExpanded(data.parent);
            toast('✅ تم تحديث الحساب', 'ok');
        } else {
            // إضافة
            data.createdAt = new Date().toISOString();
            data.createdBy = data.updatedBy;
            await push(R.coa, data);
            // 📂 احفظ موقع الإضافة وأجداده كمفتوحين (ليبقى الحساب الجديد مرئياً)
            if (data.parent) rememberAncestorsExpanded(data.parent);
            toast('✅ تم إضافة الحساب', 'ok');
        }
        cov('mCoaAccount');
    } catch (e) {
        console.error('Save account error:', e);
        toast('❌ خطأ في الحفظ: ' + (e.message || e), 'er');
    }
};

// ── حذف حساب ─────────────────
window.deleteCoaAccount = async function (key) {
    const acc = window.chartOfAccounts?.[key]; if (!acc) return;

    // فحص: هل يوجد حسابات فرعية؟
    const hasChildren = Object.values(window.chartOfAccounts || {}).some(a => a.parent === acc.code);
    if (hasChildren) {
        toast('⚠️ لا يمكن حذف الحساب لوجود حسابات فرعية', 'er');
        return;
    }

    // فحص: هل يوجد قيود؟ (سنفعّله لاحقاً)
    const hasEntries = Object.values(window.journalEntries || {}).some(j => {
        return (j.lines || []).some(l => l.accountCode === acc.code);
    });
    if (hasEntries) {
        toast('⚠️ لا يمكن حذف الحساب لوجود قيود مرتبطة به', 'er');
        return;
    }

    if (!await cf2(`هل تريد حذف الحساب "${acc.nameAr}" (${acc.code})؟`)) return;

    try {
        await remove(ref(db, 'ledger/chartOfAccounts/' + key));
        toast('✅ تم حذف الحساب', 'ok');
    } catch (e) {
        toast('❌ خطأ في الحذف: ' + (e.message || e), 'er');
    }
};

// ── تحميل/مزامنة الحسابات الافتراضية ─────────────────
// مسميات قديمة تُحدَّث تلقائياً للتصنيف الدولي (متداول/غير متداول) — التحديث آمن:
// لا يلمس إلا الحسابات التي ما زالت تحمل الاسم الافتراضي القديم حرفياً.
const COA_LEGACY_RENAMES = {
    '1200': 'الأصول الثابتة',
    '2200': 'الخصوم طويلة الأجل',
};

window.loadDefaultAccounts = async function () {
    if (!await cf2('سيتم إضافة الحسابات الافتراضية الناقصة وتحديث المسميات القديمة للتصنيف الدولي. متابعة؟')) return;
    try {
        toast('⏳ جاري المزامنة...', 'ok');
        const now = new Date().toISOString();
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        let added = 0, renamed = 0;

        for (const acc of DEFAULT_ACCOUNTS) {
            const found = Object.entries(window.chartOfAccounts || {}).find(([, a]) => a.code === acc.code);
            if (found) {
                // موجود: حدّث الاسم فقط إن كان ما زال بالمسمى الافتراضي القديم
                const [key, a] = found;
                if (COA_LEGACY_RENAMES[acc.code] === a.nameAr) {
                    await update(ref(db, 'ledger/chartOfAccounts/' + key), { nameAr: acc.nameAr, nameEn: acc.nameEn, updatedAt: now, updatedBy: userId });
                    renamed++;
                }
                continue;
            }

            await push(R.coa, {
                ...acc,
                openingBalance: 0,
                active: true,
                createdAt: now,
                updatedAt: now,
                createdBy: userId,
                updatedBy: userId
            });
            added++;
        }
        cov('mCoaLoadDefaults');
        toast(`✅ تمت المزامنة: ${added} حساب جديد${renamed ? `، ${renamed} مسمى محدَّث` : ''}`, 'ok');
    } catch (e) {
        // 🆕 إذا فشل تحميل الحسابات الافتراضية، تأكد من أن حسابات الإهلاك والإيجارات موجودة
        if (e.message.includes('5370') || e.message.includes('1290') || e.message.includes('5320')) {
            toast('❌ خطأ في التحميل: تأكد من وجود حسابات الإهلاك والإيجارات في شجرة الحسابات', 'er');
        }
        console.error('Load defaults error:', e);
        toast('❌ خطأ في التحميل: ' + (e.message || e), 'er');
    }
};

// ── تصدير Excel ─────────────────
window.exportCoaExcel = function () {
    const accs = Object.values(window.chartOfAccounts || {});
    if (!accs.length) { toast('⚠️ لا توجد حسابات للتصدير', 'er'); return; }

    const data = accs
        .sort((a, b) => (a.code || '').localeCompare(b.code || ''))
        .map(a => ({
            'الرمز': a.code || '',
            'الاسم بالعربية': a.nameAr || '',
            'الاسم بالإنجليزية': a.nameEn || '',
            'المجموعة': COA_TYPES[a.type]?.ar || a.type,
            'النوع': a.nature === 'header' ? 'رئيسي' : 'تفصيلي',
            'الحساب الأب': a.parent || '',
            'الرصيد الافتتاحي': a.openingBalance || 0,
            'نشط': a.active !== false ? 'نعم' : 'لا',
            'ملاحظات': a.notes || ''
        }));

    try {
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'شجرة الحسابات');
        const fileName = `شجرة_الحسابات_${new Date().toISOString().substring(0, 10)}.xlsx`;
        XLSX.writeFile(wb, fileName);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ في التصدير: ' + (e.message || e), 'er');
    }
};

// 🆕 دالة جديدة: إنشاء قيد محاسبي تلقائي لتكلفة المشروع الشهرية
async function createJournalForPMC(pmcData) {
    const accounts = Object.values(window.chartOfAccounts || {});
    const findAccByCode = (code) => accounts.find(a => a.code === code);

    const categoryInfo = getPMCCategoryInfo(pmcData.category);
    const debitAccCode = categoryInfo.defaultDebitAccountCode;
    const creditAccCode = categoryInfo.defaultCreditAccountCode;

    const debitAcc = findAccByCode(debitAccCode);
    const creditAcc = findAccByCode(creditAccCode);

    if (!debitAcc) {
        toast(`⚠️ لم يُنشأ قيد تكلفة المشروع: حساب المدين الافتراضي (${debitAccCode}) غير موجود`, 'wn', 8000);
        return null;
    }
    if (!creditAcc) {
        toast(`⚠️ لم يُنشأ قيد تكلفة المشروع: حساب الدائن الافتراضي (${creditAccCode}) غير موجود`, 'wn', 8000);
        return null;
    }

    const lines = [
        {
            accountCode: debitAcc.code,
            accountName: debitAcc.nameAr,
            description: pmcData.description || `تكلفة ${categoryInfo.ar} - ${pmcData.name}`,
            costCenter: pmcData.projectId || '',
            projectId: pmcData.projectId || '',
            debit: pmcData.amount,
            credit: 0
        },
        {
            accountCode: creditAcc.code,
            accountName: creditAcc.nameAr,
            description: `استحقاق تكلفة ${categoryInfo.ar} - ${pmcData.name}`,
            costCenter: pmcData.projectId || '',
            projectId: pmcData.projectId || '',
            debit: 0,
            credit: pmcData.amount
        }
    ];

    const jrnNumber = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-PMC-' + Date.now());
    const jrnData = {
        number: jrnNumber,
        date: pmcData.date || pmcData.month + '-01',
        reference: pmcData.reference || `PMC-${pmcData.month}`,
        description: `تكلفة مشروع شهرية: ${pmcData.description || categoryInfo.ar}`,
        lines, totalDebit: pmcData.amount, totalCredit: pmcData.amount,
        status: 'posted', sourceType: 'project_monthly_cost', sourceKey: pmcData.key,
        createdAt: new Date().toISOString(), createdBy: pmcData.createdBy,
        postedAt: new Date().toISOString(), postedBy: pmcData.createdBy
    };
    const jrnRef = await push(R.jrn, jrnData);
    return { key: jrnRef.key, number: jrnNumber };
}

