// ── 📋 كشف أرصدة الحسابات (هرمي: الرئيسية بمجاميع فروعها) ─────────────────
window._coaBalState = window._coaBalState || { from: '', to: '', includeDraft: false };

// حساب أرصدة كل الحسابات مع تجميع الرئيسية من فروعها (تكرارياً)
function coaBalanceRows(from, to, includeDraft) {
    const statuses = includeDraft ? ['posted', 'draft'] : ['posted'];
    const { balances } = calcFSBalances(from, to, statuses);
    const accs = Object.values(window.chartOfAccounts || {}).filter(a => a.code);
    const byCode = {}; accs.forEach(a => { byCode[a.code] = a; });
    const childrenOf = code => accs.filter(a => (a.parent || '') === code).sort((x, y) => (x.code || '').localeCompare(y.code || ''));
    const roots = accs.filter(a => !a.parent || !byCode[a.parent]).sort((x, y) => (x.code || '').localeCompare(y.code || ''));

    const totalsFor = a => {
        if (a.nature !== 'header') {
            const b = balances[a.code];
            if (b) return { opening: b.naturalOpening, debit: b.periodDebit, credit: b.periodCredit, closing: b.naturalClosing, count: b.count };
            const op = parseFloat(a.openingBalance) || 0;
            return { opening: op, debit: 0, credit: 0, closing: op, count: 0 };
        }
        const t = { opening: 0, debit: 0, credit: 0, closing: 0, count: 0 };
        childrenOf(a.code).forEach(k => {
            const kt = totalsFor(k);
            t.opening += kt.opening; t.debit += kt.debit; t.credit += kt.credit; t.closing += kt.closing; t.count += kt.count;
        });
        return t;
    };

    const rows = [];
    const walk = (a, depth) => {
        rows.push({ a, depth, header: a.nature === 'header', t: totalsFor(a) });
        if (a.nature === 'header') childrenOf(a.code).forEach(k => walk(k, depth + 1));
    };
    roots.forEach(r => walk(r, 0));
    return rows;
}

