// ── 📤 تصدير كشف الحساب التفصيلي Excel ─────────────────────────────────────
window.coaExportAccountStatementExcel = function () {
    const st = window._coaBalState;
    if (!st.opAccount) { toast('اختر حساباً أولاً', 'er'); return; }
    const acc = Object.values(window.chartOfAccounts || {}).find(a => a.code === st.opAccount);
    if (!acc) return;
    const { ops, preNet } = coaAccountOps(st.opAccount, st.from, st.to, st.includeDraft);
    if (!ops.length) { toast('لا توجد عمليات للتصدير', 'er'); return; }
    let running = (parseFloat(acc.openingBalance) || 0) + preNet;
    const data = [{ '#': '', 'التاريخ': '', 'رقم القيد': '', 'البيان': 'الرصيد قبل الفترة', 'مركز التكلفة': '', 'المشروع': '', 'مدين': '', 'دائن': '', 'الرصيد الجاري': +running.toFixed(2), 'الحالة': '' }];
    ops.forEach((o, i) => {
        running += o.debit - o.credit;
        data.push({ '#': i + 1, 'التاريخ': o.date, 'رقم القيد': o.number, 'البيان': o.description || '',
            'مركز التكلفة': o.costCenter ? ccDisplayName(o.costCenter) : '', 'المشروع': o.projectId ? ccDisplayName(o.projectId) : '',
            'مدين': o.debit, 'دائن': o.credit, 'الرصيد الجاري': +running.toFixed(2), 'الحالة': o.status === 'posted' ? 'مرحّل' : 'مسودة' });
    });
    try {
        const ws = XLSX.utils.json_to_sheet(data);
        ws['!cols'] = [4, 12, 14, 30, 18, 18, 14, 14, 14, 10].map(w => ({ wch: w }));
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'كشف الحساب');
        XLSX.writeFile(wb, `كشف_حساب_${acc.code}_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

