// ── 📤 تصدير كشف الأرصدة Excel ──────────────────────────────────────────────
window.coaExportBalancesExcel = function () {
    const st = window._coaBalState;
    const rows = coaBalanceRows(st.from, st.to, st.includeDraft);
    if (!rows.length) { toast('لا توجد حسابات للتصدير', 'er'); return; }
    const data = rows.map(r => ({
        'الرمز': r.a.code || '',
        'الحساب': '  '.repeat(r.depth) + (r.a.nameAr || ''),
        'النوع': r.header ? 'رئيسي' : 'تفصيلي',
        'المجموعة': (COA_TYPES[r.a.type] || {}).ar || r.a.type || '',
        'الرصيد الافتتاحي': +r.t.opening.toFixed(2),
        'حركة مدين': +r.t.debit.toFixed(2),
        'حركة دائن': +r.t.credit.toFixed(2),
        'الرصيد الختامي': +r.t.closing.toFixed(2),
        'عدد الحركات': r.t.count
    }));
    try {
        const ws = XLSX.utils.json_to_sheet(data);
        ws['!cols'] = [10, 32, 10, 14, 16, 16, 16, 16, 10].map(w => ({ wch: w }));
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'كشف أرصدة الحسابات');
        XLSX.writeFile(wb, `كشف_أرصدة_الحسابات_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) { toast('❌ ' + e.message, 'er'); }
};

