// ══════════════════════════════════════════════════════════════════════════
// [ACC-AMZ] إطفاء المصروفات المدفوعة مقدماً (Prepaid Amortization)
// ══════════════════════════════════════════════════════════════════════════
function amzDueMonths(t) {
    const cur = new Date().toISOString().slice(0, 7);
    const out = []; if (!t.startMonth || !t.months) return out;
    let [y, m] = t.startMonth.split('-').map(Number);
    const gen = t.generated || {};
    for (let i = 0; i < t.months; i++) {
        const ym = `${y}-${String(m).padStart(2, '0')}`;
        if (ym <= cur && !gen[ym]) out.push(ym);
        m++; if (m > 12) { m = 1; y++; }
    }
    return out;
}
window.renderAmortizations = function () {
    const container = $('pg-amortization'); if (!container) return;
    const tpls = Object.entries(window.amortizations || {});
    let totalDue = 0; tpls.forEach(([, t]) => { if (t.active !== false) totalDue += amzDueMonths(t).length; });
    container.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:14px">
            <div>
                <div style="font-size:20px;font-weight:800;color:#2c3e50">📆 إطفاء المصروفات المؤجلة (Prepaid Amortization)</div>
                <div style="font-size:12px;color:#888;margin-top:2px">توزيع المصاريف المدفوعة مقدماً (إيجار سنوي، تأمين، اشتراكات) على أشهرها بقيود إطفاء تلقائية</div>
            </div>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
                ${totalDue > 0 ? `<button onclick="generateAllDueAmort()" style="background:#e67e22;color:white;border:none;border-radius:10px;padding:9px 16px;font-weight:800;cursor:pointer;font-size:13px">⚡ توليد المستحق (${totalDue})</button>` : ''}
                <button onclick="openAmortEditor(null)" style="background:linear-gradient(135deg,#2980b9,#3498db);color:white;border:none;border-radius:10px;padding:9px 18px;font-weight:800;cursor:pointer;font-size:13px">+ جدول إطفاء</button>
            </div>
        </div>
        <div class="card" style="padding:0;overflow:auto">
            <table style="width:100%;border-collapse:collapse;font-size:13px">
                <thead><tr style="background:linear-gradient(135deg,#2c3e50,#34495e);color:white">
                    <th style="padding:11px;text-align:right">البيان</th><th style="padding:11px;text-align:center">الإجمالي</th>
                    <th style="padding:11px;text-align:center">القسط الشهري</th><th style="padding:11px;text-align:center">المدة</th>
                    <th style="padding:11px;text-align:center">المُطفأ</th><th style="padding:11px;text-align:center">مستحق</th><th style="padding:11px;text-align:center">إجراءات</th>
                </tr></thead>
                <tbody>
                ${tpls.length ? tpls.map(([key, t]) => {
                    const monthly = (parseFloat(t.totalAmount) || 0) / (t.months || 1);
                    const doneCount = Object.keys(t.generated || {}).length;
                    const due = amzDueMonths(t).length;
                    return `<tr style="border-bottom:1px solid #f0f0f0">
                        <td style="padding:9px"><strong>${esc(t.name || '')}</strong></td>
                        <td style="padding:9px;text-align:center">${fmt(t.totalAmount)}</td>
                        <td style="padding:9px;text-align:center">${fmt(monthly)}</td>
                        <td style="padding:9px;text-align:center">${doneCount}/${t.months} شهر</td>
                        <td style="padding:9px;text-align:center">${fmt(monthly * doneCount)}</td>
                        <td style="padding:9px;text-align:center">${due > 0 ? `<span style="background:#fef5e7;color:#e67e22;padding:3px 8px;border-radius:6px;font-weight:700">${due}</span>` : '<span style="color:#27ae60">✓</span>'}</td>
                        <td style="padding:9px;text-align:center;white-space:nowrap">
                            ${due > 0 ? `<button onclick="generateAllDueAmort('${key}')" style="background:#e67e22;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px" title="توليد المستحق">⚡</button>` : ''}
                            <button onclick="openAmortEditor('${key}')" style="background:#2980b9;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px;margin-left:3px">✏️</button>
                            <button onclick="deleteAmort('${key}')" style="background:#e74c3c;color:white;border:none;border-radius:6px;padding:4px 9px;cursor:pointer;font-size:11px">🗑️</button>
                        </td>
                    </tr>`;
                }).join('') : `<tr><td colspan="7" style="text-align:center;padding:30px;color:#aaa">لا توجد جداول إطفاء — أضف أول جدول</td></tr>`}
                </tbody>
            </table>
        </div>`;
};
window.openAmortEditor = function (key) {
    const t = key ? (window.amortizations || {})[key] : null;
    $('amzKey').value = key || '';
    $('amzTitle').textContent = t ? '✏️ تعديل جدول الإطفاء' : '📆 جدول إطفاء جديد';
    $('amzName').value = t?.name || '';
    $('amzTotal').value = t?.totalAmount || '';
    $('amzMonths').value = t?.months || 12;
    $('amzStart').value = t?.startMonth || new Date().toISOString().slice(0, 7);
    $('amzExpenseAcc').innerHTML = recAccountOptions(t?.expenseAcc || '');
    $('amzPrepaidAcc').innerHTML = recAccountOptions(t?.prepaidAcc || '1170');
    $('amzCostCenter').innerHTML = recCostCenterOptions(t?.costCenter || '');
    $('ovAmort').classList.add('show');
};
window.saveAmort = async function () {
    const name = $('amzName').value.trim();
    const total = parseFloat($('amzTotal').value) || 0;
    const months = parseInt($('amzMonths').value) || 0;
    if (!name) { toast('أدخل البيان', 'er'); return; }
    if (total <= 0) { toast('أدخل المبلغ الإجمالي', 'er'); return; }
    if (months < 1) { toast('أدخل عدد الأشهر', 'er'); return; }
    if (!$('amzExpenseAcc').value || !$('amzPrepaidAcc').value) { toast('اختر حساب المصروف وحساب المدفوع مقدماً', 'er'); return; }
    const data = {
        name, totalAmount: total, months, startMonth: $('amzStart').value,
        expenseAcc: $('amzExpenseAcc').value, prepaidAcc: $('amzPrepaidAcc').value,
        costCenter: $('amzCostCenter').value || '', active: true
    };
    const key = $('amzKey').value;
    if (key) { data.generated = (window.amortizations[key]?.generated) || {}; await update(ref(db, 'ledger/amortizations/' + key), data); }
    else { data.generated = {}; data.createdAt = new Date().toISOString(); await push(R.amortz, data); }
    $('ovAmort').classList.remove('show');
    toast('تم حفظ جدول الإطفاء', 'ok');
};
window.deleteAmort = async function (key) {
    const t = (window.amortizations || {})[key]; if (!t) return;
    if (!confirm(`حذف جدول "${t.name}"؟ (القيود المُولّدة تبقى)`)) return;
    await remove(ref(db, 'ledger/amortizations/' + key)); toast('تم الحذف', 'ok');
};
async function generateAmortForMonth(key, ym) {
    const t = (window.amortizations || {})[key]; if (!t || (t.generated || {})[ym]) return null;
    const accounts = Object.values(window.chartOfAccounts || {});
    const expAcc = accounts.find(a => a.code === t.expenseAcc);
    const preAcc = accounts.find(a => a.code === t.prepaidAcc);
    if (!expAcc || !preAcc) { toast('⚠️ تحقق من حسابات جدول الإطفاء', 'wn', 6000); return null; }
    const monthly = Math.round(((parseFloat(t.totalAmount) || 0) / (t.months || 1)) * 100) / 100;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const cc = t.costCenter || ''; const pj = (window.projects || {})[cc] ? cc : '';
    const lines = [
        { accountCode: expAcc.code, accountName: expAcc.nameAr, description: `إطفاء ${t.name} - ${ym}`, costCenter: cc, projectId: pj, debit: monthly, credit: 0 },
        { accountCode: preAcc.code, accountName: preAcc.nameAr, description: `إطفاء مصروف مدفوع مقدماً - ${t.name}`, costCenter: cc, projectId: pj, debit: 0, credit: monthly }
    ];
    const num = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-AMZ-' + Date.now());
    const jrnRef = await push(R.jrn, {
        number: num, date: ym + '-28', lines, totalDebit: monthly, totalCredit: monthly,
        status: 'posted', sourceType: 'amortization', sourceKey: key, reference: `AMZ-${ym}`,
        description: `إطفاء ${t.name} لشهر ${ym}`, createdAt: now, createdBy: userId, postedAt: now, postedBy: userId,
        autoGenerated: true, autoGeneratedFrom: 'amortization'
    });
    await set(ref(db, `ledger/amortizations/${key}/generated/${ym}`), num);
    return num;
}
window.generateAllDueAmort = async function (onlyKey) {
    const entries = Object.entries(window.amortizations || {}).filter(([k, t]) => t.active !== false && (!onlyKey || k === onlyKey));
    const jobs = []; entries.forEach(([key, t]) => amzDueMonths(t).forEach(ym => jobs.push({ key, ym })));
    if (!jobs.length) { toast('لا توجد أقساط مستحقة', 'wn'); return; }
    if (!confirm(`توليد ${jobs.length} قيد إطفاء مستحق؟`)) return;
    let count = 0; for (const j of jobs) { if (await generateAmortForMonth(j.key, j.ym)) count++; }
    toast(`✅ تم توليد ${count} قيد إطفاء`, 'ok', 6000); renderAmortizations();
};

