const EMPEXP_STATUS = { draft: ['مسودة', '#7f8c8d'], approved: ['معتمدة', '#2980b9'], paid: ['مدفوعة/مرحّلة', '#27ae60'], rejected: ['مرفوضة', '#c0392b'] };
