// ── 📥 استيراد قيد يومية من Excel — يفتح في المحرر للمراجعة قبل الحفظ ─────────
window.importJrnEntry = function () {
    let inp = document.getElementById('jrnImportFile');
    if (!inp) {
        inp = document.createElement('input');
        inp.type = 'file'; inp.id = 'jrnImportFile'; inp.accept = '.xlsx,.xls,.csv'; inp.style.display = 'none';
        inp.addEventListener('change', handleJrnImportFile);
        document.body.appendChild(inp);
    }
    inp.value = '';
    inp.click();
};

// تطبيع تاريخ قادم من Excel (نص / رقم تسلسلي / Date)
function jrnNormDate(v) {
    if (v === '' || v === null || v === undefined) return '';
    if (v instanceof Date && !isNaN(v)) return v.toISOString().slice(0, 10);
    if (typeof v === 'number' && XLSX.SSF) {
        const d = XLSX.SSF.parse_date_code(v);
        return d ? `${d.y}-${String(d.m).padStart(2, '0')}-${String(d.d).padStart(2, '0')}` : '';
    }
    const s = String(v).trim();
    if (/^\d{4}-\d{1,2}-\d{1,2}/.test(s)) {
        const [y, m, dd] = s.slice(0, 10).split('-');
        return `${y}-${m.padStart(2, '0')}-${dd.padStart(2, '0')}`;
    }
    const m = s.match(/^(\d{1,2})[\/\-.](\d{1,2})[\/\-.](\d{4})$/); // dd/mm/yyyy
    if (m) return `${m[3]}-${m[2].padStart(2, '0')}-${m[1].padStart(2, '0')}`;
    return '';
}

function handleJrnImportFile(ev) {
    const file = ev.target.files?.[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = e => {
        try {
            const wb = XLSX.read(new Uint8Array(e.target.result), { type: 'array' });
            const sheetName = wb.SheetNames.find(n => !n.includes('تعليمات')) || wb.SheetNames[0];
            const rows = XLSX.utils.sheet_to_json(wb.Sheets[sheetName], { defval: '' });
            if (!rows.length) { toast('⚠️ الملف فارغ — استخدم زر «فورمة الاستيراد» لتنزيل النموذج', 'er'); return; }

            // قراءة مرنة لأسماء الأعمدة
            const col = (row, names) => { for (const n of names) { if (row[n] !== undefined && row[n] !== '') return row[n]; } return ''; };
            const num = v => parseFloat(String(v).replace(/,/g, '')) || 0;
            const accounts = Object.values(window.chartOfAccounts || {});
            const ccEntries = Object.entries(window.costCenters || {});
            const projEntries = Object.entries(window.projects || {});
            const supEntries = Object.entries(window.sup || {});
            const matCatEntries = Object.entries(window.MAT_CATEGORIES || {});

            const lines = [], errors = [];
            rows.forEach((row, i) => {
                const rowNo = i + 2; // رقم الصف في Excel (بعد صف العناوين)
                const code = String(col(row, ['رقم الحساب', 'رمز الحساب', 'الرمز', 'code', 'account'])).trim();
                const debit = num(col(row, ['مدين', 'debit']));
                const credit = num(col(row, ['دائن', 'credit']));
                if (!debit && !credit) return; // صف بلا مبالغ (مثل صفوف فورمة الأرصدة الافتتاحية الفارغة) — تجاهل صامت
                const acc = accounts.find(a => a.code === code);
                if (!acc) { errors.push(`صف ${rowNo}: الحساب «${code}» غير موجود في شجرة الحسابات`); return; }
                if (acc.nature === 'header') { errors.push(`صف ${rowNo}: الحساب «${code}» رئيسي ولا يقبل قيوداً`); return; }
                if (debit > 0 && credit > 0) { errors.push(`صف ${rowNo}: لا يجوز مبلغ مدين ودائن معاً في نفس السطر`); return; }

                // مركز التكلفة: مطابقة بالرمز أو الاسم
                const ccRaw = String(col(row, ['مركز التكلفة', 'cost center', 'costCenter'])).trim();
                let costCenter = '';
                if (ccRaw) {
                    const cc = ccEntries.find(([, c]) => c.code === ccRaw || c.nameAr === ccRaw);
                    if (cc) costCenter = cc[0];
                    else errors.push(`صف ${rowNo}: مركز التكلفة «${ccRaw}» غير معرّف — تم تجاهل المركز فقط`);
                }
                // المشروع: مطابقة بالاسم
                const pjRaw = String(col(row, ['المشروع', 'project'])).trim();
                let projectId = '';
                if (pjRaw) {
                    const pj = projEntries.find(([, p]) => (p.name || '').trim() === pjRaw);
                    if (pj) projectId = pj[0];
                    else errors.push(`صف ${rowNo}: المشروع «${pjRaw}» غير معرّف — تم تجاهل المشروع فقط`);
                }

                // المورد: مطابقة بالاسم
                const supRaw = String(col(row, ['المورد', 'supplier'])).trim();
                let supplierId = '';
                if (supRaw) {
                    const s = supEntries.find(([, s]) => (s.name || '').trim() === supRaw);
                    if (s) supplierId = s[0];
                    else errors.push(`صف ${rowNo}: المورد «${supRaw}» غير معرّف — تم تجاهل المورد فقط`);
                }
                // تصنيف المادة: مطابقة بالاسم (مع/بدون الإيموجي) أو المفتاح
                const matRaw = String(col(row, ['تصنيف المادة', 'التصنيف', 'material category'])).trim();
                let matCategory = '';
                if (matRaw) {
                    const mc = matCatEntries.find(([k, lbl]) => k === matRaw || lbl === matRaw || lbl.replace(/^\S+\s/, '') === matRaw);
                    if (mc) matCategory = mc[0];
                    else errors.push(`صف ${rowNo}: تصنيف المادة «${matRaw}» غير معرّف — تم تجاهل التصنيف فقط`);
                }

                lines.push({
                    accountCode: acc.code,
                    accountName: acc.nameAr || '',
                    description: String(col(row, ['البيان', 'البيان التفصيلي', 'description'])).trim(),
                    date: jrnNormDate(col(row, ['تاريخ السطر', 'التاريخ', 'date'])),
                    costCenter, projectId, supplierId, matCategory, debit, credit
                });
            });

            if (!lines.length) {
                toast('❌ لا توجد سطور صالحة في الملف' + (errors.length ? ` — ${errors[0]}` : ''), 'er');
                return;
            }

            // 🗓️ فورمة الأرصدة الافتتاحية: نفتح المحرر كقيد افتتاحي جاهز (تاريخ وبيان أول السنة)
            const isOpeningTemplate = sheetName === 'الأرصدة الافتتاحية';
            if (isOpeningTemplate) openOpeningBalanceEntry();
            else openJrnEditor();

            while (lines.length < 2) lines.push({ accountCode: '', accountName: '', description: '', date: '', costCenter: '', projectId: '', supplierId: '', matCategory: '', debit: 0, credit: 0 });
            jrnEditorState.lines = lines;
            renderJrnLines();
            if (!isOpeningTemplate) $('mJrnTitle').textContent = '📥 قيد مستورد من Excel — راجع ثم احفظ';
            toast(`✅ تم استيراد ${lines.filter(l => l.accountCode).length} سطر — ${isOpeningTemplate ? 'راجع التوازن ثم احفظ' : 'أكمل البيان العام ثم احفظ'}`, 'ok');
            if (errors.length) showJrnImportNotes(errors);
        } catch (err) {
            console.error('Journal import error:', err);
            toast('❌ تعذر قراءة الملف: ' + (err.message || err), 'er');
        }
    };
    reader.readAsArrayBuffer(file);
}

// عرض ملاحظات الاستيراد (سطور متجاهلة أو حقول لم تُطابق) فوق المحرر
function showJrnImportNotes(errors) {
    document.getElementById('jrnImportNotes')?.remove();
    const box = document.createElement('div');
    box.id = 'jrnImportNotes';
    box.style.cssText = 'position:fixed;bottom:18px;right:18px;max-width:420px;background:#fff8e1;border:2px solid #f39c12;border-radius:12px;padding:14px 16px;z-index:10002;box-shadow:0 10px 30px rgba(0,0,0,.2);font-size:12px;color:#7d4e00;line-height:1.8';
    box.innerHTML = `
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">
            <strong>⚠️ ملاحظات الاستيراد (${errors.length})</strong>
            <button onclick="document.getElementById('jrnImportNotes').remove()" style="background:none;border:none;cursor:pointer;font-size:14px;color:#7d4e00">✕</button>
        </div>
        ${errors.slice(0, 8).map(e => `<div>• ${e}</div>`).join('')}
        ${errors.length > 8 ? `<div style="margin-top:4px;color:#888">… و${errors.length - 8} ملاحظات أخرى</div>` : ''}`;
    document.body.appendChild(box);
}

// ── ✏️🔓 تعديل قيد مرحّل (للمدير المالي فقط) ─────────────────
window.editPostedJrnEntry = async function (key) {
    const entry = window.journalEntries?.[key]; if (!entry) return;
    if (entry.status !== 'posted') { toast('⚠️ هذه الميزة للقيود المرحّلة فقط', 'er'); return; }

    // 🛡️ فحص الصلاحية
    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    if (!isAdmin && !isFinanceMgr && !canFn('edit_posted_journal')) {
        toast('🚫 هذه الميزة مخصصة للمدير المالي ومدير النظام فقط', 'er');
        return;
    }

    // 🏦 حماية التسوية البنكية: قيد له سطور مسوّاة لا يُعدَّل قبل فك تسويتها
    const recInfo = brEntryRecInfo(key);
    if (recInfo.length) {
        toast(`🔒 لا يمكن تعديل هذا القيد: ${recInfo.length} من سطوره مسوّاة بنكياً (حساب ${recInfo.map(r => r.account).join('، ')}). ألغِ تسويتها أو أعد فتح الجلسة أولاً من شاشة التسوية البنكية`, 'er', 9000);
        return;
    }

    // ⚠️ تأكيد قوي
    const warningMsg = `⚠️ تنبيه هام\n\nأنت على وشك تعديل قيد مرحّل (نهائي).\n\nرقم القيد: ${entry.number}\nالمبلغ: ${fmt(entry.totalDebit || 0)} ر\n\nهذه العملية:\n• تُسجَّل بسجل تدقيق دائم\n• تؤثر على دفتر الأستاذ\n• يجب أن يكون لها مبرر محاسبي قوي\n\nهل تريد المتابعة؟`;
    if (!await cf2(warningMsg)) return;

    jrnEditorState = { lines: [], currentSearchLineIdx: -1, currentSearchField: 'account' };
    $('mJrnTitle').innerHTML = `🔓✏️ <span style="color:#8e44ad">تعديل قيد مرحّل</span> — ${entry.number}`;
    $('mJrnKey').value = key;
    $('mJrnNumber').value = entry.number || '';
    $('mJrnDate').value = entry.date || '';
    $('mJrnRef').value = entry.reference || '';
    $('mJrnDescription').value = entry.description || '';
    $('mJrnNotes').value = entry.notes || '';

    const oldProjectId = entry.projectId || '';
    jrnEditorState.lines = (entry.lines || []).filter(l => !l._taxAuto).map(l => ({
        ...l,
        // توافق قديم: إن كانت قيمة costCenter مشروعاً تُنقل لحقل المشروع
        ...(() => {
            const raw = l.costCenter || oldProjectId || '';
            const isProj = raw && (window.projects || {})[raw] && !(window.costCenters || {})[raw];
            return { costCenter: isProj ? '' : raw, projectId: l.projectId || (isProj ? raw : '') };
        })()
    }));
    jrnEditorState.lines = jrnCollapseAnalytic(jrnEditorState.lines); // 🔀 طيّ التوزيع التحليلي
    if (jrnEditorState.lines.length < 2) {
        while (jrnEditorState.lines.length < 2) jrnEditorState.lines.push({ accountCode: '', accountName: '', description: '', date: '', costCenter: '', projectId: '', debit: 0, credit: 0 });
    }

    // 🏷️ علامة خاصة: هذا تعديل لقيد مرحّل
    jrnEditorState.editingPosted = true;
    jrnEditorState.originalEntry = JSON.parse(JSON.stringify(entry));

    renderJrnLines();

    const savePosted = $('mJrnSavePosted');
    if (savePosted) {
        savePosted.innerHTML = '🔓 حفظ التعديل (يبقى مرحّلاً)';
        savePosted.style.background = '#8e44ad';
    }
    // إخفاء زر "حفظ كمسودة" في وضع تعديل قيد مرحّل
    const draftBtn = document.querySelector('button[onclick="saveJrnEntry(\'draft\')"]');
    if (draftBtn) draftBtn.style.display = 'none';

    jrnEditorState.browsing = false; jrnEditorState.navIdx = jrnSortedKeys().indexOf(key);
    deriveJrnHeaderCc();
    jrnLoadCurrency(entry); jrnSetAttachments(entry.attachments); jrnEditorState.book = entry.journalBook || 'GEN'; jrnUpdateBookUI(); if ($('mJrnAutoRev')) $('mJrnAutoRev').value = entry.autoReverseDate || '';
    setJrnEditorMode('edit');
    renderJrnLines();
    renderJrnNav();
    updateJrnHeaderCcLabel();
    ov('mJrnEditor');
    toast('🔓 وضع تعديل قيد مرحّل — كل تغيير سيُسجَّل في سجل التدقيق', 'wn', 6000);
};
window.postJrnEntry = async function (key) {
    const entry = window.journalEntries?.[key]; if (!entry) return;
    const totalDebit = (entry.lines || []).reduce((s, l) => s + (parseFloat(l.debit) || 0), 0);
    const totalCredit = (entry.lines || []).reduce((s, l) => s + (parseFloat(l.credit) || 0), 0);
    if (Math.abs(totalDebit - totalCredit) > 0.01) { toast('❌ لا يمكن ترحيل قيد غير متوازن', 'er'); return; }
    {
        const lock = pcIsLocked(entry.date);
        if (lock) { toast(`🔒 الفترة ${lock.period} مقفلة ولا يمكن ترحيل قيود بتاريخ ${entry.date}`, 'er', 8000); return; }
    }
    // 🧾 مسار الاعتماد: القيود اليدوية التي تتجاوز الحد تتطلب اعتماداً قبل الترحيل
    if (jrnNeedsApproval(entry, totalDebit) && entry.approvalStatus !== 'approved') {
        toast('🔒 هذا القيد يتطلّب اعتماداً قبل الترحيل — أرسله للاعتماد أولاً من قائمة القيد', 'er', 7000); return;
    }
    if (!await cf2(`هل تريد ترحيل القيد ${entry.number}؟ بعد الترحيل لا يمكن تعديله.`)) return;

    try {
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        await update(ref(db, 'ledger/journalEntries/' + key), {
            status: 'posted',
            postedAt: new Date().toISOString(),
            postedBy: userId
        });
        logAudit('ترحيل', 'القيود اليومية', `ترحيل القيد ${entry.number} بمبلغ ${fmt(totalDebit)}`);
        toast('✅ تم ترحيل القيد', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧾  [ACC-APPR]   مسار اعتماد القيود اليدوية (Journal Approval Workflow)      ║
// ╚══════════════════════════════════════════════════════════════════════════╝
function jrnApprovalCfg() { return (window.gbrCfg || {}).jrnApproval || {}; }
function jrnNeedsApproval(entry, amount) { const c = jrnApprovalCfg(); if (!c.enabled) return false; if (entry && entry.sourceType) return false; const th = parseFloat(c.threshold) || 0; return (amount || 0) >= th; }
window.jrnCanApprove = function () { const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin'); const isFin = (typeof myP !== 'undefined' && myP?.role === 'finance_manager'); return isAdmin || isFin || (typeof can === 'function' && can('approve_journal')); };
window.submitJrnForApproval = async function (key) {
    const e = window.journalEntries?.[key]; if (!e) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    try {
        await update(ref(db, 'ledger/journalEntries/' + key), { approvalStatus: 'pending', submittedBy: userId, submittedAt: new Date().toISOString(), rejectReason: null });
        if (typeof logAudit === 'function') logAudit('إرسال للاعتماد', 'القيود اليومية', `القيد ${e.number || ''}`);
        toast('📤 أُرسل القيد للاعتماد', 'ok');
    } catch (err) { toast('❌ ' + (err.message || err), 'er'); }
};
window.approveJrn = async function (key) {
    if (!jrnCanApprove()) { toast('🚫 لا تملك صلاحية اعتماد القيود', 'er'); return; }
    const e = window.journalEntries?.[key]; if (!e) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    try {
        await update(ref(db, 'ledger/journalEntries/' + key), { approvalStatus: 'approved', approvedBy: userId, approvedAt: new Date().toISOString() });
        if (typeof logAudit === 'function') logAudit('اعتماد قيد', 'القيود اليومية', `القيد ${e.number || ''}`);
        toast('✅ اعتُمد القيد — يمكن ترحيله الآن', 'ok');
    } catch (err) { toast('❌ ' + (err.message || err), 'er'); }
};
window.rejectJrn = async function (key) {
    if (!jrnCanApprove()) { toast('🚫 لا تملك صلاحية اعتماد القيود', 'er'); return; }
    const e = window.journalEntries?.[key]; if (!e) return;
    const reason = (typeof prompt === 'function' ? (prompt('سبب الرفض (اختياري):', '') || '') : '');
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    try {
        await update(ref(db, 'ledger/journalEntries/' + key), { approvalStatus: 'rejected', rejectedBy: userId, rejectedAt: new Date().toISOString(), rejectReason: reason });
        if (typeof logAudit === 'function') logAudit('رفض قيد', 'القيود اليومية', `القيد ${e.number || ''}${reason ? ' — ' + reason : ''}`);
        toast('❌ رُفض القيد', 'wn');
    } catch (err) { toast('❌ ' + (err.message || err), 'er'); }
};

// ── إلغاء القيد ─────────────────
window.cancelJrnEntry = async function (key) {
    const entry = window.journalEntries?.[key]; if (!entry) return;
    // 🏦 حماية التسوية البنكية
    const recInfo = brEntryRecInfo(key);
    if (recInfo.length) {
        toast(`🔒 لا يمكن إلغاء هذا القيد: ${recInfo.length} من سطوره مسوّاة بنكياً. ألغِ تسويتها أولاً من شاشة التسوية البنكية`, 'er', 8000);
        return;
    }
    {
        const lock = pcIsLocked(entry.date);
        if (lock) { toast(`🔒 الفترة ${lock.period} مقفلة ولا يمكن إلغاء قيود بتاريخ ${entry.date}`, 'er', 8000); return; }
    }
    if (!await cf2(`هل تريد إلغاء القيد ${entry.number}؟`)) return;
    try {
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        await update(ref(db, 'ledger/journalEntries/' + key), {
            status: 'cancelled',
            cancelledAt: new Date().toISOString(),
            cancelledBy: userId
        });
        logAudit('إلغاء', 'القيود اليومية', `إلغاء القيد ${entry.number}`);
        toast('✅ تم إلغاء القيد', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── حذف القيد ─────────────────
window.deleteJrnEntry = async function (key) {
    const entry = window.journalEntries?.[key]; if (!entry) return;
    if (entry.status !== 'draft' && entry.status !== 'cancelled') { toast('⚠️ لا يمكن حذف قيد مرحّل (ألغِه بدلاً من ذلك)', 'er'); return; }
    {
        const lock = pcIsLocked(entry.date);
        if (lock) { toast(`🔒 الفترة ${lock.period} مقفلة ولا يمكن حذف قيود بتاريخ ${entry.date}`, 'er', 8000); return; }
    }
    if (!await cf2(`هل تريد حذف القيد ${entry.number} نهائياً؟`)) return;
    try {
        await remove(ref(db, 'ledger/journalEntries/' + key));
        logAudit('حذف', 'القيود اليومية', `حذف القيد ${entry.number}`);
        toast('✅ تم الحذف', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── تحديد/إلغاء تحديد الكل ─────────────────
window.toggleAllJrnCheckboxes = function (checked) {
    document.querySelectorAll('#jrnTableBody .jrn-row-check').forEach(cb => {
        if (cb.closest('tr').style.display !== 'none') cb.checked = checked;
    });
};

// ── حذف مجموعة من القيود (مسودات/ملغاة فقط) ─────────────────
async function bulkDeleteJrnEntries(keys) {
    if (!keys.length) { toast('⚠️ لم يتم تحديد أي قيد', 'er'); return; }
    // 🛡️ صلاحية الحذف (انتقلت هنا بعد فصل مربع الاختيار عن أهلية الحذف — فالمربع صار متاحاً للتصدير أيضاً)
    const _canFn = (typeof can === 'function') ? can : () => true;
    const _isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    if (!(_isAdmin || _canFn('delete_journal_entry'))) { toast('🚫 ليس لديك صلاحية حذف القيود', 'er'); return; }

    const deletable = [];
    for (const key of keys) {
        const entry = window.journalEntries?.[key];
        if (!entry) continue;
        if (entry.status !== 'draft' && entry.status !== 'cancelled') continue;
        const lock = pcIsLocked(entry.date);
        if (lock) continue;
        deletable.push([key, entry]);
    }

    if (!deletable.length) { toast('⚠️ لا توجد قيود قابلة للحذف ضمن التحديد (مسودات/ملغاة وغير مقفلة فقط)', 'er', 6000); return; }

    if (!await cf2(`هل تريد حذف ${deletable.length} قيد نهائياً؟${deletable.length < keys.length ? `\n(تم تجاهل ${keys.length - deletable.length} قيد لا يمكن حذفه)` : ''}`)) return;

    let ok = 0, fail = 0;
    for (const [key, entry] of deletable) {
        try {
            await remove(ref(db, 'ledger/journalEntries/' + key));
            logAudit('حذف', 'القيود اليومية', `حذف القيد ${entry.number}`);
            ok++;
        } catch (e) { fail++; }
    }
    toast(`✅ تم حذف ${ok} قيد${fail ? ` — فشل حذف ${fail}` : ''}`, fail ? 'er' : 'ok');
    if (typeof renderJournalEntries === 'function') renderJournalEntries();
}

// ── حذف القيود المحددة بالعلامات ─────────────────
window.deleteSelectedJrnEntries = function () {
    const keys = [...document.querySelectorAll('#jrnTableBody .jrn-row-check:checked')].map(cb => cb.value);
    bulkDeleteJrnEntries(keys);
};

// ── حذف جميع القيود المعروضة حالياً (بعد الفلاتر) ─────────────────
window.deleteAllVisibleJrnEntries = function () {
    const keys = [...document.querySelectorAll('#jrnTableBody .jrn-row-check')]
        .filter(cb => cb.closest('tr').style.display !== 'none')
        .map(cb => cb.value);
    bulkDeleteJrnEntries(keys);
};

// ── تصدير Excel ─────────────────
// entryKey: اختياري — نصّ (قيد واحد) · مصفوفة مفاتيح (مجموعة قيود محددة/معروضة) · null (كل القيود)
window.exportJrnExcel = function (entryKey = null) {
    let entries;
    if (Array.isArray(entryKey)) {                                   // 📦 مجموعة قيود
        entries = entryKey.map(k => window.journalEntries?.[k]).filter(Boolean);
        if (!entries.length) { toast('⚠️ لا توجد قيود للتصدير', 'er'); return; }
    } else if (entryKey) {                                            // 📄 قيد واحد
        const e = window.journalEntries?.[entryKey];
        if (!e) { toast('⚠️ القيد غير موجود', 'er'); return; }
        entries = [e];
    } else {                                                          // 📚 كل القيود
        entries = Object.values(window.journalEntries || {});
    }
    if (!entries.length) { toast('⚠️ لا توجد قيود للتصدير', 'er'); return; }

    const rows = [];
    entries.sort((a, b) => (a.date || '').localeCompare(b.date || '')).forEach(e => {
        (e.lines || []).forEach((l, i) => {
            rows.push({
                'رقم القيد': e.number || '',
                'التاريخ': e.date || '',
                'البيان العام': i === 0 ? (e.description || '') : '',
                'رقم الحساب': l.accountCode,
                'الحساب': l.accountName,
                'البيان التفصيلي': l.description || '',
                'مركز التكلفة': (l.costCenter && !(window.projects || {})[l.costCenter]) ? ccDisplayName(l.costCenter) : '',  // 🎯 منفصل (القيم القديمة المشروعية تظهر بعمود المشروع)
                'المشروع': ccDisplayName(l.projectId || ((window.projects || {})[l.costCenter] ? l.costCenter : '') || e.projectId || ''),  // 🏗️ منفصل
                'مدين': l.debit || 0,
                'دائن': l.credit || 0,
                'المرجع': i === 0 ? (e.reference || '') : '',
                'الحالة': i === 0 ? (e.status || 'draft') : ''
            });
        });
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = [{ wch: 16 }, { wch: 12 }, { wch: 30 }, { wch: 12 }, { wch: 25 }, { wch: 25 }, { wch: 20 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 10 }];
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'قيود اليومية');
        const today = new Date().toISOString().substring(0, 10);
        const fileName = Array.isArray(entryKey) ? `قيود_مختارة_${entries.length}_${today}.xlsx`
            : (entryKey ? `قيد_${entries[0].number || entryKey}.xlsx` : `قيود_اليومية_${today}.xlsx`);
        XLSX.writeFile(wb, fileName);
        toast(`✅ تم تصدير ${entries.length} قيد`, 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── تصدير القيود المحددة (checkboxes) إلى Excel ─────────────────
window.exportSelectedJrnEntries = function () {
    const keys = [...document.querySelectorAll('#jrnTableBody .jrn-row-check:checked')].map(cb => cb.value);
    if (!keys.length) { toast('⚠️ حدّد قيداً واحداً على الأقل للتصدير', 'wn'); return; }
    exportJrnExcel(keys);
};

// ── تصدير كل القيود المعروضة حالياً (بعد الفلاتر) إلى Excel ─────────────────
//    يعتمد على مُعرّف الصف (data-jrn-key) لا على مربعات الاختيار — فيعمل لكل المستخدمين حتى بلا صلاحية حذف
window.exportVisibleJrnEntries = function () {
    const keys = [...document.querySelectorAll('#jrnTableBody tr[data-jrn-key]')]
        .filter(tr => tr.style.display !== 'none')
        .map(tr => tr.getAttribute('data-jrn-key'));
    if (!keys.length) { toast('⚠️ لا توجد قيود معروضة للتصدير', 'wn'); return; }
    exportJrnExcel(keys);
};

console.log('✅ Journal Entries module loaded');


