window.editPMC = function (key) {
    const c = window.projectMonthlyCosts?.[key]; if (!c) return;
    openPMCEditor();
    setTimeout(() => {
        $('mPMCTitle').textContent = '✏️ تعديل التكلفة';
        $('mPMCKey').value         = key;
        $('mPMCProject').value     = c.projectId || '';
        // استعادة نوع التاريخ والقيمة
        const savedDateType = c.dateType || 'monthly';
        pmcSetGranularity(savedDateType);
        document.getElementById('mPMCDate').value = c.date || c.month || '';

        if (c.customCategory) {
            $('mPMCCategory').value = '__custom__';
            $('mPMCCustomCategory').value = c.customCategory;
            $('mPMCCustomCategory').style.display = 'block';
        } else {
            $('mPMCCategory').value = c.category || '';
            $('mPMCCustomCategory').style.display = 'none';
        }

        // استعادة المستويات
        const savedLevels = [];
        for (let i = 1; i <= 5; i++) { if (c[`level${i}`]) savedLevels.push(c[`level${i}`]); }
        pmcInitLevels(savedLevels);

        $('mPMCAmount').value      = c.amount || '';
        $('mPMCDescription').value = c.description || '';
        $('mPMCReference').value   = c.reference || '';
        $('mPMCSource').value      = c.source || 'manual';
        $('mPMCNotes').value       = c.notes || '';
    }, 80);
};

// ── حفظ ─────────────────
window.savePMC = async function (addAnother) {
    const projectId      = $('mPMCProject').value;
    const dateType       = $('mPMCDateType')?.value || 'monthly';
    const dateVal        = $('mPMCDate')?.value || '';
    const categorySelect = $('mPMCCategory').value;
    const amount         = parseFloat($('mPMCAmount').value);

    if (!projectId)            { toast('⚠️ المشروع مطلوب', 'er'); return; }
    if (!dateVal)              { toast('⚠️ التاريخ مطلوب', 'er'); return; }
    if (!categorySelect)       { toast('⚠️ نوع التكلفة مطلوب', 'er'); return; }
    if (!amount || amount <= 0){ toast('⚠️ المبلغ يجب أن يكون أكبر من الصفر', 'er'); return; }

    // اشتقاق date (YYYY-MM-DD) و month (YYYY-MM) من القيمة المُدخلة
    let date, month;
    if (dateType === 'daily') {
        date  = dateVal;                   // YYYY-MM-DD
        month = dateVal.slice(0, 7);       // YYYY-MM
    } else if (dateType === 'weekly') {
        // المستخدم يختار أي يوم → نُحوّله لسبت الأسبوع (بداية الأسبوع)
        const picked = new Date(dateVal + 'T00:00:00');
        const daysSinceSat = (picked.getDay() + 1) % 7; // 0=السبت، 6=الجمعة
        picked.setDate(picked.getDate() - daysSinceSat);
        date  = picked.toISOString().slice(0, 10);
        month = date.slice(0, 7);
    } else {
        // شهري: dateVal = YYYY-MM
        month = dateVal;
        date  = dateVal + '-01';
    }

    let category = categorySelect, customCategory = '';
    if (categorySelect === '__custom__') {
        customCategory = $('mPMCCustomCategory').value.trim();
        if (!customCategory) { toast('⚠️ اكتب اسم النوع المخصص', 'er'); return; }
        category = 'other';
    } else if (categorySelect.startsWith('custom_')) {
        // نوع مخصص محفوظ في Firebase — احفظه كـ category مباشرة
        category = categorySelect;
    }

    // قراءة المستويات الهرمية
    const levels = pmcGetLevels();

    const key    = $('mPMCKey').value;
    const userId = window.curU?.uid || (typeof curU !== 'undefined' ? curU?.uid : null) || 'system';
    const now    = new Date().toISOString();

    const data = {
        projectId, dateType, date, month,
        category, customCategory, amount,
        level1: levels[0] || '', level2: levels[1] || '',
        level3: levels[2] || '', level4: levels[3] || '',
        level5: levels[4] || '', levelCount: levels.length,
        description: $('mPMCDescription').value.trim(),
        reference:   $('mPMCReference').value.trim(),
        source:      $('mPMCSource').value,
        notes:       $('mPMCNotes').value.trim(),
        updatedAt: now, updatedBy: userId
    };

    try {
        if (key) {
            await update(ref(db, 'ledger/projectMonthlyCosts/' + key), data);
            toast('✅ تم التحديث', 'ok');
        } else {
            data.createdAt = now; data.createdBy = userId;
            await push(R.pmc, data);
            toast('✅ تم إضافة التكلفة', 'ok');
            // 🆕 إنشاء قيد محاسبي تلقائي
            const jrnResult = await createJournalForPMC(data);
            if (jrnResult) {
                await update(ref(db, 'ledger/projectMonthlyCosts/' + newRef.key), { journalEntryKey: jrnResult.key });
            }
        }
        if (addAnother) {
            $('mPMCKey').value = '';
            $('mPMCTitle').textContent = '➕ إضافة تكلفة شهرية';
            $('mPMCAmount').value = '';
            $('mPMCDescription').value = '';
            $('mPMCReference').value = '';
            pmcInitLevels([]);
            setTimeout(() => $('pmcLevel1')?.focus() || $('mPMCAmount').focus(), 100);
        } else { cov('mPMC'); }
    } catch (e) { console.error('Save PMC:', e); toast('❌ خطأ: ' + (e.message || e), 'er'); }
};

// ── حذف ─────────────────
window.deletePMC = async function (key) {
    const c = window.projectMonthlyCosts?.[key]; if (!c) return;
    const projectName = window.projects?.[c.projectId]?.name || '';

    // 🆕 إلغاء القيد المحاسبي المرتبط
    if (c.journalEntryKey) {
        await cancelJournalEntry(c.journalEntryKey, `إلغاء قيد تكلفة مشروع ${c.description}`);
    }
    const info = getPMCCategoryInfo(c.category);
    const lvl = [c.level1, c.level2, c.level3].filter(Boolean).join(' › ');
    if (!await cf2(`هل تريد حذف هذه التكلفة؟\n\nالمشروع: ${projectName}\n${lvl ? 'البند: ' + lvl + '\n' : ''}النوع: ${info.ar}\nالمبلغ: ${fmt(c.amount)} ر`)) return;
    try {
        await remove(ref(db, 'ledger/projectMonthlyCosts/' + key));
        toast('✅ تم الحذف', 'ok');
    } catch (e) { toast('❌ خطأ: ' + (e.message || e), 'er'); }
};

// ── تحديد / حذف جماعي ────────────────────────
window._pmcSelected  = new Set();
window._pmcFilteredKeys = [];

function _pmcUpdateBulkBar() {
    const sel = window._pmcSelected;
    const bar = document.getElementById('pmcBulkBar');
    if (!bar) return;
    if (sel.size === 0) { bar.style.display = 'none'; return; }
    bar.style.display = 'flex';
    document.getElementById('pmcBulkCount').textContent = `${sel.size} محدد`;
    const totalAmt = [...sel].reduce((s, k) => s + (parseFloat(window.projectMonthlyCosts?.[k]?.amount) || 0), 0);
    document.getElementById('pmcBulkAmount').textContent = `الإجمالي: ${fmt(totalAmt)} ر`;
    // sync select-all checkbox indeterminate state
    const allKeys = window._pmcFilteredKeys || [];
    const allChk  = document.getElementById('pmcChkAll');
    if (allChk) {
        allChk.indeterminate = sel.size > 0 && sel.size < allKeys.length;
        allChk.checked = sel.size === allKeys.length && allKeys.length > 0;
    }
}

window.pmcToggleRow = function (key, checked) {
    if (!window._pmcSelected) window._pmcSelected = new Set();
    checked ? window._pmcSelected.add(key) : window._pmcSelected.delete(key);
    const row = document.getElementById('pmcRow_' + key);
    if (row) row.style.background = checked ? '#fff3cd' : '';
    _pmcUpdateBulkBar();
};

window.pmcToggleAll = function (checked) {
    window._pmcSelected = new Set();
    (window._pmcFilteredKeys || []).forEach(k => {
        if (checked) window._pmcSelected.add(k);
        const chk = document.getElementById('pmcChk_' + k);
        const row = document.getElementById('pmcRow_' + k);
        if (chk) chk.checked = checked;
        if (row) row.style.background = checked ? '#fff3cd' : '';
    });
    _pmcUpdateBulkBar();
};

window.pmcSelectAll   = function () { pmcToggleAll(true);  };
window.pmcClearSelection = function () { pmcToggleAll(false); };

window.pmcDeleteSelected = async function () {
    const sel = window._pmcSelected;
    if (!sel || sel.size === 0) { toast('⚠️ لم تحدد أي سجل', 'er'); return; }
    const totalAmt = [...sel].reduce((s, k) => s + (parseFloat(window.projectMonthlyCosts?.[k]?.amount) || 0), 0);
    if (!await cf2(`هل تريد حذف ${sel.size} سجل؟\nالإجمالي: ${fmt(totalAmt)} ر\n\nلا يمكن التراجع عن هذا الإجراء.`)) return;
    try {
        const updates = {};
        sel.forEach(k => { updates['ledger/projectMonthlyCosts/' + k] = null; });
        await update(ref(db, '/'), updates);
        window._pmcSelected = new Set();
        toast(`✅ تم حذف ${sel.size} سجل`, 'ok');
    } catch(e) { toast('❌ خطأ: ' + (e.message || e), 'er'); }
};

// ── تصدير Excel مع المستويات ─────────────────
window.exportPMCExcel = function () {
    const costs = Object.values(window.projectMonthlyCosts || {});
    if (!costs.length) { toast('⚠️ لا توجد بيانات للتصدير', 'er'); return; }

    const fP = $('pmcFilterProject')?.value || '';
    const fM = $('pmcFilterMonth')?.value || '';
    const fC = $('pmcFilterCategory')?.value || '';
    const filtered = costs.filter(c =>
        (!fP || c.projectId === fP) && (!fM || c.month === fM) && (!fC || c.category === fC)
    );

    const rows = filtered.map(c => {
        const info = getPMCCategoryInfo(c.category);
        const projName = window.projects?.[c.projectId]?.name || c.projectId;
        return {
            'الشهر':       c.month || '',
            'المشروع':     projName,
            'المستوى١':    c.level1 || '',
            'المستوى٢':    c.level2 || '',
            'المستوى٣':    c.level3 || '',
            'المستوى٤':    c.level4 || '',
            'المستوى٥':    c.level5 || '',
            'النوع':       c.customCategory || info.ar,
            'المبلغ':      c.amount || 0,
            'البيان':      c.description || '',
            'المرجع':      c.reference || '',
            'المصدر':      c.source || 'manual',
            'ملاحظات':     c.notes || '',
            'تاريخ الإدخال': c.createdAt?.substring(0, 10) || ''
        };
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = [10,25,18,18,18,18,18,22,14,35,15,12,25,12].map(w=>({wch:w}));
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'تكاليف المشاريع');
        XLSX.writeFile(wb, `تكاليف_المشاريع_${new Date().toISOString().substring(0,10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) { toast('❌ خطأ في التصدير: ' + (e.message||e), 'er'); }
};

