window.pmcProcessImport = function(e) {
    const file = e.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = ev => {
        try {
            const wb   = XLSX.read(new Uint8Array(ev.target.result), {type:'array'});
            const data = XLSX.utils.sheet_to_json(wb.Sheets[wb.SheetNames[0]]);
            if (!data.length) { toast('❌ الملف فارغ', 'er'); return; }

            // معاينة أول 5 صفوف
            window._pmcImportData = data;
            const cols = Object.keys(data[0]);
            const preview = `
                <div style="font-size:12px;font-weight:700;margin-bottom:8px;color:#27ae60">
                    ✅ تم قراءة ${data.length} صف — معاينة أول 5:
                </div>
                <div style="overflow-x:auto">
                <table style="width:100%;border-collapse:collapse;font-size:11px">
                    <thead><tr>${cols.map(c=>`<th style="background:#1a3a5c;color:#fff;padding:5px 8px;text-align:right">${c}</th>`).join('')}</tr></thead>
                    <tbody>${data.slice(0,5).map((r,i)=>`<tr style="${i%2?'background:#f9f9f9':''}">${cols.map(c=>`<td style="padding:4px 8px;border:1px solid #eee">${r[c]??''}</td>`).join('')}</tr>`).join('')}</tbody>
                </table></div>`;
            $('pmcImportPreview').innerHTML = preview;
            $('pmcImportConfirmBtn').style.display = '';
        } catch(err) { toast('❌ خطأ في قراءة الملف: ' + err.message, 'er'); }
    };
    reader.readAsArrayBuffer(file);
};

window.pmcConfirmImport = async function() {
    const data = window._pmcImportData;
    if (!data?.length) return;
    const userId = window.curU?.uid || 'system';
    const now    = new Date().toISOString();
    let ok = 0, errs = 0;

    const btn = $('pmcImportConfirmBtn');
    btn.disabled = true; btn.textContent = '⏳ جاري الاستيراد...';

    for (const row of data) {
        try {
            // البحث عن معرف المشروع من اسمه
            const projEntry = Object.entries(window.projects||{})
                .find(([,p]) => p.name === (row['المشروع']||'').trim());
            const projectId = projEntry?.[0] || '';
            const amount    = parseFloat(row['المبلغ'] || 0);
            if (!amount || !row['الشهر']) { errs++; continue; }

            // تحديد النوع
            const catMap = {'materials':'materials','labor':'labor','equipment':'equipment',
                'subcontractors':'subcontractors','transport':'transport','utilities':'utilities',
                'rent':'rent','permits':'permits','indirect':'indirect','other':'other'};
            const catKey = Object.keys(PMC_CATEGORIES).find(k =>
                PMC_CATEGORIES[k].ar.replace(/[^ء-ي\s]/g,'').trim() === (row['النوع']||'').replace(/[^ء-ي\s]/g,'').trim()
            );

            const payload = {
                projectId, month: String(row['الشهر']).trim(),
                level1: (row['المستوى١']||row['المستوى 1']||'').trim(),
                level2: (row['المستوى٢']||row['المستوى 2']||'').trim(),
                level3: (row['المستوى٣']||row['المستوى 3']||'').trim(),
                level4: (row['المستوى٤']||row['المستوى 4']||'').trim(),
                level5: (row['المستوى٥']||row['المستوى 5']||'').trim(),
                levelCount: [1,2,3,4,5].filter(i=>(row[`المستوى${['١','٢','٣','٤','٥'][i-1]}`]||row[`المستوى ${i}`]||'').trim()).length,
                category: catKey || 'other',
                customCategory: catKey ? '' : (row['النوع']||'').trim(),
                amount, description: (row['البيان']||'').trim(),
                reference: (row['المرجع']||'').trim(), source: row['المصدر'] || 'imported',
                notes: (row['ملاحظات']||'').trim(),
                createdAt: now, createdBy: userId, updatedAt: now, updatedBy: userId
            };
            await push(R.pmc, payload);
            ok++;
        } catch(err) { errs++; }
    }

    btn.disabled = false; btn.textContent = '✅ استيراد البيانات';
    cov('mPMCImport');
    toast(`✅ تم استيراد ${ok} سجل${errs ? ` · ❌ ${errs} خطأ` : ''}`, ok>0?'ok':'er', 5000);
};

