// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📊  [INDCOST]   ━━━━   INDIRECT COSTS ALLOCATION   ━━━━                  ║
// ║    التكاليف غير المباشرة (إهلاك، إيجارات...) وتوزيعها على المشاريع          ║
// ╚══════════════════════════════════════════════════════════════════════════╝

const IC_CATEGORIES = {
    depreciation: { ar: '📉 إهلاك',          color: '#34495e', bg: '#ebedef' },
    rent:         { ar: '🏢 إيجارات',          color: '#5b2c6f', bg: '#f4ecf7' },
    leasehold:    { ar: '🏗️ تحسينات مستأجرة', color: '#a04000', bg: '#fbeee6' },
    salaries:     { ar: '👔 رواتب إدارية',    color: '#2d6a9f', bg: '#e8f4fd' },
    utilities:    { ar: '⚡ كهرباء ومياه',    color: '#e67e22', bg: '#fef5e7' },
    insurance:    { ar: '🛡️ تأمين',           color: '#16a085', bg: '#e8f8f5' },
    other:        { ar: '📦 أخرى',             color: '#888',    bg: '#f0f5fa' },
};

function icCatInfo(cat) { return IC_CATEGORIES[cat] || IC_CATEGORIES.other; }
function icLbl()        { return 'font-size:12px;font-weight:700;color:#555;display:block;margin-bottom:4px'; }
function icInp(extra='') { return `width:100%;padding:9px 10px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:13px;box-sizing:border-box;${extra}`; }

// قيمة الشهر = السنوي ÷ 12 ما لم يكن هناك تجاوز يدوي
function icMonthlyBase(cost, monthKey) {
    const ov = (cost.monthlyOverrides || {})[monthKey];
    if (ov !== undefined && ov !== null && ov !== '') return parseFloat(ov) || 0;
    return (parseFloat(cost.annualAmount) || 0) / 12;
}
// الحصول على خريطة التوزيع السارية لشهر معيّن:
// إذا كان هناك "تغيير توزيع" مُدخَل من تاريخ ≤ الشهر المطلوب، يُطبَّق بدلاً من التوزيع الافتراضي
function icGetAllocationForMonth(cost, monthKey) {
    const overrides = cost.allocationOverrides || {};
    const applicableMonth = Object.keys(overrides)
        .filter(m => m <= monthKey)
        .sort()
        .pop(); // الأحدث قبل أو خلال هذا الشهر
    return applicableMonth ? overrides[applicableMonth] : (cost.allocations || {});
}
function icProjectShare(cost, monthKey, projectId) {
    const alloc = icGetAllocationForMonth(cost, monthKey);
    const pct = parseFloat(alloc[projectId]) || 0;
    return icMonthlyBase(cost, monthKey) * (pct / 100);
}
// دوال عامة تُستخدم من project-detail.js أيضاً
window.icProjectMonthlyShare = function (projectId, monthKey) {
    return Object.values(window.indirectCosts || {}).reduce((s, c) => s + icProjectShare(c, monthKey, projectId), 0);
};
window.icProjectAnnualShare = function (projectId, yearPrefix) {
    let total = 0;
    for (let m = 1; m <= 12; m++) {
        total += window.icProjectMonthlyShare(projectId, `${yearPrefix}-${String(m).padStart(2,'0')}`);
    }
    return total;
};

// ── Render ────────────────────────────────────────────────────────────────
window.renderIndirectCosts = function () {
    const container = $('pg-indirectcosts'); if (!container) return;
    const costs = window.indirectCosts || {};
    const costEntries = Object.entries(costs);
    const projects = window.projects || {};
    const selectedMonth = $('icSelectedMonth')?.value || new Date().toISOString().slice(0, 7);

    const totalAnnual       = costEntries.reduce((s, [, c]) => s + (parseFloat(c.annualAmount) || 0), 0);
    const totalMonthSelected = costEntries.reduce((s, [, c]) => s + icMonthlyBase(c, selectedMonth), 0);
    const involvedProjects  = new Set();
    costEntries.forEach(([, c]) => Object.keys(c.allocations || {}).forEach(pid => involvedProjects.add(pid)));

    // توزيع الشهر المحدد على المشاريع (مجموع كل البنود)
    const projSharesMonth = {};
    costEntries.forEach(([, c]) => {
        Object.keys(c.allocations || {}).forEach(pid => {
            projSharesMonth[pid] = (projSharesMonth[pid] || 0) + icProjectShare(c, selectedMonth, pid);
        });
    });
    const sortedShares = Object.entries(projSharesMonth).sort((a, b) => b[1] - a[1]);

    container.innerHTML = `
    <!-- Hero -->
    <div style="background:linear-gradient(135deg,#34495e 0%,#5b2c6f 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(52,73,94,.25)">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
            <div>
                <div style="font-size:11px;opacity:.85;letter-spacing:1px">INDIRECT COSTS ALLOCATION</div>
                <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📊 التكاليف غير المباشرة</h1>
                <p style="margin:6px 0 0;font-size:12px;opacity:.95">سجّل تكاليف الشركة العامة (إهلاك، إيجارات، رواتب إدارية...) ووزّعها شهرياً وسنوياً على المشاريع بنسب تحددها أنت</p>
            </div>
            <button class="btn" onclick="icOpenForm()" style="background:white;color:#34495e;padding:10px 18px;font-weight:800;font-size:14px">➕ إضافة بند تكلفة</button>
        </div>
    </div>

    <!-- KPI -->
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(175px,1fr));gap:12px;margin-bottom:18px">
        <div style="background:white;border-radius:12px;padding:14px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-top:3px solid #34495e">
            <div style="font-size:11px;color:#888;font-weight:600">عدد بنود التكلفة</div>
            <div style="font-size:22px;font-weight:900;color:#34495e;margin:4px 0">${costEntries.length}</div>
        </div>
        <div style="background:white;border-radius:12px;padding:14px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-top:3px solid #8e44ad">
            <div style="font-size:11px;color:#888;font-weight:600">الإجمالي السنوي</div>
            <div style="font-size:22px;font-weight:900;color:#8e44ad;margin:4px 0">${fmt(totalAnnual)}</div>
            <div style="font-size:10px;color:#aaa">ريال / سنة</div>
        </div>
        <div style="background:white;border-radius:12px;padding:14px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-top:3px solid #2d6a9f">
            <div style="font-size:11px;color:#888;font-weight:600">تكلفة الشهر المحدد</div>
            <div style="font-size:22px;font-weight:900;color:#2d6a9f;margin:4px 0">${fmt(totalMonthSelected)}</div>
            <div style="font-size:10px;color:#aaa">ريال · ${selectedMonth}</div>
        </div>
        <div style="background:white;border-radius:12px;padding:14px;box-shadow:0 2px 8px rgba(0,0,0,.05);border-top:3px solid #16a085">
            <div style="font-size:11px;color:#888;font-weight:600">المشاريع المستفيدة</div>
            <div style="font-size:22px;font-weight:900;color:#16a085;margin:4px 0">${involvedProjects.size}</div>
            <div style="font-size:10px;color:#aaa">مشروع</div>
        </div>
    </div>

    <!-- توزيع شهر محدد على المشاريع -->
    <div class="card" style="margin-bottom:18px">
        <div class="tlb">
            <div class="c-tl" style="margin:0;border:none;padding:0">📅 توزيع التكلفة على المشاريع</div>
            <div style="display:flex;align-items:center;gap:8px">
                <label style="font-size:11px;color:#666;font-weight:700">الشهر:</label>
                <input type="month" id="icSelectedMonth" value="${selectedMonth}" onchange="renderIndirectCosts()" style="padding:8px 10px;border:1.5px solid #d0d7e0;border-radius:8px;font-family:inherit;font-size:13px">
            </div>
        </div>
        ${sortedShares.length === 0
            ? '<div class="empty"><div class="ei">📅</div><p>لا يوجد توزيع بعد — أضف بنود تكلفة وحدد نسب توزيعها على المشاريع</p></div>'
            : `<div class="tw" style="overflow-x:auto"><table class="st">
            <thead><tr><th>#</th><th>المشروع</th><th>نصيبه من الشهر</th><th>نصيبه السنوي (مبدئي)</th><th>نسبة من إجمالي الشهر</th></tr></thead>
            <tbody>
            ${sortedShares.map(([pid, amt], i) => {
                const annualShare = window.icProjectAnnualShare(pid, selectedMonth.slice(0,4));
                const pctOfTotal = totalMonthSelected > 0 ? (amt / totalMonthSelected) * 100 : 0;
                return `<tr>
                    <td style="color:#888;font-weight:700">${i+1}</td>
                    <td style="font-weight:700;color:#1a3a5c">${projects[pid]?.name || pid}</td>
                    <td style="font-weight:700;color:#2d6a9f">${fmt(amt)} ريال</td>
                    <td style="font-weight:600;color:#8e44ad">${fmt(annualShare)} ريال</td>
                    <td><div style="display:flex;align-items:center;gap:6px">
                        <div style="background:#e8f0f7;border-radius:4px;height:6px;flex:1;max-width:100px">
                            <div style="width:${Math.min(100,pctOfTotal)}%;background:#16a085;height:100%;border-radius:4px"></div>
                        </div>
                        <span style="font-size:11px;color:#888">${pctOfTotal.toFixed(1)}%</span>
                    </div></td>
                </tr>`;
            }).join('')}
            </tbody>
            <tfoot><tr style="background:#f0f5fa;font-weight:800">
                <td colspan="2" style="padding:10px;text-align:right;color:#1a3a5c">الإجمالي</td>
                <td style="color:#2d6a9f">${fmt(totalMonthSelected)} ريال</td>
                <td style="color:#8e44ad">${fmt(sortedShares.reduce((s,[,a])=>s+a,0)*12)} ريال</td>
                <td></td>
            </tr></tfoot>
        </table></div>`}
    </div>

    <!-- قائمة بنود التكلفة -->
    <div class="card" style="margin-bottom:18px">
        <div class="tlb">
            <div class="c-tl" style="margin:0;border:none;padding:0">🧾 بنود التكلفة غير المباشرة</div>
            <span style="background:#eaf2fb;color:#1a3a5c;padding:4px 12px;border-radius:10px;font-size:12px;font-weight:700">${costEntries.length} بند · ${fmt(totalAnnual)} ريال/سنة</span>
        </div>
        ${costEntries.length === 0
            ? '<div class="empty"><div class="ei">🧾</div><p>لا توجد بنود بعد — أضف أول بند (مثل الإهلاك أو الإيجار) ثم حدد نسب توزيعه على المشاريع</p></div>'
            : `<div class="tw" style="overflow-x:auto"><table class="st">
            <thead><tr>
                <th>#</th><th>البند</th><th>النوع</th><th>القيمة السنوية</th><th>الحصة الشهرية الأساسية</th><th>التوزيع</th><th>إجراءات</th>
            </tr></thead>
            <tbody>
            ${costEntries.map(([ck, c], i) => {
                const info = icCatInfo(c.category);
                const monthlyBase = (parseFloat(c.annualAmount) || 0) / 12;
                const allocCount  = Object.keys(c.allocations || {}).length;
                const allocSum    = Object.values(c.allocations || {}).reduce((s, v) => s + (parseFloat(v)||0), 0);
                const overridesCnt = Object.keys(c.monthlyOverrides || {}).length;
                return `<tr>
                    <td style="color:#888;font-weight:700">${i+1}</td>
                    <td style="font-weight:700;color:#1a3a5c">${c.name||'-'}${c.notes?`<div style="font-size:11px;color:#888;margin-top:2px">${c.notes}</div>`:''}
                    </td>
                    <td><span style="background:${info.bg};color:${info.color};padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700">${info.ar}</span></td>
                    <td style="font-weight:700;color:#8e44ad">${fmt(c.annualAmount||0)} ريال</td>
                    <td>
                        <div style="font-weight:600;color:#2d6a9f">${fmt(monthlyBase)} ريال</div>
                        ${overridesCnt>0?`<div style="font-size:10px;color:#e67e22;margin-top:2px">✏️ ${overridesCnt} شهر بقيمة يدوية</div>`:''}
                    </td>
                    <td>
                        <div style="font-weight:600;color:#16a085">${allocCount} مشروع (افتراضي)</div>
                        <div style="font-size:10px;color:${Math.abs(allocSum-100)<0.1?'#27ae60':'#e67e22'}">مجموع النسب: ${allocSum.toFixed(1)}%${Math.abs(allocSum-100)<0.1?' ✓':' ⚠️'}</div>
                        ${Object.keys(c.allocationOverrides||{}).length>0?`<div style="font-size:10px;color:#084298;margin-top:2px">📅 ${Object.keys(c.allocationOverrides).length} تغيير مجدوَل</div>`:''}
                    </td>
                    <td><div style="display:flex;gap:4px">
                        <button class="btn b-b" style="padding:3px 7px;font-size:11px" onclick="icOpenForm('${ck}')">✏️</button>
                        <button class="btn b-r" style="padding:3px 7px;font-size:11px" onclick="icDeleteCost('${ck}')">🗑️</button>
                    </div></td>
                </tr>`;
            }).join('')}
            </tbody>
        </table></div>`}
    </div>

    <!-- نموذج الإضافة/التعديل -->
    <div id="ic-cost-form" style="display:none;background:white;border-radius:12px;padding:20px;margin-bottom:18px;box-shadow:0 4px 16px rgba(0,0,0,.1);border:2px solid #34495e">
        <div style="font-size:15px;font-weight:800;color:#1a3a5c;margin-bottom:14px" id="ic-form-title">➕ إضافة بند تكلفة جديد</div>
        <input type="hidden" id="ic-cost-key">

        <!-- الحقول الأساسية -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px;margin-bottom:16px">
            <div style="grid-column:span 2">
                <label style="${icLbl()}">اسم بند التكلفة</label>
                <input id="ic-cost-name" placeholder="مثال: إهلاك المعدات، إيجار المقر الرئيسي..." style="${icInp()}">
            </div>
            <div>
                <label style="${icLbl()}">النوع</label>
                <select id="ic-cost-category" style="${icInp()}">
                    ${Object.entries(IC_CATEGORIES).map(([k,v])=>`<option value="${k}">${v.ar}</option>`).join('')}
                </select>
            </div>
            <div>
                <label style="${icLbl()}">القيمة السنوية (ريال)</label>
                <input id="ic-cost-annual" type="number" min="0" step="0.01" placeholder="0.00" oninput="icRecalcBase()" style="${icInp()}">
            </div>
            <div>
                <label style="${icLbl()}">الحصة الشهرية الأساسية (السنوي ÷ 12)</label>
                <input id="ic-monthly-base" readonly style="${icInp('background:#f0f5fa;font-weight:700;color:#2d6a9f')}">
            </div>
            <div style="grid-column:span 2">
                <label style="${icLbl()}">ملاحظات <span style="font-weight:400;color:#999">(اختياري)</span></label>
                <input id="ic-cost-notes" placeholder="أي تفاصيل إضافية..." style="${icInp()}">
            </div>
        </div>

        <!-- توزيع النسبة على المشاريع -->
        <div style="background:#f8fafc;border-radius:10px;padding:14px;margin-bottom:14px;border:1px solid #e0e7f0">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;flex-wrap:wrap;gap:8px">
                <div style="font-size:13px;font-weight:800;color:#1a3a5c">📊 توزيع النسبة على المشاريع</div>
                <div id="ic-alloc-sum-badge"></div>
            </div>
            <div id="ic-alloc-rows"></div>
            <button type="button" class="btn" onclick="icAddAllocRow()" style="margin-top:8px;padding:6px 14px;font-size:12px;background:#eaf2fb;color:#1a3a5c;border:1.5px solid #c6d9ee">➕ إضافة مشروع</button>
        </div>

        <!-- تعديلات يدوية لشهور بعينها -->
        <div style="background:#fffbee;border-radius:10px;padding:14px;margin-bottom:14px;border:1.5px dashed #f0c419">
            <div style="font-size:13px;font-weight:800;color:#7d4e00;margin-bottom:4px">✏️ تعديل قيمة شهر معيّن يدوياً</div>
            <div style="font-size:11px;color:#9a7b1f;margin-bottom:10px">للمصاريف غير المنتظمة — أي شهر بدون تعديل يستخدم السنوي ÷ 12 تلقائياً</div>
            <div id="ic-override-rows"></div>
            <button type="button" class="btn" onclick="icAddOverrideRow()" style="margin-top:8px;padding:6px 14px;font-size:12px;background:#fef3cd;color:#7d4e00;border:1.5px solid #f0c419">➕ إضافة تعديل لشهر</button>
        </div>

        <!-- تغيير التوزيع على المشاريع من تاريخ معيّن -->
        <div style="background:#f0f5fa;border-radius:10px;padding:14px;margin-bottom:16px;border:1.5px dashed #2d6a9f">
            <div style="font-size:13px;font-weight:800;color:#1a3a5c;margin-bottom:4px">📅 تغيير التوزيع على المشاريع من تاريخ معيّن</div>
            <div style="font-size:11px;color:#4a6fa5;margin-bottom:10px">استخدم هذا القسم إذا انتقلت السيارة / الموظف من مشروع لآخر، أو توقّف مشروع، أو تغيّرت النسب خلال السنة — أي شهر بدون تغيير يستخدم التوزيع الافتراضي أعلاه</div>
            <div id="ic-allocoverride-blocks"></div>
            <button type="button" class="btn" onclick="icAddAllocOverrideBlock()" style="margin-top:8px;padding:6px 14px;font-size:12px;background:#cfe2ff;color:#084298;border:1.5px solid #93b8f0">📅 إضافة تغيير توزيع من تاريخ جديد</button>
        </div>

        <div style="display:flex;gap:8px">
            <button class="btn b-g" onclick="icSaveCost()">💾 حفظ بند التكلفة</button>
            <button class="btn" onclick="$('ic-cost-form').style.display='none'" style="background:#f8fafc;color:#666;border:1.5px solid #d0d7e0">إلغاء</button>
        </div>
    </div>`;
};

window.icRecalcBase = function () {
    const annual = parseFloat($('ic-cost-annual')?.value) || 0;
    const el = $('ic-monthly-base');
    if (el) el.value = `${fmt(annual / 12)} ريال / شهر`;
};

// ── حالة النموذج المؤقتة ──────────────────────────────────────────────────
window._icFS = { allocations: [], overrides: [], allocOverrides: [] };
// allocOverrides: [ { month:'YYYY-MM', rows:[{projectId, pct}] }, ... ]

window.icRenderAllocRows = function () {
    const wrap = $('ic-alloc-rows'); if (!wrap) return;
    const projs = window.projects || {};
    const annual = parseFloat($('ic-cost-annual')?.value) || 0;
    const monthlyBase = annual / 12;
    wrap.innerHTML = window._icFS.allocations.map((row, i) => `
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:6px;flex-wrap:wrap">
            <select onchange="icAllocChange(${i},'projectId',this.value)" style="${icInp('flex:2;min-width:140px')}">
                <option value="">-- اختر مشروع --</option>
                ${Object.entries(projs).map(([k,p])=>`<option value="${k}" ${row.projectId===k?'selected':''}>${p.name||k}</option>`).join('')}
            </select>
            <input type="number" min="0" max="100" step="0.01" value="${row.pct??''}"
                placeholder="النسبة %"
                onchange="icAllocChange(${i},'pct',this.value)"
                oninput="icAllocBadgeOnly()"
                style="${icInp('width:110px')}">
            <span id="ic-row-preview-${i}" style="font-size:11px;color:#2d6a9f;font-weight:700;min-width:90px">${fmt(monthlyBase * ((parseFloat(row.pct)||0)/100))} ريال/شهر</span>
            <button type="button" class="btn b-r" style="padding:3px 8px;font-size:11px" onclick="icRemoveAllocRow(${i})">🗑️</button>
        </div>`).join('');
    // شارة مجموع النسب
    const sum = window._icFS.allocations.reduce((s, r) => s + (parseFloat(r.pct)||0), 0);
    const badge = $('ic-alloc-sum-badge');
    if (badge) {
        const ok = Math.abs(sum - 100) < 0.1;
        badge.innerHTML = window._icFS.allocations.length
            ? `<span style="background:${ok?'#d4edda':'#fff3cd'};color:${ok?'#155724':'#664d03'};padding:4px 12px;border-radius:10px;font-size:12px;font-weight:700">مجموع النسب: ${sum.toFixed(2)}%${ok?' ✓':' ⚠️'}</span>`
            : '';
    }
};

window.icAddAllocRow    = function () { window._icFS.allocations.push({projectId:'',pct:''}); icRenderAllocRows(); };
window.icRemoveAllocRow = function (i) { window._icFS.allocations.splice(i,1); icRenderAllocRows(); };
window.icAllocChange    = function (i, field, val) {
    if (!window._icFS.allocations[i]) return;
    window._icFS.allocations[i][field] = val;
    // عند تغيير النسبة (onchange) نحدّث الحالة وشارة المجموع فقط دون إعادة بناء الـDOM
    if (field === 'pct') { icAllocBadgeOnly(); } else { icRenderAllocRows(); }
};
// تحديث شارة المجموع والمعاينة الشهرية دون إعادة بناء الـDOM (يُحافظ على التركيز أثناء الكتابة)
window.icAllocBadgeOnly = function () {
    const annual = parseFloat($('ic-cost-annual')?.value) || 0;
    const monthlyBase = annual / 12;
    let sum = 0;
    window._icFS.allocations.forEach((row, i) => {
        // اقرأ القيمة الحالية من DOM مباشرة (قد تكون أحدث من _icFS)
        const inp = $('ic-alloc-rows')?.querySelectorAll('input[type=number]')[i];
        const pct = parseFloat(inp?.value ?? row.pct) || 0;
        row.pct = inp ? inp.value : row.pct; // مزامنة _icFS مع DOM
        sum += pct;
        const preview = $(`ic-row-preview-${i}`);
        if (preview) preview.textContent = `${fmt(monthlyBase * (pct/100))} ريال/شهر`;
    });
    const badge = $('ic-alloc-sum-badge');
    if (badge) {
        const ok = Math.abs(sum - 100) < 0.1;
        badge.innerHTML = window._icFS.allocations.length
            ? `<span style="background:${ok?'#d4edda':'#fff3cd'};color:${ok?'#155724':'#664d03'};padding:4px 12px;border-radius:10px;font-size:12px;font-weight:700">مجموع النسب: ${sum.toFixed(2)}%${ok?' ✓':' ⚠️'}</span>`
            : '';
    }
};

window.icRenderOverrideRows = function () {
    const wrap = $('ic-override-rows'); if (!wrap) return;
    wrap.innerHTML = window._icFS.overrides.map((row, i) => `
        <div style="display:flex;gap:8px;align-items:center;margin-bottom:6px;flex-wrap:wrap">
            <input type="month" value="${row.month||''}" onchange="icOverrideChange(${i},'month',this.value)" style="${icInp('width:160px')}">
            <input type="number" min="0" step="0.01" value="${row.amount??''}" placeholder="قيمة هذا الشهر (ريال)"
                oninput="icOverrideChange(${i},'amount',this.value)" style="${icInp('flex:1;min-width:160px')}">
            <button type="button" class="btn b-r" style="padding:3px 8px;font-size:11px" onclick="icRemoveOverrideRow(${i})">🗑️</button>
        </div>`).join('');
};
window.icAddOverrideRow    = function () { window._icFS.overrides.push({month:'',amount:''}); icRenderOverrideRows(); };
window.icRemoveOverrideRow = function (i) { window._icFS.overrides.splice(i,1); icRenderOverrideRows(); };
window.icOverrideChange    = function (i, field, val) { if (window._icFS.overrides[i]) window._icFS.overrides[i][field] = val; };

// ── تغيير التوزيع من تاريخ معيّن ──────────────────────────────────────────
window.icRenderAllocOverrides = function () {
    const wrap = $('ic-allocoverride-blocks'); if (!wrap) return;
    const projs = window.projects || {};
    const annual = parseFloat($('ic-cost-annual')?.value) || 0;
    const monthlyBase = annual / 12;
    wrap.innerHTML = window._icFS.allocOverrides.map((block, bi) => {
        const blockSum = block.rows.reduce((s, r) => s + (parseFloat(r.pct)||0), 0);
        const ok = Math.abs(blockSum - 100) < 0.1;
        return `<div style="background:white;border-radius:10px;padding:12px;margin-bottom:10px;border:1.5px solid #93b8f0">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;flex-wrap:wrap">
                <span style="font-size:12px;font-weight:700;color:#084298">📅 اعتباراً من شهر:</span>
                <input type="month" value="${block.month||''}"
                    onchange="icAllocOverrideMonthChange(${bi},this.value)"
                    style="${icInp('width:160px')}">
                <span style="background:${ok?'#d4edda':'#fff3cd'};color:${ok?'#155724':'#664d03'};padding:3px 10px;border-radius:8px;font-size:11px;font-weight:700">
                    مجموع النسب: ${blockSum.toFixed(1)}%${ok?' ✓':' ⚠️'}</span>
                <button type="button" class="btn b-r" style="padding:3px 8px;font-size:11px;margin-right:auto" onclick="icRemoveAllocOverrideBlock(${bi})">🗑️ حذف هذا التغيير</button>
            </div>
            ${block.rows.map((row, ri) => `
            <div style="display:flex;gap:8px;align-items:center;margin-bottom:6px;flex-wrap:wrap">
                <select onchange="icAllocOverrideProjChange(${bi},${ri},'projectId',this.value)" style="${icInp('flex:2;min-width:140px')}">
                    <option value="">-- اختر مشروع --</option>
                    ${Object.entries(projs).map(([k,p])=>`<option value="${k}" ${row.projectId===k?'selected':''}>${p.name||k}</option>`).join('')}
                </select>
                <input type="number" min="0" max="100" step="0.01" value="${row.pct??''}"
                    placeholder="النسبة %"
                    onchange="icAllocOverrideProjChange(${bi},${ri},'pct',this.value)"
                    oninput="icAllocOverrideBadgeOnly(${bi})"
                    style="${icInp('width:110px')}">
                <span id="ic-ao-preview-${bi}-${ri}" style="font-size:11px;color:#2d6a9f;font-weight:700;min-width:90px">${fmt(monthlyBase*((parseFloat(row.pct)||0)/100))} ريال/شهر</span>
                <button type="button" class="btn b-r" style="padding:3px 8px;font-size:11px" onclick="icRemoveAllocOverrideProjRow(${bi},${ri})">🗑️</button>
            </div>`).join('')}
            <button type="button" class="btn" onclick="icAddAllocOverrideProjRow(${bi})" style="margin-top:4px;padding:5px 12px;font-size:11px;background:#eaf2fb;color:#1a3a5c;border:1.5px solid #c6d9ee">➕ إضافة مشروع</button>
        </div>`;
    }).join('');
};

window.icAddAllocOverrideBlock = function () {
    window._icFS.allocOverrides.push({ month: '', rows: [{projectId:'',pct:''}] });
    icRenderAllocOverrides();
};
window.icRemoveAllocOverrideBlock = function (bi) {
    window._icFS.allocOverrides.splice(bi, 1);
    icRenderAllocOverrides();
};
window.icAllocOverrideMonthChange = function (bi, val) {
    if (window._icFS.allocOverrides[bi]) window._icFS.allocOverrides[bi].month = val;
};
window.icAddAllocOverrideProjRow = function (bi) {
    if (window._icFS.allocOverrides[bi]) {
        window._icFS.allocOverrides[bi].rows.push({projectId:'',pct:''});
        icRenderAllocOverrides();
    }
};
window.icRemoveAllocOverrideProjRow = function (bi, ri) {
    if (window._icFS.allocOverrides[bi]) {
        window._icFS.allocOverrides[bi].rows.splice(ri, 1);
        icRenderAllocOverrides();
    }
};
window.icAllocOverrideProjChange = function (bi, ri, field, val) {
    const block = window._icFS.allocOverrides[bi]; if (!block) return;
    if (!block.rows[ri]) return;
    block.rows[ri][field] = val;
    if (field === 'pct') icAllocOverrideBadgeOnly(bi); else icRenderAllocOverrides();
};
window.icAllocOverrideBadgeOnly = function (bi) {
    const block = window._icFS.allocOverrides[bi]; if (!block) return;
    const annual = parseFloat($('ic-cost-annual')?.value) || 0;
    const monthlyBase = annual / 12;
    let sum = 0;
    const blockEl = $('ic-allocoverride-blocks')?.querySelectorAll(':scope > div')[bi];
    if (!blockEl) return;
    const inputs = blockEl.querySelectorAll('input[type=number]');
    block.rows.forEach((row, ri) => {
        const inp = inputs[ri];
        const pct = parseFloat(inp?.value ?? row.pct) || 0;
        if (inp) row.pct = inp.value;
        sum += pct;
        const preview = $(`ic-ao-preview-${bi}-${ri}`);
        if (preview) preview.textContent = `${fmt(monthlyBase*(pct/100))} ريال/شهر`;
    });
    // تحديث شارة المجموع داخل هذا البلوك
    const badges = blockEl.querySelectorAll('span');
    for (const b of badges) {
        if (b.textContent.includes('مجموع النسب:')) {
            const ok = Math.abs(sum - 100) < 0.1;
            b.style.background = ok ? '#d4edda' : '#fff3cd';
            b.style.color = ok ? '#155724' : '#664d03';
            b.textContent = `مجموع النسب: ${sum.toFixed(1)}%${ok?' ✓':' ⚠️'}`;
            break;
        }
    }
};

window.icOpenForm = function (costKey = null) {
    const form = $('ic-cost-form'); if (!form) return;
    form.style.display = '';
    $('ic-cost-key').value    = costKey || '';
    $('ic-form-title').textContent = costKey ? '✏️ تعديل بند تكلفة' : '➕ إضافة بند تكلفة جديد';
    if (costKey) {
        const c = (window.indirectCosts || {})[costKey];
        if (c) {
            $('ic-cost-name').value     = c.name     || '';
            $('ic-cost-category').value = c.category || 'other';
            $('ic-cost-annual').value   = c.annualAmount || '';
            $('ic-cost-notes').value    = c.notes    || '';
            window._icFS.allocations   = Object.entries(c.allocations || {}).map(([projectId, pct]) => ({ projectId, pct }));
            window._icFS.overrides     = Object.entries(c.monthlyOverrides || {}).map(([month, amount]) => ({ month, amount }));
            window._icFS.allocOverrides = Object.entries(c.allocationOverrides || {})
                .sort(([a],[b]) => a.localeCompare(b))
                .map(([month, alloc]) => ({
                    month,
                    rows: Object.entries(alloc).map(([projectId, pct]) => ({ projectId, pct }))
                }));
        }
    } else {
        ['ic-cost-name','ic-cost-annual','ic-cost-notes'].forEach(id => { const el = $(id); if (el) el.value = ''; });
        $('ic-cost-category').value = 'depreciation';
        window._icFS.allocations    = [];
        window._icFS.overrides      = [];
        window._icFS.allocOverrides = [];
    }
    icRecalcBase();
    icRenderAllocRows();
    icRenderOverrideRows();
    icRenderAllocOverrides();
    form.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
};

window.icSaveCost = async function () {
    const name        = $('ic-cost-name')?.value.trim();
    const category    = $('ic-cost-category')?.value || 'other';
    const annualAmount = parseFloat($('ic-cost-annual')?.value) || 0;
    const notes       = $('ic-cost-notes')?.value.trim();

    if (!name)          { toast('أدخل اسم بند التكلفة', 'er'); return; }
    if (annualAmount <= 0) { toast('أدخل قيمة سنوية أكبر من صفر', 'er'); return; }

    // بناء كائن التوزيع — يحذف الصفوف الفارغة أو ذات النسبة صفر
    const allocations = {};
    for (const row of window._icFS.allocations) {
        if (!row.projectId) continue;
        const pct = parseFloat(row.pct) || 0;
        if (pct > 0) allocations[row.projectId] = pct;
    }
    if (!Object.keys(allocations).length) { toast('أضف مشروعاً واحداً على الأقل في التوزيع', 'er'); return; }
    if (Object.values(allocations).reduce((s,v)=>s+v,0) > 100.01) { toast('⚠️ مجموع النسب يتجاوز 100% — راجع التوزيع', 'er'); return; }

    // بناء كائن التجاوزات الشهرية — يحذف الصفوف غير المكتملة
    const monthlyOverrides = {};
    for (const row of window._icFS.overrides) {
        if (!row.month) continue;
        const amt = parseFloat(row.amount);
        if (!isNaN(amt) && amt >= 0) monthlyOverrides[row.month] = amt;
    }

    // بناء كائن تغييرات التوزيع الشهرية — { 'YYYY-MM': { projectId: pct, ... } }
    const allocationOverrides = {};
    for (const block of window._icFS.allocOverrides) {
        if (!block.month) continue;
        const alloc = {};
        for (const row of block.rows) {
            if (!row.projectId) continue;
            const pct = parseFloat(row.pct) || 0;
            alloc[row.projectId] = pct;
        }
        if (Object.keys(alloc).length) allocationOverrides[block.month] = alloc;
    }

    const data = { name, category, annualAmount, allocations, monthlyOverrides, allocationOverrides, notes, updatedAt: new Date().toISOString() };
    const costKey = $('ic-cost-key')?.value;
    try {
        if (costKey) {
            await update(ref(db, `ledger/indirectCosts/${costKey}`), data);
            toast('تم التحديث ✓', 'ok');
        } else {
            data.createdAt = new Date().toISOString();
            data.createdBy = window.curU?.uid || '';
            await push(ref(db, 'ledger/indirectCosts'), data);
            toast('تم إضافة بند التكلفة ✓', 'ok');
        }
        $('ic-cost-form').style.display = 'none';
        setTimeout(renderIndirectCosts, 400);
    } catch (e) { toast('خطأ: ' + e.message, 'er'); }
};

window.icDeleteCost = function (costKey) {
    cf2('هل تريد حذف بند التكلفة هذا؟ سيتوقف تأثيره على تكاليف المشاريع فوراً.', async () => {
        try {
            await remove(ref(db, `ledger/indirectCosts/${costKey}`));
            toast('تم الحذف', 'ok');
            setTimeout(renderIndirectCosts, 400);
        } catch (e) { toast('خطأ: ' + e.message, 'er'); }
    });
};

console.log('✅ Indirect Costs Allocation module loaded');


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📖  [ACC4]   ━━━━   GENERAL LEDGER   ━━━━                               ║
// ║                دفتر الأستاذ — حركات كل حساب                                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ── حالة دفتر الأستاذ ─────────────────
let glState = {
    accountCode: '',          // الحساب المحدد
    fromDate: '',             // من تاريخ
    toDate: '',                // إلى تاريخ
    includeStatuses: ['posted'], // فقط القيود المرحّلة افتراضياً
    costCenter: '',           // فلتر مركز التكلفة (مخصص)
    projectId: ''             // فلتر المشروع (منفصل — يمكن الجمع بينهما)
};

// ── دالة العرض الرئيسية ─────────────────
window.renderGeneralLedger = function () {
    const container = $('pg-generalledger'); if (!container) return;
    const accounts = window.chartOfAccounts || {};
    const accountsArr = Object.entries(accounts);

    // إذا لم توجد حسابات
    if (!accountsArr.length) {
        container.innerHTML = `
            <div style="background:linear-gradient(135deg,#5b2c6f 0%,#8e44ad 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white">
                <h1 style="margin:0;font-size:24px;font-weight:900">📖 دفتر الأستاذ</h1>
            </div>
            <div class="card" style="text-align:center;padding:60px 20px">
                <div style="font-size:80px;margin-bottom:16px">🌳</div>
                <div style="font-size:18px;font-weight:800;color:#1a3a5c;margin-bottom:8px">لا توجد حسابات في النظام</div>
                <div style="font-size:13px;color:#666;margin-bottom:20px">يجب إنشاء شجرة الحسابات أولاً</div>
                <button class="btn b-g" onclick="nav('chartofaccounts')" style="padding:10px 20px">🌳 الذهاب لشجرة الحسابات</button>
            </div>
        `;
        return;
    }

    // إذا لم يُختر حساب بعد، عرض شاشة الاختيار
    if (!glState.accountCode) {
        renderGLAccountSelector(container);
        return;
    }

    // عرض دفتر الأستاذ للحساب المحدد
    renderGLReport(container);
};

// ── شاشة اختيار الحساب ─────────────────
function renderGLAccountSelector(container) {
    const accounts = window.chartOfAccounts || {};
    // فقط الحسابات التفصيلية النشطة
    const detailAccounts = Object.entries(accounts)
        .filter(([, a]) => a.nature === 'detail' && a.active !== false)
        .sort((a, b) => (a[1].code || '').localeCompare(b[1].code || ''));

    // إحصائيات حركة كل حساب — تحترم فلاتر المركز/المشروع/الفترة المختارة
    const journalEntries = window.journalEntries || {};
    const movementCounts = {};
    Object.values(journalEntries).forEach(e => {
        if (e.status !== 'posted') return;
        (e.lines || []).forEach(l => {
            if (!l.accountCode) return;
            const d = l.date || e.date || ''; // 📅 التاريخ الجانبي للسطر إن وُجد
            if (glState.fromDate && d < glState.fromDate) return;
            if (glState.toDate && d > glState.toDate) return;
            if (glState.costCenter && l.costCenter !== glState.costCenter) return;
            if (glState.projectId && !ccLineMatchesProject(l, glState.projectId)) return;
            movementCounts[l.accountCode] = (movementCounts[l.accountCode] || 0) + 1;
        });
    });
    const hasGLFilter = glState.costCenter || glState.projectId || glState.fromDate || glState.toDate;

    // إحصائيات لكل نوع
    const stats = { asset: 0, liability: 0, equity: 0, revenue: 0, expense: 0, withMovements: 0 };
    detailAccounts.forEach(([, a]) => {
        if (stats[a.type] !== undefined) stats[a.type]++;
        if (movementCounts[a.code]) stats.withMovements++;
    });

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#5b2c6f 0%,#8e44ad 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(142,68,173,.25)">
            <div>
                <div style="font-size:11px;opacity:.85;letter-spacing:1px">GENERAL LEDGER</div>
                <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📖 دفتر الأستاذ</h1>
                <p style="margin:6px 0 0;font-size:12px;opacity:.95">عرض كافة حركات أي حساب مع الأرصدة الافتتاحية والختامية</p>
            </div>
        </div>

        <!-- Info -->
        <div style="background:linear-gradient(135deg,#f4ecf7,#fff);border-right:4px solid #8e44ad;border-radius:10px;padding:12px 16px;margin-bottom:14px;font-size:12px;color:#5b2c6f;line-height:1.7">
            💡 <strong>كيف يعمل دفتر الأستاذ؟</strong>
            <br>اختر حساباً من القائمة أدناه لرؤية: <strong>الرصيد الافتتاحي</strong> + <strong>كل الحركات</strong> (مدين/دائن) + <strong>الرصيد بعد كل حركة</strong> + <strong>الرصيد الختامي</strong>.
        </div>

        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">📊 الحسابات التفصيلية</div>
                <div style="font-size:24px;font-weight:900;color:#1a3a5c">${detailAccounts.length}</div>
            </div>
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #8e44ad">
                <div style="font-size:11px;color:#666">📒 لها حركات</div>
                <div style="font-size:24px;font-weight:900;color:#8e44ad">${stats.withMovements}</div>
            </div>
            ${Object.entries(COA_TYPES).map(([k, t]) => `
                <div style="background:${t.bg};border-radius:12px;padding:12px;border-right:4px solid ${t.color}">
                    <div style="font-size:11px;color:#666">${t.ar}</div>
                    <div style="font-size:20px;font-weight:900;color:${t.color}">${stats[k] || 0}</div>
                </div>
            `).join('')}
        </div>

        <!-- 🎯 فلاتر البحث: مركز التكلفة / المشروع / الفترة — تنتقل تلقائياً لعرض الدفتر -->
        <div style="background:#f4f7fb;border:1px solid #dce8f8;border-radius:10px;padding:12px 14px;margin-bottom:14px">
            <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:8px">
                <div style="font-size:13px;font-weight:900;color:#1a3a5c">🔍 فلاتر البحث — يتأثر بها عدد الحركات وتُطبَّق عند فتح أي دفتر</div>
                ${hasGLFilter ? `<button onclick="glState.costCenter='';glState.projectId='';glState.fromDate='';glState.toDate='';renderGeneralLedger()" style="background:#e74c3c;color:white;border:none;padding:5px 12px;border-radius:6px;cursor:pointer;font-size:11px;font-weight:700">↺ إعادة ضبط</button>` : ''}
            </div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px;align-items:end">
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🎯 مركز التكلفة</label>
                    <select onchange="updateGLFilter('costCenter', this.value)" style="width:100%;padding:8px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px;background:white">
                        ${ccOnlyOptions(glState.costCenter, '-- الكل --')}
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🏗️ المشروع</label>
                    <select onchange="updateGLFilter('projectId', this.value)" style="width:100%;padding:8px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px;background:white">
                        ${projOnlyOptions(glState.projectId, '-- الكل --')}
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 من تاريخ</label>
                    <input type="date" value="${glState.fromDate || ''}" onchange="updateGLFilter('fromDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 إلى تاريخ</label>
                    <input type="date" value="${glState.toDate || ''}" onchange="updateGLFilter('toDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
            </div>
            ${hasGLFilter ? `<div style="margin-top:8px;font-size:11px;color:#1e8449;background:#eafaf1;border-radius:6px;padding:6px 10px;display:inline-block">✅ فلتر نشط: ${[glState.costCenter ? '🎯 ' + ccDisplayName(glState.costCenter) : '', glState.projectId ? '🏗️ ' + ccDisplayName(glState.projectId) : '', (glState.fromDate || glState.toDate) ? `📅 ${glState.fromDate || '...'} ← ${glState.toDate || '...'}` : ''].filter(Boolean).join(' · ')} — عدد الحركات بجانب كل حساب يعكس هذا الفلتر</div>` : ''}
        </div>

        <!-- Account Selector -->
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:14px;flex-wrap:wrap;gap:10px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c">📋 اختر الحساب لعرض دفتر الأستاذ</div>
                <input type="text" id="glAccSearch" placeholder="🔍 ابحث برمز أو اسم..." oninput="filterGLAccounts(this.value)" style="padding:7px 12px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;min-width:240px">
            </div>
            <div style="overflow-x:auto;max-height:600px;overflow-y:auto">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:700px">
                    <thead style="background:#1a3a5c;color:white;position:sticky;top:0;z-index:5">
                        <tr>
                            <th style="padding:10px;text-align:right">رمز الحساب</th>
                            <th style="padding:10px;text-align:right">اسم الحساب</th>
                            <th style="padding:10px;text-align:right">المجموعة</th>
                            <th style="padding:10px;text-align:center">عدد الحركات</th>
                            <th style="padding:10px;text-align:center">إجراء</th>
                        </tr>
                    </thead>
                    <tbody id="glAccountsTable">
                        ${detailAccounts.map(([key, a], i) => {
                            const type = COA_TYPES[a.type] || { ar: '—', color: '#888', bg: '#f0f5fa' };
                            const movements = movementCounts[a.code] || 0;
                            return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}" data-search="${(a.code || '').toLowerCase()} ${(a.nameAr || '').toLowerCase()} ${(a.nameEn || '').toLowerCase()}">
                                <td style="padding:8px;font-family:monospace;font-weight:800;color:${type.color}">${a.code}</td>
                                <td style="padding:8px;font-weight:600">${a.nameAr}
                                    ${a.nameEn ? `<div style="font-size:10px;color:#888;direction:ltr">${a.nameEn}</div>` : ''}
                                </td>
                                <td style="padding:8px"><span style="background:${type.bg};color:${type.color};padding:3px 10px;border-radius:6px;font-size:11px;font-weight:700">${type.ar}</span></td>
                                <td style="padding:8px;text-align:center">
                                    ${movements > 0 ? `<span style="background:#8e44ad;color:white;padding:3px 10px;border-radius:6px;font-size:11px;font-weight:700">${movements}</span>` : '<span style="color:#ccc">—</span>'}
                                </td>
                                <td style="padding:8px;text-align:center">
                                    <button class="btn" onclick="openGLForAccount('${a.code}')" style="background:#8e44ad;color:white;padding:5px 12px;font-size:11px;font-weight:700">📖 عرض الدفتر</button>
                                </td>
                            </tr>`;
                        }).join('')}
                    </tbody>
                </table>
            </div>
        </div>
    `;
};

window.filterGLAccounts = function (query) {
    query = (query || '').toLowerCase().trim();
    document.querySelectorAll('#glAccountsTable tr').forEach(row => {
        const txt = row.getAttribute('data-search') || '';
        row.style.display = (!query || txt.includes(query)) ? '' : 'none';
    });
};

window.openGLForAccount = function (code) {
    glState.accountCode = code;
    // افتراضياً: من بداية السنة الحالية إلى اليوم
    const today = new Date();
    glState.fromDate = today.getFullYear() + '-01-01';
    glState.toDate = today.toISOString().slice(0, 10);
    renderGeneralLedger();
};

window.backToGLSelector = function () {
    glState.accountCode = '';
    glState.fromDate = '';
    glState.toDate = '';
    renderGeneralLedger();
};

// ── عرض دفتر الأستاذ لحساب محدد ─────────────────
function renderGLReport(container) {
    const account = Object.values(window.chartOfAccounts || {}).find(a => a.code === glState.accountCode);
    if (!account) {
        toast('⚠️ الحساب غير موجود', 'er');
        glState.accountCode = '';
        renderGeneralLedger();
        return;
    }

    const type = COA_TYPES[account.type] || { ar: '—', color: '#888', bg: '#f0f5fa' };

    // جمع كل الحركات من قيود اليومية المرحّلة
    const journalEntries = window.journalEntries || {};
    const movements = [];
    let preNet = 0; // 🟢 رصيد ما قبل الفترة + القيد الافتتاحي → يُضاف للرصيد الافتتاحي (لا يظهر كحركة)

    Object.entries(journalEntries).forEach(([key, e]) => {
        // تطبيق فلتر الحالة
        if (!glState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e);

        (e.lines || []).forEach((line, lineIdx) => {
            if (line.accountCode !== glState.accountCode) return;

            // 📅 التاريخ الفعلي للسطر: التاريخ الجانبي إن وُجد وإلا تاريخ القيد
            const effDate = line.date || e.date || '';
            if (glState.toDate && effDate > glState.toDate) return;

            // تطبيق فلتر مركز التكلفة
            if (glState.costCenter && line.costCenter !== glState.costCenter) return;
            if (glState.projectId && !ccLineMatchesProject(line, glState.projectId)) return;

            const debit = parseFloat(line.debit) || 0;
            const credit = parseFloat(line.credit) || 0;
            // 🟢 القيد الافتتاحي (دائماً) أو أي حركة قبل بداية الفترة → رصيد افتتاحي وليس حركة معروضة
            if (isOpen || (glState.fromDate && effDate < glState.fromDate)) {
                preNet += debit - credit;
                return;
            }

            movements.push({
                entryKey: key,
                lineIdx,
                date: effDate,
                number: e.number,
                description: e.description,
                lineDescription: line.description,
                reference: e.reference,
                costCenter: line.costCenter || '',
                projectId: line.projectId || '',
                debit,
                credit,
                status: e.status
            });
        });
    });

    // ترتيب حسب التاريخ ثم رقم القيد
    movements.sort((a, b) => {
        const dCmp = (a.date || '').localeCompare(b.date || '');
        if (dCmp !== 0) return dCmp;
        return (a.number || '').localeCompare(b.number || '');
    });

    // الرصيد الافتتاحي = رصيد الحساب الثابت + رصيد ما قبل الفترة + القيد الافتتاحي
    const openingBalance = (parseFloat(account.openingBalance) || 0) + preNet;

    // حساب الرصيد الجاري (Running Balance)
    let runningBalance = openingBalance;
    movements.forEach(m => {
        runningBalance += m.debit - m.credit;
        m.balance = runningBalance;
    });

    const totalDebit = movements.reduce((s, m) => s + m.debit, 0);
    const totalCredit = movements.reduce((s, m) => s + m.credit, 0);
    const closingBalance = openingBalance + totalDebit - totalCredit;

    // تحديد طبيعة الرصيد (مدين/دائن) حسب نوع الحساب
    function balanceLabel(bal, accType) {
        if (Math.abs(bal) < 0.01) return { label: 'متوازن', color: '#888' };
        // الأصول والمصروفات: طبيعتها مدينة (موجبة)
        // الخصوم وحقوق الملكية والإيرادات: طبيعتها دائنة (سالبة طبيعياً، نعرضها موجبة)
        const naturallyDebit = ['asset', 'expense'].includes(accType);
        if (bal > 0) {
            return naturallyDebit
                ? { label: 'مدين', color: '#27ae60', natural: true }
                : { label: 'مدين (شاذ)', color: '#e67e22', natural: false };
        } else {
            return naturallyDebit
                ? { label: 'دائن (شاذ)', color: '#e67e22', natural: false }
                : { label: 'دائن', color: '#27ae60', natural: true };
        }
    }

    const closingInfo = balanceLabel(closingBalance, account.type);

    // قائمة مراكز التكلفة المستخدمة
    const ccUsed = new Set();
    movements.forEach(m => { if (m.costCenter) ccUsed.add(m.costCenter); });

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,${type.color},${type.color}dd);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px ${type.color}33">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">GENERAL LEDGER · ${type.en || ''}</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📖 ${account.nameAr}</h1>
                    <div style="margin-top:6px;font-size:12px;opacity:.95;display:flex;gap:14px;flex-wrap:wrap">
                        <span>🔢 <strong>${account.code}</strong></span>
                        <span>${type.ar}</span>
                        ${account.nameEn ? `<span style="direction:ltr">${account.nameEn}</span>` : ''}
                    </div>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    <button class="btn" onclick="backToGLSelector()" style="background:rgba(255,255,255,.2);color:white;padding:9px 16px;font-weight:700;backdrop-filter:blur(10px)">← العودة للحسابات</button>
                    <button class="btn" onclick="printGLReport()" style="background:white;color:${type.color};padding:9px 16px;font-weight:800">🖨️ طباعة</button>
                    <button class="btn" onclick="exportGLExcel()" style="background:rgba(255,255,255,.2);color:white;padding:9px 16px;font-weight:700;backdrop-filter:blur(10px)">📤 Excel</button>
                </div>
            </div>
        </div>

        <!-- Filters -->
        <div class="card" style="margin-bottom:14px;padding:14px">
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;align-items:end">
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 من تاريخ</label>
                    <input type="date" id="glFromDate" value="${glState.fromDate}" onchange="updateGLFilter('fromDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 إلى تاريخ</label>
                    <input type="date" id="glToDate" value="${glState.toDate}" onchange="updateGLFilter('toDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📊 حالة القيود</label>
                    <select id="glStatuses" onchange="updateGLStatuses(this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        <option value="posted" ${glState.includeStatuses.length === 1 && glState.includeStatuses[0] === 'posted' ? 'selected' : ''}>✅ المرحّلة فقط (رسمي)</option>
                        <option value="posted,draft" ${glState.includeStatuses.includes('draft') && !glState.includeStatuses.includes('cancelled') ? 'selected' : ''}>📝 مرحّلة + مسودات</option>
                        <option value="posted,draft,cancelled" ${glState.includeStatuses.includes('cancelled') ? 'selected' : ''}>📋 كل القيود</option>
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🎯 مركز التكلفة</label>
                    <select id="glCostCenter" onchange="updateGLFilter('costCenter', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        ${ccOnlyOptions(glState.costCenter, '-- الكل --')}
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🏗️ المشروع</label>
                    <select id="glProject" onchange="updateGLFilter('projectId', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        ${projOnlyOptions(glState.projectId, '-- الكل --')}
                    </select>
                </div>
                <div style="display:flex;gap:6px">
                    <button class="btn b-pu" onclick="setGLDateRange('thisMonth')" style="padding:8px;font-size:11px;flex:1" title="الشهر الحالي">📅 شهر</button>
                    <button class="btn b-pu" onclick="setGLDateRange('thisQuarter')" style="padding:8px;font-size:11px;flex:1" title="الربع الحالي">📅 ربع</button>
                    <button class="btn b-pu" onclick="setGLDateRange('thisYear')" style="padding:8px;font-size:11px;flex:1" title="السنة الحالية">📅 سنة</button>
                    <button class="btn b-pu" onclick="setGLDateRange('all')" style="padding:8px;font-size:11px;flex:1" title="كل التواريخ">📅 الكل</button>
                </div>
            </div>
        </div>

        <!-- Summary Cards -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">💼 الرصيد الافتتاحي</div>
                <div style="font-size:20px;font-weight:900;color:#1a3a5c">${fmt(openingBalance)}</div>
            </div>
            <div style="background:#e8f4fd;border-radius:12px;padding:12px;border-right:4px solid #2d6a9f">
                <div style="font-size:11px;color:#0d4f7c">💰 إجمالي المدين</div>
                <div style="font-size:20px;font-weight:900;color:#2d6a9f">${fmt(totalDebit)}</div>
            </div>
            <div style="background:#fadbd8;border-radius:12px;padding:12px;border-right:4px solid #c0392b">
                <div style="font-size:11px;color:#641e16">💸 إجمالي الدائن</div>
                <div style="font-size:20px;font-weight:900;color:#c0392b">${fmt(totalCredit)}</div>
            </div>
            <div style="background:#e8f8f5;border-radius:12px;padding:12px;border-right:4px solid #27ae60">
                <div style="font-size:11px;color:#0e6655">📊 عدد الحركات</div>
                <div style="font-size:24px;font-weight:900;color:#27ae60">${movements.length}</div>
            </div>
            <div style="background:linear-gradient(135deg,${closingInfo.color}22,#fff);border-radius:12px;padding:12px;border-right:4px solid ${closingInfo.color}">
                <div style="font-size:11px;color:#666">🏁 الرصيد الختامي</div>
                <div style="font-size:22px;font-weight:900;color:${closingInfo.color}">${fmt(Math.abs(closingBalance))}</div>
                <div style="font-size:10px;color:${closingInfo.color};font-weight:700;margin-top:2px">${closingInfo.label}</div>
            </div>
            ${ccUsed.size > 0 ? `<div style="background:#f4ecf7;border-radius:12px;padding:12px;border-right:4px solid #8e44ad">
                <div style="font-size:11px;color:#5b2c6f">🎯 مراكز التكلفة</div>
                <div style="font-size:24px;font-weight:900;color:#8e44ad">${ccUsed.size}</div>
            </div>` : ''}
        </div>

        <!-- Movements Table -->
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c">📋 الحركات التفصيلية (${movements.length})</div>
                <div style="font-size:11px;color:#666">⚠️ <strong>طبيعة الحساب:</strong> ${['asset', 'expense'].includes(account.type) ? 'مدينة (يزيد بالمدين)' : 'دائنة (يزيد بالدائن)'}</div>
            </div>
            <div style="overflow-x:auto" id="glReportTable">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:1000px">
                    <thead style="background:#1a3a5c;color:white">
                        <tr>
                            <th style="padding:10px;text-align:right">#</th>
                            <th style="padding:10px;text-align:right">📅 التاريخ</th>
                            <th style="padding:10px;text-align:right">📄 رقم القيد</th>
                            <th style="padding:10px;text-align:right">📝 البيان</th>
                            <th style="padding:10px;text-align:right">🎯 م. التكلفة</th>
                            <th style="padding:10px;text-align:center;background:#27ae60">💰 مدين</th>
                            <th style="padding:10px;text-align:center;background:#c0392b">💸 دائن</th>
                            <th style="padding:10px;text-align:center">💼 الرصيد</th>
                        </tr>
                    </thead>
                    <tbody>
                        <!-- الرصيد الافتتاحي -->
                        <tr style="background:#f0f5fa;font-weight:800">
                            <td colspan="5" style="padding:10px;text-align:left;color:#1a3a5c">💼 الرصيد الافتتاحي (${glState.fromDate || 'البداية'})</td>
                            <td style="padding:10px;text-align:center;color:#888">—</td>
                            <td style="padding:10px;text-align:center;color:#888">—</td>
                            <td style="padding:10px;text-align:center;color:#1a3a5c;font-size:14px">${fmt(openingBalance)}</td>
                        </tr>
                        ${movements.length === 0 ? `
                            <tr><td colspan="8" style="text-align:center;padding:40px;color:#888;font-size:13px">📭 لا توجد حركات في الفترة المحددة</td></tr>
                        ` : movements.map((m, i) => {
                            const ccName = ccProjLabel(m, '');
                            const statusBadge = m.status === 'draft' ? '<span style="background:#f39c12;color:white;padding:1px 5px;border-radius:3px;font-size:9px">مسودة</span>' :
                                m.status === 'cancelled' ? '<span style="background:#c0392b;color:white;padding:1px 5px;border-radius:3px;font-size:9px">ملغى</span>' : '';
                            return `<tr style="${i % 2 ? 'background:#fafbfc' : ''};cursor:pointer" onclick="jrnRowMenu('${m.entryKey}', event)" title="انقر لعرض خيارات القيد (عرض/تعديل/حذف/تصدير)">
                                <td style="padding:7px;text-align:center;color:#888">${i + 1}</td>
                                <td style="padding:7px;font-family:monospace">${m.date || '-'}</td>
                                <td style="padding:7px;font-family:monospace;font-weight:700;color:#2d6a9f">${m.number || '-'} ${statusBadge}</td>
                                <td style="padding:7px;max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${m.description || ''}">
                                    ${m.description || '—'}
                                    ${m.lineDescription && m.lineDescription !== m.description ? `<div style="font-size:10px;color:#888">↳ ${m.lineDescription}</div>` : ''}
                                </td>
                                <td style="padding:7px;font-size:11px;color:#666">${ccName}</td>
                                <td style="padding:7px;text-align:center;color:#27ae60;font-weight:700">${m.debit ? fmt(m.debit) : '—'}</td>
                                <td style="padding:7px;text-align:center;color:#c0392b;font-weight:700">${m.credit ? fmt(m.credit) : '—'}</td>
                                <td style="padding:7px;text-align:center;font-weight:800;color:#1a3a5c">${fmt(Math.abs(m.balance))} <span style="font-size:9px;color:${m.balance >= 0 ? '#27ae60' : '#c0392b'}">${m.balance >= 0 ? 'م' : 'د'}</span></td>
                            </tr>`;
                        }).join('')}
                    </tbody>
                    <tfoot style="background:#1a3a5c;color:white;font-weight:900">
                        <!-- إجمالي الحركات -->
                        <tr>
                            <td colspan="5" style="padding:10px;text-align:left">📊 إجمالي الحركات</td>
                            <td style="padding:10px;text-align:center;font-size:13px">${fmt(totalDebit)}</td>
                            <td style="padding:10px;text-align:center;font-size:13px">${fmt(totalCredit)}</td>
                            <td style="padding:10px;text-align:center">—</td>
                        </tr>
                        <!-- الرصيد الختامي -->
                        <tr style="background:${closingInfo.color}">
                            <td colspan="5" style="padding:12px;text-align:left;font-size:14px">🏁 الرصيد الختامي (${glState.toDate || 'الآن'})</td>
                            <td style="padding:12px;text-align:center" colspan="2">${closingInfo.label}</td>
                            <td style="padding:12px;text-align:center;font-size:16px">${fmt(Math.abs(closingBalance))}</td>
                        </tr>
                    </tfoot>
                </table>
            </div>
            <div style="margin-top:10px;font-size:11px;color:#666;background:#f8fafc;padding:8px;border-radius:6px">
                💡 <strong>ملاحظة:</strong> انقر على أي سطر لعرض القيد الكامل · 
                <strong>الرصيد:</strong> م = مدين، د = دائن
            </div>
        </div>
    `;
}

// ── تحديث الفلاتر ─────────────────
window.updateGLFilter = function (field, value) {
    glState[field] = value;
    renderGeneralLedger();
};

window.updateGLStatuses = function (value) {
    glState.includeStatuses = value.split(',');
    renderGeneralLedger();
};

window.setGLDateRange = function (range) {
    const today = new Date();
    const y = today.getFullYear();
    const m = today.getMonth();
    switch (range) {
        case 'thisMonth':
            glState.fromDate = new Date(y, m, 1).toISOString().slice(0, 10);
            glState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'thisQuarter':
            const qStart = Math.floor(m / 3) * 3;
            glState.fromDate = new Date(y, qStart, 1).toISOString().slice(0, 10);
            glState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'thisYear':
            glState.fromDate = y + '-01-01';
            glState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'all':
            glState.fromDate = '';
            glState.toDate = '';
            break;
    }
    renderGeneralLedger();
};

// ── طباعة دفتر الأستاذ ─────────────────
window.printGLReport = function () {
    const account = Object.values(window.chartOfAccounts || {}).find(a => a.code === glState.accountCode);
    if (!account) return;
    const type = COA_TYPES[account.type] || { ar: '—', color: '#888' };

    // إعادة جمع الحركات (نفس منطق العرض)
    const journalEntries = window.journalEntries || {};
    const movements = [];
    let preNet = 0; // 🟢 رصيد ما قبل الفترة + القيد الافتتاحي → رصيد افتتاحي
    Object.entries(journalEntries).forEach(([key, e]) => {
        if (!glState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e);
        if (glState.toDate && (e.date || '') > glState.toDate) return;
        (e.lines || []).forEach(line => {
            if (line.accountCode !== glState.accountCode) return;
            if (glState.costCenter && line.costCenter !== glState.costCenter) return;
            if (glState.projectId && !ccLineMatchesProject(line, glState.projectId)) return;
            const debit = parseFloat(line.debit) || 0, credit = parseFloat(line.credit) || 0;
            if (isOpen || (glState.fromDate && (e.date || '') < glState.fromDate)) { preNet += debit - credit; return; }
            movements.push({
                date: e.date, number: e.number, description: e.description,
                lineDescription: line.description, costCenter: line.costCenter || '',
                debit, credit
            });
        });
    });
    movements.sort((a, b) => (a.date || '').localeCompare(b.date || ''));

    const openingBalance = (parseFloat(account.openingBalance) || 0) + preNet;
    let runningBalance = openingBalance;
    movements.forEach(m => { runningBalance += m.debit - m.credit; m.balance = runningBalance; });
    const totalDebit = movements.reduce((s, m) => s + m.debit, 0);
    const totalCredit = movements.reduce((s, m) => s + m.credit, 0);
    const closingBalance = openingBalance + totalDebit - totalCredit;

    const html = `<!DOCTYPE html><html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>دفتر الأستاذ - ${account.nameAr}</title>
    <style>
        * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        body { font-family: 'Tajawal', Tahoma, Arial; padding: 20px; color: #1a3a5c; direction: rtl; background: white; }
        h1 { text-align: center; border-bottom: 3px solid ${type.color}; padding-bottom: 10px; margin-bottom: 20px; }
        .info { background: #f0f5fa; padding: 14px; border-radius: 8px; margin-bottom: 14px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; font-size: 12px; }
        table { width: 100%; border-collapse: collapse; font-size: 11px; margin-top: 14px; }
        th { background: #1a3a5c; color: white; padding: 8px; border: 1px solid #1a3a5c; }
        td { padding: 6px 8px; border: 1px solid #ddd; }
        .opening { background: #f0f5fa; font-weight: 800; }
        .totals { background: #1a3a5c; color: white; font-weight: 900; }
        .closing { background: ${type.color}; color: white; font-weight: 900; }
        @page { size: A4 landscape; margin: 1.5cm; }
    </style></head><body>
    <h1>📖 دفتر الأستاذ — ${account.nameAr} (${account.code})</h1>
    <div class="info">
        <div><strong>📅 الفترة:</strong> ${glState.fromDate || 'من البداية'} → ${glState.toDate || 'حتى الآن'}</div>
        <div><strong>🏷️ النوع:</strong> ${type.ar}</div>
        <div><strong>📊 عدد الحركات:</strong> ${movements.length}</div>
    </div>
    <table>
        <thead><tr>
            <th>#</th><th>التاريخ</th><th>رقم القيد</th><th>البيان</th>
            <th style="background:#27ae60">مدين</th><th style="background:#c0392b">دائن</th><th>الرصيد</th>
        </tr></thead>
        <tbody>
            <tr class="opening"><td colspan="4" style="text-align:left">الرصيد الافتتاحي</td><td>—</td><td>—</td><td>${fmt(openingBalance)}</td></tr>
            ${movements.map((m, i) => `<tr>
                <td style="text-align:center">${i + 1}</td>
                <td>${m.date || '-'}</td>
                <td style="font-family:monospace;font-weight:700">${m.number || '-'}</td>
                <td>${m.description || '-'}${m.lineDescription && m.lineDescription !== m.description ? '<br><small>↳ ' + m.lineDescription + '</small>' : ''}</td>
                <td style="text-align:left;color:#27ae60">${m.debit ? fmt(m.debit) : '—'}</td>
                <td style="text-align:left;color:#c0392b">${m.credit ? fmt(m.credit) : '—'}</td>
                <td style="text-align:left;font-weight:700">${fmt(Math.abs(m.balance))} ${m.balance >= 0 ? 'م' : 'د'}</td>
            </tr>`).join('')}
        </tbody>
        <tfoot>
            <tr class="totals"><td colspan="4" style="text-align:left">إجمالي الحركات</td><td>${fmt(totalDebit)}</td><td>${fmt(totalCredit)}</td><td>—</td></tr>
            <tr class="closing"><td colspan="6" style="text-align:left;padding:10px">🏁 الرصيد الختامي</td><td style="padding:10px;font-size:14px">${fmt(Math.abs(closingBalance))} ${closingBalance >= 0 ? 'مدين' : 'دائن'}</td></tr>
        </tfoot>
    </table>
    <div style="margin-top:40px;display:grid;grid-template-columns:repeat(3,1fr);gap:30px;text-align:center;font-size:11px">
        <div>✍️ المحاسب<br><strong>___________</strong></div>
        <div>✍️ المراجع<br><strong>___________</strong></div>
        <div>✍️ المدير المالي<br><strong>___________</strong></div>
    </div>
    </body></html>`;

    const w = window.open('', '_blank');
    w.document.write(html);
    w.document.close();
    setTimeout(() => { try { w.print(); } catch (e) { } }, 500);
};

// ── تصدير Excel ─────────────────
window.exportGLExcel = function () {
    const account = Object.values(window.chartOfAccounts || {}).find(a => a.code === glState.accountCode);
    if (!account) return;

    const journalEntries = window.journalEntries || {};
    const movements = [];
    let preNet = 0; // 🟢 رصيد ما قبل الفترة + القيد الافتتاحي → رصيد افتتاحي
    Object.entries(journalEntries).forEach(([key, e]) => {
        if (!glState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e);
        if (glState.toDate && (e.date || '') > glState.toDate) return;
        (e.lines || []).forEach(line => {
            if (line.accountCode !== glState.accountCode) return;
            if (glState.costCenter && line.costCenter !== glState.costCenter) return;
            if (glState.projectId && !ccLineMatchesProject(line, glState.projectId)) return;
            const debit = parseFloat(line.debit) || 0, credit = parseFloat(line.credit) || 0;
            if (isOpen || (glState.fromDate && (e.date || '') < glState.fromDate)) { preNet += debit - credit; return; }
            const ccName = ccDisplayName(line.costCenter);
            movements.push({
                date: e.date, number: e.number, description: e.description,
                lineDescription: line.description, costCenter: ccName, status: e.status,
                debit, credit
            });
        });
    });
    movements.sort((a, b) => (a.date || '').localeCompare(b.date || ''));

    const openingBalance = (parseFloat(account.openingBalance) || 0) + preNet;
    let bal = openingBalance;

    const rows = [
        { 'التاريخ': glState.fromDate || '', 'رقم القيد': '', 'البيان': '💼 الرصيد الافتتاحي', 'مدين': '', 'دائن': '', 'الرصيد': openingBalance, 'مركز التكلفة': '', 'الحالة': '' }
    ];
    movements.forEach(m => {
        bal += m.debit - m.credit;
        rows.push({
            'التاريخ': m.date || '',
            'رقم القيد': m.number || '',
            'البيان': m.description || '',
            'بيان السطر': m.lineDescription || '',
            'مدين': m.debit || '',
            'دائن': m.credit || '',
            'الرصيد': bal,
            'مركز التكلفة': m.costCenter,
            'الحالة': m.status
        });
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = [{ wch: 12 }, { wch: 16 }, { wch: 30 }, { wch: 25 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 20 }, { wch: 10 }];
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'دفتر الأستاذ');
        XLSX.writeFile(wb, `دفتر_الأستاذ_${account.code}_${account.nameAr}_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

console.log('✅ General Ledger module loaded');


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ⚖️  [ACC5]   ━━━━   TRIAL BALANCE   ━━━━                                ║
// ║                ميزان المراجعة — إثبات توازن النظام المحاسبي                   ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ── حالة ميزان المراجعة ─────────────────
let tbState = {
    fromDate: '',
    toDate: '',
    includeStatuses: ['posted'],
    showZero: false,           // إظهار الحسابات بدون رصيد؟
    groupBy: 'type',           // تجميع: type / parent / none
    costCenter: '',
    projectId: ''              // فلتر المشروع (منفصل عن مركز التكلفة)
};

// ── دالة العرض الرئيسية ─────────────────
window.renderTrialBalance = function () {
    const container = $('pg-trialbalance'); if (!container) return;

    const accounts = window.chartOfAccounts || {};
    const accountsArr = Object.entries(accounts);

    if (!accountsArr.length) {
        container.innerHTML = `
            <div style="background:linear-gradient(135deg,#922b21 0%,#c0392b 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white">
                <h1 style="margin:0;font-size:24px;font-weight:900">⚖️ ميزان المراجعة</h1>
            </div>
            <div class="card" style="text-align:center;padding:60px 20px">
                <div style="font-size:80px;margin-bottom:16px">🌳</div>
                <div style="font-size:18px;font-weight:800;color:#1a3a5c;margin-bottom:8px">لا توجد حسابات في النظام</div>
                <div style="font-size:13px;color:#666;margin-bottom:20px">يجب إنشاء شجرة الحسابات أولاً</div>
                <button class="btn b-g" onclick="nav('chartofaccounts')" style="padding:10px 20px">🌳 الذهاب لشجرة الحسابات</button>
            </div>
        `;
        return;
    }

    // إذا لم تُحدد تواريخ، استخدم السنة الحالية افتراضياً
    if (!tbState.toDate) {
        tbState.toDate = new Date().toISOString().slice(0, 10);
    }

    // ── حساب أرصدة كل الحسابات ─────────────
    const journalEntries = window.journalEntries || {};
    const balances = {}; // { accountCode: { debit, credit, opening } }

    // 1. الأرصدة الافتتاحية لكل حساب
    accountsArr.forEach(([key, a]) => {
        if (a.nature === 'header') return; // الحسابات الرئيسية لا تحوي حركات مباشرة
        balances[a.code] = {
            key,
            account: a,
            opening: parseFloat(a.openingBalance) || 0,
            debit: 0,
            credit: 0,
            count: 0
        };
    });

    // 2. جمع الحركات من القيود
    Object.values(journalEntries).forEach(e => {
        if (!tbState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e); // 🟢 القيد الافتتاحي = رصيد أول المدة دائماً (لا حركة)
        if (tbState.toDate && (e.date || '') > tbState.toDate) return;
        if (!isOpen && tbState.fromDate && (e.date || '') < tbState.fromDate) return;

        (e.lines || []).forEach(line => {
            if (!line.accountCode) return;
            // تطبيق فلتر مركز التكلفة
            if (tbState.costCenter && line.costCenter !== tbState.costCenter) return;
            if (tbState.projectId && !ccLineMatchesProject(line, tbState.projectId)) return;
            if (!balances[line.accountCode]) return; // حساب رئيسي أو غير موجود

            const debit = parseFloat(line.debit) || 0;
            const credit = parseFloat(line.credit) || 0;
            if (isOpen) { balances[line.accountCode].opening += debit - credit; }
            else {
                balances[line.accountCode].debit += debit;
                balances[line.accountCode].credit += credit;
                balances[line.accountCode].count++;
            }
        });
    });

    // 3. حساب الرصيد الختامي = افتتاحي + مدين - دائن
    Object.values(balances).forEach(b => {
        b.netBalance = b.opening + b.debit - b.credit;
        // الرصيد النهائي للعرض: إما مدين (موجب) أو دائن (موجب)
        // الأصول والمصروفات: طبيعتها مدينة (Net موجب = مدين)
        // الخصوم وحقوق الملكية والإيرادات: طبيعتها دائنة (Net سالب = دائن)
        const naturallyDebit = ['asset', 'expense'].includes(b.account.type);
        if (naturallyDebit) {
            // الرصيد الموجب = مدين، السالب = دائن (شاذ)
            b.finalDebit = b.netBalance > 0 ? b.netBalance : 0;
            b.finalCredit = b.netBalance < 0 ? Math.abs(b.netBalance) : 0;
        } else {
            // الرصيد السالب = دائن، الموجب = مدين (شاذ)
            b.finalDebit = b.netBalance > 0 ? b.netBalance : 0;
            b.finalCredit = b.netBalance < 0 ? Math.abs(b.netBalance) : 0;
        }
        b.isAnomaly = (naturallyDebit && b.netBalance < 0) || (!naturallyDebit && b.netBalance > 0);
    });

    // 4. تصفية الحسابات بدون حركة (إذا showZero = false)
    let displayBalances = Object.values(balances);
    if (!tbState.showZero) {
        displayBalances = displayBalances.filter(b =>
            b.opening !== 0 || b.debit !== 0 || b.credit !== 0
        );
    }

    // 5. الإجماليات
    const totals = displayBalances.reduce((acc, b) => {
        acc.opening += b.opening;
        acc.debit += b.debit;
        acc.credit += b.credit;
        acc.finalDebit += b.finalDebit;
        acc.finalCredit += b.finalCredit;
        return acc;
    }, { opening: 0, debit: 0, credit: 0, finalDebit: 0, finalCredit: 0 });

    // 6. التحقق من التوازن
    const debitCreditBalance = Math.abs(totals.debit - totals.credit) < 0.01;
    const finalBalance = Math.abs(totals.finalDebit - totals.finalCredit) < 0.01;

    // 7. إحصائيات
    const stats = {
        totalAccounts: displayBalances.length,
        withMovements: displayBalances.filter(b => b.count > 0).length,
        anomalies: displayBalances.filter(b => b.isAnomaly).length,
        byType: { asset: 0, liability: 0, equity: 0, revenue: 0, expense: 0 }
    };
    displayBalances.forEach(b => {
        if (stats.byType[b.account.type] !== undefined) {
            stats.byType[b.account.type] += b.finalDebit - b.finalCredit;
        }
    });

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#922b21 0%,#c0392b 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(192,57,43,.25)">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">TRIAL BALANCE</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">⚖️ ميزان المراجعة</h1>
                    <p style="margin:6px 0 0;font-size:12px;opacity:.95">إثبات توازن النظام المحاسبي — كل الحسابات في تقرير واحد</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    <button class="btn" onclick="printTrialBalance()" style="background:white;color:#922b21;padding:9px 16px;font-weight:800">🖨️ طباعة</button>
                    <button class="btn" onclick="exportTrialBalanceExcel()" style="background:rgba(255,255,255,.2);color:white;padding:9px 16px;font-weight:700;backdrop-filter:blur(10px)">📤 Excel</button>
                </div>
            </div>
        </div>

        <!-- Balance Status -->
        <div style="background:linear-gradient(135deg,${finalBalance ? '#27ae60' : '#c0392b'},${finalBalance ? '#1e8449' : '#922b21'});color:white;border-radius:14px;padding:18px;margin-bottom:14px;text-align:center;box-shadow:0 4px 14px rgba(0,0,0,.1)">
            <div style="font-size:11px;opacity:.85;letter-spacing:2px">SYSTEM BALANCE STATUS</div>
            <div style="font-size:32px;font-weight:900;margin-top:6px">
                ${finalBalance ? '✅ النظام متوازن' : '⚠️ النظام غير متوازن'}
            </div>
            <div style="margin-top:8px;display:flex;justify-content:center;gap:24px;flex-wrap:wrap;font-size:13px">
                <div>📥 إجمالي المدين: <strong>${fmt(totals.finalDebit)}</strong></div>
                <div>📤 إجمالي الدائن: <strong>${fmt(totals.finalCredit)}</strong></div>
                ${!finalBalance ? `<div>⚠️ الفرق: <strong>${fmt(Math.abs(totals.finalDebit - totals.finalCredit))}</strong></div>` : ''}
            </div>
        </div>

        <!-- Filters -->
        <div class="card" style="margin-bottom:14px;padding:14px">
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:10px;align-items:end">
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 من تاريخ</label>
                    <input type="date" id="tbFromDate" value="${tbState.fromDate}" onchange="updateTBFilter('fromDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📅 إلى تاريخ</label>
                    <input type="date" id="tbToDate" value="${tbState.toDate}" onchange="updateTBFilter('toDate', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📊 الحالة</label>
                    <select id="tbStatuses" onchange="updateTBStatuses(this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        <option value="posted" ${tbState.includeStatuses.length === 1 ? 'selected' : ''}>✅ المرحّلة فقط</option>
                        <option value="posted,draft" ${tbState.includeStatuses.includes('draft') && !tbState.includeStatuses.includes('cancelled') ? 'selected' : ''}>📝 مرحّلة + مسودات</option>
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🎯 مركز التكلفة</label>
                    <select id="tbCostCenter" onchange="updateTBFilter('costCenter', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        ${ccOnlyOptions(tbState.costCenter, '-- الكل --')}
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">🏗️ المشروع</label>
                    <select id="tbProject" onchange="updateTBFilter('projectId', this.value)" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        ${projOnlyOptions(tbState.projectId, '-- الكل --')}
                    </select>
                </div>
                <div>
                    <label style="font-size:11px;color:#666;font-weight:700">📋 العرض</label>
                    <select id="tbShowZero" onchange="tbState.showZero = this.value === 'all'; renderTrialBalance();" style="width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">
                        <option value="active" ${!tbState.showZero ? 'selected' : ''}>🟢 النشطة فقط</option>
                        <option value="all" ${tbState.showZero ? 'selected' : ''}>📋 كل الحسابات</option>
                    </select>
                </div>
                <div style="display:flex;gap:6px">
                    <button class="btn b-pu" onclick="setTBDateRange('thisMonth')" style="padding:8px;font-size:11px;flex:1">📅 شهر</button>
                    <button class="btn b-pu" onclick="setTBDateRange('thisQuarter')" style="padding:8px;font-size:11px;flex:1">📅 ربع</button>
                    <button class="btn b-pu" onclick="setTBDateRange('thisYear')" style="padding:8px;font-size:11px;flex:1">📅 سنة</button>
                    <button class="btn b-pu" onclick="setTBDateRange('all')" style="padding:8px;font-size:11px;flex:1">📅 الكل</button>
                </div>
            </div>
        </div>

        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">📊 الحسابات</div>
                <div style="font-size:24px;font-weight:900;color:#1a3a5c">${stats.totalAccounts}</div>
                <div style="font-size:10px;color:#666">${stats.withMovements} بحركات</div>
            </div>
            ${Object.entries(COA_TYPES).map(([k, t]) => {
                const val = stats.byType[k] || 0;
                return `<div style="background:${t.bg};border-radius:12px;padding:12px;border-right:4px solid ${t.color}">
                    <div style="font-size:11px;color:#666">${t.ar}</div>
                    <div style="font-size:16px;font-weight:900;color:${t.color}">${fmt(Math.abs(val))}</div>
                    <div style="font-size:10px;color:${t.color}">${val >= 0 ? 'مدين' : 'دائن'}</div>
                </div>`;
            }).join('')}
            ${stats.anomalies > 0 ? `<div style="background:#fadbd8;border-radius:12px;padding:12px;border-right:4px solid #c0392b">
                <div style="font-size:11px;color:#641e16">⚠️ أرصدة شاذة</div>
                <div style="font-size:24px;font-weight:900;color:#c0392b">${stats.anomalies}</div>
                <div style="font-size:10px;color:#c0392b">تحتاج مراجعة</div>
            </div>` : ''}
        </div>

        ${!finalBalance ? `
        <!-- Imbalance Warning -->
        <div style="background:linear-gradient(135deg,#fadbd8,#fff);border:2px solid #c0392b;border-radius:12px;padding:14px;margin-bottom:14px">
            <div style="font-size:14px;font-weight:800;color:#641e16;margin-bottom:8px">⚠️ تنبيه: النظام غير متوازن!</div>
            <div style="font-size:12px;color:#641e16;line-height:1.7">
                إجمالي المدين <strong>(${fmt(totals.finalDebit)})</strong> لا يساوي إجمالي الدائن <strong>(${fmt(totals.finalCredit)})</strong>.<br>
                الفرق = <strong style="color:#c0392b;font-size:14px">${fmt(Math.abs(totals.finalDebit - totals.finalCredit))} ر</strong><br>
                <strong>💡 الأسباب المحتملة:</strong> قيود غير متوازنة، أرصدة افتتاحية خاطئة، أو حسابات بأرصدة شاذة.
            </div>
        </div>
        ` : ''}

        ${stats.anomalies > 0 ? `
        <!-- Anomalies Warning -->
        <div style="background:linear-gradient(135deg,#fef9e7,#fff);border-right:4px solid #f39c12;border-radius:10px;padding:12px;margin-bottom:14px;font-size:12px;color:#7d4e00;line-height:1.7">
            ⚠️ <strong>أرصدة شاذة:</strong> ${stats.anomalies} حساب لديه رصيد بعكس طبيعته (مثلاً: حساب أصل برصيد دائن).
            هذه قد تكون أخطاء محاسبية تحتاج مراجعة.
        </div>
        ` : ''}

        <!-- Trial Balance Table -->
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:10px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c">📋 الحسابات وأرصدتها</div>
                <input type="text" id="tbSearch" placeholder="🔍 ابحث برمز أو اسم..." oninput="filterTBTable(this.value)" style="padding:7px 12px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;min-width:240px">
            </div>
            <div style="overflow-x:auto">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:1100px">
                    <thead style="background:#1a3a5c;color:white;position:sticky;top:0;z-index:5">
                        <tr>
                            <th style="padding:10px;text-align:right">رمز</th>
                            <th style="padding:10px;text-align:right">اسم الحساب</th>
                            <th style="padding:10px;text-align:right">المجموعة</th>
                            <th style="padding:10px;text-align:center">رصيد افتتاحي</th>
                            <th style="padding:10px;text-align:center;background:#2d6a9f">حركات مدين</th>
                            <th style="padding:10px;text-align:center;background:#8e44ad">حركات دائن</th>
                            <th style="padding:10px;text-align:center;background:#27ae60">رصيد ختامي مدين</th>
                            <th style="padding:10px;text-align:center;background:#c0392b">رصيد ختامي دائن</th>
                        </tr>
                    </thead>
                    <tbody id="tbTableBody">
                        ${renderTBGrouped(displayBalances)}
                    </tbody>
                    <tfoot style="background:#1a3a5c;color:white;font-weight:900">
                        <tr style="border-top:3px solid #fff">
                            <td colspan="3" style="padding:12px;text-align:left;font-size:14px">📊 الإجمالي العام</td>
                            <td style="padding:12px;text-align:center">${fmt(totals.opening)}</td>
                            <td style="padding:12px;text-align:center;background:#2d6a9f">${fmt(totals.debit)}</td>
                            <td style="padding:12px;text-align:center;background:#8e44ad">${fmt(totals.credit)}</td>
                            <td style="padding:12px;text-align:center;background:#27ae60;font-size:14px">${fmt(totals.finalDebit)}</td>
                            <td style="padding:12px;text-align:center;background:#c0392b;font-size:14px">${fmt(totals.finalCredit)}</td>
                        </tr>
                        <tr style="background:${finalBalance ? '#27ae60' : '#c0392b'}">
                            <td colspan="6" style="padding:14px;text-align:left;font-size:15px">${finalBalance ? '✅ النظام متوازن (الأرصدة المدينة = الأرصدة الدائنة)' : '⚠️ النظام غير متوازن — الفرق: ' + fmt(Math.abs(totals.finalDebit - totals.finalCredit))}</td>
                            <td colspan="2" style="padding:14px;text-align:center;font-size:14px">${finalBalance ? '⚖️ متوازن' : '⚠️ غير متوازن'}</td>
                        </tr>
                    </tfoot>
                </table>
            </div>
            <div style="margin-top:10px;font-size:11px;color:#666;background:#f8fafc;padding:8px;border-radius:6px;line-height:1.7">
                💡 <strong>كيف تقرأ الميزان:</strong>
                <br>• <strong>الرصيد الافتتاحي:</strong> رصيد الحساب في بداية الفترة.
                <br>• <strong>الحركات:</strong> مجموع الحركات (مدين/دائن) خلال الفترة.
                <br>• <strong>الرصيد الختامي:</strong> يظهر في عمود واحد فقط (مدين أو دائن) حسب طبيعة الحساب.
                <br>• <strong>التوازن:</strong> إجمالي المدين الختامي = إجمالي الدائن الختامي (القاعدة الذهبية للمحاسبة).
            </div>
        </div>
    `;
};

// ── رسم الجدول مع تجميع حسب النوع ─────────────────
function renderTBGrouped(balances) {
    // تجميع حسب النوع
    const grouped = { asset: [], liability: [], equity: [], revenue: [], expense: [] };
    balances.forEach(b => {
        if (grouped[b.account.type]) grouped[b.account.type].push(b);
    });

    // ترتيب كل مجموعة حسب الكود
    Object.values(grouped).forEach(arr => arr.sort((a, b) => (a.account.code || '').localeCompare(b.account.code || '')));

    let html = '';
    Object.entries(COA_TYPES).forEach(([typeKey, typeInfo]) => {
        const items = grouped[typeKey];
        if (!items.length) return;

        // مجموع المجموعة
        const groupTotal = items.reduce((acc, b) => {
            acc.opening += b.opening;
            acc.debit += b.debit;
            acc.credit += b.credit;
            acc.finalDebit += b.finalDebit;
            acc.finalCredit += b.finalCredit;
            return acc;
        }, { opening: 0, debit: 0, credit: 0, finalDebit: 0, finalCredit: 0 });

        // رأس المجموعة
        html += `<tr style="background:${typeInfo.bg};border-top:3px solid ${typeInfo.color}">
            <td colspan="8" style="padding:8px 10px;font-weight:900;color:${typeInfo.color};font-size:13px">
                ${typeInfo.ar} (${items.length} حساب)
            </td>
        </tr>`;

        // الحسابات
        items.forEach((b, i) => {
            const a = b.account;
            const anomalyMark = b.isAnomaly ? ' <span style="background:#f39c12;color:white;padding:1px 5px;border-radius:3px;font-size:9px;font-weight:700" title="رصيد بعكس طبيعة الحساب">⚠️ شاذ</span>' : '';
            html += `<tr style="${i % 2 ? 'background:#fafbfc' : ''}" data-search="${(a.code || '').toLowerCase()} ${(a.nameAr || '').toLowerCase()}">
                <td style="padding:7px;font-family:monospace;font-weight:700;color:${typeInfo.color}">${a.code}</td>
                <td style="padding:7px;font-weight:600">
                    <span style="cursor:pointer;color:#2d6a9f;text-decoration:underline" onclick="openGLForAccount('${a.code}');nav('generalledger')" title="عرض دفتر الأستاذ">${a.nameAr}</span>
                    ${anomalyMark}
                    ${a.nameEn ? `<div style="font-size:10px;color:#888;direction:ltr">${a.nameEn}</div>` : ''}
                </td>
                <td style="padding:7px;font-size:11px;color:#666">${typeInfo.ar}</td>
                <td style="padding:7px;text-align:center;color:#666">${b.opening !== 0 ? fmt(b.opening) : '—'}</td>
                <td style="padding:7px;text-align:center;color:#2d6a9f;font-weight:700">${b.debit ? fmt(b.debit) : '—'}</td>
                <td style="padding:7px;text-align:center;color:#8e44ad;font-weight:700">${b.credit ? fmt(b.credit) : '—'}</td>
                <td style="padding:7px;text-align:center;color:#27ae60;font-weight:800">${b.finalDebit > 0 ? fmt(b.finalDebit) : '—'}</td>
                <td style="padding:7px;text-align:center;color:#c0392b;font-weight:800">${b.finalCredit > 0 ? fmt(b.finalCredit) : '—'}</td>
            </tr>`;
        });

        // مجموع المجموعة
        html += `<tr style="background:${typeInfo.color};color:white;font-weight:900">
            <td colspan="3" style="padding:8px;text-align:left">إجمالي ${typeInfo.ar}</td>
            <td style="padding:8px;text-align:center">${fmt(groupTotal.opening)}</td>
            <td style="padding:8px;text-align:center">${fmt(groupTotal.debit)}</td>
            <td style="padding:8px;text-align:center">${fmt(groupTotal.credit)}</td>
            <td style="padding:8px;text-align:center">${fmt(groupTotal.finalDebit)}</td>
            <td style="padding:8px;text-align:center">${fmt(groupTotal.finalCredit)}</td>
        </tr>`;
    });
    return html;
}

window.filterTBTable = function (query) {
    query = (query || '').toLowerCase().trim();
    document.querySelectorAll('#tbTableBody tr[data-search]').forEach(row => {
        const txt = row.getAttribute('data-search') || '';
        row.style.display = (!query || txt.includes(query)) ? '' : 'none';
    });
};

window.updateTBFilter = function (field, value) {
    tbState[field] = value;
    renderTrialBalance();
};

window.updateTBStatuses = function (value) {
    tbState.includeStatuses = value.split(',');
    renderTrialBalance();
};

window.setTBDateRange = function (range) {
    const today = new Date();
    const y = today.getFullYear();
    const m = today.getMonth();
    switch (range) {
        case 'thisMonth':
            tbState.fromDate = new Date(y, m, 1).toISOString().slice(0, 10);
            tbState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'thisQuarter':
            const qStart = Math.floor(m / 3) * 3;
            tbState.fromDate = new Date(y, qStart, 1).toISOString().slice(0, 10);
            tbState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'thisYear':
            tbState.fromDate = y + '-01-01';
            tbState.toDate = today.toISOString().slice(0, 10);
            break;
        case 'all':
            tbState.fromDate = '';
            tbState.toDate = today.toISOString().slice(0, 10);
            break;
    }
    renderTrialBalance();
};

// ── طباعة ─────────────────
window.printTrialBalance = function () {
    const accounts = window.chartOfAccounts || {};
    const journalEntries = window.journalEntries || {};

    // إعادة الحسابات (نفس منطق العرض)
    const balances = {};
    Object.entries(accounts).forEach(([key, a]) => {
        if (a.nature === 'header') return;
        balances[a.code] = { account: a, opening: parseFloat(a.openingBalance) || 0, debit: 0, credit: 0 };
    });
    Object.values(journalEntries).forEach(e => {
        if (!tbState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e); // 🟢 القيد الافتتاحي = رصيد أول المدة دائماً
        if (tbState.toDate && (e.date || '') > tbState.toDate) return;
        if (!isOpen && tbState.fromDate && (e.date || '') < tbState.fromDate) return;
        (e.lines || []).forEach(line => {
            if (!line.accountCode || !balances[line.accountCode]) return;
            if (tbState.costCenter && line.costCenter !== tbState.costCenter) return;
            if (tbState.projectId && !ccLineMatchesProject(line, tbState.projectId)) return;
            const debit = parseFloat(line.debit) || 0;
            const credit = parseFloat(line.credit) || 0;
            if (isOpen) { balances[line.accountCode].opening += debit - credit; }
            else { balances[line.accountCode].debit += debit; balances[line.accountCode].credit += credit; }
        });
    });
    Object.values(balances).forEach(b => {
        b.netBalance = b.opening + b.debit - b.credit;
        b.finalDebit = b.netBalance > 0 ? b.netBalance : 0;
        b.finalCredit = b.netBalance < 0 ? Math.abs(b.netBalance) : 0;
    });
    let displayBalances = Object.values(balances);
    if (!tbState.showZero) displayBalances = displayBalances.filter(b => b.opening !== 0 || b.debit !== 0 || b.credit !== 0);
    const totals = displayBalances.reduce((a, b) => ({
        opening: a.opening + b.opening, debit: a.debit + b.debit, credit: a.credit + b.credit,
        finalDebit: a.finalDebit + b.finalDebit, finalCredit: a.finalCredit + b.finalCredit
    }), { opening: 0, debit: 0, credit: 0, finalDebit: 0, finalCredit: 0 });

    const grouped = { asset: [], liability: [], equity: [], revenue: [], expense: [] };
    displayBalances.forEach(b => { if (grouped[b.account.type]) grouped[b.account.type].push(b); });
    Object.values(grouped).forEach(arr => arr.sort((a, b) => (a.account.code || '').localeCompare(b.account.code || '')));
    const isBalanced = Math.abs(totals.finalDebit - totals.finalCredit) < 0.01;

    let rowsHtml = '';
    Object.entries(COA_TYPES).forEach(([typeKey, typeInfo]) => {
        const items = grouped[typeKey]; if (!items.length) return;
        rowsHtml += `<tr style="background:${typeInfo.bg}"><td colspan="7" style="padding:8px;font-weight:900;color:${typeInfo.color}">${typeInfo.ar}</td></tr>`;
        const gt = { opening: 0, debit: 0, credit: 0, finalDebit: 0, finalCredit: 0 };
        items.forEach(b => {
            gt.opening += b.opening; gt.debit += b.debit; gt.credit += b.credit;
            gt.finalDebit += b.finalDebit; gt.finalCredit += b.finalCredit;
            rowsHtml += `<tr>
                <td style="font-family:monospace;font-weight:700">${b.account.code}</td>
                <td>${b.account.nameAr}</td>
                <td style="text-align:left">${b.opening !== 0 ? fmt(b.opening) : '—'}</td>
                <td style="text-align:left;color:#2d6a9f">${b.debit ? fmt(b.debit) : '—'}</td>
                <td style="text-align:left;color:#8e44ad">${b.credit ? fmt(b.credit) : '—'}</td>
                <td style="text-align:left;color:#27ae60;font-weight:700">${b.finalDebit > 0 ? fmt(b.finalDebit) : '—'}</td>
                <td style="text-align:left;color:#c0392b;font-weight:700">${b.finalCredit > 0 ? fmt(b.finalCredit) : '—'}</td>
            </tr>`;
        });
        rowsHtml += `<tr style="background:${typeInfo.color};color:white;font-weight:900">
            <td colspan="2">إجمالي ${typeInfo.ar}</td>
            <td style="text-align:left">${fmt(gt.opening)}</td>
            <td style="text-align:left">${fmt(gt.debit)}</td>
            <td style="text-align:left">${fmt(gt.credit)}</td>
            <td style="text-align:left">${fmt(gt.finalDebit)}</td>
            <td style="text-align:left">${fmt(gt.finalCredit)}</td>
        </tr>`;
    });

    const html = `<!DOCTYPE html><html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>ميزان المراجعة</title>
    <style>
        * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        body { font-family: 'Tajawal', Tahoma, Arial; padding: 20px; color: #1a3a5c; direction: rtl; }
        h1 { text-align: center; border-bottom: 3px solid #c0392b; padding-bottom: 10px; }
        .info { background: #f0f5fa; padding: 12px; border-radius: 8px; margin: 14px 0; display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; font-size: 12px; }
        .status { padding: 12px; border-radius: 8px; margin-bottom: 14px; text-align: center; font-weight: 900; background: ${isBalanced ? '#27ae60' : '#c0392b'}; color: white; }
        table { width: 100%; border-collapse: collapse; font-size: 11px; }
        th { background: #1a3a5c; color: white; padding: 8px; border: 1px solid #1a3a5c; }
        td { padding: 6px 8px; border: 1px solid #ddd; }
        tfoot td { background: #1a3a5c; color: white; font-weight: 900; padding: 10px; font-size: 13px; }
        @page { size: A4 landscape; margin: 1cm; }
    </style></head><body>
    <h1>⚖️ ميزان المراجعة</h1>
    <div class="info">
        <div><strong>📅 الفترة:</strong> ${tbState.fromDate || 'من البداية'} → ${tbState.toDate}</div>
        <div><strong>📊 الحسابات:</strong> ${displayBalances.length}</div>
        <div><strong>📅 تاريخ الطباعة:</strong> ${new Date().toLocaleDateString('ar-SA')}</div>
    </div>
    <div class="status">${isBalanced ? '✅ النظام متوازن' : '⚠️ النظام غير متوازن'}</div>
    <table>
        <thead><tr>
            <th>رمز</th><th>اسم الحساب</th><th>رصيد افتتاحي</th>
            <th style="background:#2d6a9f">مدين</th><th style="background:#8e44ad">دائن</th>
            <th style="background:#27ae60">رصيد ختامي مدين</th><th style="background:#c0392b">رصيد ختامي دائن</th>
        </tr></thead>
        <tbody>${rowsHtml}</tbody>
        <tfoot>
            <tr>
                <td colspan="2" style="text-align:left">📊 الإجمالي العام</td>
                <td style="text-align:left">${fmt(totals.opening)}</td>
                <td style="text-align:left">${fmt(totals.debit)}</td>
                <td style="text-align:left">${fmt(totals.credit)}</td>
                <td style="text-align:left">${fmt(totals.finalDebit)}</td>
                <td style="text-align:left">${fmt(totals.finalCredit)}</td>
            </tr>
        </tfoot>
    </table>
    <div style="margin-top:30px;display:grid;grid-template-columns:repeat(3,1fr);gap:30px;text-align:center;font-size:11px">
        <div>✍️ المحاسب<br><strong>___________</strong></div>
        <div>✍️ المراجع<br><strong>___________</strong></div>
        <div>✍️ المدير المالي<br><strong>___________</strong></div>
    </div>
    </body></html>`;

    const w = window.open('', '_blank');
    w.document.write(html);
    w.document.close();
    setTimeout(() => { try { w.print(); } catch (e) { } }, 500);
};

// ── تصدير Excel ─────────────────
window.exportTrialBalanceExcel = function () {
    const accounts = window.chartOfAccounts || {};
    const journalEntries = window.journalEntries || {};

    const balances = {};
    Object.entries(accounts).forEach(([key, a]) => {
        if (a.nature === 'header') return;
        balances[a.code] = { account: a, opening: parseFloat(a.openingBalance) || 0, debit: 0, credit: 0 };
    });
    Object.values(journalEntries).forEach(e => {
        if (!tbState.includeStatuses.includes(e.status || 'draft')) return;
        const isOpen = fsIsOpeningEntry(e); // 🟢 القيد الافتتاحي = رصيد أول المدة دائماً
        if (tbState.toDate && (e.date || '') > tbState.toDate) return;
        if (!isOpen && tbState.fromDate && (e.date || '') < tbState.fromDate) return;
        (e.lines || []).forEach(line => {
            if (!line.accountCode || !balances[line.accountCode]) return;
            if (tbState.costCenter && line.costCenter !== tbState.costCenter) return;
            if (tbState.projectId && !ccLineMatchesProject(line, tbState.projectId)) return;
            const debit = parseFloat(line.debit) || 0;
            const credit = parseFloat(line.credit) || 0;
            if (isOpen) { balances[line.accountCode].opening += debit - credit; }
            else { balances[line.accountCode].debit += debit; balances[line.accountCode].credit += credit; }
        });
    });

    const rows = [];
    Object.values(balances).forEach(b => {
        if (!tbState.showZero && b.opening === 0 && b.debit === 0 && b.credit === 0) return;
        const net = b.opening + b.debit - b.credit;
        const finalDebit = net > 0 ? net : 0;
        const finalCredit = net < 0 ? Math.abs(net) : 0;
        const type = COA_TYPES[b.account.type] || { ar: '—' };
        rows.push({
            'الرمز': b.account.code,
            'اسم الحساب': b.account.nameAr,
            'المجموعة': type.ar,
            'الرصيد الافتتاحي': b.opening,
            'حركات مدين': b.debit,
            'حركات دائن': b.credit,
            'الرصيد الختامي - مدين': finalDebit,
            'الرصيد الختامي - دائن': finalCredit
        });
    });

    rows.sort((a, b) => (a['الرمز'] || '').localeCompare(b['الرمز'] || ''));

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = [{ wch: 10 }, { wch: 28 }, { wch: 15 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 18 }, { wch: 18 }];
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'ميزان المراجعة');
        XLSX.writeFile(wb, `ميزان_المراجعة_${tbState.toDate}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

