// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧑‍💼  [ACC6]   ━━━━   CUSTOMERS   ━━━━                                   ║
// ║                إدارة العملاء وأرصدتهم                                       ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ── توليد رمز العميل التالي ─────────────────
function generateCustomerCode() {
    const customers = Object.values(window.customers || {});
    const nums = customers.map(c => parseInt((c.code || '').replace(/\D/g, '')) || 0);
    const next = nums.length ? Math.max(...nums) + 1 : 1;
    return 'CUST-' + String(next).padStart(4, '0');
}

// ذاكرة مؤقتة محدودة بزمن رسم القائمة (تُفعَّل/تُمسح داخل renderCustomers فقط)
let _custRenderMemo = null;
function calcCustomerBalance(customerKey) {
    if (_custRenderMemo && _custRenderMemo.bal[customerKey]) return _custRenderMemo.bal[customerKey];
    const customer = window.customers?.[customerKey];
    if (!customer) return { opening: 0, invoiced: 0, paid: 0, balance: 0, overdue: 0 };

    const opening = parseFloat(customer.openingBalance) || 0;
    let invoiced = 0, paid = 0, overdue = 0, credited = 0;
    const today = new Date().toISOString().slice(0, 10);

    Object.values(window.salesInvoices || {}).forEach(inv => {
        if (inv.customerId !== customerKey) return;
        if (inv.status !== 'posted') return;
        if (inv.fullyCredited) return; // أُلغيت بالكامل بإشعار دائن
        const grand = Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
        const invPaid = Math.round((parseFloat(inv.paidAmount) || 0) * 100) / 100;
        const cnAmt = Math.round((parseFloat(inv.creditedAmount) || 0) * 100) / 100; // إشعار دائن جزئي
        invoiced += grand;
        paid += invPaid;
        credited += cnAmt;
        const rem = grand - invPaid - cnAmt;
        if (inv.dueDate && inv.dueDate < today && rem > 0.01) {
            overdue += rem;
        }
    });

    const res = {
        opening,
        invoiced,
        paid,
        credited,
        balance: opening + invoiced - paid - credited,
        overdue
    };
    if (_custRenderMemo) _custRenderMemo.bal[customerKey] = res;
    return res;
}

// ── حالة عرض قسم العملاء ─────────────────
window._custState = window._custState || { view: 'list', filter: 'all', sort: { col: 'code', dir: 1 }, search: '' };
const CUST_TYPE_LABELS = { company: { label: '🏢 شركة', color: '#2d6a9f' }, individual: { label: '👤 فرد', color: '#16a085' }, government: { label: '🏛️ حكومية', color: '#8e44ad' } };

// تاريخ استحقاق الفاتورة (يعتمد dueDate أو date + مهلة العميل)
function custInvoiceDue(inv, terms) {
    if (inv.dueDate) return inv.dueDate;
    if (inv.date) { const d = new Date(inv.date); d.setDate(d.getDate() + (parseInt(terms) || 0)); return d.toISOString().slice(0, 10); }
    return '';
}

// ── تحليل أعمار الديون لعميل ─────────────────
function calcCustomerAging(key) {
    const c = window.customers?.[key] || {};
    const terms = c.paymentTerms || 0;
    const today = new Date(); today.setHours(0, 0, 0, 0);
    const buckets = { current: 0, d30: 0, d60: 0, d90: 0, d120: 0, over120: 0, total: 0 };
    Object.values(window.salesInvoices || {}).forEach(inv => {
        if (inv.customerId !== key || inv.status !== 'posted') return;
        if (inv.fullyCredited) return; // أُلغيت بإشعار دائن
        const grand = Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
        const paid = Math.round((parseFloat(inv.paidAmount) || 0) * 100) / 100;
        const cnAmt = Math.round((parseFloat(inv.creditedAmount) || 0) * 100) / 100;
        const rem = Math.round((grand - paid - cnAmt) * 100) / 100;
        if (rem <= 0.01) return;
        const due = custInvoiceDue(inv, terms);
        const dueMs = due ? new Date(due).getTime() : today.getTime();
        const days = Math.floor((today.getTime() - dueMs) / 86400000);
        if (days <= 0) buckets.current += rem;
        else if (days <= 30) buckets.d30 += rem;
        else if (days <= 60) buckets.d60 += rem;
        else if (days <= 90) buckets.d90 += rem;
        else if (days <= 120) buckets.d120 += rem;
        else buckets.over120 += rem;
        buckets.total += rem;
    });
    return buckets;
}

// ── سندات قبض العميل ─────────────────
function customerReceipts(key) {
    return Object.entries(window.receipts || {}).filter(([, r]) => r && r.partyId === key).map(([k, r]) => ({ k, ...r }));
}

// ── مؤشرات العميل (آخر فاتورة/دفعة، مبيعات، DSO) ─────────────────
function calcCustomerKpis(key) {
    if (_custRenderMemo && _custRenderMemo.kp[key]) return _custRenderMemo.kp[key];
    let lastInvoice = '', lastPayment = '', totalSales = 0, invoiceCount = 0;
    Object.values(window.salesInvoices || {}).forEach(inv => {
        if (inv.customerId !== key || inv.status !== 'posted') return;
        invoiceCount++; totalSales += Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
        if ((inv.date || '') > lastInvoice) lastInvoice = inv.date || '';
    });
    // DSO تقريبي: متوسط أيام التحصيل الموزون من سندات القبض المرحّلة المخصّصة لفواتير
    let wDays = 0, wAmt = 0;
    customerReceipts(key).forEach(r => {
        if (r.status !== 'posted') return;
        if ((r.date || '') > lastPayment) lastPayment = r.date || '';
        const allocs = r.allocations || {};
        Object.entries(allocs).forEach(([invK, amt]) => {
            const inv = window.salesInvoices?.[invK]; if (!inv || !inv.date || !r.date) return;
            const days = Math.max(0, Math.floor((new Date(r.date).getTime() - new Date(inv.date).getTime()) / 86400000));
            const a = parseFloat(amt) || 0; wDays += days * a; wAmt += a;
        });
    });
    const dso = wAmt > 0 ? Math.round(wDays / wAmt) : null;
    const res = { lastInvoice, lastPayment, totalSales, invoiceCount, dso };
    if (_custRenderMemo) _custRenderMemo.kp[key] = res;
    return res;
}

// ── معلومات الائتمان ─────────────────
function creditInfo(key) {
    const c = window.customers?.[key] || {};
    const limit = parseFloat(c.creditLimit) || 0;
    const used = calcCustomerBalance(key).balance;
    const pct = limit > 0 ? Math.round((used / limit) * 100) : (used > 0 ? 999 : 0);
    let status = 'none';
    if (limit > 0) { if (used > limit + 0.01) status = 'over'; else if (pct >= 80) status = 'warning'; else status = 'ok'; }
    return { limit, used, pct, status };
}

// ── دالة العرض الرئيسية للعملاء ─────────────────
window.custSetView = function (v) { window._custState.view = v; renderCustomers(); };
window.custSetFilter = function (f) { window._custState.filter = f; renderCustomers(); };
window.custSetSort = function (col) { const s = window._custState.sort; if (s.col === col) s.dir *= -1; else { s.col = col; s.dir = 1; } renderCustomers(); };
window.renderCustomers = function () {
    const container = $('pg-customers'); if (!container) return;
    const customers = window.customers || {};
    const custArr = Object.entries(customers).sort((a, b) => (a[1].code || '').localeCompare(b[1].code || ''));
    _custRenderMemo = { bal: {}, kp: {} }; // تفعيل الذاكرة المؤقتة لزمن الرسم

    // إحصائيات
    const stats = { total: custArr.length, active: 0, totalReceivable: 0, totalOverdue: 0, totalOpening: 0 };
    custArr.forEach(([key, c]) => {
        if (c.active !== false) stats.active++;
        const bal = calcCustomerBalance(key);
        stats.totalReceivable += bal.balance;
        stats.totalOverdue += bal.overdue;
        stats.totalOpening += bal.opening;
    });

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const canManage = isAdmin || canFn('manage_customers');

    // مؤشرات إضافية: DSO المتوسط + عدد المتجاوزين للحد
    let dsoSum = 0, dsoCount = 0, overLimitCount = 0, totalSales = 0;
    custArr.forEach(([key]) => { const kp = calcCustomerKpis(key); if (kp.dso != null) { dsoSum += kp.dso; dsoCount++; } totalSales += kp.totalSales; if (creditInfo(key).status === 'over') overLimitCount++; });
    const avgDso = dsoCount ? Math.round(dsoSum / dsoCount) : null;

    const st = window._custState;
    const tab = (id, label, icon) => `<button class="btn" onclick="custSetView('${id}')" style="${st.view === id ? 'background:#0e6251;color:#fff' : 'background:#eef2f0;color:#0e6251'};padding:9px 18px;font-weight:800;font-size:13px;border-radius:9px">${icon} ${label}</button>`;

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#0e6251 0%,#16a085 100%);border-radius:16px;padding:20px;margin-bottom:16px;color:white;box-shadow:0 6px 20px rgba(22,160,133,.25)">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">CUSTOMERS · 360°</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">🧑‍💼 إدارة العملاء</h1>
                    <p style="margin:6px 0 0;font-size:12px;opacity:.95">العملاء، الذمم، أعمار الديون، الائتمان، والتحليلات</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    ${canManage ? '<button class="btn" onclick="openCustomerEditor()" style="background:white;color:#0e6251;padding:10px 18px;font-weight:800;font-size:14px">➕ عميل جديد</button>' : ''}
                    ${canManage ? `<button class="btn" onclick="openArApGroups('customer')" style="background:rgba(255,255,255,.2);color:white;padding:10px 18px;font-weight:700;backdrop-filter:blur(10px)" title="إدارة مجموعات العملاء وحسابات المراقبة">👥 المجموعات</button>` : ''}
                    <button class="btn" onclick="exportCustomersExcel()" style="background:rgba(255,255,255,.2);color:white;padding:10px 18px;font-weight:700;backdrop-filter:blur(10px)">📤 Excel</button>
                    <button class="btn" onclick="downloadCustomerTemplate()" style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border:1.5px solid rgba(255,255,255,.4)" title="تحميل نموذج Excel فارغ للتعبئة والاستيراد">📥 نموذج الاستيراد</button>
                    <label style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border-radius:8px;cursor:pointer;border:1.5px solid rgba(255,255,255,.4);font-size:13px" title="استيراد عملاء من Excel">
                        📂 استيراد Excel
                        <input type="file" accept=".xlsx,.xls" style="display:none" onchange="importCustomersExcel(this.files[0]);this.value=''">
                    </label>
                    ${canManage ? '<button class="btn" onclick="openCustMergeTool()" style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border:1.5px solid rgba(255,255,255,.4)" title="اكتشاف ودمج العملاء المكررين">🔗 دمج المكررين</button>' : ''}
                    <button class="btn" onclick="custScheduleMonthlyStatements()" style="background:rgba(255,255,255,.15);color:white;padding:10px 16px;font-weight:700;border:1.5px solid rgba(255,255,255,.4)" title="إنشاء تذكير شهري لإرسال الكشوف">🗓️ كشوف شهرية</button>
                </div>
            </div>
        </div>

        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:10px;margin-bottom:14px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">📊 إجمالي العملاء</div>
                <div style="font-size:24px;font-weight:900;color:#1a3a5c">${stats.total}</div>
                <div style="font-size:10px;color:#666">${stats.active} نشط</div>
            </div>
            <div style="background:#e8f4fd;border-radius:12px;padding:12px;border-right:4px solid #2d6a9f">
                <div style="font-size:11px;color:#0d4f7c">💰 إجمالي الذمم المدينة</div>
                <div style="font-size:20px;font-weight:900;color:#2d6a9f">${fmt(stats.totalReceivable)}</div>
            </div>
            <div style="background:${stats.totalOverdue > 0 ? '#fadbd8' : '#e8f8f5'};border-radius:12px;padding:12px;border-right:4px solid ${stats.totalOverdue > 0 ? '#c0392b' : '#27ae60'}">
                <div style="font-size:11px;color:${stats.totalOverdue > 0 ? '#641e16' : '#0e6655'}">⚠️ المتأخرات</div>
                <div style="font-size:20px;font-weight:900;color:${stats.totalOverdue > 0 ? '#c0392b' : '#27ae60'}">${fmt(stats.totalOverdue)}</div>
            </div>
            <div style="background:#f5eef8;border-radius:12px;padding:12px;border-right:4px solid #8e44ad">
                <div style="font-size:11px;color:#5b2c6f">📈 إجمالي المبيعات</div>
                <div style="font-size:20px;font-weight:900;color:#8e44ad">${fmt(totalSales)}</div>
            </div>
            <div style="background:#fef9e7;border-radius:12px;padding:12px;border-right:4px solid #f39c12">
                <div style="font-size:11px;color:#7d4e00">⏱️ متوسط أيام التحصيل</div>
                <div style="font-size:20px;font-weight:900;color:#f39c12">${avgDso != null ? avgDso + ' يوم' : '—'}</div>
                ${overLimitCount ? `<div style="font-size:10px;color:#c0392b;font-weight:700">🚫 ${overLimitCount} تجاوز الحد الائتماني</div>` : ''}
            </div>
        </div>

        <!-- Tabs -->
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
            ${tab('list', 'القائمة', '📋')} ${tab('aging', 'أعمار الديون', '📊')} ${tab('collections', 'التحصيل', '📞')} ${tab('analytics', 'التحليلات', '📈')}
        </div>

        ${!custArr.length ? `
        <div class="card" style="text-align:center;padding:60px 20px">
            <div style="font-size:80px;margin-bottom:16px">🧑‍💼</div>
            <div style="font-size:18px;font-weight:800;color:#1a3a5c;margin-bottom:8px">لا يوجد عملاء بعد</div>
            <div style="font-size:13px;color:#666;margin-bottom:20px">ابدأ بإضافة عملائك لإصدار فواتير المبيعات</div>
            ${canManage ? '<button class="btn b-g" onclick="openCustomerEditor()" style="padding:12px 24px;font-size:14px">➕ إضافة عميل جديد</button>' : ''}
        </div>
        ` : `<div id="custViewArea">${st.view === 'aging' ? renderCustAgingHtml(custArr) : st.view === 'collections' ? renderCustCollectionsHtml(custArr) : st.view === 'analytics' ? renderCustAnalyticsHtml(custArr) : renderCustListHtml(custArr, canManage)}</div>`}
    `;
    _custRenderMemo = null; // مسح الذاكرة بعد انتهاء الرسم
    if (custArr.length && st.view === 'analytics') setTimeout(drawCustCharts, 60);
};

// ── عرض القائمة (فلاتر + فرز + ائتمان) ─────────────────
function custSortedArray(custArr) {
    const st = window._custState; const f = st.filter;
    let arr = custArr.filter(([key, c]) => {
        if (f === 'active') return c.active !== false;
        if (f === 'inactive') return c.active === false;
        if (f === 'overdue') return calcCustomerBalance(key).overdue > 0;
        if (f === 'overlimit') return creditInfo(key).status === 'over';
        return true;
    });
    const { col, dir } = st.sort;
    arr.sort((a, b) => {
        let va, vb;
        if (col === 'name') { va = a[1].nameAr || ''; vb = b[1].nameAr || ''; return va.localeCompare(vb, 'ar') * dir; }
        if (col === 'balance') { va = calcCustomerBalance(a[0]).balance; vb = calcCustomerBalance(b[0]).balance; }
        else if (col === 'overdue') { va = calcCustomerBalance(a[0]).overdue; vb = calcCustomerBalance(b[0]).overdue; }
        else if (col === 'sales') { va = calcCustomerKpis(a[0]).totalSales; vb = calcCustomerKpis(b[0]).totalSales; }
        else { va = a[1].code || ''; vb = b[1].code || ''; return va.localeCompare(vb, 'ar') * dir; }
        return (va - vb) * dir;
    });
    return arr;
}
function renderCustListHtml(custArr, canManage) {
    const st = window._custState;
    const arr = custSortedArray(custArr);
    const fcount = f => custArr.filter(([key, c]) => f === 'all' ? true : f === 'active' ? c.active !== false : f === 'inactive' ? c.active === false : f === 'overdue' ? calcCustomerBalance(key).overdue > 0 : f === 'overlimit' ? creditInfo(key).status === 'over' : true).length;
    const chip = (id, label) => `<button class="btn" onclick="custSetFilter('${id}')" style="${st.filter === id ? 'background:#0e6251;color:#fff' : 'background:#eef2f0;color:#0e6251'};padding:6px 13px;font-size:12px;font-weight:700;border-radius:18px">${label} (${fcount(id)})</button>`;
    const sortArrow = c => st.sort.col === c ? (st.sort.dir > 0 ? ' ▲' : ' ▼') : '';
    const sh = (c, label, align) => `<th onclick="custSetSort('${c}')" style="padding:10px;text-align:${align || 'right'};cursor:pointer;user-select:none" title="فرز">${label}${sortArrow(c)}</th>`;
    return `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
            <div style="display:flex;gap:6px;flex-wrap:wrap">${chip('all', 'الكل')} ${chip('active', 'نشط')} ${chip('overdue', '⚠️ متأخر')} ${chip('overlimit', '🚫 تجاوز الحد')} ${chip('inactive', 'معطّل')}</div>
            <input type="text" id="custSearch" placeholder="🔍 ابحث بالرمز، الاسم، الهاتف..." oninput="filterCustTable(this.value)" style="padding:7px 12px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;min-width:240px">
        </div>
        <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:1180px">
                <thead style="background:#1a3a5c;color:white"><tr>
                    ${sh('code', '🔢 الرمز')}
                    <th style="padding:10px;text-align:right">🏷️ النوع</th>
                    ${sh('name', '📝 الاسم')}
                    <th style="padding:10px;text-align:right">🧑‍💼 المندوب</th>
                    <th style="padding:10px;text-align:right">📞 التواصل</th>
                    ${sh('balance', '💵 الرصيد', 'center')}
                    <th style="padding:10px;text-align:center">💳 الائتمان</th>
                    ${sh('overdue', '⚠️ المتأخرات', 'center')}
                    <th style="padding:10px;text-align:center">📊 الحالة</th>
                    <th style="padding:10px;text-align:center">⚙️</th>
                </tr></thead>
                <tbody id="custTableBody">
                    ${arr.map(([key, c], i) => renderCustomerRow(key, c, i, canManage)).join('')}
                </tbody>
            </table>
        </div>
        ${!arr.length ? '<div style="text-align:center;color:#999;padding:30px">لا يوجد عملاء مطابقون للفلتر</div>' : ''}
    </div>`;
}

function renderCustomerRow(key, c, idx, canManage) {
    const bal = calcCustomerBalance(key);
    const t = CUST_TYPE_LABELS[c.type] || CUST_TYPE_LABELS.company;
    const isActive = c.active !== false;
    const cr = creditInfo(key);
    const crColor = cr.status === 'over' ? '#c0392b' : cr.status === 'warning' ? '#f39c12' : '#27ae60';
    const creditCell = cr.limit > 0
        ? `<div style="font-size:10px;color:#666;margin-bottom:2px">${fmt(cr.used)} / ${fmt(cr.limit)}</div>
           <div style="background:#eee;border-radius:6px;height:6px;overflow:hidden"><div style="width:${Math.min(100, Math.max(0, cr.pct))}%;height:100%;background:${crColor}"></div></div>
           ${cr.status === 'over' ? '<div style="font-size:9px;color:#c0392b;font-weight:800;margin-top:2px">🚫 تجاوز الحد</div>' : cr.status === 'warning' ? `<div style="font-size:9px;color:#f39c12;font-weight:700;margin-top:2px">${cr.pct}%</div>` : ''}`
        : '<span style="color:#ccc;font-size:11px">بلا حد</span>';

    return `<tr style="${idx % 2 ? 'background:#fafbfc' : ''}" data-search="${(c.code || '').toLowerCase()} ${(c.nameAr || '').toLowerCase()} ${(c.nameEn || '').toLowerCase()} ${(c.phone || '').toLowerCase()} ${(c.vatNumber || '').toLowerCase()} ${(c.salespersonName || '').toLowerCase()}">
        <td style="padding:8px;font-family:monospace;font-weight:800;color:#1a3a5c">${c.code || '—'}</td>
        <td style="padding:8px"><span style="background:${t.color}22;color:${t.color};padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700">${t.label}</span></td>
        <td style="padding:8px;font-weight:700">
            <span onclick="openCustomer360('${key}')" style="color:#0e6251;cursor:pointer;text-decoration:underline" title="فتح بطاقة العميل 360°">${c.nameAr || '—'}</span>
            ${c.nameEn ? `<div style="font-size:10px;color:#888;direction:ltr">${c.nameEn}</div>` : ''}
            ${c.category ? `<div style="font-size:9px;color:#8e44ad;font-weight:700">🗂️ ${c.category}</div>` : ''}
        </td>
        <td style="padding:8px;font-size:11px;color:#555">${c.salespersonName || '<span style="color:#ccc">—</span>'}${c.region ? `<div style="font-size:9px;color:#999">📍 ${c.region}</div>` : ''}</td>
        <td style="padding:8px;font-size:11px">
            ${c.phone ? `<div style="direction:ltr;text-align:right">📞 ${c.phone}</div>` : ''}
            ${c.email ? `<div style="direction:ltr;text-align:right;color:#666">✉️ ${c.email}</div>` : ''}
            ${!c.phone && !c.email ? '<span style="color:#ccc">—</span>' : ''}
        </td>
        <td style="padding:8px;text-align:center;font-weight:800;color:${bal.balance > 0 ? '#2d6a9f' : bal.balance < 0 ? '#c0392b' : '#888'};font-size:13px">${fmt(Math.abs(bal.balance))}
            ${bal.balance !== 0 ? `<div style="font-size:9px;color:${bal.balance > 0 ? '#2d6a9f' : '#c0392b'};font-weight:700">${bal.balance > 0 ? 'مدين' : 'دائن'}</div>` : ''}
        </td>
        <td style="padding:8px;text-align:center;min-width:110px">${creditCell}</td>
        <td style="padding:8px;text-align:center">
            ${bal.overdue > 0 ? `<span style="background:#c0392b;color:white;padding:3px 8px;border-radius:6px;font-size:11px;font-weight:700">${fmt(bal.overdue)}</span>` : '<span style="color:#ccc">—</span>'}
        </td>
        <td style="padding:8px;text-align:center">
            <span style="background:${isActive ? '#27ae60' : '#888'};color:white;padding:3px 10px;border-radius:6px;font-size:11px;font-weight:700">${isActive ? '✅ نشط' : '⏸️ معطّل'}</span>
            <div style="margin-top:4px;display:flex;gap:3px;justify-content:center;flex-wrap:wrap">
                <span title="درجة المخاطر" style="background:${custRiskScore(key).color};color:#fff;padding:1px 7px;border-radius:5px;font-size:9px;font-weight:800">${custRiskScore(key).rating}</span>
                ${c.creditHold ? '<span title="موقوف ائتمانياً" style="background:#c0392b;color:#fff;padding:1px 6px;border-radius:5px;font-size:9px;font-weight:800">🔒</span>' : ''}
            </div>
        </td>
        <td style="padding:8px;text-align:center">
            <div style="display:flex;gap:3px;justify-content:center;flex-wrap:wrap">
                <button class="btn" onclick="openCustomer360('${key}')" style="background:#0e6251;color:white;padding:3px 8px;font-size:10px" title="بطاقة 360°">👁️</button>
                <button class="btn" onclick="viewCustomerStatement('${key}')" style="background:#16a085;color:white;padding:3px 8px;font-size:10px" title="كشف الحساب">📋</button>
                ${canManage ? `<button class="btn" onclick="editCustomer('${key}')" style="background:#2d6a9f;color:white;padding:3px 8px;font-size:10px" title="تعديل">✏️</button>` : ''}
                ${canManage ? `<button class="btn" onclick="deleteCustomer('${key}')" style="background:#c0392b;color:white;padding:3px 8px;font-size:10px" title="حذف">🗑️</button>` : ''}
            </div>
        </td>
    </tr>`;
}

window.filterCustTable = function (query) {
    query = (query || '').toLowerCase().trim();
    document.querySelectorAll('#custTableBody tr').forEach(row => {
        const txt = row.getAttribute('data-search') || '';
        row.style.display = (!query || txt.includes(query)) ? '' : 'none';
    });
};

// ── تقرير أعمار الديون ─────────────────
function renderCustAgingHtml(custArr) {
    const totals = { current: 0, d30: 0, d60: 0, d90: 0, d120: 0, over120: 0, total: 0 };
    const rows = custArr.map(([key, c]) => ({ key, c, ag: calcCustomerAging(key) })).filter(x => x.ag.total > 0.01).sort((a, b) => b.ag.total - a.ag.total);
    rows.forEach(x => { Object.keys(totals).forEach(k => totals[k] += x.ag[k]); });
    const cell = (v, color) => `<td style="padding:8px;text-align:left;direction:ltr;font-weight:700;color:${v > 0.01 ? (color || '#1a3a5c') : '#ccc'}">${v > 0.01 ? fmt(v) : '—'}</td>`;
    const body = rows.map((x, i) => `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
        <td style="padding:8px;font-weight:700"><span onclick="openCustomer360('${x.key}')" style="color:#0e6251;cursor:pointer;text-decoration:underline">${x.c.nameAr || x.c.code}</span></td>
        ${cell(x.ag.current, '#27ae60')}${cell(x.ag.d30, '#2d6a9f')}${cell(x.ag.d60, '#f39c12')}${cell(x.ag.d90, '#e67e22')}${cell(x.ag.d120, '#c0392b')}${cell(x.ag.over120, '#922b21')}
        <td style="padding:8px;text-align:left;direction:ltr;font-weight:900;color:#1a3a5c">${fmt(x.ag.total)}</td>
    </tr>`).join('');
    return `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
            <div style="font-size:15px;font-weight:900;color:#1a3a5c">📊 تحليل أعمار الديون <span style="font-size:11px;color:#888;font-weight:400">(حسب تاريخ الاستحقاق)</span></div>
            <div style="display:flex;gap:6px"><button class="btn" onclick="printCustAging()" style="background:#1a3a5c;color:#fff;padding:7px 14px;font-size:12px;font-weight:700">🖨️ طباعة</button><button class="btn" onclick="exportCustAging()" style="background:#16a085;color:#fff;padding:7px 14px;font-size:12px;font-weight:700">📊 Excel</button></div>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px;margin-bottom:14px">
            ${[['جاري', totals.current, '#27ae60'], ['1-30 يوم', totals.d30, '#2d6a9f'], ['31-60', totals.d60, '#f39c12'], ['61-90', totals.d90, '#e67e22'], ['91-120', totals.d120, '#c0392b'], ['+120', totals.over120, '#922b21']].map(([l, v, col]) => `<div style="background:${col}14;border-radius:10px;padding:10px;text-align:center;border-bottom:3px solid ${col}"><div style="font-size:10px;color:#666">${l}</div><div style="font-size:15px;font-weight:900;color:${col}">${fmt(v)}</div></div>`).join('')}
        </div>
        <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
            <thead style="background:#1a3a5c;color:#fff"><tr>
                <th style="padding:9px;text-align:right">العميل</th>
                <th style="padding:9px;text-align:left">جاري</th><th style="padding:9px;text-align:left">1-30</th><th style="padding:9px;text-align:left">31-60</th><th style="padding:9px;text-align:left">61-90</th><th style="padding:9px;text-align:left">91-120</th><th style="padding:9px;text-align:left">+120</th>
                <th style="padding:9px;text-align:left">الإجمالي</th>
            </tr></thead>
            <tbody>${body || '<tr><td colspan="8" style="text-align:center;padding:30px;color:#999">لا توجد ذمم مستحقة 🎉</td></tr>'}</tbody>
            ${rows.length ? `<tfoot><tr style="background:#f0f5fa;font-weight:900;color:#1a3a5c;border-top:2px solid #1a3a5c">
                <td style="padding:9px">الإجمالي (${rows.length} عميل)</td>
                ${[totals.current, totals.d30, totals.d60, totals.d90, totals.d120, totals.over120, totals.total].map(v => `<td style="padding:9px;text-align:left;direction:ltr">${fmt(v)}</td>`).join('')}
            </tr></tfoot>` : ''}
        </table></div>
    </div>`;
}
window.exportCustAging = function () {
    if (!window.XLSX) { toast('⚠️ مكتبة Excel غير محمّلة', 'er'); return; }
    const custArr = Object.entries(window.customers || {});
    const rows = custArr.map(([key, c]) => ({ key, c, ag: calcCustomerAging(key) })).filter(x => x.ag.total > 0.01).sort((a, b) => b.ag.total - a.ag.total)
        .map(x => ({ 'العميل': x.c.nameAr || x.c.code, 'جاري': x.ag.current, '1-30': x.ag.d30, '31-60': x.ag.d60, '61-90': x.ag.d90, '91-120': x.ag.d120, '+120': x.ag.over120, 'الإجمالي': x.ag.total }));
    if (!rows.length) { toast('⚠️ لا توجد ذمم', 'er'); return; }
    const ws = XLSX.utils.json_to_sheet(rows); const wb = XLSX.utils.book_new(); XLSX.utils.book_append_sheet(wb, ws, 'أعمار الديون');
    XLSX.writeFile(wb, 'aging_' + new Date().toISOString().slice(0, 10) + '.xlsx'); toast('📊 تم التصدير', 'ok');
};
window.printCustAging = function () {
    const custArr = Object.entries(window.customers || {});
    const rows = custArr.map(([key, c]) => ({ c, ag: calcCustomerAging(key) })).filter(x => x.ag.total > 0.01).sort((a, b) => b.ag.total - a.ag.total);
    const tot = { current: 0, d30: 0, d60: 0, d90: 0, d120: 0, over120: 0, total: 0 }; rows.forEach(x => Object.keys(tot).forEach(k => tot[k] += x.ag[k]));
    const co = custCoName();
    const tr = rows.map(x => `<tr><td style="text-align:right">${x.c.nameAr || x.c.code}</td><td>${fmt(x.ag.current)}</td><td>${fmt(x.ag.d30)}</td><td>${fmt(x.ag.d60)}</td><td>${fmt(x.ag.d90)}</td><td>${fmt(x.ag.d120)}</td><td>${fmt(x.ag.over120)}</td><td style="font-weight:900">${fmt(x.ag.total)}</td></tr>`).join('');
    const w = window.open('', '_blank');
    w.document.write(`<html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="utf-8"><title>أعمار الديون</title><style>body{font-family:'Tajawal',Tahoma,sans-serif;padding:24px;direction:rtl}h1{color:#1a3a5c}table{width:100%;border-collapse:collapse;font-size:12px;margin-top:12px}th,td{border:1px solid #ccc;padding:7px;text-align:left}th{background:#1a3a5c;color:#fff}td:first-child,th:first-child{text-align:right}tfoot td{background:#f0f5fa;font-weight:900}</style></head><body><h1>📊 تقرير أعمار الديون — ${co}</h1><div style="font-size:12px;color:#666">بتاريخ ${new Date().toLocaleDateString('ar-SA')}</div><table><thead><tr><th>العميل</th><th>جاري</th><th>1-30</th><th>31-60</th><th>61-90</th><th>91-120</th><th>+120</th><th>الإجمالي</th></tr></thead><tbody>${tr}</tbody><tfoot><tr><td>الإجمالي</td><td>${fmt(tot.current)}</td><td>${fmt(tot.d30)}</td><td>${fmt(tot.d60)}</td><td>${fmt(tot.d90)}</td><td>${fmt(tot.d120)}</td><td>${fmt(tot.over120)}</td><td>${fmt(tot.total)}</td></tr></tfoot></table><script>setTimeout(()=>print(),400)<\/script></body></html>`);
    w.document.close();
};

// ── التحليلات ─────────────────
function renderCustAnalyticsHtml(custArr) {
    const top = custArr.map(([key, c]) => ({ key, name: c.nameAr || c.code, sales: calcCustomerKpis(key).totalSales })).filter(x => x.sales > 0).sort((a, b) => b.sales - a.sales).slice(0, 10);
    window._custAnalytics = { top };
    return `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:14px">
        <div class="card" style="padding:14px"><div style="font-weight:800;color:#1a3a5c;margin-bottom:8px">🏆 أهم 10 عملاء (بالمبيعات)</div><canvas id="custChartTop" height="220"></canvas></div>
        <div class="card" style="padding:14px"><div style="font-weight:800;color:#1a3a5c;margin-bottom:8px">📈 اتجاه المبيعات (آخر 12 شهراً)</div><canvas id="custChartTrend" height="220"></canvas></div>
        <div class="card" style="padding:14px"><div style="font-weight:800;color:#1a3a5c;margin-bottom:8px">📊 توزيع أعمار الديون</div><canvas id="custChartAging" height="220"></canvas></div>
        <div class="card" style="padding:14px"><div style="font-weight:800;color:#1a3a5c;margin-bottom:8px">🗂️ العملاء حسب التصنيف</div><canvas id="custChartCat" height="220"></canvas></div>
    </div>`;
}
window._custCharts = window._custCharts || {};
function drawCustCharts() {
    if (!window.Chart) return;
    Object.values(window._custCharts).forEach(c => { try { c.destroy(); } catch (e) { } }); window._custCharts = {};
    const mk = (id, cfg) => { const el = document.getElementById(id); if (el) window._custCharts[id] = new Chart(el, cfg); };
    Chart.defaults.font.family = "'Segoe UI',Tahoma,sans-serif";
    const top = (window._custAnalytics || {}).top || [];
    mk('custChartTop', { type: 'bar', data: { labels: top.map(x => x.name), datasets: [{ data: top.map(x => x.sales), backgroundColor: '#16a085' }] }, options: { indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { beginAtZero: true } } } });
    // اتجاه المبيعات 12 شهر
    const months = []; const now = new Date();
    for (let i = 11; i >= 0; i--) { const d = new Date(now.getFullYear(), now.getMonth() - i, 1); months.push({ key: d.getFullYear() + '-' + String(d.getMonth() + 1).padStart(2, '0'), label: d.toLocaleDateString('ar-EG', { month: 'short', year: '2-digit' }), v: 0 }); }
    Object.values(window.salesInvoices || {}).forEach(inv => { if (inv.status !== 'posted' || !inv.date) return; const mk2 = (inv.date || '').slice(0, 7); const m = months.find(x => x.key === mk2); if (m) m.v += Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100; });
    mk('custChartTrend', { type: 'line', data: { labels: months.map(m => m.label), datasets: [{ data: months.map(m => m.v), borderColor: '#2d6a9f', backgroundColor: 'rgba(45,106,159,.15)', fill: true, tension: .35 }] }, options: { plugins: { legend: { display: false } }, scales: { y: { beginAtZero: true } } } });
    // توزيع الأعمار
    const agT = { current: 0, d30: 0, d60: 0, d90: 0, d120: 0, over120: 0 };
    Object.keys(window.customers || {}).forEach(k => { const a = calcCustomerAging(k); Object.keys(agT).forEach(b => agT[b] += a[b]); });
    mk('custChartAging', { type: 'doughnut', data: { labels: ['جاري', '1-30', '31-60', '61-90', '91-120', '+120'], datasets: [{ data: [agT.current, agT.d30, agT.d60, agT.d90, agT.d120, agT.over120], backgroundColor: ['#27ae60', '#2d6a9f', '#f39c12', '#e67e22', '#c0392b', '#922b21'] }] }, options: { plugins: { legend: { position: 'bottom', rtl: true, labels: { font: { size: 10 } } } } } });
    // حسب التصنيف
    const cats = {}; Object.values(window.customers || {}).forEach(c => { const k = c.category || 'بدون تصنيف'; cats[k] = (cats[k] || 0) + 1; });
    mk('custChartCat', { type: 'pie', data: { labels: Object.keys(cats), datasets: [{ data: Object.values(cats), backgroundColor: ['#0e6251', '#2d6a9f', '#8e44ad', '#f39c12', '#c0392b', '#16a085', '#7f8c8d'] }] }, options: { plugins: { legend: { position: 'bottom', rtl: true, labels: { font: { size: 10 } } } } } });
}

// اسم الشركة من الإعدادات (gbrCfg متاح دائماً على window، cfg قد لا يكون مرئياً هنا)
function custCoName() {
    const g = window.gbrCfg || {};
    return g.companyAr || g.companyEn || (typeof cfg !== 'undefined' && (cfg.companyAr || cfg.companyEn)) || 'بنيان للمقاولات';
}

// ── تصنيف المخاطر ─────────────────
function custRiskScore(key) {
    const bal = calcCustomerBalance(key), kp = calcCustomerKpis(key), cr = creditInfo(key);
    let score = 0;
    // نسبة المتأخرات من الرصيد
    if (bal.balance > 0.01) score += Math.min(40, (bal.overdue / bal.balance) * 40);
    // أيام التحصيل
    if (kp.dso != null) { if (kp.dso > 90) score += 30; else if (kp.dso > 60) score += 20; else if (kp.dso > 30) score += 10; }
    // استهلاك الائتمان
    if (cr.status === 'over') score += 30; else if (cr.status === 'warning') score += 15;
    score = Math.round(Math.min(100, score));
    let rating, color;
    if (score >= 70) { rating = 'D'; color = '#922b21'; }
    else if (score >= 50) { rating = 'C'; color = '#c0392b'; }
    else if (score >= 30) { rating = 'B'; color = '#f39c12'; }
    else if (score >= 12) { rating = 'A'; color = '#27ae60'; }
    else { rating = 'A+'; color = '#0e6251'; }
    return { score, rating, color };
}
// أقدم أيام تأخر للعميل
function custOldestOverdueDays(key) {
    const c = window.customers?.[key] || {}; const terms = c.paymentTerms || 0;
    const today = new Date(); today.setHours(0, 0, 0, 0); let oldest = 0;
    Object.values(window.salesInvoices || {}).forEach(inv => {
        if (inv.customerId !== key || inv.status !== 'posted') return;
        if (inv.fullyCredited) return;
        const rem = Math.round(((parseFloat(inv.grandTotal) || 0) - (parseFloat(inv.paidAmount) || 0) - (parseFloat(inv.creditedAmount) || 0)) * 100) / 100;
        if (rem <= 0.01) return;
        const due = custInvoiceDue(inv, terms); if (!due) return;
        const days = Math.floor((today.getTime() - new Date(due).getTime()) / 86400000);
        if (days > oldest) oldest = days;
    });
    return oldest;
}
function custDunning(days) {
    if (days <= 0) return { level: 0, label: '—', color: '#27ae60' };
    if (days <= 30) return { level: 1, label: 'تذكير ودّي', color: '#2d6a9f' };
    if (days <= 60) return { level: 2, label: 'مطالبة', color: '#f39c12' };
    if (days <= 90) return { level: 3, label: 'إنذار', color: '#e67e22' };
    return { level: 4, label: 'تصعيد', color: '#c0392b' };
}
// إيقاف ائتماني يدوي
window.toggleCreditHold = function (key) {
    const c = window.customers?.[key]; if (!c) return;
    const next = !c.creditHold;
    update(ref(db, 'ledger/customers/' + key), { creditHold: next }).then(() => { toast(next ? '🔒 تم الإيقاف الائتماني للعميل' : '🔓 أُلغي الإيقاف الائتماني', next ? 'wn' : 'ok'); cust360Refresh(); }).catch(e => toast('❌ ' + (e.message || e), 'er'));
};

// ── ورشة التحصيل (Collections) ─────────────────
function renderCustCollectionsHtml(custArr) {
    const rows = custArr.map(([key, c]) => ({ key, c, bal: calcCustomerBalance(key), days: custOldestOverdueDays(key), risk: custRiskScore(key) }))
        .filter(x => x.bal.overdue > 0.01).sort((a, b) => b.days - a.days || b.bal.overdue - a.bal.overdue);
    const totalOverdue = rows.reduce((s, x) => s + x.bal.overdue, 0);
    const body = rows.map((x, i) => {
        const d = custDunning(x.days); const p2p = x.c.promiseToPay;
        const p2pHtml = p2p && p2p.date ? `<div style="font-size:10px;color:#16a085">🤝 ${p2p.date}${p2p.amount ? ' · ' + fmt(p2p.amount) : ''}</div>` : '<span style="color:#ccc;font-size:11px">—</span>';
        return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
            <td style="padding:8px;font-weight:700"><span onclick="openCustomer360('${x.key}')" style="color:#0e6251;cursor:pointer;text-decoration:underline">${x.c.nameAr || x.c.code}</span>${x.c.phone ? `<div style="font-size:10px;color:#888;direction:ltr;text-align:right">📞 ${x.c.phone}</div>` : ''}</td>
            <td style="padding:8px;text-align:left;direction:ltr;font-weight:800;color:#c0392b">${fmt(x.bal.overdue)}</td>
            <td style="padding:8px;text-align:center;font-weight:700">${x.days} يوم</td>
            <td style="padding:8px;text-align:center"><span style="background:${d.color}18;color:${d.color};padding:2px 9px;border-radius:8px;font-size:10px;font-weight:800">${d.label}</span></td>
            <td style="padding:8px;text-align:center"><span style="background:${x.risk.color};color:#fff;padding:2px 8px;border-radius:6px;font-size:10px;font-weight:800">${x.risk.rating}</span></td>
            <td style="padding:8px;text-align:center">${p2pHtml}</td>
            <td style="padding:8px;text-align:center"><div style="display:flex;gap:3px;justify-content:center;flex-wrap:wrap">
                <button class="btn" onclick="custPromiseToPay('${x.key}')" style="background:#16a085;color:#fff;padding:3px 7px;font-size:10px" title="وعد بالسداد">🤝</button>
                <button class="btn" onclick="custCreateCollectionTask('${x.key}')" style="background:#5b2c6f;color:#fff;padding:3px 7px;font-size:10px" title="إنشاء مهمة/تذكير تحصيل">⏰</button>
                <button class="btn" onclick="custDunningMessage('${x.key}')" style="background:#25d366;color:#fff;padding:3px 7px;font-size:10px" title="رسالة مطالبة واتساب">📲</button>
                <button class="btn" onclick="openCustomer360('${x.key}')" style="background:#0e6251;color:#fff;padding:3px 7px;font-size:10px" title="بطاقة العميل">👁️</button>
            </div></td>
        </tr>`;
    }).join('');
    return `<div class="card">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
            <div style="font-size:15px;font-weight:900;color:#c0392b">📞 ورشة التحصيل <span style="font-size:12px;color:#888;font-weight:400">— ${rows.length} عميل متأخر · إجمالي ${fmt(totalOverdue)}</span></div>
            <button class="btn" onclick="printOverdueStatements()" style="background:#1a3a5c;color:#fff;padding:7px 14px;font-size:12px;font-weight:700">🖨️ كشوف المتأخرين</button>
        </div>
        <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:820px">
            <thead style="background:#922b21;color:#fff"><tr><th style="padding:9px;text-align:right">العميل</th><th style="padding:9px;text-align:left">المتأخرات</th><th style="padding:9px;text-align:center">أقدم تأخر</th><th style="padding:9px;text-align:center">المستوى</th><th style="padding:9px;text-align:center">المخاطر</th><th style="padding:9px;text-align:center">وعد سداد</th><th style="padding:9px;text-align:center">إجراءات</th></tr></thead>
            <tbody>${body || '<tr><td colspan="7" style="text-align:center;padding:30px;color:#27ae60">لا توجد متأخرات 🎉</td></tr>'}</tbody>
        </table></div>
    </div>`;
}
window.custPromiseToPay = function (key) {
    const c = window.customers?.[key]; if (!c) return;
    const date = prompt('📅 تاريخ الوعد بالسداد (YYYY-MM-DD):', (c.promiseToPay && c.promiseToPay.date) || new Date().toISOString().slice(0, 10));
    if (date === null) return;
    const amount = prompt('💵 المبلغ الموعود (اتركه فارغاً للكل):', (c.promiseToPay && c.promiseToPay.amount) || '');
    if (amount === null) return;
    const data = { date: date.trim(), amount: parseFloat(amount) || 0, at: Date.now(), byName: (window.myP && window.myP.name) || '' };
    update(ref(db, 'ledger/customers/' + key), { promiseToPay: data }).then(() => {
        push(ref(db, 'ledger/customers/' + key + '/activity'), { type: 'followup', text: `وعد بالسداد بتاريخ ${data.date}${data.amount ? ' بمبلغ ' + fmt(data.amount) : ''}`, byName: data.byName, at: Date.now() });
        toast('🤝 سُجّل الوعد بالسداد', 'ok'); renderCustomers();
    }).catch(e => toast('❌ ' + (e.message || e), 'er'));
};
window.custCreateCollectionTask = function (key) {
    const c = window.customers?.[key]; if (!c) return; if (!window.R || !window.R.tasks) { toast('⚠️ وحدة المهام غير متاحة', 'er'); return; }
    const bal = calcCustomerBalance(key); const days = custOldestOverdueDays(key); const dun = custDunning(days);
    const due = new Date(); due.setDate(due.getDate() + 1);
    const ds = due.getFullYear() + '-' + String(due.getMonth() + 1).padStart(2, '0') + '-' + String(due.getDate()).padStart(2, '0');
    const uid = (window.curU && window.curU.uid) || 'system'; const now = Date.now();
    push(R.tasks, {
        title: `تحصيل من ${c.nameAr} — ${fmt(bal.overdue)} (${dun.label})`,
        parent: '', priority: days > 90 ? 'urgent' : days > 60 ? 'high' : 'medium', status: 'open',
        notes: `متأخرات ${fmt(bal.overdue)} · أقدم تأخر ${days} يوم${c.phone ? ' · 📞 ' + c.phone : ''}`,
        dueDate: ds, dueTime: '10:00',
        linkType: 'customer', linkId: key, linkName: c.nameAr || c.code,
        tags: ['تحصيل'],
        reminder: { enabled: true, type: 'once', date: ds, time: '10:00', lead: 0, note: `تحصيل من ${c.nameAr}`, lastFiredAt: now, snoozeUntil: null },
        createdAt: now, createdBy: uid, updatedAt: now
    }).then(() => toast('⏰ أُنشئت مهمة تحصيل بتذكير في ' + ds, 'ok', 3500)).catch(e => toast('❌ ' + (e.message || e), 'er'));
};
window.custDunningMessage = function (key) {
    const c = window.customers?.[key]; if (!c) return;
    const bal = calcCustomerBalance(key); const days = custOldestOverdueDays(key); const dun = custDunning(days);
    const co = custCoName();
    let intro = 'نأمل التكرّم بسداد المبلغ المستحق';
    if (dun.level >= 4) intro = 'نفيدكم بأن المبلغ المستحق متأخر منذ فترة طويلة، ونطالب بسداده عاجلاً تفادياً للإجراءات';
    else if (dun.level === 3) intro = 'هذا إنذار بضرورة سداد المبلغ المستحق المتأخر';
    else if (dun.level === 2) intro = 'نذكّركم بالمبلغ المستحق المتأخر ونأمل سداده';
    const txt = `${co}\nالسادة / ${c.nameAr}\nتحية طيبة،\n${intro}.\nالمبلغ المتأخر: ${fmt(bal.overdue)} ر.س\nإجمالي الرصيد المستحق: ${fmt(bal.balance)} ر.س\nأقدم تأخر: ${days} يوم\nشاكرين تعاونكم.`;
    window.open('https://wa.me/' + (c.phone || '').replace(/[^\d]/g, '') + '?text=' + encodeURIComponent(txt), '_blank');
    push(ref(db, 'ledger/customers/' + key + '/activity'), { type: 'call', text: `أُرسلت رسالة مطالبة (${dun.label}) بمبلغ ${fmt(bal.overdue)}`, byName: (window.myP && window.myP.name) || '', at: Date.now() });
};

// كشوف المتأخرين (طباعة مجمّعة)
window.printOverdueStatements = function () {
    const custArr = Object.entries(window.customers || {});
    const rows = custArr.map(([key, c]) => ({ key, c, bal: calcCustomerBalance(key), ag: calcCustomerAging(key), days: custOldestOverdueDays(key) })).filter(x => x.bal.overdue > 0.01).sort((a, b) => b.bal.overdue - a.bal.overdue);
    if (!rows.length) { toast('✅ لا توجد متأخرات', 'ok'); return; }
    const co = custCoName();
    const total = rows.reduce((s, x) => s + x.bal.overdue, 0);
    const sec = rows.map(x => `<div style="page-break-inside:avoid;border:1px solid #ddd;border-radius:8px;padding:12px;margin-bottom:12px">
        <div style="display:flex;justify-content:space-between;border-bottom:2px solid #1a3a5c;padding-bottom:6px;margin-bottom:8px"><b style="color:#1a3a5c">${x.c.nameAr || x.c.code}</b><span style="color:#888">${x.c.phone || ''}</span></div>
        <div style="display:flex;gap:14px;flex-wrap:wrap;font-size:12px"><span>الرصيد: <b>${fmt(x.bal.balance)}</b></span><span style="color:#c0392b">المتأخر: <b>${fmt(x.bal.overdue)}</b></span><span>أقدم تأخر: <b>${x.days} يوم</b></span></div>
        <div style="font-size:11px;color:#555;margin-top:6px">أعمار: جاري ${fmt(x.ag.current)} · 1-30 ${fmt(x.ag.d30)} · 31-60 ${fmt(x.ag.d60)} · 61-90 ${fmt(x.ag.d90)} · +90 ${fmt(x.ag.d120 + x.ag.over120)}</div>
    </div>`).join('');
    const w = window.open('', '_blank');
    w.document.write(`<html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="utf-8"><title>كشوف المتأخرين</title><style>body{font-family:'Tajawal',Tahoma,sans-serif;padding:24px;direction:rtl;color:#1a3a5c}h1{font-size:20px}</style></head><body><h1>📞 كشوف العملاء المتأخرين — ${co}</h1><div style="font-size:12px;color:#666;margin-bottom:14px">بتاريخ ${new Date().toLocaleDateString('ar-SA')} · ${rows.length} عميل · إجمالي المتأخرات ${fmt(total)} ر.س</div>${sec}<script>setTimeout(()=>print(),500)<\/script></body></html>`);
    w.document.close();
};

// ── ويدجت الذمم في لوحة البداية ─────────────────
window.renderCustHomeWidget = function () {
    const el = document.getElementById('custHomeWidget'); if (!el) return;
    const custArr = Object.entries(window.customers || {});
    if (!custArr.length) { el.innerHTML = ''; return; }
    let totalRecv = 0, totalOverdue = 0;
    const rows = custArr.map(([key, c]) => { const b = calcCustomerBalance(key); totalRecv += b.balance; totalOverdue += b.overdue; return { key, name: c.nameAr || c.code, overdue: b.overdue, days: b.overdue > 0 ? custOldestOverdueDays(key) : 0 }; })
        .filter(x => x.overdue > 0.01).sort((a, b) => b.days - a.days).slice(0, 5);
    if (totalRecv <= 0.01 && !rows.length) { el.innerHTML = ''; return; }
    el.innerHTML = `<div style="background:linear-gradient(135deg,#f0faf7,#fff);border:1.5px solid #cdeee3;border-radius:14px;padding:16px 20px;box-shadow:0 4px 14px rgba(0,0,0,.05)">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:12px">
            <div style="display:flex;align-items:center;gap:10px"><div style="font-size:26px">💰</div><div><div style="font-size:15px;font-weight:800;color:#0e6251">ذمم العملاء</div><div style="font-size:12px;color:#666;margin-top:2px">إجمالي مستحق <b style="color:#2d6a9f">${fmt(totalRecv)}</b>${totalOverdue > 0.01 ? ` · <span style="color:#c0392b;font-weight:700">متأخر ${fmt(totalOverdue)}</span>` : ''}</div></div></div>
            <button class="btn" style="padding:7px 14px;font-size:12px;background:#0e6251;color:#fff" onclick="nav('customers',document.getElementById('n-customers'))">🧑‍💼 فتح العملاء</button>
        </div>
        ${rows.length ? `<div style="display:grid;gap:7px">${rows.map(x => `<div style="display:flex;align-items:center;gap:10px;padding:9px 12px;background:#fff;border-radius:9px;border-right:4px solid #c0392b;cursor:pointer" onclick="nav('customers',document.getElementById('n-customers'));setTimeout(()=>openCustomer360('${x.key}'),300)"><div style="flex:1;min-width:0"><div style="font-size:13px;font-weight:700;color:#1a3a5c">${(x.name || '').replace(/</g, '&lt;')}</div></div><div style="font-size:11px;color:#888">${x.days} يوم</div><div style="background:#fdedec;color:#c0392b;padding:4px 11px;border-radius:9px;font-size:11px;font-weight:800;white-space:nowrap">${fmt(x.overdue)}</div></div>`).join('')}</div>` : '<div style="font-size:12px;color:#27ae60;text-align:center;padding:8px">لا توجد متأخرات 🎉</div>'}
    </div>`;
};
(function custWidgetInit() {
    if (window._custWidgetInit) return;
    if (typeof window.nav !== 'function') { setTimeout(custWidgetInit, 800); return; }
    window._custWidgetInit = true;
    const _n = window.nav;
    window.nav = function (pg) { const r = _n.apply(this, arguments); if (pg === 'dashboard') setTimeout(() => { try { renderCustHomeWidget(); } catch (e) { } }, 80); return r; };
    setTimeout(() => { try { if (document.getElementById('pg-dashboard')?.classList.contains('act')) renderCustHomeWidget(); } catch (e) { } }, 1800);
})();

// ── دمج العملاء المكررين ─────────────────
function custNormName(s) { return (s || '').toString().trim().toLowerCase().replace(/\s+/g, ' ').replace(/[^؀-ۿ\w ]/g, ''); }
function custFindDuplicates() {
    const arr = Object.entries(window.customers || {});
    const groups = {};
    arr.forEach(([key, c]) => {
        const keys = [];
        if (c.nameAr) keys.push('n:' + custNormName(c.nameAr));
        if (c.phone) keys.push('p:' + (c.phone || '').replace(/[^\d]/g, ''));
        if (c.vatNumber) keys.push('v:' + c.vatNumber.trim());
        keys.forEach(k => { (groups[k] = groups[k] || []).push(key); });
    });
    const dupSets = []; const seen = new Set();
    Object.values(groups).forEach(keys => {
        const uniq = [...new Set(keys)]; if (uniq.length < 2) return;
        const sig = uniq.slice().sort().join(',');
        if (seen.has(sig)) return; seen.add(sig);
        dupSets.push(uniq);
    });
    return dupSets;
}
window.openCustMergeTool = function () {
    const canManage = (typeof myP !== 'undefined' && myP?.role === 'admin') || (typeof can === 'function' && can('manage_customers'));
    if (!canManage) { toast('🚫 صلاحية الدمج للمدير فقط', 'er'); return; }
    const dups = custFindDuplicates();
    document.getElementById('taskEditorOverlay')?.remove();
    const ov = document.createElement('div'); ov.id = 'taskEditorOverlay';
    ov.style = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9992;display:flex;align-items:flex-start;justify-content:center;overflow:auto;padding:24px';
    const body = dups.length ? dups.map((set, gi) => {
        const opts = set.map(k => { const c = window.customers[k]; return { k, c, bal: calcCustomerBalance(k) }; });
        return `<div class="card" style="padding:12px;margin-bottom:10px">
            <div style="font-weight:800;color:#c0392b;margin-bottom:8px">⚠️ مجموعة مكررة (${set.length})</div>
            ${opts.map(o => `<div style="display:flex;align-items:center;gap:8px;font-size:12px;padding:5px 0;border-bottom:1px dashed #eee">
                <input type="radio" name="primary${gi}" value="${o.k}" ${o === opts[0] ? 'checked' : ''} title="السجل الأساسي الذي يُحتفظ به">
                <span style="flex:1"><b>${(o.c.nameAr || o.c.code).replace(/</g, '&lt;')}</b> <span style="color:#888;font-family:monospace">${o.c.code || ''}</span>${o.c.phone ? ` · ${o.c.phone}` : ''} · رصيد ${fmt(o.bal.balance)}</span>
            </div>`).join('')}
            <button class="btn" onclick="custDoMerge(${gi})" data-keys="${set.join(',')}" style="background:#c0392b;color:#fff;padding:6px 14px;font-size:12px;font-weight:700;margin-top:8px">🔗 دمج في الأساسي المحدد</button>
        </div>`;
    }).join('') : '<div style="text-align:center;color:#27ae60;padding:30px">لا يوجد عملاء مكررون 🎉</div>';
    ov.innerHTML = `<div style="background:#f4f7f6;border-radius:14px;max-width:640px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,.3)">
        <div style="background:linear-gradient(135deg,#922b21,#c0392b);color:#fff;padding:14px 18px;border-radius:14px 14px 0 0;display:flex;justify-content:space-between;align-items:center"><div style="font-size:15px;font-weight:900">🔗 دمج العملاء المكررين</div><button onclick="tasksCloseEditor?tasksCloseEditor():document.getElementById('taskEditorOverlay').remove()" style="background:rgba(255,255,255,.2);border:none;color:#fff;width:28px;height:28px;border-radius:7px;cursor:pointer">✖</button></div>
        <div style="padding:16px;max-height:74vh;overflow:auto"><div style="font-size:12px;color:#666;margin-bottom:10px">يُكتشف التكرار بالاسم/الهاتف/الرقم الضريبي. تُنقل الفواتير وسندات القبض إلى السجل الأساسي ويُحذف الباقي.</div>${body}</div>
    </div>`;
    document.body.appendChild(ov);
};
window.custDoMerge = async function (gi) {
    const btn = document.querySelector(`button[onclick="custDoMerge(${gi})"]`); if (!btn) return;
    const set = (btn.getAttribute('data-keys') || '').split(',').filter(Boolean);
    const primary = (document.querySelector(`input[name="primary${gi}"]:checked`) || {}).value;
    if (!primary) { toast('⚠️ اختر السجل الأساسي', 'er'); return; }
    const others = set.filter(k => k !== primary);
    if (!others.length) return;
    if (!await cf2(`دمج ${others.length} سجل في «${window.customers[primary].nameAr}»؟ ستُنقل فواتيرهم وسنداتهم ثم تُحذف سجلاتهم. لا يمكن التراجع.`)) return;
    const upd = {};
    Object.entries(window.salesInvoices || {}).forEach(([ik, inv]) => { if (others.includes(inv.customerId)) upd['ledger/salesInvoices/' + ik + '/customerId'] = primary; });
    Object.entries(window.receipts || {}).forEach(([rk, r]) => { if (others.includes(r.partyId)) upd['ledger/receipts/' + rk + '/partyId'] = primary; });
    others.forEach(k => { upd['ledger/customers/' + k] = null; });
    try { await update(ref(db), upd); toast('✅ تم الدمج بنجاح', 'ok'); openCustMergeTool(); renderCustomers(); }
    catch (e) { toast('❌ خطأ في الدمج: ' + (e.message || e), 'er'); }
};

