window.saveInvoiceAsRecurring = function (key) {
    const inv = window.salesInvoices?.[key]; if (!inv) return; const c = window.customers?.[inv.customerId];
    const name = prompt('🔁 اسم القالب الدوري:', 'عقد ' + (c?.nameAr || ''));
    if (!name) return;
    const freq = prompt('التكرار: اكتب monthly (شهري) أو quarterly (ربع سنوي):', 'monthly');
    if (!freq) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    push(ref(db, 'ledger/recurringTemplates'), {
        name: name.trim(), customerId: inv.customerId || '', customerName: c?.nameAr || '', projectId: inv.projectId || '',
        subject: inv.subject || '', discount: inv.discount || 0, salesAccountCode: inv.salesAccountCode || '4100', salesAccountName: inv.salesAccountName || '',
        lines: (inv.lines || []).map(l => ({ ...l })), frequency: (freq.trim() === 'quarterly' ? 'quarterly' : 'monthly'), active: true,
        lastGenerated: '', createdAt: new Date().toISOString(), createdBy: userId
    }).then(() => toast('🔁 حُفظ القالب الدوري — ولّد منه فواتير من «الفواتير الدورية»', 'ok', 4000)).catch(e => toast('❌ ' + (e.message || e), 'er'));
};
window.openRecurringManager = function () {
    const tpls = window.recurringTemplates || {};
    document.getElementById('taskEditorOverlay')?.remove();
    const ov = document.createElement('div'); ov.id = 'taskEditorOverlay';
    ov.style = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:9992;display:flex;align-items:flex-start;justify-content:center;overflow:auto;padding:24px';
    const rows = Object.entries(tpls).length ? Object.entries(tpls).map(([id, t]) => `<div class="card" style="padding:12px;margin-bottom:8px;display:flex;align-items:center;gap:10px;flex-wrap:wrap">
        <div style="flex:1;min-width:160px"><div style="font-weight:800;color:#1a3a5c">${(t.name || '').replace(/</g, '&lt;')}</div><div style="font-size:11px;color:#888">${t.customerName || ''} · ${t.frequency === 'quarterly' ? 'ربع سنوي' : 'شهري'} · ${(t.lines || []).length} بند${t.lastGenerated ? ' · آخر توليد ' + t.lastGenerated : ''}</div></div>
        <button class="btn" onclick="generateFromRecurring('${id}')" style="background:#16a085;color:#fff;padding:6px 14px;font-size:12px;font-weight:700">🧾 توليد فاتورة الآن</button>
        <button class="btn" onclick="deleteRecurring('${id}')" style="background:#f0e0e0;color:#c0392b;padding:6px 10px;font-size:12px">🗑️</button>
    </div>`).join('') : '<div style="text-align:center;color:#999;padding:24px">لا توجد قوالب دورية بعد — أنشئ قالباً من أي فاتورة (زر 🔁 في النسخة)، أو من بطاقة الفاتورة.</div>';
    ov.innerHTML = `<div style="background:#f4f7f6;border-radius:14px;max-width:620px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,.3)">
        <div style="background:linear-gradient(135deg,#2d6a9f,#1f618d);color:#fff;padding:14px 18px;border-radius:14px 14px 0 0;display:flex;justify-content:space-between;align-items:center"><div style="font-size:15px;font-weight:900">🔁 الفواتير الدورية</div><button onclick="document.getElementById('taskEditorOverlay').remove()" style="background:rgba(255,255,255,.2);border:none;color:#fff;width:28px;height:28px;border-radius:7px;cursor:pointer">✖</button></div>
        <div style="padding:16px;max-height:74vh;overflow:auto"><div style="font-size:12px;color:#666;margin-bottom:10px">التوليد ينشئ فاتورة مسودة جاهزة للمراجعة والترحيل. <button class="btn" onclick="custScheduleMonthlyRecurring()" style="background:#5b2c6f;color:#fff;padding:5px 12px;font-size:11px;font-weight:700;margin-right:6px">🗓️ تذكير شهري بالتوليد</button></div>${rows}</div>
    </div>`;
    document.body.appendChild(ov);
};
