// ── حفظ المورد ─────────────────
window.saveVendor = async function () {
    const nameAr = $('mVendNameAr').value.trim();
    if (!nameAr) { toast('⚠️ اسم المورد بالعربية مطلوب', 'er'); return; }

    let code = $('mVendCode').value.trim();
    if (!code) code = generateVendorCode();

    const key = $('mVendKey').value;
    const duplicate = Object.entries(window.vendors || {}).find(([k, v]) => v.code === code && k !== key);
    if (duplicate) { toast('⚠️ رمز المورد مستخدم بالفعل', 'er'); return; }

    const vat = $('mVendVAT').value.trim();
    if (vat && vat.length !== 15) { toast('⚠️ الرقم الضريبي يجب أن يكون 15 خانة', 'er'); return; }

    // 🚚 مجموعة المورد (إجبارية في نمط المجموعات)
    const groupId = ($('mVendGroup') ? $('mVendGroup').value : '') || '';
    if (arApMode() === 'groups' && !groupId) { toast('⚠️ اختر مجموعة المورد (نمط المجموعات مُفعّل)', 'er'); return; }

    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();

    const data = {
        code,
        type: $('mVendType').value,
        groupId,
        groupAccount: supGroupAccount(groupId),
        nameAr,
        nameEn: $('mVendNameEn').value.trim(),
        contact: $('mVendContact').value.trim(),
        phone: $('mVendPhone').value.trim(),
        email: $('mVendEmail').value.trim(),
        iban: $('mVendIBAN').value.trim(),
        vatNumber: vat,
        crNumber: $('mVendCR').value.trim(),
        address: $('mVendAddress').value.trim(),
        openingBalance: parseFloat($('mVendOpeningBalance').value) || 0,
        paymentTerms: parseInt($('mVendPaymentTerms').value) || 30,
        creditLimit: parseFloat($('mVendCreditLimit').value) || 0,
        notes: $('mVendNotes').value.trim(),
        active: $('mVendActive').checked,
        updatedAt: now,
        updatedBy: userId
    };

    try {
        if (key) {
            await update(ref(db, 'ledger/vendors/' + key), data);
            toast('✅ تم تحديث المورد', 'ok');
        } else {
            data.createdAt = now;
            data.createdBy = userId;
            await push(R.vend, data);
            toast('✅ تم إضافة المورد', 'ok');
        }
        cov('mVendor');
    } catch (e) {
        console.error('Save vendor error:', e);
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── حذف المورد ─────────────────
// حركات المورد (فواتير مشتريات · سندات صرف · إشعارات مدينة)
function vendorMovementInfo(key) {
    const inv = Object.values(window.purchaseInvoices || {}).filter(x => x && x.vendorId === key).length;
    const pay = Object.values(window.payments || {}).filter(x => x && x.partyId === key).length;
    const dn = Object.values(window.debitNotes || {}).filter(x => x && x.vendorId === key).length;
    return { inv, pay, dn, total: inv + pay + dn };
}

window.deleteVendor = async function (key) {
    const v = window.vendors?.[key]; if (!v) return;

    // 🔒 لا يُحذف مورد له أي حركات
    const mv = vendorMovementInfo(key);
    if (mv.total > 0) {
        const parts = [];
        if (mv.inv) parts.push(`${mv.inv} فاتورة`);
        if (mv.pay) parts.push(`${mv.pay} سند صرف`);
        if (mv.dn) parts.push(`${mv.dn} إشعار مدين`);
        toast(`⚠️ لا يمكن حذف المورد «${v.nameAr}» — له حركات (${parts.join(' · ')}). عطّله بدلاً من الحذف.`, 'er', 8000);
        return;
    }

    if (!await cf2(`هل تريد حذف المورد "${v.nameAr}" نهائياً؟`)) return;
    try {
        await remove(ref(db, 'ledger/vendors/' + key));
        toast('✅ تم الحذف', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── كشف حساب المورد ─────────────────
window.viewVendorStatement = function (key) {
    const v = window.vendors?.[key]; if (!v) return;
    const bal = calcVendorBalance(key);
    const invoices = Object.entries(window.purchaseInvoices || {})
        .filter(([, inv]) => inv.vendorId === key)
        .sort((a, b) => (a[1].date || '').localeCompare(b[1].date || ''));

    const html = `<!DOCTYPE html><html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>كشف حساب - ${v.nameAr}</title>
    <style>
        * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        body { font-family: 'Tajawal', Tahoma, Arial; padding: 20px; color: #1a3a5c; direction: rtl; }
        h1 { text-align: center; border-bottom: 3px solid #8e44ad; padding-bottom: 10px; }
        .info { background: #f0f5fa; padding: 14px; border-radius: 8px; margin: 14px 0; display: grid; grid-template-columns: 1fr 1fr; gap: 10px; font-size: 12px; }
        .balance { background: #8e44ad; color: white; padding: 14px; border-radius: 8px; margin-bottom: 14px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; text-align: center; }
        .balance div { padding: 6px; }
        table { width: 100%; border-collapse: collapse; font-size: 11px; }
        th { background: #1a3a5c; color: white; padding: 8px; }
        td { padding: 7px; border: 1px solid #ddd; }
        @page { size: A4 landscape; margin: 1.5cm; }
    </style></head><body>
    <h1>📋 كشف حساب المورد — ${v.nameAr}</h1>
    <div class="info">
        <div><strong>🔢 رمز المورد:</strong> ${v.code}</div>
        <div><strong>📞 الهاتف:</strong> ${v.phone || '—'}</div>
        <div><strong>🆔 الرقم الضريبي:</strong> ${v.vatNumber || '—'}</div>
        <div><strong>📅 تاريخ الإصدار:</strong> ${new Date().toLocaleDateString('ar-SA')}</div>
    </div>
    <div class="balance">
        <div><div style="font-size:11px;opacity:.85">الرصيد الافتتاحي</div><div style="font-size:18px;font-weight:900;margin-top:4px">${fmt(bal.opening)}</div></div>
        <div><div style="font-size:11px;opacity:.85">إجمالي الفواتير</div><div style="font-size:18px;font-weight:900;margin-top:4px">${fmt(bal.invoiced)}</div></div>
        <div><div style="font-size:11px;opacity:.85">المسدد</div><div style="font-size:18px;font-weight:900;margin-top:4px">${fmt(bal.paid)}</div></div>
        <div><div style="font-size:11px;opacity:.85">الرصيد المستحق</div><div style="font-size:20px;font-weight:900;margin-top:4px">${fmt(bal.balance)}</div></div>
    </div>
    <table>
        <thead><tr>
            <th>التاريخ</th><th>رقم الفاتورة</th><th>رقم فاتورة المورد</th><th>الموضوع</th>
            <th>الإجمالي</th><th>المسدد</th><th>المتبقي</th><th>الحالة</th>
        </tr></thead>
        <tbody>
            ${invoices.length === 0 ? '<tr><td colspan="8" style="text-align:center;padding:30px;color:#888">لا توجد فواتير</td></tr>' :
            invoices.map(([k, inv]) => {
                const grand = parseFloat(inv.grandTotal) || 0;
                const paid = parseFloat(inv.paidAmount) || 0;
                const remaining = grand - paid;
                return `<tr>
                    <td>${inv.date || '-'}</td>
                    <td style="font-family:monospace;font-weight:700">${inv.number || '-'}</td>
                    <td style="font-family:monospace">${inv.vendorRef || '-'}</td>
                    <td>${inv.subject || '-'}</td>
                    <td style="text-align:left;font-weight:700">${fmt(grand)}</td>
                    <td style="text-align:left;color:#27ae60">${fmt(paid)}</td>
                    <td style="text-align:left;color:${remaining > 0 ? '#c0392b' : '#27ae60'};font-weight:700">${fmt(remaining)}</td>
                    <td style="text-align:center">${inv.status === 'posted' ? '✅ مرحّلة' : inv.status === 'draft' ? '📝 مسودة' : '❌ ملغاة'}</td>
                </tr>`;
            }).join('')}
        </tbody>
    </table>
    </body></html>`;

    const w = window.open('', '_blank');
    w.document.write(html);
    w.document.close();
    setTimeout(() => { try { w.print(); } catch (e) { } }, 500);
};

// ── تصدير Excel للموردين ─────────────────
window.exportVendorsExcel = function () {
    const vendors = Object.entries(window.vendors || {});
    if (!vendors.length) { toast('⚠️ لا يوجد موردون', 'er'); return; }

    const rows = vendors.map(([key, v]) => {
        const bal = calcVendorBalance(key);
        const typeLabels = { materials: 'مواد', services: 'خدمات', equipment: 'معدات', subcontractor: 'مقاولات', utilities: 'خدمات عامة', other: 'أخرى' };
        return {
            'الرمز': v.code || '',
            'النوع': typeLabels[v.type] || '',
            'الاسم بالعربية': v.nameAr || '',
            'الاسم بالإنجليزية': v.nameEn || '',
            'الشخص المسؤول': v.contact || '',
            'الهاتف': v.phone || '',
            'البريد': v.email || '',
            'IBAN': v.iban || '',
            'الرقم الضريبي': v.vatNumber || '',
            'السجل التجاري': v.crNumber || '',
            'العنوان': v.address || '',
            'الرصيد الافتتاحي': bal.opening,
            'إجمالي الفواتير': bal.invoiced,
            'المسدد': bal.paid,
            'الرصيد المستحق': bal.balance,
            'المتأخر': bal.overdue,
            'شروط السداد': v.paymentTerms || 30,
            'الحالة': v.active !== false ? 'نشط' : 'معطّل'
        };
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(18).fill({ wch: 14 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'الموردون');
        XLSX.writeFile(wb, `الموردون_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

