// ── استيراد الموردين من Excel ───────────────────────────────────────────────
window.importVendorsExcel = async function (file) {
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (e) => {
        try {
            const wb = XLSX.read(e.target.result, { type: 'array' });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { defval: '' });
            if (!rows.length) { toast('⚠️ الملف فارغ', 'er'); return; }

            const existingByCode = {};
            Object.entries(window.vendors || {}).forEach(([k, v]) => { if (v.code) existingByCode[v.code] = k; });
            const existingCodes = new Set(Object.keys(existingByCode));

            let added = 0, updated = 0, skipped = 0, errors = [];
            const typeMap = { 'مورد': 'supplier', 'مقاول': 'contractor', 'خدمات': 'service', 'حكومية': 'government', 'supplier': 'supplier', 'contractor': 'contractor', 'service': 'service' };

            for (const row of rows) {
                const nameAr = String(row['الاسم بالعربية *'] || row['الاسم بالعربية'] || '').trim();
                if (!nameAr) { skipped++; continue; }

                const rawCode = String(row['الرمز (اختياري)'] || row['الرمز'] || '').trim();
                const vatNum = String(row['الرقم الضريبي (15 خانة)'] || row['الرقم الضريبي'] || '').trim();
                if (vatNum && vatNum.length !== 15) { errors.push(`${nameAr}: الرقم الضريبي يجب أن يكون 15 خانة`); continue; }

                const statusRaw = String(row['الحالة (نشط / معطّل)'] || row['الحالة'] || 'نشط').trim();
                const typeRaw = String(row['النوع (مورد / مقاول / خدمات / حكومية)'] || row['النوع'] || 'مورد').trim();
                const now = new Date().toISOString();
                const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';

                let code = rawCode || generateVendorCode();
                while (!rawCode && existingCodes.has(code)) code = generateVendorCode();

                const data = {
                    code,
                    type: typeMap[typeRaw] || 'supplier',
                    nameAr,
                    nameEn: String(row['الاسم بالإنجليزية'] || '').trim(),
                    contact: String(row['الشخص المسؤول'] || '').trim(),
                    phone: String(row['الهاتف'] || '').trim(),
                    email: String(row['البريد الإلكتروني'] || row['البريد'] || '').trim(),
                    iban: String(row['رقم IBAN'] || '').trim(),
                    vatNumber: vatNum,
                    crNumber: String(row['السجل التجاري'] || '').trim(),
                    address: String(row['العنوان'] || '').trim(),
                    openingBalance: parseFloat(row['الرصيد الافتتاحي (رقم)'] || row['الرصيد الافتتاحي'] || 0) || 0,
                    paymentTerms: parseInt(row['شروط السداد (أيام)'] || row['شروط السداد'] || 30) || 30,
                    creditLimit: parseFloat(row['حد الائتمان (رقم)'] || row['حد الائتمان'] || 0) || 0,
                    notes: String(row['ملاحظات'] || '').trim(),
                    active: !['معطّل', 'inactive', 'false', '0'].includes(statusRaw.toLowerCase()),
                    updatedAt: now, updatedBy: userId
                };

                try {
                    const existingKey = existingByCode[rawCode];
                    if (rawCode && existingKey) {
                        await update(ref(db, 'ledger/vendors/' + existingKey), data);
                        updated++;
                    } else {
                        data.createdAt = now; data.createdBy = userId;
                        await push(R.vend, data);
                        existingCodes.add(code);
                        added++;
                    }
                } catch (err) { errors.push(`${nameAr}: ${err.message}`); }
            }

            let msg = `✅ مكتمل: مضاف ${added}، مُحدَّث ${updated}`;
            if (skipped) msg += `، مُتجاهَل ${skipped}`;
            if (errors.length) msg += `، أخطاء ${errors.length}`;
            toast(msg, errors.length ? 'wn' : 'ok', 6000);
        } catch (err) { toast('❌ خطأ في قراءة الملف: ' + err.message, 'er'); }
    };
    reader.readAsArrayBuffer(file);
};

console.log('✅ Vendors (Accounting) module loaded');


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📋  [ACC9]   ━━━━   PURCHASE INVOICES   ━━━━                             ║
// ║                فواتير المشتريات مع الربط التلقائي بالقيود                    ║
// ╚══════════════════════════════════════════════════════════════════════════╝

let pInvEditorState = { lines: [], editingPosted: false, originalInvoice: null };

// ── توليد رقم فاتورة مشتريات ─────────────────
function generatePInvNumber() {
    const invoices = Object.values(window.purchaseInvoices || {});
    const year = new Date().getFullYear();
    const yearPrefix = 'PINV-' + year + '-';
    const thisYear = invoices.filter(i => (i.number || '').startsWith(yearPrefix));
    const nums = thisYear.map(i => parseInt((i.number || '').split('-')[2]) || 0);
    const next = nums.length ? Math.max(...nums) + 1 : 1;
    return yearPrefix + String(next).padStart(5, '0');
}

// ── الحسابات الافتراضية لكل نوع مصروف (المشتريات تذهب لحسابات المشتريات 51xx) ─────
function getExpenseAccountForType(expenseType) {
    // ترجع رمز الحساب المناسب من شجرة الحسابات
    const mapping = {
        materials: '5110',      // مشتريات مواد (افتراضي للمواد)
        services: '5120',       // مشتريات خدمات
        equipment_rent: '5130', // مشتريات معدات (إيجار)
        subcontractor: '5140',  // مشتريات مقاولات من الباطن
        transport: '5220',      // تكلفة النقل (مشاريع مباشرة)
        utilities: '5330',      // كهرباء/مياه (إدارية)
        rent: '5320',          // إيجارات (إدارية)
        other: '5190'          // مشتريات أخرى
    };
    return mapping[expenseType] || '5190';
}

// ── جلب كل الحسابات المؤهلة لاستخدامها كحساب مدين في فاتورة مشتريات ─────────
function getEligibleExpenseAccounts() {
    const accounts = Object.values(window.chartOfAccounts || {})
        .filter(a => a.nature !== 'header' && a.active !== false)
        .filter(a => a.type === 'expense' || a.type === 'asset') // مصروفات أو أصول (للمخزون)
        .sort((a, b) => (a.code || '').localeCompare(b.code || ''));
    return accounts;
}

// ── دالة العرض الرئيسية لفواتير المشتريات ─────────────────
window.renderPurchaseInvoices = function () {
    const container = $('pg-purchaseinvoices'); if (!container) return;
    const invoices = window.purchaseInvoices || {};
    const invArr = Object.entries(invoices).sort((a, b) => (b[1].date || '').localeCompare(a[1].date || ''));

    const today = new Date().toISOString().slice(0, 10);
    const stats = { total: invArr.length, draft: 0, posted: 0, totalAmount: 0, totalPaid: 0, totalUnpaid: 0, overdue: 0 };
    invArr.forEach(([, inv]) => {
        if (inv.status === 'draft') stats.draft++;
        if (inv.status === 'posted') {
            stats.posted++;
            const grand = Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
            const paid  = Math.round((parseFloat(inv.paidAmount)  || 0) * 100) / 100;
            stats.totalAmount += grand;
            stats.totalPaid += paid;
            stats.totalUnpaid += Math.max(0, grand - paid);
            if (inv.dueDate && inv.dueDate < today && paid < grand - 0.01) stats.overdue++;
        }
    });

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const canCreate = isAdmin || canFn('create_purchase_invoice');

    container.innerHTML = `
        <!-- Hero -->
        <div style="background:linear-gradient(135deg,#b9770e 0%,#e67e22 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(230,126,34,.25)">
            <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:14px">
                <div>
                    <div style="font-size:11px;opacity:.85;letter-spacing:1px">PURCHASE INVOICES</div>
                    <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📋 فواتير المشتريات</h1>
                    <p style="margin:6px 0 0;font-size:12px;opacity:.95">إصدار وإدارة فواتير المشتريات — يُنشئ قيداً محاسبياً تلقائياً عند الترحيل</p>
                </div>
                <div style="display:flex;gap:10px;flex-wrap:wrap">
                    ${canCreate ? '<button class="btn" onclick="openPInvEditor()" style="background:white;color:#b9770e;padding:10px 18px;font-weight:800;font-size:14px">➕ فاتورة جديدة</button>' : ''}
                    ${canCreate ? '<button class="btn" onclick="openPInvOCR()" style="background:#8e44ad;color:white;padding:10px 18px;font-weight:800;font-size:14px" title="ارفع PDF أو صورة الفاتورة وسيقرأها النظام تلقائياً">📷 قراءة فاتورة (PDF/صورة)</button>' : ''}
                    <button class="btn" onclick="exportPInvExcel()" style="background:rgba(255,255,255,.2);color:white;padding:10px 18px;font-weight:700;backdrop-filter:blur(10px)">📤 Excel</button>
                </div>
            </div>
        </div>

        <!-- KPIs -->
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(180px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #1a3a5c">
                <div style="font-size:11px;color:#666">📊 إجمالي الفواتير</div>
                <div style="font-size:24px;font-weight:900;color:#1a3a5c">${stats.total}</div>
            </div>
            <div style="background:#e8f8f5;border-radius:12px;padding:12px;border-right:4px solid #27ae60">
                <div style="font-size:11px;color:#0e6655">✅ مرحّلة</div>
                <div style="font-size:24px;font-weight:900;color:#27ae60">${stats.posted}</div>
            </div>
            <div style="background:#fef9e7;border-radius:12px;padding:12px;border-right:4px solid #f39c12">
                <div style="font-size:11px;color:#7d4e00">📝 مسودات</div>
                <div style="font-size:24px;font-weight:900;color:#f39c12">${stats.draft}</div>
            </div>
            <div style="background:#fef5e7;border-radius:12px;padding:12px;border-right:4px solid #e67e22">
                <div style="font-size:11px;color:#7d4e00">💸 إجمالي المشتريات</div>
                <div style="font-size:18px;font-weight:900;color:#e67e22">${fmt(stats.totalAmount)}</div>
            </div>
            <div style="background:#fadbd8;border-radius:12px;padding:12px;border-right:4px solid #c0392b">
                <div style="font-size:11px;color:#641e16">⏳ غير مسدد</div>
                <div style="font-size:18px;font-weight:900;color:#c0392b">${fmt(stats.totalUnpaid)}</div>
                ${stats.overdue > 0 ? `<div style="font-size:10px;color:#c0392b;font-weight:700">${stats.overdue} فاتورة متأخرة</div>` : ''}
            </div>
        </div>

        ${!invArr.length ? `
        <div class="card" style="text-align:center;padding:60px 20px">
            <div style="font-size:80px;margin-bottom:16px">📋</div>
            <div style="font-size:18px;font-weight:800;color:#1a3a5c;margin-bottom:8px">لا توجد فواتير مشتريات بعد</div>
            <div style="font-size:13px;color:#666;margin-bottom:20px">ابدأ بتسجيل فواتير المشتريات للحصول على تقارير دقيقة</div>
            ${canCreate ? '<button class="btn b-g" onclick="openPInvEditor()" style="padding:12px 24px;font-size:14px">➕ فاتورة جديدة</button>' : ''}
        </div>
        ` : `
        <div class="card">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;flex-wrap:wrap;gap:8px">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c">📋 قائمة الفواتير (${invArr.length})</div>
                <input type="text" id="pinvSearch" placeholder="🔍 ابحث برقم، مورد، موضوع..." oninput="filterPInvTable(this.value)" style="padding:7px 12px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;min-width:280px">
            </div>
            <div style="overflow-x:auto">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:1200px">
                    <thead style="background:#1a3a5c;color:white">
                        <tr>
                            <th style="padding:10px;text-align:right">رقم الفاتورة</th>
                            <th style="padding:10px;text-align:right">رقم المورد</th>
                            <th style="padding:10px;text-align:right">التاريخ</th>
                            <th style="padding:10px;text-align:right">المورد</th>
                            <th style="padding:10px;text-align:right">الموضوع</th>
                            <th style="padding:10px;text-align:right">الاستحقاق</th>
                            <th style="padding:10px;text-align:center">الإجمالي</th>
                            <th style="padding:10px;text-align:center">المسدد</th>
                            <th style="padding:10px;text-align:center">الحالة</th>
                            <th style="padding:10px;text-align:center">⚙️</th>
                        </tr>
                    </thead>
                    <tbody id="pinvTableBody">
                        ${invArr.map(([key, inv], i) => renderPInvRow(key, inv, i)).join('')}
                    </tbody>
                </table>
            </div>
        </div>
        `}
    `;
};

function renderPInvRow(key, inv, idx) {
    const vendor = window.vendors?.[inv.vendorId];
    const today = new Date().toISOString().slice(0, 10);
    const grand = Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
    const paid  = Math.round((parseFloat(inv.paidAmount)  || 0) * 100) / 100;
    const isPaid = paid >= grand - 0.01;
    const isOverdue = inv.dueDate && inv.dueDate < today && !isPaid && inv.status === 'posted';

    const statusColors = {
        draft: { bg: '#f39c12', label: '📝 مسودة' },
        posted: { bg: isPaid ? '#27ae60' : isOverdue ? '#c0392b' : '#e67e22', label: isPaid ? '✅ مسددة' : isOverdue ? '⚠️ متأخرة' : '✅ مرحّلة' },
        cancelled: { bg: '#7f8c8d', label: '❌ ملغاة' }
    };
    const sc = statusColors[inv.status] || statusColors.draft;

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    const canEdit = inv.status === 'draft' && (isAdmin || canFn('create_purchase_invoice'));
    const canEditPosted = inv.status === 'posted' && (isAdmin || isFinanceMgr || canFn('edit_posted_purchase_invoice'));
    const canPost = inv.status === 'draft' && (isAdmin || canFn('post_purchase_invoice'));
    const canDelete = inv.status === 'draft' && (isAdmin || canFn('delete_purchase_invoice'));

    return `<tr style="${idx % 2 ? 'background:#fafbfc' : ''}" data-search="${(inv.number || '').toLowerCase()} ${(inv.vendorRef || '').toLowerCase()} ${(vendor?.nameAr || '').toLowerCase()} ${(inv.subject || '').toLowerCase()}">
        <td style="padding:8px;font-family:monospace;font-weight:800;color:#1a3a5c">${inv.number || '-'}</td>
        <td style="padding:8px;font-family:monospace;font-size:11px;color:#666">${inv.vendorRef || '—'}</td>
        <td style="padding:8px">${inv.date || '-'}</td>
        <td style="padding:8px">
            <div style="font-weight:700">${vendor?.nameAr || '—'}</div>
            ${vendor?.code ? `<div style="font-size:10px;color:#888;font-family:monospace">${vendor.code}</div>` : ''}
        </td>
        <td style="padding:8px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${inv.subject || ''}">${inv.subject || '—'}</td>
        <td style="padding:8px;color:${isOverdue ? '#c0392b' : '#666'};font-weight:${isOverdue ? '700' : 'normal'}">${inv.dueDate || '-'}</td>
        <td style="padding:8px;text-align:center;font-weight:800;color:#1a3a5c">${fmt(grand)}</td>
        <td style="padding:8px;text-align:center;color:${isPaid ? '#27ae60' : '#666'};font-weight:700">${fmt(paid)}</td>
        <td style="padding:8px;text-align:center">
            <span style="background:${sc.bg};color:white;padding:3px 10px;border-radius:6px;font-size:11px;font-weight:700">${sc.label}</span>
            ${inv.lastEditedAt && inv.status === 'posted' ? '<div style="margin-top:3px;font-size:9px;color:#8e44ad;font-weight:700">🔓 معدّلة</div>' : ''}
        </td>
        <td style="padding:8px;text-align:center">
            <div style="display:flex;gap:3px;justify-content:center;flex-wrap:wrap">
                <button class="btn" onclick="viewPInv('${key}')" style="background:#16a085;color:white;padding:3px 8px;font-size:10px" title="عرض/طباعة">👁️</button>
                ${canEdit ? `<button class="btn" onclick="editPInv('${key}')" style="background:#2d6a9f;color:white;padding:3px 8px;font-size:10px" title="تعديل">✏️</button>` : ''}
                ${canEditPosted ? `<button class="btn" onclick="editPostedPInv('${key}')" style="background:#8e44ad;color:white;padding:3px 8px;font-size:10px;border:1px solid #5b2c6f" title="تعديل فاتورة مرحّلة (المدير المالي)">🔓✏️</button>` : ''}
                ${canPost ? `<button class="btn" onclick="postPInv('${key}')" style="background:#27ae60;color:white;padding:3px 8px;font-size:10px" title="ترحيل">✅</button>` : ''}
                ${(inv.status === 'posted' && !inv.fullyDebited && (isAdmin || canFn('create_purchase_invoice'))) ? `<button class="btn" onclick="openDebitNote('${key}')" style="background:#1f618d;color:white;padding:3px 8px;font-size:10px" title="إشعار مدين / مرتجع مشتريات">↩️🧾</button>` : ''}
                ${inv.fullyDebited ? `<span style="background:#d6eaf8;color:#1f618d;padding:3px 7px;border-radius:5px;font-size:9px;font-weight:700" title="أُلغيت بإشعار مدين">↩️ مدين كامل</span>` : (inv.debitedAmount > 0 ? `<span style="background:#eaf2f8;color:#1f618d;padding:3px 7px;border-radius:5px;font-size:9px;font-weight:700" title="مرتجع جزئي ${fmt(inv.debitedAmount)}">↩️ جزئي</span>` : '')}
                ${canDelete ? `<button class="btn" onclick="deletePInv('${key}')" style="background:#c0392b;color:white;padding:3px 8px;font-size:10px" title="حذف">🗑️</button>` : ''}
            </div>
        </td>
    </tr>`;
}

window.filterPInvTable = function (query) {
    query = (query || '').toLowerCase().trim();
    document.querySelectorAll('#pinvTableBody tr').forEach(row => {
        const txt = row.getAttribute('data-search') || '';
        row.style.display = (!query || txt.includes(query)) ? '' : 'none';
    });
};

// ── فتح محرر فاتورة المشتريات ─────────────────
window.openPInvEditor = function () {
    pInvEditorState = { lines: [], editingPosted: false, originalInvoice: null };
    $('mPInvTitle').textContent = '📋 فاتورة مشتريات جديدة';
    $('mPInvKey').value = '';
    $('mPInvNumber').value = generatePInvNumber();
    const today = new Date().toISOString().slice(0, 10);
    $('mPInvDate').value = today;
    const due = new Date(); due.setDate(due.getDate() + 30);
    $('mPInvDueDate').value = due.toISOString().slice(0, 10);
    $('mPInvVendor').value = '';
    $('mPInvProject').value = '';
    $('mPInvVendorRef').value = '';
    $('mPInvSubject').value = '';
    $('mPInvExpenseType').value = 'materials';
    $('mPInvDiscount').value = 0;
    $('mPInvNotes').value = '';
    if ($('mPInvWarehouse')) fillWarehouseSelect($('mPInvWarehouse'));
    if ($('mPInvCostCenter')) $('mPInvCostCenter').innerHTML = window.ccOnlyOptions('', '-- بدون --');

    // إعادة تعيين أزرار الحفظ
    const savePosted = $('mPInvSavePosted');
    if (savePosted) {
        savePosted.innerHTML = '💾 حفظ وترحيل (يُنشئ قيد محاسبي)';
        savePosted.style.background = '';
        savePosted.setAttribute('onclick', "savePInv('posted')");
    }
    const draftBtn = document.querySelector('button[onclick="savePInv(\'draft\')"]');
    if (draftBtn) draftBtn.style.display = '';

    fillPInvVendors();
    fillPInvProjects();
    fillPInvDebitAccounts();  // 💼 ملء قائمة الحسابات
    // الافتراضي: حساب المشتريات للمواد (5110)
    onPInvExpenseTypeChange();
    populatePInvCurrency(baseCurrencyCode()); // 💱 العملة الافتراضية

    pInvEditorState.lines = [{ description: '', qty: 1, unit: '', unitPrice: 0, vatRate: 15, total: 0 }];
    renderPInvLines();

    ov('mPInvEditor');
    setTimeout(() => $('mPInvVendor').focus(), 100);
};

// ── ملء قائمة الحسابات المؤهلة كحساب مدين ─────────────────
function fillPInvDebitAccounts() {
    const sel = $('mPInvDebitAccount');
    if (!sel) return;
    const current = sel.value;
    sel.innerHTML = '<option value="">-- اختر الحساب --</option>';

    const accounts = getEligibleExpenseAccounts();
    // تجميع حسب النوع: مشتريات، أصول (مخزون)، مصروفات
    const groups = { purchases: [], inventory: [], expenses: [] };
    accounts.forEach(a => {
        if ((a.code || '').startsWith('51')) groups.purchases.push(a);
        else if (a.type === 'asset') groups.inventory.push(a);
        else groups.expenses.push(a);
    });

    const buildGroup = (label, arr) => {
        if (!arr.length) return '';
        return `<optgroup label="${label}">` +
            arr.map(a => `<option value="${a.code}">${a.code} — ${a.nameAr}</option>`).join('') +
            `</optgroup>`;
    };

    sel.innerHTML += buildGroup('🛒 المشتريات (51xx)', groups.purchases);
    sel.innerHTML += buildGroup('📦 المخزون (أصول)', groups.inventory);
    sel.innerHTML += buildGroup('💸 المصروفات الأخرى', groups.expenses);

    if (current) sel.value = current;
}

// ── تغيير الحساب الافتراضي عند تغيير نوع المصروف ─────────────────
window.onPInvExpenseTypeChange = function () {
    const type = $('mPInvExpenseType').value;
    const defaultCode = getExpenseAccountForType(type);
    const sel = $('mPInvDebitAccount');
    if (!sel) return;
    // اختر الحساب الافتراضي تلقائياً (إذا كان موجوداً في القائمة)
    const optionExists = Array.from(sel.options).some(o => o.value === defaultCode);
    if (optionExists) {
        sel.value = defaultCode;
    } else {
        // إذا لم يكن موجوداً، حاول أن تجد أقرب حساب مشتريات
        const fallback = Array.from(sel.options).find(o => o.value.startsWith('51'));
        if (fallback) sel.value = fallback.value;
    }
};

window.fillPInvVendors = function () {
    const sel = $('mPInvVendor');
    const current = sel.value;
    sel.innerHTML = '<option value="">-- اختر المورد --</option>';
    const vendors = Object.entries(window.vendors || {})
        .filter(([, v]) => v.active !== false)
        .sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || ''));
    vendors.forEach(([k, v]) => {
        sel.innerHTML += `<option value="${k}">${v.nameAr} (${v.code || ''})</option>`;
    });
    if (current) sel.value = current;
};

function fillPInvProjects() {
    const sel = $('mPInvProject');
    const current = sel.value;
    sel.innerHTML = '<option value="">-- بدون --</option>';
    if (window.projects) {
        Object.entries(window.projects).forEach(([k, p]) => {
            sel.innerHTML += `<option value="${k}">${p.name || k}</option>`;
        });
    }
    if (current) sel.value = current;
}

window.onPInvVendorChange = function () {
    const vendKey = $('mPInvVendor').value;
    if (!vendKey) return;
    const v = window.vendors?.[vendKey];
    if (!v) return;
    const terms = parseInt(v.paymentTerms) || 30;
    const date = new Date($('mPInvDate').value);
    date.setDate(date.getDate() + terms);
    $('mPInvDueDate').value = date.toISOString().slice(0, 10);
};

window.addPInvLine = function () {
    pInvEditorState.lines.push({ description: '', qty: 1, unit: '', unitPrice: 0, vatRate: 15, total: 0 });
    renderPInvLines();
};

window.removePInvLine = function (idx) {
    if (pInvEditorState.lines.length <= 1) {
        toast('⚠️ يجب أن يكون هناك بند واحد على الأقل', 'er');
        return;
    }
    pInvEditorState.lines.splice(idx, 1);
    renderPInvLines();
};

function renderPInvLines() {
    const tbody = $('mPInvLines'); if (!tbody) return;
    tbody.innerHTML = pInvEditorState.lines.map((line, i) => `
        <tr>
            <td style="padding:4px;text-align:center;font-weight:700;color:#888">${i + 1}</td>
            <td style="padding:4px">
                <div style="display:flex;gap:4px;align-items:center">
                    <button type="button" onclick="pinvOpenItemPicker(${i}, this)" class="ss-trigger" style="flex:1;min-width:0;background:#f8fafc;font-size:11px;padding:6px 8px;min-height:30px" title="ابحث واختر صنف">
                        <span class="ss-cap" style="${line.itemId ? 'color:#1a3a5c' : 'color:#888'}">${line.itemId ? sInvItemDisplay(line.itemId).replace(/</g, '&lt;') : '🔍 ابحث/اختر صنف (اختياري)...'}</span><span class="ss-arrow">▾</span>
                    </button>
                    <button onclick="openQuickInvItemEditor(${i}, 'pinv')" style="background:#27ae60;color:white;border:none;padding:6px 8px;border-radius:4px;cursor:pointer;font-size:11px;font-weight:700" title="إضافة صنف جديد">➕</button>
                </div>
                <input type="text" value="${line.description || ''}" onchange="updatePInvLineField(${i}, 'description', this.value)" placeholder="وصف المنتج/الخدمة..." style="width:100%;padding:6px;border:1px solid #d0d7e0;border-radius:4px;font-size:12px;margin-top:4px">
            </td>
            <td style="padding:4px">
                <input type="number" step="0.001" value="${line.qty || ''}" onchange="updatePInvLineField(${i}, 'qty', this.value)" style="width:100%;padding:6px;border:1px solid #d0d7e0;border-radius:4px;text-align:center;font-weight:700;font-size:12px">
            </td>
            <td style="padding:4px">
                <input type="text" value="${line.unit || ''}" onchange="updatePInvLineField(${i}, 'unit', this.value)" placeholder="قطعة" style="width:100%;padding:6px;border:1px solid #d0d7e0;border-radius:4px;text-align:center;font-size:11px">
            </td>
            <td style="padding:4px">
                <input type="number" step="0.01" value="${line.unitPrice || ''}" onchange="updatePInvLineField(${i}, 'unitPrice', this.value)" placeholder="0.00" style="width:100%;padding:6px;border:1px solid #e67e22;border-radius:4px;text-align:left;direction:ltr;font-weight:700;color:#e67e22;font-size:12px">
            </td>
            <td style="padding:4px">
                <select onchange="updatePInvLineField(${i}, 'vatRate', this.value)" style="width:100%;padding:6px;border:1px solid #d0d7e0;border-radius:4px;font-size:11px;text-align:center">
                    <option value="15" ${line.vatRate == 15 ? 'selected' : ''}>15%</option>
                    <option value="0" ${line.vatRate == 0 ? 'selected' : ''}>0%</option>
                    <option value="5" ${line.vatRate == 5 ? 'selected' : ''}>5%</option>
                </select>
            </td>
            <td style="padding:4px;background:#fef5e7;text-align:center;font-weight:900;color:#e67e22;font-size:13px">${fmt(line.total || 0)}</td>
            <td style="padding:4px;text-align:center">
                <button onclick="removePInvLine(${i})" style="background:#c0392b;color:white;border:none;padding:5px 7px;border-radius:4px;cursor:pointer;font-size:11px" title="حذف">🗑️</button>
            </td>
        </tr>
    `).join('');
    updatePInvTotals();
}

// ── بناء خيارات الأصناف (مواد + خدمات) ─────────────────
window.buildInvItemsOptions = function (selectedKey, filter) {
    const items = Object.entries(window.inventoryItems || {})
        .filter(([, it]) => it.active !== false)
        .filter(([, it]) => filter === 'all' || (filter === 'material' && it.type !== 'service') || (filter === 'service' && it.type === 'service'))
        .sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || ''));

    // تجميع حسب النوع
    const materials = items.filter(([, it]) => it.type !== 'service');
    const services = items.filter(([, it]) => it.type === 'service');

    let html = '';
    if (materials.length) {
        html += '<optgroup label="🏗️ المواد">';
        html += materials.map(([k, it]) => `<option value="${k}" ${k === selectedKey ? 'selected' : ''}>${it.nameAr} (${it.code || ''})</option>`).join('');
        html += '</optgroup>';
    }
    if (services.length) {
        html += '<optgroup label="🔧 الخدمات">';
        html += services.map(([k, it]) => `<option value="${k}" ${k === selectedKey ? 'selected' : ''}>${it.nameAr} (${it.code || ''})</option>`).join('');
        html += '</optgroup>';
    }
    return html;
};

// ── عند اختيار صنف لبند فاتورة مشتريات: املأ التفاصيل تلقائياً ─────────────────
window.onPInvLineItemChange = function (idx, itemKey) {
    const line = pInvEditorState.lines[idx];
    if (!line) return;
    line.itemId = itemKey || '';
    if (itemKey) {
        const item = window.inventoryItems?.[itemKey];
        if (item) {
            line.description = item.nameAr || '';
            line.unit = INV_UNITS[item.unit] || item.unit || '';
            // إذا لم يكن السعر معبأ، استخدم سعر التكلفة
            if (!line.unitPrice || line.unitPrice == 0) {
                line.unitPrice = parseFloat(item.costPrice) || 0;
            }
            if (!line.vatRate && line.vatRate !== 0) {
                line.vatRate = parseFloat(item.vatRate) || 15;
            }
            line.total = (parseFloat(line.qty) || 0) * (parseFloat(line.unitPrice) || 0);
        }
    }
    renderPInvLines();
};

window.updatePInvLineField = function (idx, field, value) {
    const line = pInvEditorState.lines[idx];
    if (!line) return;
    line[field] = ['qty', 'unitPrice', 'vatRate'].includes(field) ? (parseFloat(value) || 0) : value;
    line.total = (parseFloat(line.qty) || 0) * (parseFloat(line.unitPrice) || 0);
    renderPInvLines();
};

window.updatePInvTotals = function () {
    const subTotal = pInvEditorState.lines.reduce((s, l) => s + (parseFloat(l.total) || 0), 0);
    const discount = parseFloat($('mPInvDiscount').value) || 0;
    const netBeforeTax = subTotal - discount;

    let vatTotal = 0;
    if (subTotal > 0) {
        const discountRatio = discount / subTotal;
        pInvEditorState.lines.forEach(l => {
            const lineNet = (l.total || 0) * (1 - discountRatio);
            vatTotal += lineNet * ((l.vatRate || 0) / 100);
        });
    }

    const grandTotal = netBeforeTax + vatTotal;

    $('mPInvSubTotal').textContent = fmt(subTotal);
    $('mPInvNetBeforeTax').textContent = fmt(netBeforeTax);
    $('mPInvVATTotal').textContent = fmt(vatTotal);
    $('mPInvGrandTotal').textContent = fmt(grandTotal);

    // 💱 المعادل بالعملة الدفترية
    const code = $('mPInvCurrency')?.value || baseCurrencyCode();
    const rate = parseFloat($('mPInvRate')?.value) || 1;
    const equiv = $('mPInvBaseEquiv');
    if (equiv) {
        equiv.innerHTML = (code !== baseCurrencyCode())
            ? `= <strong>${fmt(grandTotal * rate)} ${(currencyList()[baseCurrencyCode()] || {}).symbol || ''}</strong> بالعملة الدفترية (القيد يُرحَّل بهذه القيمة)`
            : '';
    }

    if (grandTotal > 0 && typeof numberToArabicWords === 'function') {
        $('mPInvWords').innerHTML = '📝 <strong>التفقيط:</strong> ' + numberToArabicWords(grandTotal);
    } else {
        $('mPInvWords').textContent = '';
    }
};

// 💱 تعبئة قائمة عملات فاتورة المشتريات
function populatePInvCurrency(selected) {
    const sel = $('mPInvCurrency'); if (!sel) return;
    const list = currencyList();
    sel.innerHTML = Object.entries(list).map(([code, c]) => `<option value="${code}" ${selected === code ? 'selected' : ''}>${c.nameAr} (${code})${c.isBase ? ' — دفترية' : ''}</option>`).join('');
    if (selected) sel.value = selected;
    onPInvCurrencyChange();
}
window.populatePInvCurrency = populatePInvCurrency;
window.onPInvCurrencyChange = function () {
    const code = $('mPInvCurrency')?.value || baseCurrencyCode();
    if ($('mPInvRate')) {
        $('mPInvRate').value = getCurrencyRate(code);
        $('mPInvRate').readOnly = (code === baseCurrencyCode());
    }
    updatePInvTotals();
};

// ── تعديل فاتورة (مسودة) ─────────────────
window.editPInv = function (key) {
    const inv = window.purchaseInvoices?.[key]; if (!inv) return;
    if (inv.status !== 'draft') { toast('⚠️ لا يمكن تعديل فاتورة مرحّلة (استخدم 🔓✏️ للمدير المالي)', 'er'); return; }

    openPInvEditor();
    setTimeout(() => {
        $('mPInvTitle').textContent = '✏️ تعديل الفاتورة: ' + (inv.number || '');
        $('mPInvKey').value = key;
        $('mPInvNumber').value = inv.number || '';
        $('mPInvDate').value = inv.date || '';
        $('mPInvDueDate').value = inv.dueDate || '';
        $('mPInvVendor').value = inv.vendorId || '';
        $('mPInvProject').value = inv.projectId || '';
        $('mPInvVendorRef').value = inv.vendorRef || '';
        $('mPInvSubject').value = inv.subject || '';
        if ($('mPInvWarehouse')) $('mPInvWarehouse').value = inv.warehouseId || mainWarehouseId();
        if ($('mPInvCostCenter')) $('mPInvCostCenter').innerHTML = window.ccOnlyOptions(inv.costCenter || '', '-- بدون --');
        $('mPInvExpenseType').value = inv.expenseType || 'materials';
        // 💼 استعد الحساب المحفوظ (أو استخدم الافتراضي إذا غير موجود)
        onPInvExpenseTypeChange();
        if (inv.debitAccountCode) {
            const opt = Array.from($('mPInvDebitAccount').options).find(o => o.value === inv.debitAccountCode);
            if (opt) $('mPInvDebitAccount').value = inv.debitAccountCode;
        }
        $('mPInvDiscount').value = inv.discount || 0;
        $('mPInvNotes').value = inv.notes || '';
        populatePInvCurrency(inv.currency || baseCurrencyCode());
        if ($('mPInvRate')) $('mPInvRate').value = inv.exchangeRate || getCurrencyRate(inv.currency || baseCurrencyCode());
        pInvEditorState.lines = (inv.lines || []).map(l => ({ ...l }));
        if (!pInvEditorState.lines.length) pInvEditorState.lines = [{ description: '', qty: 1, unit: '', unitPrice: 0, vatRate: 15, total: 0 }];
        renderPInvLines();
    }, 100);
};

// ── 🔓✏️ تعديل فاتورة مرحّلة (للمدير المالي) ─────────────────
window.editPostedPInv = async function (key) {
    const inv = window.purchaseInvoices?.[key]; if (!inv) return;
    if (inv.status !== 'posted') { toast('⚠️ هذه الميزة للفواتير المرحّلة فقط', 'er'); return; }

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    if (!isAdmin && !isFinanceMgr && !canFn('edit_posted_purchase_invoice')) {
        toast('🚫 هذه الميزة مخصصة للمدير المالي ومدير النظام فقط', 'er');
        return;
    }

    const vendor = window.vendors?.[inv.vendorId];
    const warningMsg = `⚠️ تنبيه هام\n\nأنت على وشك تعديل فاتورة مشتريات مرحّلة.\n\nرقم الفاتورة: ${inv.number}\nالمورد: ${vendor?.nameAr || ''}\nالإجمالي: ${fmt(inv.grandTotal)} ر\n\nهذه العملية:\n• تُسجَّل بسجل تدقيق دائم\n• يُعاد إنشاء القيد المحاسبي بالقيم الجديدة\n• تؤثر على رصيد المورد ودفتر الأستاذ\n\nهل تريد المتابعة؟`;
    if (!await cf2(warningMsg)) return;

    openPInvEditor();
    setTimeout(() => {
        $('mPInvTitle').innerHTML = `🔓✏️ <span style="color:#8e44ad">تعديل فاتورة مرحّلة</span> — ${inv.number}`;
        $('mPInvKey').value = key;
        $('mPInvNumber').value = inv.number || '';
        $('mPInvDate').value = inv.date || '';
        $('mPInvDueDate').value = inv.dueDate || '';
        $('mPInvVendor').value = inv.vendorId || '';
        $('mPInvProject').value = inv.projectId || '';
        $('mPInvVendorRef').value = inv.vendorRef || '';
        $('mPInvSubject').value = inv.subject || '';
        if ($('mPInvWarehouse')) $('mPInvWarehouse').value = inv.warehouseId || mainWarehouseId();
        if ($('mPInvCostCenter')) $('mPInvCostCenter').innerHTML = window.ccOnlyOptions(inv.costCenter || '', '-- بدون --');
        $('mPInvExpenseType').value = inv.expenseType || 'materials';
        // 💼 استعد الحساب المحفوظ
        onPInvExpenseTypeChange();
        if (inv.debitAccountCode) {
            const opt = Array.from($('mPInvDebitAccount').options).find(o => o.value === inv.debitAccountCode);
            if (opt) $('mPInvDebitAccount').value = inv.debitAccountCode;
        }
        $('mPInvDiscount').value = inv.discount || 0;
        $('mPInvNotes').value = inv.notes || '';
        populatePInvCurrency(inv.currency || baseCurrencyCode());
        if ($('mPInvRate')) $('mPInvRate').value = inv.exchangeRate || getCurrencyRate(inv.currency || baseCurrencyCode());
        pInvEditorState.lines = (inv.lines || []).map(l => ({ ...l }));
        if (!pInvEditorState.lines.length) pInvEditorState.lines = [{ description: '', qty: 1, unit: '', unitPrice: 0, vatRate: 15, total: 0 }];

        pInvEditorState.editingPosted = true;
        pInvEditorState.originalInvoice = JSON.parse(JSON.stringify(inv));

        renderPInvLines();

        const savePosted = $('mPInvSavePosted');
        if (savePosted) {
            savePosted.innerHTML = '🔓 حفظ التعديل (يبقى مرحّلاً)';
            savePosted.style.background = '#8e44ad';
            savePosted.setAttribute('onclick', "savePInv('posted')");
        }
        const draftBtn = document.querySelector('button[onclick="savePInv(\'draft\')"]');
        if (draftBtn) draftBtn.style.display = 'none';
    }, 100);

    toast('🔓 وضع تعديل فاتورة مرحّلة — سيُعاد إنشاء القيد المحاسبي', 'wn', 6000);
};

// ── حفظ فاتورة المشتريات ─────────────────
// 🆕 مطابقة بنود الفاتورة بكتالوج الأصناف، وإنشاء الأصناف الجديدة تلقائياً (صامت) — للمواد فقط
async function pinvEnsureItemsForLines(lines, expenseType) {
    if (!['materials', 'goods', 'inventory'].includes(expenseType)) return; // غير المواد لا تدخل المخزون
    if (!window.R || !window.push || !R.items) return;
    const items = window.inventoryItems || {};
    const norm = s => (typeof vatRecNormStr === 'function') ? vatRecNormStr(s) : String(s || '').trim().toLowerCase();
    let created = 0;
    for (const line of lines) {
        if (line.itemId) continue;
        const code = (line.code || '').trim();
        const desc = (line.description || '').trim();
        let matchKey = '';
        // 1) مطابقة بالرمز
        if (code) { const f = Object.entries(items).find(([, it]) => it.code && String(it.code) === code); if (f) matchKey = f[0]; }
        // 2) مطابقة بالاسم (مطابق تماماً أو تشابه عالٍ)
        if (!matchKey && desc) {
            const dn = norm(desc); let best = 0;
            Object.entries(items).forEach(([k, it]) => {
                const nm = it.nameAr || it.nameEn || ''; if (!nm) return;
                if (norm(nm) === dn) { matchKey = k; best = 1; return; }
                const s = (typeof vatRecNameSim === 'function') ? vatRecNameSim(desc, nm) : 0;
                if (s > best && s >= 0.7) { best = s; matchKey = k; }
            });
        }
        if (matchKey) { line.itemId = matchKey; continue; }
        if (!desc) continue; // بلا اسم — يبقى نصاً حراً
        // 3) إنشاء صنف جديد صامت
        let newCode = code;
        if (!newCode || Object.values(items).some(it => String(it.code) === newCode)) {
            newCode = (typeof generateInvItemCode === 'function') ? generateInvItemCode('material') : ('AUTO-' + Date.now());
        }
        const now = new Date().toISOString();
        const uid = (typeof curU !== 'undefined' && curU && curU.uid) ? curU.uid : 'system';
        const data = {
            code: newCode, type: 'material', category: '', nameAr: desc, nameEn: '', description: '',
            unit: line.unit || '', openingQty: 0, minQty: 0, barcode: '', reservedQty: 0,
            costPrice: parseFloat(line.unitPrice) || 0, salePrice: 0, vatRate: parseFloat(line.vatRate) || 15,
            purchaseAccountCode: '', revenueAccountCode: '', notes: 'أُنشئ تلقائياً من فاتورة مشتريات',
            active: true, autoCreated: true, createdAt: now, createdBy: uid, updatedAt: now, updatedBy: uid
        };
        try { const r = await push(R.items, data); line.itemId = r.key; items[r.key] = data; created++; }
        catch (e) { console.error('auto-create item error:', e); }
    }
    if (created > 0) toast(`🆕 تم إنشاء ${created} صنف جديد في كتالوج الأصناف تلقائياً وربطه بالمخزون`, 'ok', 6000);
}

window.savePInv = async function (status) {
    const vendorId = $('mPInvVendor').value;
    if (!vendorId) { toast('⚠️ يجب اختيار مورد', 'er'); return; }

    const vendorRef = $('mPInvVendorRef').value.trim();
    if (!vendorRef) { toast('⚠️ رقم فاتورة المورد مطلوب', 'er'); return; }

    const validLines = pInvEditorState.lines.filter(l => l.description && (parseFloat(l.qty) || 0) > 0 && (parseFloat(l.unitPrice) || 0) > 0);
    if (!validLines.length) { toast('⚠️ يجب إضافة بند واحد على الأقل', 'er'); return; }

    // 🆕 مطابقة/إنشاء صامت للأصناف الجديدة (للمواد فقط) — لربطها بالمخزون
    await pinvEnsureItemsForLines(validLines, $('mPInvExpenseType').value);

    const subTotal = validLines.reduce((s, l) => s + ((l.qty || 0) * (l.unitPrice || 0)), 0);
    const discount = parseFloat($('mPInvDiscount').value) || 0;
    const netBeforeTax = subTotal - discount;
    let vatTotal = 0;
    if (subTotal > 0) {
        const discountRatio = discount / subTotal;
        validLines.forEach(l => {
            const lineNet = (l.qty || 0) * (l.unitPrice || 0) * (1 - discountRatio);
            vatTotal += lineNet * ((l.vatRate || 0) / 100);
        });
    }
    const grandTotal = netBeforeTax + vatTotal;

    const key = $('mPInvKey').value;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();

    const data = {
        number: $('mPInvNumber').value,
        vendorRef,
        date: $('mPInvDate').value,
        dueDate: $('mPInvDueDate').value,
        vendorId,
        projectId: $('mPInvProject').value,
        costCenter: $('mPInvCostCenter')?.value || '',
        warehouseId: $('mPInvWarehouse')?.value || mainWarehouseId(),
        expenseType: $('mPInvExpenseType').value,
        debitAccountCode: $('mPInvDebitAccount').value || getExpenseAccountForType($('mPInvExpenseType').value),  // 💼 الحساب المدين المختار
        subject: $('mPInvSubject').value.trim(),
        lines: validLines.map(l => ({
            itemId: l.itemId || '',
            description: l.description,
            qty: parseFloat(l.qty) || 0,
            unit: l.unit || '',
            unitPrice: parseFloat(l.unitPrice) || 0,
            vatRate: parseFloat(l.vatRate) || 0,
            total: (parseFloat(l.qty) || 0) * (parseFloat(l.unitPrice) || 0)
        })),
        subTotal,
        discount,
        netBeforeTax,
        vatTotal,
        grandTotal,
        currency: $('mPInvCurrency')?.value || baseCurrencyCode(),
        exchangeRate: parseFloat($('mPInvRate')?.value) || 1,
        grandTotalBase: grandTotal * (parseFloat($('mPInvRate')?.value) || 1),
        paidAmount: 0,
        notes: $('mPInvNotes').value.trim(),
        status,
        updatedAt: now,
        updatedBy: userId
    };

    try {
        // 🔓 حالة خاصة: تعديل فاتورة مرحّلة
        if (pInvEditorState.editingPosted && key) {
            const original = pInvEditorState.originalInvoice || {};
            const auditEntry = {
                editedAt: now,
                editedBy: userId,
                editorName: (typeof myP !== 'undefined' && myP?.name) || userId,
                originalSnapshot: {
                    subject: original.subject,
                    date: original.date,
                    dueDate: original.dueDate,
                    vendorId: original.vendorId,
                    vendorRef: original.vendorRef,
                    lines: original.lines,
                    subTotal: original.subTotal,
                    discount: original.discount,
                    netBeforeTax: original.netBeforeTax,
                    vatTotal: original.vatTotal,
                    grandTotal: original.grandTotal,
                    oldJournalEntryKey: original.journalEntryKey,
                    oldJournalEntryNumber: original.journalEntryNumber
                }
            };
            const existingAudit = (typeof window.purchaseInvoices?.[key]?.auditLog === 'object' && window.purchaseInvoices[key].auditLog) || {};
            const auditKey = 'edit_' + Date.now();

            const updateData = { ...data, status: 'posted' };
            updateData.paidAmount = parseFloat(original.paidAmount) || 0;
            updateData.lastEditedAt = now;
            updateData.lastEditedBy = userId;
            updateData.auditLog = { ...existingAudit, [auditKey]: auditEntry };

            // إلغاء القيد القديم
            if (original.journalEntryKey) {
                try {
                    await update(ref(db, 'ledger/journalEntries/' + original.journalEntryKey), {
                        status: 'cancelled',
                        cancelledAt: now,
                        cancelledBy: userId,
                        cancelReason: `تعديل فاتورة المشتريات ${data.number} — استُبدل بقيد جديد`
                    });
                } catch (e) { console.error('Cancel old journal error:', e); }
            }

            await update(ref(db, 'ledger/purchaseInvoices/' + key), updateData);
            // 📦 احذف حركات المخزون القديمة + أنشئ جديدة
            await deleteInventoryMovementsForInvoice('purchase_invoice', key);
            await createJournalForPInv(key, { ...data, status: 'posted', postedAt: now, postedBy: userId });
            await createInventoryMovementsForPInv(key, { ...data, status: 'posted' });

            toast(`✅ تم تعديل الفاتورة المرحّلة ${data.number} — استُبدل القيد القديم بقيد جديد`, 'ok');
            pInvEditorState.editingPosted = false;
            pInvEditorState.originalInvoice = null;
            cov('mPInvEditor');
            return;
        }

        // الحالة العادية
        let invKey = key;
        if (key) {
            await update(ref(db, 'ledger/purchaseInvoices/' + key), data);
        } else {
            data.createdAt = now;
            data.createdBy = userId;
            const newRef = await push(R.pinv, data);
            invKey = newRef.key;
        }

        if (status === 'posted') {
            data.postedAt = now;
            data.postedBy = userId;
            await update(ref(db, 'ledger/purchaseInvoices/' + invKey), { status: 'posted', postedAt: now, postedBy: userId });
            await createJournalForPInv(invKey, data);
            // 📦 إنشاء حركات مخزون دخول تلقائياً
            await createInventoryMovementsForPInv(invKey, data);
        }

        toast(`✅ تم ${status === 'posted' ? 'ترحيل الفاتورة وإنشاء القيد المحاسبي' : 'حفظ الفاتورة كمسودة'}`, 'ok');
        cov('mPInvEditor');
    } catch (e) {
        console.error('Save purchase invoice error:', e);
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── إنشاء قيد محاسبي تلقائي لفاتورة المشتريات ─────────────────
// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   💵 → 📒  ربط مسير الرواتب بالقيود المحاسبية                                ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// إنشاء قيد محاسبي تلقائي عند اعتماد مسير الرواتب
window.createJournalForPayroll = async function (payrollKey, payroll) {
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const userName = (typeof myP !== 'undefined' && myP?.name) || userId;
    const now = new Date().toISOString();

    const accounts = Object.values(window.chartOfAccounts || {});
    const findAccByCode = (code) => accounts.find(a => a.code === code);

    // 🆕 اقرأ الإعدادات المخصصة لكل مشروع
    const settings = window.payrollAccSettings || {};
    const defaultSett = settings._default || {};

    // 🆕 دالة لإرجاع الحساب المناسب لمشروع معين
    // الترتيب: إعدادات المشروع → الإعدادات الافتراضية المُخصصة → الكود الثابت
    function getAccountForProject(projectId, field, fallbackCode) {
        const projSett = projectId && settings[projectId] ? settings[projectId] : null;
        // 1. حساب المشروع المحدد
        if (projSett && projSett[field]) {
            const acc = findAccByCode(projSett[field]);
            if (acc) return acc;
        }
        // 2. الحساب الافتراضي المُخصص من قبل المستخدم
        if (defaultSett[field]) {
            const acc = findAccByCode(defaultSett[field]);
            if (acc) return acc;
        }
        // 3. الـ fallback من شجرة الحسابات
        return findAccByCode(fallbackCode);
    }

    // الحسابات الأساسية (Fallback codes)
    const FALLBACK_EXPENSE = '5310';   // أو 5210
    const FALLBACK_PAYABLE = '2120';   // الرواتب المستحقة
    const FALLBACK_LOAN = '1220';      // السلف للموظفين
    const FALLBACK_BONUS = '5310';     // مكافآت = نفس مصروف الرواتب افتراضياً

    // تحقق من وجود الحساب الافتراضي للرواتب على الأقل
    const defaultExpenseAcc = getAccountForProject(null, 'expenseAcc', FALLBACK_EXPENSE)
        || findAccByCode('5210');
    const defaultPayableAcc = getAccountForProject(null, 'payableAcc', FALLBACK_PAYABLE);

    if (!defaultExpenseAcc) {
        toast('⚠️ المسير اعُتمد، لكن لم يُنشأ القيد: حساب الرواتب الافتراضي (5310/5210) غير موجود في شجرة الحسابات أو الإعدادات', 'wn', 10000);
        return null;
    }
    if (!defaultPayableAcc) {
        toast('⚠️ المسير اعُتمد، لكن لم يُنشأ القيد: حساب الرواتب المستحقة الافتراضي (2120) غير موجود', 'wn', 10000);
        return null;
    }

    // تجميع البيانات من بنود المسير
    const items = payroll.items || [];

    // 🆕 تجميع حسب مركز التكلفة (المشروع) لمعالجة منفصلة لكل مشروع
    // كل مشروع له:
    //   - مبلغ مصروف الرواتب (مع المكافآت الموجبة)
    //   - مبلغ السلف
    //   - مبلغ الصافي (الرواتب المستحقة)
    //   - الخصومات الشهرية
    const groupedByProject = {};
    items.forEach(item => {
        const projId = item.projectId || '';   // فارغ = استخدم الافتراضي
        if (!groupedByProject[projId]) {
            groupedByProject[projId] = {
                projectId: projId,
                projectName: projId && window.projects?.[projId] ? window.projects[projId].name : '',
                expense: 0, loan: 0, monthDeduct: 0, perfBonus: 0, net: 0,
                count: 0
            };
        }
        const g = groupedByProject[projId];
        const earned = parseFloat(item.earnedNet || item.grossSalary) || 0;
        const bonus = parseFloat(item.perfBonusAmt) || 0;
        // المصروف = الراتب + المكافأة الموجبة
        g.expense += earned + (bonus > 0 ? bonus : 0);
        g.loan += parseFloat(item.loanDeductTotal) || 0;
        g.monthDeduct += parseFloat(item.monthDeductTotal) || 0;
        g.perfBonus += bonus;
        g.net += parseFloat(item.finalNet) || 0;
        g.count += 1;
    });

    const lines = [];
    const mLabel = typeof formatMonthLabel === 'function' ? formatMonthLabel(payroll.month) : payroll.month;
    const scopeLabel = payroll.scope === 'project' ? `(📁 ${payroll.projectName || ''})` :
                       payroll.scope === 'dept' ? `(🏢 ${payroll.dept || ''})` : '';

    // 🎯 لكل مشروع: أنشئ سطور القيد الخاصة به
    Object.values(groupedByProject).forEach(g => {
        const projectId = g.projectId || null;
        const projName = g.projectName || 'عام (بدون مشروع)';
        const cc = projectId || '';

        // 💸 المدين: مصروف الرواتب
        const expenseAcc = getAccountForProject(projectId, 'expenseAcc', FALLBACK_EXPENSE) || defaultExpenseAcc;
        if (g.expense > 0) {
            lines.push({
                accountCode: expenseAcc.code,
                accountName: expenseAcc.nameAr,
                description: `رواتب ${mLabel} — ${projName} (${g.count} موظف)`,
                costCenter: cc,
                debit: parseFloat(g.expense.toFixed(2)),
                credit: 0
            });
        }

        // 💳 الدائن: السلف
        if (g.loan > 0) {
            const loanAcc = getAccountForProject(projectId, 'loanAcc', FALLBACK_LOAN);
            if (loanAcc) {
                lines.push({
                    accountCode: loanAcc.code,
                    accountName: loanAcc.nameAr,
                    description: `سداد أقساط سلف — ${projName} — مسير ${mLabel}`,
                    costCenter: cc,
                    debit: 0,
                    credit: parseFloat(g.loan.toFixed(2))
                });
            } else {
                toast(`⚠️ حساب السلف غير محدد لمشروع "${projName}" — لن يُسجَّل قسط السلف (${fmt(g.loan)})`, 'wn', 8000);
            }
        }

        // 💵 الدائن: الرواتب المستحقة (الصافي للدفع)
        const payableAcc = getAccountForProject(projectId, 'payableAcc', FALLBACK_PAYABLE) || defaultPayableAcc;
        if (g.net > 0) {
            lines.push({
                accountCode: payableAcc.code,
                accountName: payableAcc.nameAr,
                description: `صافي رواتب ${mLabel} — ${projName} — مستحقة للدفع`,
                costCenter: cc,
                debit: 0,
                credit: parseFloat(g.net.toFixed(2))
            });
        }

        // ⚖️ التحقق من توازن هذا المشروع (الخصومات المتنوعة)
        const projDebit = g.expense;
        const projCredit = g.loan + g.net;
        const projDiff = projDebit - projCredit;

        if (Math.abs(projDiff) > 0.01) {
            if (projDiff > 0) {
                // فرق = خصومات شهرية متنوعة (تذهب لحساب الرواتب المستحقة)
                lines.push({
                    accountCode: payableAcc.code,
                    accountName: payableAcc.nameAr,
                    description: `خصومات شهرية متنوعة — ${projName} — مسير ${mLabel}`,
                    costCenter: cc,
                    debit: 0,
                    credit: parseFloat(projDiff.toFixed(2))
                });
            } else {
                // فرق سالب = مكافآت أداء سالبة
                lines.push({
                    accountCode: payableAcc.code,
                    accountName: payableAcc.nameAr,
                    description: `تعديلات وأداء سالب — ${projName} — مسير ${mLabel}`,
                    costCenter: cc,
                    debit: parseFloat(Math.abs(projDiff).toFixed(2)),
                    credit: 0
                });
            }
        }
    });

    // التأكد النهائي من التوازن الكلي
    const finalDebit = lines.reduce((s, l) => s + (parseFloat(l.debit) || 0), 0);
    const finalCredit = lines.reduce((s, l) => s + (parseFloat(l.credit) || 0), 0);

    // 📅 التاريخ = آخر يوم في شهر المسير
    const [yyP, mmP] = payroll.month.split('-').map(Number);
    const lastDayOfMonth = new Date(yyP, mmP, 0).getDate();
    const jrnDate = `${payroll.month}-${String(lastDayOfMonth).padStart(2, '0')}`;

    const jrnNumber = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-AUTO-' + Date.now());
    const jrnData = {
        number: jrnNumber,
        date: jrnDate,
        lines,
        totalDebit: parseFloat(finalDebit.toFixed(2)),
        totalCredit: parseFloat(finalCredit.toFixed(2)),
        status: 'draft',  // 🆕 يبدأ كمسودة ليُراجَع ويُعتمَد ويُرحَّل
        sourceType: 'payroll',
        sourceKey: payrollKey,
        sourceLabel: `مسير ${mLabel}${scopeLabel ? ' ' + scopeLabel : ''}`,
        reference: `PAY-${payroll.month}-${(payroll.scope || 'all').toUpperCase()}`,
        description: `إثبات رواتب ${mLabel}${scopeLabel ? ' ' + scopeLabel : ''} - ${items.length} موظف`,
        createdAt: now,
        createdBy: userId,
        createdByName: userName,
        autoGenerated: true,
        autoGeneratedFrom: 'payroll_approval'
    };

    try {
        const jrnRef = await push(R.jrn, jrnData);
        // ربط القيد بالمسير
        await update(ref(db, 'ledger/payrolls/' + payrollKey), {
            journalEntryKey: jrnRef.key,
            journalEntryNumber: jrnNumber,
            journalEntryStatus: 'draft'
        });
        return { key: jrnRef.key, number: jrnNumber };
    } catch (e) {
        console.error('Create payroll journal error:', e);
        toast('❌ خطأ في إنشاء القيد: ' + e.message, 'er');
        return null;
    }
};

async function createJournalForPInv(invKey, inv) {
    const vendor = window.vendors?.[inv.vendorId];
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();

    const accounts = Object.values(window.chartOfAccounts || {});
    // 💼 استخدم الحساب المدين المحفوظ في الفاتورة (مختار يدوياً)
    // إذا لم يكن موجوداً، ارجع للحساب الافتراضي حسب النوع
    const expenseCode = inv.debitAccountCode || getExpenseAccountForType(inv.expenseType);
    const expenseAcc = accounts.find(a => a.code === expenseCode);
    const vendorAcc = accounts.find(a => a.code === vendPayableAccount(inv.vendorId)); // الموردون (حساب مجموعته أو الموحّد)
    const vatInputAcc = accounts.find(a => a.code === '1180'); // VAT مدخل

    if (!expenseAcc || !vendorAcc) {
        toast(`⚠️ الفاتورة رُحّلت، لكن لم يُنشأ القيد: الحسابات ${expenseCode} أو 2110 غير موجودة`, 'wn', 8000);
        return;
    }

    // 💱 تعدد العملات: تُرحَّل القيود بالعملة الدفترية
    const baseCode = typeof baseCurrencyCode === 'function' ? baseCurrencyCode() : 'SAR';
    const curCode = inv.currency || baseCode;
    const fx = (curCode !== baseCode) ? (parseFloat(inv.exchangeRate) || 1) : 1;
    const cvt = (v) => Math.round(((+v || 0) * fx) * 100) / 100;
    const grandBase = cvt(inv.grandTotal);
    const curNote = fx !== 1 ? ` [${fmt(inv.grandTotal)} ${curCode} × ${fx}]` : '';

    const lines = [];
    // مدين: حساب المصروف/المخزون (الصافي قبل الضريبة)
    lines.push({
        accountCode: expenseAcc.code,
        accountName: expenseAcc.nameAr,
        description: `فاتورة ${inv.number} (مورد: ${inv.vendorRef}) - ${vendor?.nameAr || ''}${curNote}`,
        costCenter: inv.costCenter || inv.projectId || '',
        debit: cvt(inv.netBeforeTax),
        credit: 0
    });
    // مدين: VAT مدخل (إذا VAT > 0)
    if (inv.vatTotal > 0 && vatInputAcc) {
        lines.push({
            accountCode: vatInputAcc.code,
            accountName: vatInputAcc.nameAr,
            description: `VAT مدخل - فاتورة ${inv.number}`,
            costCenter: inv.costCenter || inv.projectId || '',
            debit: cvt(inv.vatTotal),
            credit: 0
        });
    } else if (inv.vatTotal > 0) {
        // VAT موجود لكن الحساب 1180 غير موجود → أضف للمصروفات
        lines[0].debit = Math.round((lines[0].debit + cvt(inv.vatTotal)) * 100) / 100;
        toast('⚠️ حساب 1180 (VAT مدخل) غير موجود — تم إضافة الضريبة للمصروفات', 'wn', 6000);
    }
    // ضمان توازن القيد بعد التقريب: عدّل سطر المصروف بفرق التقريب
    const totDebit = lines.reduce((s, l) => s + l.debit, 0);
    const roundDiff = Math.round((grandBase - totDebit) * 100) / 100;
    if (Math.abs(roundDiff) >= 0.01) lines[0].debit = Math.round((lines[0].debit + roundDiff) * 100) / 100;
    // دائن: الموردون (الإجمالي)
    lines.push({
        accountCode: vendorAcc.code,
        accountName: vendorAcc.nameAr,
        description: `استحقاق فاتورة ${inv.number}`,
        costCenter: inv.costCenter || inv.projectId || '',
        debit: 0,
        credit: grandBase
    });

    const jrnNumber = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-AUTO-' + Date.now());
    const jrnData = {
        number: jrnNumber,
        date: inv.date,
        reference: 'فاتورة مشتريات ' + inv.number + ' / مورد: ' + inv.vendorRef,
        description: `إثبات فاتورة مشتريات ${inv.number} - ${vendor?.nameAr || ''}`,
        lines,
        totalDebit: grandBase,
        totalCredit: grandBase,
        currency: curCode,
        exchangeRate: fx,
        foreignTotal: inv.grandTotal,
        status: 'posted',
        sourceType: 'purchase_invoice',
        sourceKey: invKey,
        createdAt: now,
        createdBy: userId,
        postedAt: now,
        postedBy: userId
    };

    const jrnRef = await push(R.jrn, jrnData);
    await update(ref(db, 'ledger/purchaseInvoices/' + invKey), { journalEntryKey: jrnRef.key, journalEntryNumber: jrnNumber });
}

// ── ترحيل فاتورة موجودة ─────────────────
window.postPInv = async function (key) {
    const inv = window.purchaseInvoices?.[key]; if (!inv) return;
    if (inv.status !== 'draft') return;
    if (!await cf2(`هل تريد ترحيل فاتورة المشتريات ${inv.number}؟\nسيُنشأ قيد محاسبي تلقائي بمبلغ ${fmt(inv.grandTotal)} ر`)) return;

    try {
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        const now = new Date().toISOString();
        await update(ref(db, 'ledger/purchaseInvoices/' + key), {
            status: 'posted',
            postedAt: now,
            postedBy: userId
        });
        await createJournalForPInv(key, { ...inv, status: 'posted', postedAt: now, postedBy: userId });
        // 📦 إنشاء حركات مخزون
        await createInventoryMovementsForPInv(key, inv);
        toast('✅ تم الترحيل وإنشاء القيد المحاسبي', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── حذف فاتورة (مسودة فقط) ─────────────────
window.deletePInv = async function (key) {
    const inv = window.purchaseInvoices?.[key]; if (!inv) return;
    if (inv.status !== 'draft') { toast('⚠️ لا يمكن حذف فاتورة مرحّلة', 'er'); return; }
    if (!await cf2(`هل تريد حذف الفاتورة ${inv.number} نهائياً؟`)) return;
    try {
        await remove(ref(db, 'ledger/purchaseInvoices/' + key));
        toast('✅ تم الحذف', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── عرض/طباعة الفاتورة ─────────────────
