// تهيئة state
window.receipts = window.receipts || {};
window.payments = window.payments || {};

let voucherEditorState = { type: 'receipt', allocations: {}, editingPosted: false, originalVoucher: null };

// ── توليد رقم سند ─────────────────
function generateVoucherNumber(type) {
    const data = type === 'receipt' ? (window.receipts || {}) : (window.payments || {});
    const year = new Date().getFullYear();
    const prefix = type === 'receipt' ? 'RCV-' : 'PAY-';
    const yearPrefix = prefix + year + '-';
    const thisYear = Object.values(data).filter(v => (v.number || '').startsWith(yearPrefix));
    const nums = thisYear.map(v => parseInt((v.number || '').split('-')[2]) || 0);
    const next = nums.length ? Math.max(...nums) + 1 : 1;
    return yearPrefix + String(next).padStart(5, '0');
}

