// ── رسم صف سند (موحّد للقبض والصرف) ─────────────────
function renderVoucherRow(key, v, idx, type) {
    const party = type === 'receipt' ? window.customers?.[v.partyId] : window.vendors?.[v.partyId];

    const methodLabels = {
        cash: { label: '💵 نقدي', color: '#27ae60' },
        bank_transfer: { label: '🏦 تحويل', color: '#2d6a9f' },
        check: { label: '📝 شيك', color: '#8e44ad' },
        card: { label: '💳 بطاقة', color: '#e67e22' },
        other: { label: '📦 أخرى', color: '#7f8c8d' }
    };
    const m = methodLabels[v.method] || methodLabels.other;

    const statusColors = {
        draft: { bg: '#f39c12', label: '📝 مسودة' },
        posted: { bg: '#27ae60', label: '✅ مرحّل' },
        cancelled: { bg: '#7f8c8d', label: '❌ ملغى' }
    };
    const sc = statusColors[v.status] || statusColors.draft;

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    const canEdit = v.status === 'draft' && (isAdmin || canFn('create_' + type));
    const canEditPosted = v.status === 'posted' && (isAdmin || isFinanceMgr || canFn('edit_posted_' + type));
    const canPost = v.status === 'draft' && (isAdmin || canFn('post_' + type));
    const canDelete = v.status === 'draft' && (isAdmin || canFn('delete_' + type));
    const canDeletePosted = v.status === 'posted' && (isAdmin || isFinanceMgr || canFn('edit_posted_' + type));

    const tableBody = type === 'receipt' ? 'rcptTableBody' : 'paymTableBody';

    return `<tr style="${idx % 2 ? 'background:#fafbfc' : ''}" data-search="${(v.number || '').toLowerCase()} ${(party?.nameAr || '').toLowerCase()} ${(v.description || '').toLowerCase()}">
        <td style="padding:8px;font-family:monospace;font-weight:800;color:#1a3a5c">${v.number || '-'}</td>
        <td style="padding:8px">${v.date || '-'}</td>
        <td style="padding:8px">
            <div style="font-weight:700">${party?.nameAr || '—'}</div>
            ${party?.code ? `<div style="font-size:10px;color:#888;font-family:monospace">${party.code}</div>` : ''}
        </td>
        <td style="padding:8px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${v.description || ''}">${v.description || '—'}</td>
        <td style="padding:8px"><span style="background:${m.color}22;color:${m.color};padding:3px 8px;border-radius:4px;font-size:11px;font-weight:700">${m.label}</span></td>
        <td style="padding:8px;text-align:center;font-weight:900;color:${type === 'receipt' ? '#27ae60' : '#c0392b'};font-size:14px">${fmt(v.amount)}</td>
        <td style="padding:8px;text-align:center">
            <span style="background:${sc.bg};color:white;padding:3px 10px;border-radius:6px;font-size:11px;font-weight:700">${sc.label}</span>
            ${v.lastEditedAt && v.status === 'posted' ? '<div style="margin-top:3px;font-size:9px;color:#8e44ad;font-weight:700">🔓 معدّل</div>' : ''}
        </td>
        <td style="padding:8px;text-align:center">
            <div style="display:flex;gap:3px;justify-content:center;flex-wrap:wrap">
                <button class="btn" onclick="viewVoucher('${key}','${type}')" style="background:#16a085;color:white;padding:3px 8px;font-size:10px" title="عرض/طباعة">👁️</button>
                ${canEdit ? `<button class="btn" onclick="editVoucher('${key}','${type}')" style="background:#2d6a9f;color:white;padding:3px 8px;font-size:10px" title="تعديل">✏️</button>` : ''}
                ${canEditPosted ? `<button class="btn" onclick="editPostedVoucher('${key}','${type}')" style="background:#8e44ad;color:white;padding:3px 8px;font-size:10px;border:1px solid #5b2c6f" title="تعديل مرحّل (المدير المالي)">🔓✏️</button>` : ''}
                ${canPost ? `<button class="btn" onclick="postVoucher('${key}','${type}')" style="background:#27ae60;color:white;padding:3px 8px;font-size:10px" title="ترحيل">✅</button>` : ''}
                ${canDelete ? `<button class="btn" onclick="deleteVoucher('${key}','${type}')" style="background:#c0392b;color:white;padding:3px 8px;font-size:10px" title="حذف">🗑️</button>` : ''}
                ${canDeletePosted ? `<button class="btn" onclick="deleteVoucher('${key}','${type}')" style="background:#7b241c;color:white;padding:3px 8px;font-size:10px;border:1px solid #c0392b" title="حذف المرحّل (مع إلغاء القيد)">🗑️🔓</button>` : ''}
            </div>
        </td>
    </tr>`;
}

window.filterVoucherTable = function (prefix, query) {
    query = (query || '').toLowerCase().trim();
    document.querySelectorAll(`#${prefix}TableBody tr`).forEach(row => {
        const txt = row.getAttribute('data-search') || '';
        row.style.display = (!query || txt.includes(query)) ? '' : 'none';
    });
};

// ═══════════════════════════════════════════════════════════════════
// 🎬 محرر السند (موحّد للقبض والصرف)
// ═══════════════════════════════════════════════════════════════════

window.openVoucherEditor = function (type) {
    voucherEditorState = { type, allocations: {}, editingPosted: false, originalVoucher: null };

    const isReceipt = type === 'receipt';
    const config = {
        receipt: {
            title: '💵 سند قبض جديد',
            partyLabel: '🧑‍💼 العميل *',
            color: '#27ae60',
            headerBg: '#e8f8f5'
        },
        payment: {
            title: '💸 سند صرف جديد',
            partyLabel: '🏭 المورد *',
            color: '#c0392b',
            headerBg: '#fadbd8'
        }
    };
    const cfg = config[type];

    $('mVoucherTitle').textContent = cfg.title;
    $('mVoucherType').value = type;
    $('mVoucherKey').value = '';
    $('mVoucherPartyLabel').textContent = cfg.partyLabel;
    $('mVoucherHeader').style.background = cfg.headerBg;
    $('mVoucherHeader').style.borderColor = cfg.color;

    $('mVoucherNumber').value = generateVoucherNumber(type);
    $('mVoucherDate').value = new Date().toISOString().slice(0, 10);
    $('mVoucherMethod').value = 'cash';
    $('mVoucherAmount').value = '';
    $('mVoucherDescription').value = '';
    $('mVoucherNotes').value = '';
    $('mVoucherProject').value = '';

    // ملء قوائم الاختيار
    fillVoucherParties(type);
    fillVoucherProjects();
    fillVoucherAccounts();
    populateVoucherCurrency(baseCurrencyCode()); // 💱 العملة الافتراضية

    // إعادة تعيين أزرار الحفظ
    const savePosted = $('mVoucherSavePosted');
    if (savePosted) {
        savePosted.innerHTML = '💾 حفظ وترحيل (يُنشئ قيد)';
        savePosted.style.background = '';
        savePosted.setAttribute('onclick', "saveVoucher('posted')");
    }
    const draftBtn = document.querySelector('button[onclick="saveVoucher(\'draft\')"]');
    if (draftBtn) draftBtn.style.display = '';

    // إخفاء معلومات الرصيد + قائمة الفواتير
    $('mVoucherBalanceInfo').style.display = 'none';
    $('mVoucherInvoicesSection').style.display = 'none';

    onVoucherMethodChange();
    updateVoucherWords();

    ov('mVoucher');
    setTimeout(() => $('mVoucherParty').focus(), 100);
};

// ── فتح سند قبض جاهز لسداد فاتورة مبيعات محددة (من صفحة فواتير المشروع مثلاً) ──
window.openReceiptForInvoice = function (invKey) {
    const inv = window.salesInvoices?.[invKey]; if (!inv) return;
    if (inv.status !== 'posted') { toast('⚠️ لا يمكن تسجيل سداد إلا لفاتورة مرحَّلة', 'er'); return; }
    const remaining = Math.round(((parseFloat(inv.grandTotal) || 0) - (parseFloat(inv.paidAmount) || 0)) * 100) / 100;
    if (remaining <= 0.01) { toast('✅ هذه الفاتورة مسددة بالكامل', 'ok'); return; }

    openVoucherEditor('receipt');
    $('mVoucherParty').value = inv.customerId || '';
    onVoucherPartyChange();
    if (inv.projectId) $('mVoucherProject').value = inv.projectId;
    $('mVoucherDescription').value = `سداد فاتورة ${inv.number}`;
    $('mVoucherAmount').value = remaining.toFixed(2);

    const allocInput = document.querySelector(`#mVoucherInvoicesList input[oninput^="updateVoucherAllocation('${invKey}',"]`);
    if (allocInput) {
        allocInput.value = remaining.toFixed(2);
        updateVoucherAllocation(invKey, remaining, remaining);
    }
    updateVoucherWords();
};

function fillVoucherParties(type) {
    const sel = $('mVoucherParty');
    sel.innerHTML = '<option value="">-- اختر --</option>';
    const data = type === 'receipt' ? (window.customers || {}) : (window.vendors || {});
    const arr = Object.entries(data)
        .filter(([, p]) => p.active !== false)
        .sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || ''));
    arr.forEach(([k, p]) => {
        sel.innerHTML += `<option value="${k}">${p.nameAr} (${p.code || ''})</option>`;
    });
}

function fillVoucherProjects() {
    const sel = $('mVoucherProject');
    sel.innerHTML = '<option value="">-- بدون --</option>';
    if (window.projects) {
        Object.entries(window.projects).forEach(([k, p]) => {
            sel.innerHTML += `<option value="${k}">${p.name || k}</option>`;
        });
    }
}

function fillVoucherAccounts() {
    const accounts = Object.values(window.chartOfAccounts || {})
        .filter(a => a.nature !== 'header' && a.active !== false)
        .sort((a, b) => (a.code || '').localeCompare(b.code || ''));

    // الصندوق (1110 + فروعه)
    const cashAccs = accounts.filter(a => (a.code || '').startsWith('111'));
    // البنوك (112x + فروعها)
    const bankAccs = accounts.filter(a => (a.code || '').startsWith('112'));
    // كل الحسابات النقدية + البنكية (111x, 112x)
    const allMoney = [...cashAccs, ...bankAccs];

    const buildOpts = (arr) => arr.map(a => `<option value="${a.code}">${a.code} — ${a.nameAr}</option>`).join('');

    if ($('mVoucherCashAccount')) $('mVoucherCashAccount').innerHTML = '<option value="">-- اختر --</option>' + buildOpts(cashAccs.length ? cashAccs : allMoney);
    if ($('mVoucherBankAccount')) $('mVoucherBankAccount').innerHTML = '<option value="">-- اختر --</option>' + buildOpts(bankAccs.length ? bankAccs : allMoney);
    if ($('mVoucherCheckAccount')) $('mVoucherCheckAccount').innerHTML = '<option value="">-- اختر --</option>' + buildOpts(allMoney);
    if ($('mVoucherCardAccount')) $('mVoucherCardAccount').innerHTML = '<option value="">-- اختر --</option>' + buildOpts(bankAccs.length ? bankAccs : allMoney);
    if ($('mVoucherOtherAccount')) $('mVoucherOtherAccount').innerHTML = '<option value="">-- اختر --</option>' + buildOpts(allMoney);

    // اختيار افتراضي للنقدي
    if (cashAccs.length && $('mVoucherCashAccount') && !$('mVoucherCashAccount').value) {
        $('mVoucherCashAccount').value = cashAccs[0].code;
    }
}

window.onVoucherMethodChange = function () {
    const method = $('mVoucherMethod').value;
    ['Cash', 'Bank', 'Check', 'Card', 'Other'].forEach(k => {
        const el = $('mvDetails' + k);
        if (el) el.style.display = 'none';
    });
    const map = { cash: 'Cash', bank_transfer: 'Bank', check: 'Check', card: 'Card', other: 'Other' };
    const target = $('mvDetails' + (map[method] || 'Other'));
    if (target) target.style.display = 'block';
};

window.onVoucherPartyChange = function () {
    const type = voucherEditorState.type;
    const partyId = $('mVoucherParty').value;
    const balanceInfo = $('mVoucherBalanceInfo');
    const invoicesSection = $('mVoucherInvoicesSection');

    if (!partyId) {
        balanceInfo.style.display = 'none';
        invoicesSection.style.display = 'none';
        return;
    }

    // عرض رصيد العميل/المورد
    if (type === 'receipt') {
        const bal = typeof calcCustomerBalance === 'function' ? calcCustomerBalance(partyId) : { balance: 0, overdue: 0 };
        balanceInfo.style.display = 'block';
        $('mVoucherBalanceText').innerHTML = `💰 رصيد العميل المستحق: <strong style="color:#2d6a9f">${fmt(bal.balance)}</strong> ر${bal.overdue > 0 ? ` · ⚠️ منها متأخر: <strong style="color:#c0392b">${fmt(bal.overdue)}</strong>` : ''}`;
    } else {
        const bal = typeof calcVendorBalance === 'function' ? calcVendorBalance(partyId) : { balance: 0, overdue: 0 };
        balanceInfo.style.display = 'block';
        $('mVoucherBalanceText').innerHTML = `💸 المستحق للمورد: <strong style="color:#c0392b">${fmt(bal.balance)}</strong> ر${bal.overdue > 0 ? ` · ⚠️ منها متأخر: <strong style="color:#c0392b">${fmt(bal.overdue)}</strong>` : ''}`;
    }

    // عرض الفواتير غير المسددة
    renderUnpaidInvoicesForVoucher(partyId, type);
};

function renderUnpaidInvoicesForVoucher(partyId, type) {
    const invoices = type === 'receipt' ? (window.salesInvoices || {}) : (window.purchaseInvoices || {});
    const partyKey = type === 'receipt' ? 'customerId' : 'vendorId';

    const unpaid = Object.entries(invoices)
        .filter(([, inv]) => inv[partyKey] === partyId && inv.status === 'posted')
        .filter(([, inv]) => Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100 > Math.round((parseFloat(inv.paidAmount) || 0) * 100) / 100 + 0.01)
        .sort((a, b) => (a[1].dueDate || a[1].date || '').localeCompare(b[1].dueDate || b[1].date || ''));

    const section = $('mVoucherInvoicesSection');
    const list = $('mVoucherInvoicesList');
    const counter = $('mVoucherInvoicesCount');

    voucherEditorState.allocations = {};

    if (!unpaid.length) {
        section.style.display = 'block';
        list.innerHTML = '<div style="text-align:center;color:#27ae60;padding:14px;font-size:12px">✅ لا توجد فواتير غير مسددة</div>';
        counter.textContent = '';
        $('mVoucherAllocationSummary').style.display = 'none';
        return;
    }

    section.style.display = 'block';
    counter.textContent = `${unpaid.length} فاتورة غير مسددة`;

    const today = new Date().toISOString().slice(0, 10);
    list.innerHTML = unpaid.map(([key, inv]) => {
        const grand = parseFloat(inv.grandTotal) || 0;
        const paid = parseFloat(inv.paidAmount) || 0;
        const remaining = grand - paid;
        const isOverdue = inv.dueDate && inv.dueDate < today;
        return `<div style="display:grid;grid-template-columns:1fr 100px 100px;gap:8px;align-items:center;padding:6px;border-bottom:1px solid #eef;font-size:11px">
            <div>
                <strong style="font-family:monospace">${inv.number}</strong>
                ${isOverdue ? '<span style="background:#c0392b;color:white;padding:1px 4px;border-radius:3px;font-size:9px;margin-right:4px">⚠️ متأخرة</span>' : ''}
                <div style="font-size:10px;color:#888">${inv.subject || ''} · استحقاق ${inv.dueDate || '-'}</div>
            </div>
            <div style="text-align:center;font-weight:700;color:${isOverdue ? '#c0392b' : '#1a3a5c'}">${fmt(remaining)}</div>
            <div>
                <input type="number" step="0.01" max="${remaining}" placeholder="0.00" oninput="updateVoucherAllocation('${key}', this.value, ${remaining})" style="width:100%;padding:4px;border:1px solid #d0d7e0;border-radius:4px;text-align:left;direction:ltr;font-size:11px">
            </div>
        </div>`;
    }).join('');

    $('mVoucherAllocationSummary').style.display = 'block';
    updateAllocationSummary();
}

window.updateVoucherAllocation = function (invKey, value, maxAmount) {
    const amt = parseFloat(value) || 0;
    if (amt > maxAmount + 0.01) {
        toast(`⚠️ المبلغ تجاوز المتبقي (${fmt(maxAmount)})`, 'wn');
    }
    if (amt > 0) voucherEditorState.allocations[invKey] = amt;
    else delete voucherEditorState.allocations[invKey];
    updateAllocationSummary();
};

function updateAllocationSummary() {
    const total = Object.values(voucherEditorState.allocations).reduce((s, a) => s + a, 0);
    const voucherAmt = parseFloat($('mVoucherAmount').value) || 0;
    $('mVoucherAllocationTotal').textContent = fmt(total);
    const diff = voucherAmt - total;
    const diffEl = $('mVoucherAllocationDiff');
    if (Math.abs(diff) < 0.01 && total > 0) {
        diffEl.innerHTML = '<span style="color:#27ae60;font-weight:700">✅ مطابق</span>';
    } else if (diff > 0) {
        diffEl.innerHTML = `<span style="color:#f39c12;font-weight:700">⚠️ غير مخصص: ${fmt(diff)}</span>`;
    } else if (diff < 0) {
        diffEl.innerHTML = `<span style="color:#c0392b;font-weight:700">⚠️ تجاوز المبلغ: ${fmt(Math.abs(diff))}</span>`;
    } else {
        diffEl.innerHTML = '';
    }
}

window.updateVoucherWords = function () {
    const amt = parseFloat($('mVoucherAmount').value) || 0;
    const wordsEl = $('mVoucherAmountWords');
    if (amt > 0 && typeof numberToArabicWords === 'function') {
        wordsEl.innerHTML = '📝 ' + numberToArabicWords(amt);
    } else {
        wordsEl.textContent = '';
    }
    updateAllocationSummary();
};

// ═══════════════════════════════════════════════════════════════════
// 💾 حفظ السند
// ═══════════════════════════════════════════════════════════════════

// 💱 عملة السند (قبض/صرف)
function populateVoucherCurrency(selected) {
    const sel = $('mVoucherCurrency'); if (!sel) return;
    const list = currencyList();
    sel.innerHTML = Object.entries(list).map(([code, c]) => `<option value="${code}" ${selected === code ? 'selected' : ''}>${c.nameAr} (${code})${c.isBase ? ' — دفترية' : ''}</option>`).join('');
    if (selected) sel.value = selected;
    onVoucherCurrencyChange();
}
window.populateVoucherCurrency = populateVoucherCurrency;
window.onVoucherCurrencyChange = function () {
    const code = $('mVoucherCurrency')?.value || baseCurrencyCode();
    if ($('mVoucherRate')) {
        $('mVoucherRate').value = getCurrencyRate(code);
        $('mVoucherRate').readOnly = (code === baseCurrencyCode());
    }
    updateVoucherBaseEquiv();
};
window.updateVoucherBaseEquiv = function () {
    const code = $('mVoucherCurrency')?.value || baseCurrencyCode();
    const rate = parseFloat($('mVoucherRate')?.value) || 1;
    const amount = parseFloat($('mVoucherAmount')?.value) || 0;
    const equiv = $('mVoucherBaseEquiv');
    if (equiv) {
        equiv.innerHTML = (code !== baseCurrencyCode())
            ? `= <strong>${fmt(amount * rate)} ${(currencyList()[baseCurrencyCode()] || {}).symbol || ''}</strong> بالعملة الدفترية (القيد يُرحَّل بهذه القيمة)`
            : '';
    }
};

window.saveVoucher = async function (status) {
    const type = voucherEditorState.type;
    const partyId = $('mVoucherParty').value;
    if (!partyId) { toast(`⚠️ يجب اختيار ${type === 'receipt' ? 'العميل' : 'المورد'}`, 'er'); return; }

    const amount = parseFloat($('mVoucherAmount').value) || 0;
    if (amount <= 0) { toast('⚠️ المبلغ يجب أن يكون أكبر من الصفر', 'er'); return; }

    const description = $('mVoucherDescription').value.trim();
    if (!description) { toast('⚠️ البيان مطلوب', 'er'); return; }

    const method = $('mVoucherMethod').value;
    let cashAccountCode = '';
    let methodDetails = {};

    // تحديد حساب الصندوق/البنك حسب طريقة الدفع
    if (method === 'cash') {
        cashAccountCode = $('mVoucherCashAccount').value;
        if (!cashAccountCode) { toast('⚠️ يجب اختيار حساب الصندوق', 'er'); return; }
    } else if (method === 'bank_transfer') {
        cashAccountCode = $('mVoucherBankAccount').value;
        if (!cashAccountCode) { toast('⚠️ يجب اختيار الحساب البنكي', 'er'); return; }
        methodDetails.bankRef = $('mVoucherBankRef').value.trim();
    } else if (method === 'check') {
        cashAccountCode = $('mVoucherCheckAccount').value;
        if (!cashAccountCode) { toast('⚠️ يجب اختيار حساب الإيداع/السحب', 'er'); return; }
        methodDetails.checkBank = $('mVoucherCheckBank').value.trim();
        methodDetails.checkNumber = $('mVoucherCheckNumber').value.trim();
        methodDetails.checkDate = $('mVoucherCheckDate').value;
        if (!methodDetails.checkNumber) { toast('⚠️ رقم الشيك مطلوب', 'er'); return; }
    } else if (method === 'card') {
        cashAccountCode = $('mVoucherCardAccount').value;
        if (!cashAccountCode) { toast('⚠️ يجب اختيار حساب الإيداع', 'er'); return; }
        methodDetails.cardRef = $('mVoucherCardRef').value.trim();
    } else {
        cashAccountCode = $('mVoucherOtherAccount').value;
        if (!cashAccountCode) { toast('⚠️ يجب اختيار الحساب', 'er'); return; }
    }

    // التحقق من التخصيص (إذا تم تخصيص)
    const allocTotal = Object.values(voucherEditorState.allocations).reduce((s, a) => s + a, 0);
    if (allocTotal > amount + 0.01) {
        toast(`❌ مجموع التخصيص (${fmt(allocTotal)}) تجاوز المبلغ (${fmt(amount)})`, 'er');
        return;
    }

    const key = $('mVoucherKey').value;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();

    const data = {
        number: $('mVoucherNumber').value,
        date: $('mVoucherDate').value,
        type,
        partyId,
        method,
        ...methodDetails,
        cashAccountCode,
        amount,
        currency: $('mVoucherCurrency')?.value || baseCurrencyCode(),
        exchangeRate: parseFloat($('mVoucherRate')?.value) || 1,
        amountBase: amount * (parseFloat($('mVoucherRate')?.value) || 1),
        projectId: $('mVoucherProject').value,
        description,
        allocations: { ...voucherEditorState.allocations },
        notes: $('mVoucherNotes').value.trim(),
        status,
        updatedAt: now,
        updatedBy: userId
    };

    const dbRef = type === 'receipt' ? R.rcpt : R.paym;
    const dbPath = type === 'receipt' ? 'ledger/receipts/' : 'ledger/payments/';

    try {
        // 🔓 حالة خاصة: تعديل سند مرحّل
        if (voucherEditorState.editingPosted && key) {
            const original = voucherEditorState.originalVoucher || {};
            const auditEntry = {
                editedAt: now,
                editedBy: userId,
                editorName: (typeof myP !== 'undefined' && myP?.name) || userId,
                originalSnapshot: original
            };
            const existing = type === 'receipt' ? window.receipts?.[key] : window.payments?.[key];
            const existingAudit = existing?.auditLog || {};
            const auditKey = 'edit_' + Date.now();

            // إلغاء القيد القديم + إلغاء التخصيصات القديمة على الفواتير
            if (original.journalEntryKey) {
                try {
                    await update(ref(db, 'ledger/journalEntries/' + original.journalEntryKey), {
                        status: 'cancelled',
                        cancelledAt: now,
                        cancelledBy: userId,
                        cancelReason: `تعديل السند ${data.number} — استُبدل بقيد جديد`
                    });
                } catch (e) { console.error('Cancel old journal error:', e); }
            }
            // إلغاء التخصيصات القديمة
            await unallocateFromInvoices(original.allocations, type);

            const updateData = { ...data, status: 'posted' };
            updateData.lastEditedAt = now;
            updateData.lastEditedBy = userId;
            updateData.auditLog = { ...existingAudit, [auditKey]: auditEntry };

            await update(ref(db, dbPath + key), updateData);
            // تطبيق التخصيصات الجديدة + إنشاء قيد جديد
            await allocateToInvoices(data.allocations, type, key);
            await createJournalForVoucher(key, { ...data, status: 'posted', postedAt: now, postedBy: userId });

            toast(`✅ تم تعديل السند ${data.number} — استُبدل القيد القديم بقيد جديد`, 'ok');
            voucherEditorState.editingPosted = false;
            voucherEditorState.originalVoucher = null;
            cov('mVoucher');
            return;
        }

        // الحالة العادية
        let vKey = key;
        if (key) {
            await update(ref(db, dbPath + key), data);
        } else {
            data.createdAt = now;
            data.createdBy = userId;
            const newRef = await push(dbRef, data);
            vKey = newRef.key;
        }

        if (status === 'posted') {
            data.postedAt = now;
            data.postedBy = userId;
            await update(ref(db, dbPath + vKey), { status: 'posted', postedAt: now, postedBy: userId });
            // تطبيق التخصيصات على الفواتير
            await allocateToInvoices(data.allocations, type, vKey);
            // إنشاء القيد المحاسبي
            await createJournalForVoucher(vKey, data);
        }

        toast(`✅ تم ${status === 'posted' ? 'ترحيل السند وإنشاء القيد' : 'حفظ السند كمسودة'}`, 'ok');
        cov('mVoucher');
    } catch (e) {
        console.error('Save voucher error:', e);
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── تطبيق التخصيصات على الفواتير ─────────────────
async function allocateToInvoices(allocations, type, voucherKey) {
    if (!allocations || !Object.keys(allocations).length) return;
    const invPath = type === 'receipt' ? 'ledger/salesInvoices/' : 'ledger/purchaseInvoices/';

    for (const [invKey, amt] of Object.entries(allocations)) {
        if (!invKey || !(parseFloat(amt) > 0)) continue;
        try {
            // قراءة القيمة الحالية مباشرة من Firebase لتفادي الكاش القديم
            const snap = await get(ref(db, invPath + invKey));
            if (!snap.exists()) { console.warn('allocateToInvoices: invoice not found', invKey); continue; }
            const currentPaid = parseFloat(snap.val().paidAmount) || 0;
            const newPaid = Math.round((currentPaid + parseFloat(amt)) * 100) / 100;
            await update(ref(db, invPath + invKey), { paidAmount: newPaid });
        } catch (e) {
            console.error('Allocate to invoice error:', invKey, e);
        }
    }
}

// ── إلغاء التخصيصات السابقة (عند تعديل سند مرحّل) ─────────────────
async function unallocateFromInvoices(allocations, type) {
    if (!allocations || !Object.keys(allocations).length) return;
    const invPath = type === 'receipt' ? 'ledger/salesInvoices/' : 'ledger/purchaseInvoices/';

    for (const [invKey, amt] of Object.entries(allocations)) {
        if (!invKey || !(parseFloat(amt) > 0)) continue;
        try {
            const snap = await get(ref(db, invPath + invKey));
            if (!snap.exists()) continue;
            const currentPaid = parseFloat(snap.val().paidAmount) || 0;
            const newPaid = Math.max(0, Math.round((currentPaid - parseFloat(amt)) * 100) / 100);
            await update(ref(db, invPath + invKey), { paidAmount: newPaid });
        } catch (e) {
            console.error('Unallocate from invoice error:', invKey, e);
        }
    }
}

// ── إعادة حساب paidAmount لجميع فواتير المبيعات من سندات القبض ─────────────────
window.recalcSInvPaidAmounts = async function () {
    if (!await cf2('⚠️ سيتم إعادة حساب المبالغ المسددة لجميع فواتير المبيعات من سندات القبض المرحّلة.\nهل تريد المتابعة؟')) return;
    try {
        toast('⏳ جاري إعادة الحساب...', 'ok', 60000);

        // قراءة سندات القبض مباشرة من Firebase
        const rcptSnap = await get(ref(db, 'ledger/receipts'));
        const receipts = rcptSnap.exists() ? rcptSnap.val() : {};

        // اجمع جميع تخصيصات السندات المرحّلة
        const totals = {};
        for (const rcpt of Object.values(receipts)) {
            if (rcpt.status !== 'posted' || !rcpt.allocations) continue;
            for (const [invKey, amt] of Object.entries(rcpt.allocations)) {
                totals[invKey] = Math.round(((totals[invKey] || 0) + (parseFloat(amt) || 0)) * 100) / 100;
            }
        }

        // قراءة الفواتير مباشرة من Firebase
        const invSnap = await get(ref(db, 'ledger/salesInvoices'));
        const invoices = invSnap.exists() ? invSnap.val() : {};

        const updates = {};
        for (const [invKey, inv] of Object.entries(invoices)) {
            const correctPaid = totals[invKey] || 0;
            const currentPaid = parseFloat(inv.paidAmount) || 0;
            if (Math.abs(correctPaid - currentPaid) > 0.005) {
                updates['ledger/salesInvoices/' + invKey + '/paidAmount'] = correctPaid;
            }
        }

        if (!Object.keys(updates).length) {
            toast('✅ جميع المبالغ المسددة صحيحة — لا يوجد ما يحتاج تصحيح', 'ok', 4000);
            return;
        }
        await update(ref(db, '/'), updates);
        toast(`✅ تم تصحيح ${Object.keys(updates).length} فاتورة بنجاح`, 'ok', 4000);
    } catch (e) {
        console.error('recalcSInvPaidAmounts error:', e);
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

// ── إنشاء القيد المحاسبي للسند ─────────────────
async function createJournalForVoucher(voucherKey, voucher) {
    const type = voucher.type;
    const party = type === 'receipt' ? window.customers?.[voucher.partyId] : window.vendors?.[voucher.partyId];
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();

    const accounts = Object.values(window.chartOfAccounts || {});
    const cashAcc = accounts.find(a => a.code === voucher.cashAccountCode);
    // العملاء = 1130 (مدين)، الموردون = 2110 (دائن) — أو حساب المجموعة في نمط المجموعات
    const partyAccCode = type === 'receipt' ? custReceivableAccount(voucher.partyId) : vendPayableAccount(voucher.partyId);
    const partyAcc = accounts.find(a => a.code === partyAccCode);

    if (!cashAcc || !partyAcc) {
        toast(`⚠️ السند رُحّل، لكن لم يُنشأ القيد: حساب ${voucher.cashAccountCode} أو ${partyAccCode} غير موجود`, 'wn', 8000);
        return;
    }

    // 💱 تعدد العملات: يُرحَّل السند بالعملة الدفترية (× سعر الصرف)
    const baseCode = typeof baseCurrencyCode === 'function' ? baseCurrencyCode() : 'SAR';
    const curCode = voucher.currency || baseCode;
    const fx = (curCode !== baseCode) ? (parseFloat(voucher.exchangeRate) || 1) : 1;
    const amtBase = Math.round(((+voucher.amount || 0) * fx) * 100) / 100;
    const curNote = fx !== 1 ? ` [${fmt(voucher.amount)} ${curCode} × ${fx}]` : '';

    const lines = [];
    if (type === 'receipt') {
        // قبض من عميل:
        // مدين: الصندوق/البنك (1110/1120)
        // دائن: العملاء (1130)
        lines.push({
            accountCode: cashAcc.code,
            accountName: cashAcc.nameAr,
            description: `قبض من ${party?.nameAr || ''} - سند ${voucher.number}${curNote}`,
            costCenter: voucher.projectId || '',
            debit: amtBase,
            credit: 0
        });
        lines.push({
            accountCode: partyAcc.code,
            accountName: partyAcc.nameAr,
            description: `سداد فواتير ${party?.nameAr || ''}`,
            costCenter: voucher.projectId || '',
            debit: 0,
            credit: amtBase
        });
    } else {
        // صرف لمورد:
        // مدين: الموردون (2110)
        // دائن: الصندوق/البنك (1110/1120)
        lines.push({
            accountCode: partyAcc.code,
            accountName: partyAcc.nameAr,
            description: `صرف لـ ${party?.nameAr || ''} - سند ${voucher.number}${curNote}`,
            costCenter: voucher.projectId || '',
            debit: amtBase,
            credit: 0
        });
        lines.push({
            accountCode: cashAcc.code,
            accountName: cashAcc.nameAr,
            description: `سداد فواتير ${party?.nameAr || ''}`,
            costCenter: voucher.projectId || '',
            debit: 0,
            credit: amtBase
        });
    }

    const jrnNumber = typeof generateJrnNumber === 'function' ? generateJrnNumber() : ('JV-AUTO-' + Date.now());
    const jrnData = {
        number: jrnNumber,
        date: voucher.date,
        reference: voucher.number,
        description: `${type === 'receipt' ? 'سند قبض' : 'سند صرف'} ${voucher.number} - ${voucher.description}`,
        lines,
        totalDebit: amtBase,
        totalCredit: amtBase,
        currency: curCode,
        exchangeRate: fx,
        foreignTotal: voucher.amount,
        status: 'posted',
        sourceType: type === 'receipt' ? 'receipt' : 'payment',
        sourceKey: voucherKey,
        createdAt: now,
        createdBy: userId,
        postedAt: now,
        postedBy: userId
    };

    const jrnRef = await push(R.jrn, jrnData);
    const path = type === 'receipt' ? 'ledger/receipts/' : 'ledger/payments/';
    await update(ref(db, path + voucherKey), { journalEntryKey: jrnRef.key, journalEntryNumber: jrnNumber });
}

// ═══════════════════════════════════════════════════════════════════
// 🛠️ تعديل / حذف / ترحيل
// ═══════════════════════════════════════════════════════════════════

// ── دالة داخلية لملء حقول محرر السند ──
function _populateVoucherEditor(key, type, data) {
    openVoucherEditor(type);
    setTimeout(() => {
        $('mVoucherTitle').textContent = (type === 'receipt' ? '✏️ تعديل سند قبض' : '✏️ تعديل سند صرف') + ' — ' + data.number;
        $('mVoucherKey').value = key;
        $('mVoucherNumber').value = data.number || '';
        $('mVoucherDate').value = data.date || '';
        $('mVoucherParty').value = data.partyId || '';
        $('mVoucherMethod').value = data.method || 'cash';
        $('mVoucherAmount').value = data.amount || '';
        $('mVoucherDescription').value = data.description || '';
        $('mVoucherProject').value = data.projectId || '';
        $('mVoucherNotes').value = data.notes || '';
        populateVoucherCurrency(data.currency || baseCurrencyCode());
        if ($('mVoucherRate')) $('mVoucherRate').value = data.exchangeRate || getCurrencyRate(data.currency || baseCurrencyCode());

        onVoucherMethodChange();
        if (data.method === 'cash' && $('mVoucherCashAccount')) $('mVoucherCashAccount').value = data.cashAccountCode || '';
        else if (data.method === 'bank_transfer') {
            $('mVoucherBankAccount').value = data.cashAccountCode || '';
            $('mVoucherBankRef').value = data.bankRef || '';
        } else if (data.method === 'check') {
            $('mVoucherCheckAccount').value = data.cashAccountCode || '';
            $('mVoucherCheckBank').value = data.checkBank || '';
            $('mVoucherCheckNumber').value = data.checkNumber || '';
            $('mVoucherCheckDate').value = data.checkDate || '';
        } else if (data.method === 'card') {
            $('mVoucherCardAccount').value = data.cashAccountCode || '';
            $('mVoucherCardRef').value = data.cardRef || '';
        } else {
            $('mVoucherOtherAccount').value = data.cashAccountCode || '';
        }

        onVoucherPartyChange();
        voucherEditorState.allocations = { ...(data.allocations || {}) };
        setTimeout(() => {
            Object.entries(voucherEditorState.allocations).forEach(([invK, amt]) => {
                document.querySelectorAll(`#mVoucherInvoicesList input[oninput*="${invK}"]`).forEach(inp => inp.value = amt);
            });
            updateAllocationSummary();
        }, 200);
        updateVoucherWords();
    }, 100);
}

window.editVoucher = function (key, type) {
    const data = type === 'receipt' ? window.receipts?.[key] : window.payments?.[key];
    if (!data) return;
    if (data.status !== 'draft') { toast('⚠️ لا يمكن تعديل سند مرحّل (استخدم 🔓✏️ للمدير المالي)', 'er'); return; }
    _populateVoucherEditor(key, type, data);
};

window.editPostedVoucher = async function (key, type) {
    const data = type === 'receipt' ? window.receipts?.[key] : window.payments?.[key];
    if (!data) return;
    if (data.status !== 'posted') { toast('⚠️ هذه الميزة للسندات المرحّلة فقط', 'er'); return; }

    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    if (!isAdmin && !isFinanceMgr && !canFn('edit_posted_' + type)) {
        toast('🚫 هذه الميزة مخصصة للمدير المالي ومدير النظام', 'er');
        return;
    }

    const party = type === 'receipt' ? window.customers?.[data.partyId] : window.vendors?.[data.partyId];
    const partyLabel = type === 'receipt' ? 'العميل' : 'المورد';
    const docLabel = type === 'receipt' ? 'سند قبض' : 'سند صرف';

    const warningMsg = `⚠️ تنبيه هام\n\nأنت على وشك تعديل ${docLabel} مرحّل.\n\nرقم السند: ${data.number}\n${partyLabel}: ${party?.nameAr || ''}\nالمبلغ: ${fmt(data.amount)} ر\n\nهذه العملية:\n• تُسجَّل بسجل تدقيق دائم\n• تُلغى تخصيصات الفواتير القديمة\n• تُلغى القيد القديم ويُنشأ قيد جديد\n• تؤثر على رصيد ${partyLabel} والفواتير\n\nهل تريد المتابعة؟`;
    if (!await cf2(warningMsg)) return;

    _populateVoucherEditor(key, type, data);

    setTimeout(() => {
        $('mVoucherTitle').innerHTML = `🔓✏️ <span style="color:#8e44ad">تعديل ${docLabel} مرحّل</span> — ${data.number}`;
        voucherEditorState.editingPosted = true;
        voucherEditorState.originalVoucher = JSON.parse(JSON.stringify(data));

        const savePosted = $('mVoucherSavePosted');
        if (savePosted) {
            savePosted.innerHTML = '🔓 حفظ التعديل (يبقى مرحّلاً)';
            savePosted.style.background = '#8e44ad';
        }
        const draftBtn = document.querySelector('button[onclick="saveVoucher(\'draft\')"]');
        if (draftBtn) draftBtn.style.display = 'none';
    }, 150);

    toast('🔓 وضع تعديل سند مرحّل — سيُعاد إنشاء القيد', 'wn', 6000);
};

window.postVoucher = async function (key, type) {
    const data = type === 'receipt' ? window.receipts?.[key] : window.payments?.[key];
    if (!data) return;
    if (data.status !== 'draft') return;
    const docLabel = type === 'receipt' ? 'سند القبض' : 'سند الصرف';
    if (!await cf2(`هل تريد ترحيل ${docLabel} ${data.number}؟\nسيُنشأ قيد محاسبي تلقائي بمبلغ ${fmt(data.amount)} ر`)) return;

    try {
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        const now = new Date().toISOString();
        const path = type === 'receipt' ? 'ledger/receipts/' : 'ledger/payments/';
        await update(ref(db, path + key), { status: 'posted', postedAt: now, postedBy: userId });
        await allocateToInvoices(data.allocations, type, key);
        await createJournalForVoucher(key, { ...data, status: 'posted', postedAt: now, postedBy: userId });
        toast('✅ تم الترحيل وإنشاء القيد', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

window.deleteVoucher = async function (key, type) {
    const data = type === 'receipt' ? window.receipts?.[key] : window.payments?.[key];
    if (!data) return;
    if (data.status === 'draft') {
        if (!await cf2(`هل تريد حذف السند ${data.number} نهائياً؟`)) return;
        try {
            const path = type === 'receipt' ? 'ledger/receipts/' : 'ledger/payments/';
            await remove(ref(db, path + key));
            toast('✅ تم الحذف', 'ok');
        } catch (e) {
            toast('❌ خطأ: ' + (e.message || e), 'er');
        }
        return;
    }

    // سند مرحّل — يتطلب صلاحية المدير
    const canFn = (typeof can === 'function') ? can : () => true;
    const isAdmin = (typeof myP !== 'undefined' && myP?.role === 'admin');
    const isFinanceMgr = (typeof myP !== 'undefined' && myP?.role === 'finance_manager');
    if (!isAdmin && !isFinanceMgr && !canFn('edit_posted_' + type)) {
        toast('🚫 حذف السندات المرحّلة مخصص للمدير المالي ومدير النظام', 'er');
        return;
    }

    const docLabel = type === 'receipt' ? 'سند القبض' : 'سند الصرف';
    const partyLabel = type === 'receipt' ? 'العميل' : 'المورد';
    const party = type === 'receipt' ? window.customers?.[data.partyId] : window.vendors?.[data.partyId];
    const warningMsg = `⚠️ تحذير — حذف ${docLabel} مرحّل\n\nرقم السند: ${data.number}\n${partyLabel}: ${party?.nameAr || ''}\nالمبلغ: ${fmt(data.amount)} ر\n\nهذه العملية ستقوم بـ:\n• إلغاء القيد المحاسبي المرتبط\n• إلغاء تخصيصات الفواتير\n• حذف السند نهائياً لا يمكن التراجع عنه\n\nهل أنت متأكد؟`;
    if (!await cf2(warningMsg)) return;

    try {
        const path = type === 'receipt' ? 'ledger/receipts/' : 'ledger/payments/';
        const now = new Date().toISOString();
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';

        // 1. إلغاء القيد المحاسبي المرتبط
        if (data.journalEntryKey) {
            try {
                await update(ref(db, 'ledger/journalEntries/' + data.journalEntryKey), {
                    status: 'cancelled',
                    cancelledAt: now,
                    cancelledBy: userId,
                    cancelReason: `حذف ${docLabel} ${data.number}`
                });
            } catch (e) { console.error('Cancel journal error:', e); }
        }

        // 2. إلغاء تخصيصات الفواتير
        if (data.allocations && Object.keys(data.allocations).length) {
            await unallocateFromInvoices(data.allocations, type);
        }

        // 3. حذف السند
        await remove(ref(db, path + key));
        toast(`✅ تم حذف ${docLabel} ${data.number} وإلغاء القيد المرتبط`, 'ok', 5000);
    } catch (e) {
        console.error('Delete posted voucher error:', e);
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

