// 📤 تصدير Excel
// ═══════════════════════════════════════════════════════════════════

window.exportVouchersExcel = function (type) {
    const data = type === 'receipt' ? (window.receipts || {}) : (window.payments || {});
    const vouchers = Object.values(data);
    if (!vouchers.length) { toast('⚠️ لا توجد بيانات', 'er'); return; }

    const partyLabel = type === 'receipt' ? 'العميل' : 'المورد';
    const partySource = type === 'receipt' ? (window.customers || {}) : (window.vendors || {});
    const methodLabels = { cash: 'نقدي', bank_transfer: 'تحويل بنكي', check: 'شيك', card: 'بطاقة', other: 'أخرى' };

    const rows = vouchers.sort((a, b) => (a.date || '').localeCompare(b.date || '')).map(v => {
        const party = partySource[v.partyId];
        return {
            'رقم السند': v.number || '',
            'التاريخ': v.date || '',
            [partyLabel]: party?.nameAr || '',
            'البيان': v.description || '',
            'طريقة الدفع': methodLabels[v.method] || '',
            'الحساب النقدي': v.cashAccountCode || '',
            'المبلغ': v.amount || 0,
            'الحالة': v.status || '',
            'رقم القيد': v.journalEntryNumber || '',
            'ملاحظات': v.notes || ''
        };
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(10).fill({ wch: 16 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, type === 'receipt' ? 'سندات القبض' : 'سندات الصرف');
        const fileName = (type === 'receipt' ? 'سندات_القبض_' : 'سندات_الصرف_') + new Date().toISOString().substring(0, 10) + '.xlsx';
        XLSX.writeFile(wb, fileName);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

