// 📤 تصدير Excel
// ═══════════════════════════════════════════════════════════════════

window.exportInventoryExcel = function () {
    const items = Object.entries(window.inventoryItems || {});
    if (!items.length) { toast('⚠️ لا توجد أصناف', 'er'); return; }

    const rows = items.map(([key, it]) => {
        const bal = calcInvItemBalance(key);
        const cat = INV_CATEGORIES[it.category] || { label: '' };
        return {
            'الرمز': it.code || '',
            'النوع': it.type === 'service' ? 'خدمة' : 'مادة',
            'الفئة': cat.label.replace(/[^\u0600-\u06FF\s]/g, '').trim(),
            'الاسم بالعربية': it.nameAr || '',
            'الاسم بالإنجليزية': it.nameEn || '',
            'الوصف': it.description || '',
            'الوحدة': INV_UNITS[it.unit] || '',
            'الرصيد الافتتاحي': it.openingQty || 0,
            'إجمالي الدخول': bal.totalIn,
            'إجمالي الخروج': bal.totalOut,
            'الرصيد الحالي': bal.balance,
            'الحد الأدنى': it.minQty || 0,
            'سعر التكلفة': it.costPrice || 0,
            'متوسط التكلفة': bal.avgCost,
            'سعر البيع': it.salePrice || 0,
            'قيمة المخزون': bal.balance * (parseFloat(it.costPrice) || 0),
            'VAT%': it.vatRate || 0,
            'الحالة': it.active !== false ? 'نشط' : 'معطّل'
        };
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(18).fill({ wch: 14 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'المخزون');
        XLSX.writeFile(wb, `المخزون_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

window.exportInvMovementsExcel = function () {
    const moves = Object.entries(window.inventoryMovements || {});
    if (!moves.length) { toast('⚠️ لا توجد حركات', 'er'); return; }

    const reasons = { ...INV_MOV_REASONS_IN, ...INV_MOV_REASONS_OUT };
    const rows = moves.sort((a, b) => (a[1].date || '').localeCompare(b[1].date || '')).map(([k, m]) => {
        const item = window.inventoryItems?.[m.itemId];
        const proj = m.projectId && window.projects?.[m.projectId] ? window.projects[m.projectId].name : '';
        const qty = parseFloat(m.qty) || 0;
        const price = parseFloat(m.unitPrice) || 0;
        return {
            'رقم الحركة': m.number || '',
            'التاريخ': m.date || '',
            'النوع': m.type === 'in' ? 'دخول' : 'خروج',
            'رمز الصنف': item?.code || '',
            'اسم الصنف': item?.nameAr || '',
            'الوحدة': INV_UNITS[item?.unit] || '',
            'الكمية': qty,
            'سعر الوحدة': price,
            'الإجمالي': qty * price,
            'السبب': (reasons[m.reason] || '').replace(/[^\u0600-\u06FF\s]/g, '').trim(),
            'المشروع': proj,
            'البيان': m.description || '',
            'ملاحظات': m.notes || ''
        };
    });

    try {
        const ws = XLSX.utils.json_to_sheet(rows);
        ws['!cols'] = Array(13).fill({ wch: 14 });
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, 'حركات المخزون');
        XLSX.writeFile(wb, `حركات_المخزون_${new Date().toISOString().substring(0, 10)}.xlsx`);
        toast('✅ تم التصدير', 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

