// ║   🔗  [ACC11.5]   ━━━━   INVOICE → INVENTORY LINK   ━━━━                   ║
// ║                ربط فواتير المشتريات والمبيعات بحركات المخزون                  ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ── إنشاء حركات مخزون من فاتورة مشتريات (دخول) ─────────────────
async function createInventoryMovementsForPInv(invKey, inv) {
    if (!inv.lines || !inv.lines.length) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    let count = 0;

    for (const line of inv.lines) {
        if (!line.itemId) continue; // لا يوجد صنف مرتبط
        const item = window.inventoryItems?.[line.itemId];
        if (!item) continue;
        if (item.type === 'service') continue; // الخدمات لا تُسجَّل في المخزون

        try {
            const movNumber = generateInvMovNumber('in');
            await push(R.invmov, {
                number: movNumber,
                date: inv.date,
                type: 'in',
                itemId: line.itemId,
                warehouseId: inv.warehouseId || mainWarehouseId(),
                qty: parseFloat(line.qty) || 0,
                unitPrice: parseFloat(line.unitPrice) || 0,
                projectId: inv.projectId || '',
                reason: 'purchase',
                description: `شراء من فاتورة ${inv.number}${line.description ? ' - ' + line.description : ''}`,
                notes: `مرتبط تلقائياً بفاتورة مشتريات ${inv.number}`,
                sourceType: 'purchase_invoice',
                sourceKey: invKey,
                createdAt: now,
                createdBy: userId
            });
            count++;
        } catch (e) {
            console.error('Create inventory movement (purchase) error:', e);
        }
    }
    if (count > 0) {
        toast(`📦 تم إنشاء ${count} حركة دخول للمخزون تلقائياً`, 'ok', 4000);
    }
}

// ── إنشاء حركات مخزون من فاتورة مبيعات (خروج) ─────────────────
async function createInventoryMovementsForSInv(invKey, inv) {
    if (!inv.lines || !inv.lines.length) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    let count = 0;
    const warnings = [];

    for (const line of inv.lines) {
        if (!line.itemId) continue;
        const item = window.inventoryItems?.[line.itemId];
        if (!item) continue;
        if (item.type === 'service') continue; // الخدمات لا تُخصم من المخزون

        // فحص الرصيد (تنبيه فقط)
        const bal = calcInvItemBalance(line.itemId);
        const qty = parseFloat(line.qty) || 0;
        if (qty > bal.balance + 0.001) {
            warnings.push(`${item.nameAr}: مطلوب ${fmt(qty)} والرصيد ${fmt(bal.balance)}`);
        }

        try {
            const movNumber = generateInvMovNumber('out');
            // للمبيعات نستخدم متوسط التكلفة لحساب تكلفة البضاعة المباعة (COGS)
            const cogsPrice = bal.avgCost > 0 ? bal.avgCost : (parseFloat(item.costPrice) || parseFloat(line.unitPrice) || 0);
            await push(R.invmov, {
                number: movNumber,
                date: inv.date,
                type: 'out',
                itemId: line.itemId,
                qty,
                unitPrice: cogsPrice, // تكلفة الخروج (للقيد المحاسبي للمخزون)
                salePrice: parseFloat(line.unitPrice) || 0, // سعر البيع للمرجعية
                projectId: inv.projectId || '',
                reason: 'sale',
                description: `بيع - فاتورة ${inv.number}${line.description ? ' - ' + line.description : ''}`,
                notes: `مرتبط تلقائياً بفاتورة مبيعات ${inv.number}`,
                sourceType: 'sales_invoice',
                sourceKey: invKey,
                createdAt: now,
                createdBy: userId
            });
            count++;
        } catch (e) {
            console.error('Create inventory movement (sale) error:', e);
        }
    }
    if (count > 0) {
        toast(`📦 تم إنشاء ${count} حركة خروج للمخزون تلقائياً`, 'ok', 4000);
    }
    if (warnings.length > 0) {
        toast(`⚠️ تنبيه: بعض الأصناف بدون رصيد كافٍ:\n${warnings.slice(0, 3).join('\n')}`, 'wn', 8000);
    }
}

// ── حذف حركات المخزون المرتبطة بفاتورة (عند تعديل/إلغاء/حذف) ─────────────────
async function deleteInventoryMovementsForInvoice(sourceType, invKey) {
    if (!window.inventoryMovements) return;
    const movementsToDelete = Object.entries(window.inventoryMovements)
        .filter(([, m]) => m.sourceType === sourceType && m.sourceKey === invKey);

    for (const [mKey] of movementsToDelete) {
        try {
            await remove(ref(db, 'ledger/inventoryMovements/' + mKey));
        } catch (e) {
            console.error('Delete inventory movement error:', e);
        }
    }
    if (movementsToDelete.length > 0) {
        console.log(`🗑️ تم حذف ${movementsToDelete.length} حركة مخزون مرتبطة بـ ${sourceType}/${invKey}`);
    }
}

