let invReportState = {
    activeReport: 'balance',
    fromDate: '', toDate: '',
    categoryFilter: '', typeFilter: 'material',
    itemFilter: '', movTypeFilter: '', projectFilter: ''
};

window.renderInventoryReports = function () {
    const container = $('pg-inventoryreports'); if (!container) return;
    if (!invReportState.toDate) {
        const today = new Date();
        invReportState.fromDate = today.getFullYear() + '-01-01';
        invReportState.toDate = today.toISOString().slice(0, 10);
    }
    container.innerHTML = `
        <div style="background:linear-gradient(135deg,#1a5276 0%,#2980b9 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(41,128,185,.25)">
            <div>
                <div style="font-size:11px;opacity:.85;letter-spacing:1px">INVENTORY REPORTS</div>
                <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📊 تقارير المخزون</h1>
                <p style="margin:6px 0 0;font-size:12px;opacity:.95">تقارير احترافية: الأرصدة، الحركات، التنبيهات، التقييم، كرت الصنف</p>
            </div>
        </div>
        <div class="card" style="margin-bottom:14px;padding:14px">
            <div style="font-size:13px;font-weight:800;color:#1a3a5c;margin-bottom:10px">🎯 اختر نوع التقرير</div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:8px">
                ${invRptTab('balance', '📦 الأرصدة الحالية', '#1a5276')}
                ${invRptTab('movements', '📈 حركة المخزون', '#27ae60')}
                ${invRptTab('lowstock', '⚠️ تحت الحد الأدنى', '#c0392b')}
                ${invRptTab('valuation', '💰 تقييم المخزون', '#e67e22')}
                ${invRptTab('itemcard', '📋 كشف صنف', '#8e44ad')}
                ${invRptTab('stockcount', '🧮 جرد دوري', '#16a085')}
                ${invRptTab('aging', '🕒 أصناف راكدة', '#7f8c8d')}
                ${invRptTab('dashboard', '📟 لوحة المخزون', '#2c3e50')}
            </div>
        </div>
        <div id="invReportContent"></div>
    `;
    renderActiveInvReport();
};

function invRptTab(id, label, color) {
    const isActive = invReportState.activeReport === id;
    return `<button onclick="switchInvReport('${id}')" style="padding:12px;border-radius:8px;border:2px solid ${color};background:${isActive ? color : 'white'};color:${isActive ? 'white' : color};font-weight:800;cursor:pointer;font-size:12px;transition:all .2s">${label}</button>`;
}

window.switchInvReport = function (id) {
    invReportState.activeReport = id;
    renderActiveInvReport();
};

function renderActiveInvReport() {
    const container = $('invReportContent'); if (!container) return;
    switch (invReportState.activeReport) {
        case 'balance': renderStockBalanceReport(container); break;
        case 'movements': renderStockMovementsReport(container); break;
        case 'lowstock': renderLowStockReport(container); break;
        case 'valuation': renderValuationReport(container); break;
        case 'itemcard': renderItemCardReport(container); break;
        case 'stockcount': renderStockCountReport(container); break;
        case 'aging': renderInvAgingReport(container); break;
        case 'dashboard': renderInvDashboardReport(container); break;
    }
}

window.setInvReportDateRange = function (range) {
    const today = new Date();
    const y = today.getFullYear(); const m = today.getMonth();
    if (range === 'month') invReportState.fromDate = new Date(y, m, 1).toISOString().slice(0, 10);
    else if (range === 'quarter') invReportState.fromDate = new Date(y, Math.floor(m / 3) * 3, 1).toISOString().slice(0, 10);
    else if (range === 'year') invReportState.fromDate = y + '-01-01';
    invReportState.toDate = today.toISOString().slice(0, 10);
    renderActiveInvReport();
};

