// ============================================================
// [ACC-VAT] VAT Return (الإقرار الضريبي — ضريبة القيمة المضافة)
// ============================================================
const VAT_OUT_ACC = '2140';
const VAT_IN_ACC = '1180';

window._vatState = window._vatState || (() => {
    const now = new Date();
    return {
        ptype: 'quarter',
        month: now.toISOString().slice(0, 7),
        quarter: 'Q' + (Math.floor(now.getMonth() / 3) + 1),
        year: now.getFullYear(),
        from: '', to: '',
        view: 'return'   // return | reconcile (مطابقة ملفين ضريبيين)
    };
})();

function vatPeriod(st) {
    let from, to, label;
    const y = st.year;
    if (st.ptype === 'month') {
        const [yy, mm] = st.month.split('-').map(Number);
        from = `${yy}-${String(mm).padStart(2, '0')}-01`;
        const lastDay = new Date(yy, mm, 0).getDate();
        to = `${yy}-${String(mm).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
        label = `شهر ${mm}/${yy}`;
    } else if (st.ptype === 'quarter') {
        const q = parseInt(st.quarter.replace('Q', ''));
        const startMonth = (q - 1) * 3 + 1;
        const endMonth = startMonth + 2;
        from = `${y}-${String(startMonth).padStart(2, '0')}-01`;
        const lastDay = new Date(y, endMonth, 0).getDate();
        to = `${y}-${String(endMonth).padStart(2, '0')}-${String(lastDay).padStart(2, '0')}`;
        label = `${st.quarter} ${y}`;
    } else if (st.ptype === 'year') {
        from = `${y}-01-01`;
        to = `${y}-12-31`;
        label = `سنة ${y}`;
    } else {
        from = st.from;
        to = st.to;
        label = (from && to) ? `${from} → ${to}` : 'فترة مخصصة';
    }
    return { from, to, label };
}

function vatCompute(from, to) {
    const res = {
        ledgerOut: 0, ledgerIn: 0, outCount: 0, inCount: 0,
        sales: { '15': { base: 0, vat: 0 }, '5': { base: 0, vat: 0 }, '0': { base: 0, vat: 0 } },
        purch: { '15': { base: 0, vat: 0 }, '5': { base: 0, vat: 0 }, '0': { base: 0, vat: 0 } },
        invSalesVat: 0, invPurchVat: 0, salesBase: 0, purchBase: 0,
        outAdj: 0, inAdj: 0, net: 0
    };
    const entries = window.journalEntries || {};
    Object.entries(entries).forEach(([key, e]) => {
        if (e.status !== 'posted') return;
        (e.lines || []).forEach(l => {
            const effDate = l.date || e.date || '';
            if (!effDate || effDate < from || effDate > to) return;
            if (l.accountCode === VAT_OUT_ACC) {
                res.ledgerOut += (parseFloat(l.credit) || 0) - (parseFloat(l.debit) || 0);
                res.outCount++;
            } else if (l.accountCode === VAT_IN_ACC) {
                res.ledgerIn += (parseFloat(l.debit) || 0) - (parseFloat(l.credit) || 0);
                res.inCount++;
            }
        });
    });

    const sales = window.salesInvoices || window.invoices || {};
    Object.entries(sales).forEach(([key, inv]) => {
        if (inv.status !== 'posted' && inv.status !== 'confirmed') return;
        const d = inv.date || '';
        if (!d || d < from || d > to) return;
        (inv.lines || inv.items || []).forEach(it => {
            const rate = String(it.vatRate ?? inv.vatRate ?? 15);
            const base = (parseFloat(it.qty) || 1) * (parseFloat(it.price) || parseFloat(it.amount) || 0);
            const vat = base * (parseFloat(rate) / 100);
            if (!res.sales[rate]) res.sales[rate] = { base: 0, vat: 0 };
            res.sales[rate].base += base;
            res.sales[rate].vat += vat;
            res.salesBase += base;
            res.invSalesVat += vat;
        });
    });

    const purch = window.purchaseInvoices || {};
    Object.entries(purch).forEach(([key, inv]) => {
        if (inv.status !== 'posted' && inv.status !== 'confirmed') return;
        const d = inv.date || '';
        if (!d || d < from || d > to) return;
        (inv.lines || inv.items || []).forEach(it => {
            const rate = String(it.vatRate ?? inv.vatRate ?? 15);
            const base = (parseFloat(it.qty) || 1) * (parseFloat(it.price) || parseFloat(it.amount) || 0);
            const vat = base * (parseFloat(rate) / 100);
            if (!res.purch[rate]) res.purch[rate] = { base: 0, vat: 0 };
            res.purch[rate].base += base;
            res.purch[rate].vat += vat;
            res.purchBase += base;
            res.invPurchVat += vat;
        });
    });

    res.outAdj = res.ledgerOut - res.invSalesVat;
    res.inAdj = res.ledgerIn - res.invPurchVat;
    res.net = res.ledgerOut - res.ledgerIn;
    return res;
}

window.renderVatReturn = function () {
    const pg = $('pg-vatreturn');
    if (!pg) return;
    if (typeof fsExtEnsureListeners === 'function') fsExtEnsureListeners();
    const st = window._vatState;

    // شريط التبديل بين الإقرار ومديول المطابقة
    const viewTabs = `
    <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
        <button class="btn ${st.view !== 'reconcile' ? 'pri' : ''}" onclick="vatSetView('return')" style="${st.view !== 'reconcile' ? 'background:#0d9488;color:#fff' : ''};padding:10px 18px;font-weight:800">🧾 الإقرار الضريبي</button>
        <button class="btn ${st.view === 'reconcile' ? 'pri' : ''}" onclick="vatSetView('reconcile')" style="${st.view === 'reconcile' ? 'background:#0d9488;color:#fff' : ''};padding:10px 18px;font-weight:800">🔍 مطابقة ملفين ضريبيين</button>
    </div>`;

    if (st.view === 'reconcile') {
        pg.innerHTML = `
        <div class="card" style="background:linear-gradient(135deg,#0f766e,#0d9488);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
            <h2 style="margin:0;display:flex;align-items:center;gap:8px">🔍 مطابقة ملفين ضريبيين — محرّك مطابقة ذكي</h2>
            <div style="opacity:.9;margin-top:4px;font-size:13px">ارفع ملفين (مثلاً: ملف ضريبة المشتريات وكشف حساب المورد)، ويتعرّف المحرّك تلقائياً على التواريخ والمبالغ والأرقام والأسماء ويطابقها ويُظهر الفروقات</div>
        </div>` + viewTabs + vatRecRender();
        setTimeout(() => { if (window._vatRec && window._vatRec.result) vatRecBuildChart(); }, 0);
        return;
    }

    const byCode = brByCode ? brByCode() : {};
    const hasOut = !!byCode[VAT_OUT_ACC];
    const hasIn = !!byCode[VAT_IN_ACC];

    const period = vatPeriod(st);
    const data = (period.from && period.to) ? vatCompute(period.from, period.to) : null;

    const years = [];
    const curY = new Date().getFullYear();
    for (let y = curY; y >= curY - 4; y--) years.push(y);

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#0f766e,#0d9488);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">🧾 الإقرار الضريبي — ضريبة القيمة المضافة</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">احتساب الضريبة شهرياً، ربع سنوياً، سنوياً، أو لفترة مخصصة وفق نموذج هيئة الزكاة والضريبة والجمارك (ZATCA)</div>
    </div>` + viewTabs;

    if (!hasOut || !hasIn) {
        html += `<div class="card" style="background:#fef3c7;border:1px solid #f59e0b;padding:12px 16px;border-radius:8px;margin-bottom:14px;color:#92400e">
            ⚠️ تنبيه: ${!hasOut ? `حساب ضريبة المخرجات المستحقة (${VAT_OUT_ACC}) غير موجود في شجرة الحسابات. ` : ''}${!hasIn ? `حساب ضريبة المدخلات المدفوعة (${VAT_IN_ACC}) غير موجود في شجرة الحسابات.` : ''}
        </div>`;
    }

    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px">
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px">
            <button class="btn ${st.ptype === 'month' ? 'pri' : ''}" onclick="vatSetType('month')">شهري</button>
            <button class="btn ${st.ptype === 'quarter' ? 'pri' : ''}" onclick="vatSetType('quarter')">ربع سنوي</button>
            <button class="btn ${st.ptype === 'year' ? 'pri' : ''}" onclick="vatSetType('year')">سنوي</button>
            <button class="btn ${st.ptype === 'custom' ? 'pri' : ''}" onclick="vatSetType('custom')">فترة مخصصة</button>
        </div>
        <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center">`;

    if (st.ptype === 'month') {
        html += `<label>الشهر: <input type="month" value="${st.month}" onchange="vatSetField('month', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd"></label>`;
    } else if (st.ptype === 'quarter') {
        html += `<label>الربع: <select onchange="vatSetField('quarter', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
            ${['Q1', 'Q2', 'Q3', 'Q4'].map(q => `<option value="${q}" ${st.quarter === q ? 'selected' : ''}>${q}</option>`).join('')}
        </select></label>
        <label>السنة: <select onchange="vatSetField('year', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
            ${years.map(y => `<option value="${y}" ${st.year === y ? 'selected' : ''}>${y}</option>`).join('')}
        </select></label>`;
    } else if (st.ptype === 'year') {
        html += `<label>السنة: <select onchange="vatSetField('year', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
            ${years.map(y => `<option value="${y}" ${st.year === y ? 'selected' : ''}>${y}</option>`).join('')}
        </select></label>`;
    } else {
        html += `<label>من: <input type="date" value="${st.from}" onchange="vatSetField('from', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd"></label>
        <label>إلى: <input type="date" value="${st.to}" onchange="vatSetField('to', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd"></label>`;
    }

    html += `<span style="font-weight:700;color:#0d9488;margin-right:auto">${period.label}</span>
        </div>
    </div>`;

    if (data) {
        const netLabel = data.net >= 0 ? 'ضريبة مستحقة الدفع' : 'ضريبة قابلة للاسترداد';
        const netColor = data.net >= 0 ? '#dc2626' : '#16a34a';

        html += `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin-bottom:14px">
            <div class="card" style="padding:14px 16px;text-align:center">
                <div style="color:#666;font-size:13px">إجمالي ضريبة المخرجات (المبيعات)</div>
                <div style="font-size:24px;font-weight:800;color:#0d9488">${fmt(data.ledgerOut)}</div>
            </div>
            <div class="card" style="padding:14px 16px;text-align:center">
                <div style="color:#666;font-size:13px">إجمالي ضريبة المدخلات (المشتريات)</div>
                <div style="font-size:24px;font-weight:800;color:#7c3aed">${fmt(data.ledgerIn)}</div>
            </div>
            <div class="card" style="padding:14px 16px;text-align:center;border:2px solid ${netColor}">
                <div style="color:#666;font-size:13px">${netLabel}</div>
                <div style="font-size:24px;font-weight:800;color:${netColor}">${fmt(Math.abs(data.net))}</div>
            </div>
        </div>`;

        const rateRow = (label, b15, b5, b0) => `
            <tr>
                <td style="font-weight:600">${label}</td>
                <td>${fmt(b15.base)}</td><td>${fmt(b15.vat)}</td>
                <td>${fmt(b5.base)}</td><td>${fmt(b5.vat)}</td>
                <td>${fmt(b0.base)}</td><td>${fmt(b0.vat)}</td>
            </tr>`;

        html += `<div class="card" style="padding:14px 16px;margin-bottom:14px;overflow:auto">
            <h3 style="margin-top:0">نموذج الإقرار الضريبي (تفصيلي)</h3>
            <table class="tbl" style="width:100%;text-align:center">
                <thead>
                    <tr style="background:#f8f9fa">
                        <th>البند</th>
                        <th colspan="2">نسبة 15%</th>
                        <th colspan="2">نسبة 5%</th>
                        <th colspan="2">نسبة 0% / معفى</th>
                    </tr>
                    <tr style="background:#f8f9fa;font-size:12px;color:#666">
                        <th></th><th>الأساس</th><th>الضريبة</th><th>الأساس</th><th>الضريبة</th><th>الأساس</th><th>الضريبة</th>
                    </tr>
                </thead>
                <tbody>
                    ${rateRow('المبيعات / الإيرادات (من الفواتير)', data.sales['15'], data.sales['5'], data.sales['0'])}
                    <tr><td colspan="7" style="text-align:right;color:#666;font-size:12px">تسويات ضريبة المخرجات (دفتر الأستاذ − الفواتير): ${fmt(data.outAdj)}</td></tr>
                    <tr style="font-weight:700;background:#f0fdfa">
                        <td>إجمالي ضريبة المخرجات (من السجلات)</td>
                        <td colspan="6">${fmt(data.ledgerOut)}</td>
                    </tr>
                    ${rateRow('المشتريات / المصروفات (من الفواتير)', data.purch['15'], data.purch['5'], data.purch['0'])}
                    <tr><td colspan="7" style="text-align:right;color:#666;font-size:12px">تسويات ضريبة المدخلات (دفتر الأستاذ − الفواتير): ${fmt(data.inAdj)}</td></tr>
                    <tr style="font-weight:700;background:#faf5ff">
                        <td>إجمالي ضريبة المدخلات (من السجلات)</td>
                        <td colspan="6">${fmt(data.ledgerIn)}</td>
                    </tr>
                    <tr style="font-weight:800;background:${data.net >= 0 ? '#fef2f2' : '#f0fdf4'};color:${netColor}">
                        <td>صافي الضريبة (${netLabel})</td>
                        <td colspan="6">${fmt(Math.abs(data.net))}</td>
                    </tr>
                </tbody>
            </table>
        </div>`;

        html += `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
            <button class="btn pri" onclick="vatSaveReturn('draft')">💾 حفظ كمسودة</button>
            <button class="btn" style="background:#16a34a;color:#fff" onclick="vatSaveReturn('filed')">✅ اعتماد وتقديم الإقرار</button>
            <button class="btn" onclick="vatPrint()">🖨️ طباعة</button>
            <button class="btn" onclick="vatExport()">📊 تصدير Excel</button>
        </div>`;
    }

    const saved = window.vatReturns || {};
    const savedRows = Object.entries(saved).sort((a, b) => (b[1].to || '').localeCompare(a[1].to || ''));
    html += `<div class="card" style="padding:14px 16px">
        <h3 style="margin-top:0">📋 الإقرارات المحفوظة</h3>`;
    if (!savedRows.length) {
        html += `<div style="text-align:center;color:#999;padding:20px">لا توجد إقرارات محفوظة</div>`;
    } else {
        html += `<table class="tbl" style="width:100%;text-align:center">
            <thead><tr style="background:#f8f9fa"><th>الفترة</th><th>من</th><th>إلى</th><th>ضريبة المخرجات</th><th>ضريبة المدخلات</th><th>الصافي</th><th>الحالة</th><th>إجراءات</th></tr></thead>
            <tbody>`;
        savedRows.forEach(([key, r]) => {
            const f = r.figures || {};
            const netC = (f.net || 0) >= 0 ? '#dc2626' : '#16a34a';
            html += `<tr>
                <td>${r.label || ''}</td>
                <td>${r.from || ''}</td>
                <td>${r.to || ''}</td>
                <td>${fmt(f.ledgerOut || 0)}</td>
                <td>${fmt(f.ledgerIn || 0)}</td>
                <td style="color:${netC};font-weight:700">${fmt(Math.abs(f.net || 0))}</td>
                <td>${r.status === 'filed' ? '<span style="color:#16a34a;font-weight:700">✅ مقدم</span>' : '<span style="color:#f59e0b">📝 مسودة</span>'}</td>
                <td>
                    <button class="btn sm" onclick="vatOpenSaved('${key}')">عرض</button>
                    ${r.status !== 'filed' ? `<button class="btn sm" style="color:#dc2626" onclick="vatDeleteSaved('${key}')">حذف</button>` : ''}
                </td>
            </tr>`;
        });
        html += `</tbody></table>`;
    }
    html += `</div>`;

    pg.innerHTML = html;
};

window.vatSetType = function (ptype) {
    window._vatState.ptype = ptype;
    renderVatReturn();
};

window.vatSetField = function (field, value) {
    window._vatState[field] = field === 'year' ? parseInt(value) : value;
    renderVatReturn();
};

window.vatSaveReturn = async function (status) {
    const st = window._vatState;
    const period = vatPeriod(st);
    if (!period.from || !period.to) { toast('⚠️ يرجى تحديد الفترة', 'er'); return; }
    if (status === 'filed' && !brIsFinance()) {
        toast('🚫 اعتماد الإقرار يتطلب صلاحية المحاسبة المالية', 'er');
        return;
    }
    const data = vatCompute(period.from, period.to);
    const figures = {
        ledgerOut: data.ledgerOut, ledgerIn: data.ledgerIn,
        invSalesVat: data.invSalesVat, invPurchVat: data.invPurchVat,
        outAdj: data.outAdj, inAdj: data.inAdj, net: data.net,
        sales: data.sales, purch: data.purch
    };

    const saved = window.vatReturns || {};
    const existing = Object.entries(saved).find(([k, r]) => r.from === period.from && r.to === period.to);

    if (existing && existing[1].status === 'filed' && status !== 'filed') {
        toast('🔒 هذا الإقرار مُعتمد ومقدم بالفعل ولا يمكن تعديله', 'er');
        return;
    }

    const payload = {
        from: period.from, to: period.to, label: period.label,
        ptype: st.ptype, figures, status,
        updatedAt: Date.now(), updatedBy: brUser()
    };

    if (existing) {
        await update(ref(db, `ledger/vatReturns/${existing[0]}`), payload);
    } else {
        payload.createdAt = Date.now();
        payload.createdBy = brUser();
        await push(R.vatReturns, payload);
    }
    if (status === 'filed') logAudit('اعتماد إقرار ضريبي', 'المحاسبة', `اعتماد وتقديم الإقرار الضريبي للفترة ${period.label}`);
    toast(status === 'filed' ? '✅ تم اعتماد وتقديم الإقرار الضريبي' : '💾 تم حفظ المسودة', 'ok');
};

