console.log('✅ VAT Return module [ACC-VAT] loaded — monthly/quarterly/yearly/custom');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🔍  [ACC-VAT-REC]   مطابقة ملفين ضريبيين — محرّك مطابقة ذكي                 ║
// ║   تعرّف تلقائي على الأعمدة (تاريخ/مبلغ/ضريبة/رقم/جهة) + مطابقة ضبابية + فروقات  ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._vatRec = window._vatRec || { A: null, B: null, result: null, filter: 'all', tolAmt: 1, tolPct: 0.5, tolDays: 5, manualLinks: [], brokenPairs: [], cross: null, crossFrom: '', crossTo: '' };

window.vatSetView = function (v) { window._vatState.view = v; renderVatReturn(); };

// ── أدوات مساعدة ─────────────────
function vatRecNum(v) {
    if (typeof v === 'number') return isFinite(v) ? v : 0;
    if (v === null || v === undefined || v === '') return 0;
    const n = parseFloat(String(v).replace(/[٬,،\s]/g, '').replace(/[()]/g, m => '').replace(/[^\d.\-]/g, ''));
    return isNaN(n) ? 0 : n;
}
function vatRecStr(v) { return String(v == null ? '' : v).replace(/\s+/g, ' ').trim(); }
function vatRecNormStr(s) {
    return vatRecStr(s).toLowerCase()
        .replace(/[ً-ْ]/g, '')          // تشكيل
        .replace(/[أإآ]/g, 'ا').replace(/ة/g, 'ه').replace(/ى/g, 'ي').replace(/ؤ/g, 'و').replace(/ئ/g, 'ي')
        .replace(/[^ء-ي0-9a-z ]/g, ' ')
        .replace(/\b(ال|شركه|شركة|مؤسسه|مؤسسة|the)\b/g, ' ')
        .replace(/\s+/g, ' ').trim();
}
function vatRecNormDoc(s) { return vatRecStr(s).replace(/[^0-9A-Za-z]/g, '').replace(/^0+/, ''); }
function vatRecParseDate(v) {
    if (v == null || v === '') return null;
    if (v instanceof Date && !isNaN(v)) return v;
    if (typeof v === 'number' && v > 20000 && v < 80000) return new Date(Date.UTC(1899, 11, 30) + v * 86400000);
    const s = String(v).trim();
    let m = s.match(/^(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})/);
    if (m) { const d = new Date(+m[1], +m[2] - 1, +m[3]); return isNaN(d) ? null : d; }
    m = s.match(/^(\d{1,2})[-/.](\d{1,2})[-/.](\d{2,4})/);
    if (m) { let y = +m[3]; if (y < 100) y += 2000; const d = new Date(y, +m[2] - 1, +m[1]); return isNaN(d) ? null : d; }
    const d = new Date(s); return isNaN(d) ? null : d;
}
function vatRecNameSim(a, b) {
    const na = vatRecNormStr(a), nb = vatRecNormStr(b);
    if (!na || !nb) return 0;
    if (na === nb) return 1;
    const ta = new Set(na.split(' ').filter(Boolean)), tb = new Set(nb.split(' ').filter(Boolean));
    if (!ta.size || !tb.size) return 0;
    let inter = 0; ta.forEach(t => { if (tb.has(t)) inter++; });
    return inter / (ta.size + tb.size - inter); // Jaccard
}

// ── رفع ملف ─────────────────
window.vatRecUpload = function (input, slot) {
    const file = input.files && input.files[0]; if (!file) return;
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة قراءة الملفات غير محمّلة', 'er'); return; }
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const wb = XLSX.read(e.target.result, { type: 'array', cellDates: true });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false, defval: '' });
            if (!rows.length) { toast('⚠️ الملف فارغ', 'er'); input.value = ''; return; }
            const det = vatRecDetectCols(rows);
            window._vatRec[slot] = { name: file.name, rows, hdrIdx: det.hdrIdx, headers: rows[det.hdrIdx] || [], cols: det.cols, records: [] };
            vatRecBuildRecords(slot);
            window._vatRec.result = null;
            renderVatReturn();
            toast(`✅ تم تحميل الملف (${slot === 'A' ? 'أ' : 'ب'}) — ${window._vatRec[slot].records.length} سجل`, 'ok', 4000);
        } catch (err) { toast('❌ تعذّر قراءة الملف: ' + (err.message || err), 'er', 8000); }
        input.value = '';
    };
    reader.onerror = () => { toast('❌ خطأ في القراءة', 'er'); input.value = ''; };
    reader.readAsArrayBuffer(file);
};

// ── التعرّف التلقائي على الأعمدة ─────────────────
function vatRecDetectCols(rows) {
    const scan = Math.min(rows.length, 15);
    const kwAny = /تاريخ|مبلغ|ضريب|مورد|عميل|اسم|رقم|سند|فاتور|مدين|دائن|رصيد|بيان|قيم|خاضع|date|amount|tax|name|no|debit|credit|balance|total|vat/i;
    let hdrIdx = 0, best = -1;
    for (let i = 0; i < scan; i++) {
        const r = rows[i] || []; let c = 0;
        r.forEach(x => { const s = vatRecStr(x); if (s && kwAny.test(s)) c++; });
        if (c > best) { best = c; hdrIdx = i; }
    }
    const H = (rows[hdrIdx] || []).map(x => vatRecStr(x).toLowerCase());
    const find = (re, avoid) => H.findIndex(h => h && re.test(h) && !(avoid && avoid.test(h)));
    const ncol = H.length;
    const dataRows = rows.slice(hdrIdx + 1, hdrIdx + 60);

    const cols = { date: -1, doc: -1, party: -1, tax: -1, amount: -1, credit: -1 };
    cols.tax = find(/ضريب|قيمه مضاف|قيمة مضاف|vat|tax/);
    cols.date = find(/تاريخ|date/);
    cols.doc = find(/رقم|سند|فاتور|مستند|مرجع|no\b|inv|ref|doc/, /حساب/);
    cols.party = find(/مورد|عميل|اسم|جهه|جهة|طرف|بيان|supplier|customer|vendor|client|name|desc/);
    const debit = find(/مدين|debit|dr\b/), credit = find(/دائن|credit|cr\b/);
    if (debit > -1 && credit > -1) { cols.amount = debit; cols.credit = credit; }
    else cols.amount = find(/خاضع|صافي|مبلغ|قيم|amount|total|value|base|net/, /ضريب|رصيد|balance/);

    // قياس عددية كل عمود ونسبة التواريخ (للتعويض عند غياب العناوين)
    const numFrac = [], dateFrac = [], avgAbs = [], txtLen = [], uniq = [];
    for (let c = 0; c < ncol; c++) {
        let nn = 0, nd = 0, sum = 0, tl = 0, tot = 0; const seen = new Set();
        dataRows.forEach(r => {
            const v = r ? r[c] : ''; const s = vatRecStr(v); if (!s) return; tot++;
            const num = vatRecNum(v); if (s && (typeof v === 'number' || /^[()\-\d.,٬،\s]+$/.test(s)) && num !== 0) { nn++; sum += Math.abs(num); }
            if (vatRecParseDate(v)) nd++;
            tl += s.length; seen.add(s);
        });
        numFrac[c] = tot ? nn / tot : 0; dateFrac[c] = tot ? nd / tot : 0;
        avgAbs[c] = nn ? sum / nn : 0; txtLen[c] = tot ? tl / tot : 0; uniq[c] = seen.size;
    }
    if (cols.date === -1) { let bi = -1, bf = 0.5; dateFrac.forEach((f, c) => { if (f > bf) { bf = f; bi = c; } }); cols.date = bi; }
    if (cols.amount === -1) {
        let bi = -1, bv = 0; for (let c = 0; c < ncol; c++) { if (c === cols.tax || c === cols.date) continue; if (numFrac[c] > 0.6 && avgAbs[c] > bv) { bv = avgAbs[c]; bi = c; } } cols.amount = bi;
    }
    if (cols.party === -1) { let bi = -1, bl = 6; txtLen.forEach((l, c) => { if (numFrac[c] < 0.3 && dateFrac[c] < 0.3 && l > bl) { bl = l; bi = c; } }); cols.party = bi; }
    if (cols.doc === -1) { let bi = -1, bu = 0; for (let c = 0; c < ncol; c++) { if (c === cols.amount || c === cols.tax || c === cols.party || c === cols.date) continue; if (numFrac[c] > 0.5 && uniq[c] > bu) { bu = uniq[c]; bi = c; } } cols.doc = bi; }
    return { hdrIdx, cols };
}

// ── بناء السجلات من الأعمدة المحددة ─────────────────
function vatRecBuildRecords(slot) {
    const f = window._vatRec[slot]; if (!f) return;
    const { rows, hdrIdx, cols } = f;
    const recs = [];
    for (let i = hdrIdx + 1; i < rows.length; i++) {
        const r = rows[i]; if (!r) continue;
        const dateV = cols.date > -1 ? r[cols.date] : '';
        const date = vatRecParseDate(dateV);
        const docNo = cols.doc > -1 ? vatRecStr(r[cols.doc]) : '';
        const party = cols.party > -1 ? vatRecStr(r[cols.party]) : '';
        let amount = cols.amount > -1 ? vatRecNum(r[cols.amount]) : 0;
        if (cols.credit > -1) amount += vatRecNum(r[cols.credit]);
        amount = Math.abs(Math.round(amount * 100) / 100);
        const tax = cols.tax > -1 ? Math.abs(Math.round(vatRecNum(r[cols.tax]) * 100) / 100) : null;
        // تجاهل الصفوف الفارغة/الإجماليات (لا مبلغ ولا رقم ولا جهة)
        if (!amount && !docNo && !party) continue;
        if (!amount && tax === null) continue;
        recs.push({ id: slot + ':' + i, row: i, date, dateVal: date ? date.getTime() : null, docNo, party, amount, tax, used: false });
    }
    f.records = recs;
    // إعادة بناء السجلات تُلغي الروابط اليدوية (المعرّفات قد تتغيّر)
    window._vatRec.manualLinks = []; window._vatRec.brokenPairs = []; window._vatRec.cross = null;
}

window.vatRecSetCol = function (slot, field, idx) {
    const f = window._vatRec[slot]; if (!f) return;
    idx = parseInt(idx);
    f.cols[field] = isNaN(idx) ? -1 : idx;
    if (field === 'amount') f.cols.credit = -1; // التعيين اليدوي يلغي عمود الدائن التلقائي
    vatRecBuildRecords(slot);
    window._vatRec.result = null;
    renderVatReturn();
};
window.vatRecClear = function (slot) { window._vatRec[slot] = null; window._vatRec.result = null; renderVatReturn(); };
window.vatRecSetFilter = function (fl) { window._vatRec.filter = fl; renderVatReturn(); };
window.vatRecSetTol = function (field, val) { window._vatRec[field] = parseFloat(val) || 0; window._vatRec.result = null; renderVatReturn(); };

// ── مطابقة يدوية: ربط / فك ─────────────────
window.vatRecLink = function (aId, bId) {
    if (!aId || !bId) return;
    const R2 = window._vatRec;
    R2.brokenPairs = (R2.brokenPairs || []).filter(k => k !== aId + '|' + bId);
    R2.manualLinks = (R2.manualLinks || []).filter(l => l.aId !== aId && l.bId !== bId);
    R2.manualLinks.push({ aId, bId });
    vatRecRun();
    toast('🔗 تم الربط يدوياً', 'ok', 3000);
};
window.vatRecUnlink = function (aId, bId) {
    const R2 = window._vatRec;
    const wasManual = (R2.manualLinks || []).some(l => l.aId === aId && l.bId === bId);
    R2.manualLinks = (R2.manualLinks || []).filter(l => !(l.aId === aId && l.bId === bId));
    if (!wasManual) { R2.brokenPairs = R2.brokenPairs || []; R2.brokenPairs.push(aId + '|' + bId); }
    vatRecRun();
    toast('✂️ تم فكّ الارتباط', 'ok', 3000);
};

// ── محرّك المطابقة ─────────────────
window.vatRecRun = function () {
    const R2 = window._vatRec;
    if (!R2.A || !R2.B || !R2.A.records.length || !R2.B.records.length) { toast('⚠️ ارفع الملفين أولاً', 'er'); return; }
    const A = R2.A.records, B = R2.B.records;
    A.forEach(r => r.used = false); B.forEach(r => r.used = false);
    const tolAmt = R2.tolAmt, tolPct = R2.tolPct / 100, tolDays = R2.tolDays || 5;

    // فهرسة B حسب المبلغ المقرّب (للأداء) + حسب رقم المستند
    const byAmt = {}, byDoc = {};
    B.forEach((b, j) => {
        const k = Math.round(b.amount);
        (byAmt[k] = byAmt[k] || []).push(j);
        const d = vatRecNormDoc(b.docNo); if (d) (byDoc[d] = byDoc[d] || []).push(j);
    });

    const score = (a, b) => {
        const amtTol = Math.max(tolAmt, a.amount * tolPct);
        const amtClose = Math.abs(a.amount - b.amount) <= amtTol;
        const docEq = a.docNo && b.docNo && vatRecNormDoc(a.docNo) === vatRecNormDoc(b.docNo) && vatRecNormDoc(a.docNo).length > 0;
        if (!amtClose && !docEq) return 0;
        let s = 0;
        if (amtClose) s += 50 + 10 * (1 - Math.abs(a.amount - b.amount) / Math.max(amtTol, 1e-9));
        if (docEq) s += 40;
        if (a.tax != null && b.tax != null) { const tt = Math.max(tolAmt, Math.abs(a.tax) * tolPct); if (Math.abs(a.tax - b.tax) <= tt) s += 15; }
        if (a.dateVal && b.dateVal) { const days = Math.abs(a.dateVal - b.dateVal) / 86400000; if (days <= tolDays) s += 20 * (1 - days / tolDays); }
        s += 15 * vatRecNameSim(a.party, b.party);
        return s;
    };

    const aById = {}, bById = {};
    A.forEach(a => aById[a.id] = a); B.forEach(b => bById[b.id] = b);
    const mkPair = (a, b, sc, manual) => ({ a, b, score: sc, manual: !!manual, amtDiff: Math.round((a.amount - b.amount) * 100) / 100, taxDiff: (a.tax != null && b.tax != null) ? Math.round((a.tax - b.tax) * 100) / 100 : null });
    const matched = [];

    // 1) الروابط اليدوية أولاً (لها الأولوية المطلقة)
    (R2.manualLinks || []).forEach(lk => {
        const a = aById[lk.aId], b = bById[lk.bId];
        if (!a || !b || a.used || b.used) return;
        a.used = true; b.used = true;
        matched.push(mkPair(a, b, 100, true));
    });

    // 2) المطابقة التلقائية على المتبقّي (مع تخطّي الأزواج التي فكّها المستخدم)
    const broken = new Set(R2.brokenPairs || []);
    const cand = [];
    A.forEach((a, i) => {
        if (a.used) return;
        const seen = new Set();
        const k = Math.round(a.amount);
        [k - 1, k, k + 1].forEach(kk => (byAmt[kk] || []).forEach(j => seen.add(j)));
        const d = vatRecNormDoc(a.docNo); if (d) (byDoc[d] || []).forEach(j => seen.add(j));
        seen.forEach(j => { if (B[j].used) return; if (broken.has(a.id + '|' + B[j].id)) return; const s = score(a, B[j]); if (s >= 45) cand.push({ i, j, s }); });
    });
    cand.sort((x, y) => y.s - x.s);
    cand.forEach(c => {
        if (A[c.i].used || B[c.j].used) return;
        A[c.i].used = true; B[c.j].used = true;
        matched.push(mkPair(A[c.i], B[c.j], c.s, false));
    });
    const onlyA = A.filter(r => !r.used), onlyB = B.filter(r => !r.used);

    // اقتراحات: لكل سجل غير مطابَق في (أ) أقرب 3 سجلات من (ب) غير المطابَقة (حتى لو دون العتبة)
    onlyA.forEach(a => {
        a._suggest = onlyB.map(b => ({ b, s: score(a, b) })).filter(x => x.s > 0).sort((x, y) => y.s - x.s).slice(0, 3);
    });

    const diffTol = Math.max(tolAmt, 0.01);
    const exact = matched.filter(m => Math.abs(m.amtDiff) <= diffTol && (m.taxDiff == null || Math.abs(m.taxDiff) <= diffTol));
    const diffs = matched.filter(m => !(Math.abs(m.amtDiff) <= diffTol && (m.taxDiff == null || Math.abs(m.taxDiff) <= diffTol)));

    R2.result = {
        matched, exact, diffs, onlyA, onlyB,
        sumA: A.reduce((s, r) => s + r.amount, 0), sumB: B.reduce((s, r) => s + r.amount, 0),
        taxA: A.reduce((s, r) => s + (r.tax || 0), 0), taxB: B.reduce((s, r) => s + (r.tax || 0), 0),
        sumDiff: diffs.reduce((s, m) => s + Math.abs(m.amtDiff), 0),
        sumOnlyA: onlyA.reduce((s, r) => s + r.amount, 0), sumOnlyB: onlyB.reduce((s, r) => s + r.amount, 0)
    };
    renderVatReturn();
    toast(`✅ اكتملت المطابقة: ${exact.length} تامة · ${diffs.length} بفروقات · ${onlyA.length} في(أ) · ${onlyB.length} في(ب)`, 'ok', 6000);
};

// ── العرض ─────────────────
function vatRecRender() {
    const R2 = window._vatRec;
    const fmtD = d => d ? d.toISOString().slice(0, 10) : '—';

    const slotCard = (slot) => {
        const f = R2[slot]; const lbl = slot === 'A' ? 'الملف (أ)' : 'الملف (ب)';
        const color = slot === 'A' ? '#2563eb' : '#7c3aed';
        if (!f) return `
            <div style="border:2px dashed ${color};border-radius:12px;padding:18px;text-align:center;background:#fafbff">
                <div style="font-size:14px;font-weight:900;color:${color};margin-bottom:8px">${lbl}</div>
                <label class="btn" style="background:${color};color:#fff;padding:10px 18px;font-weight:800;cursor:pointer">
                    📤 رفع الملف
                    <input type="file" accept=".xlsx,.xls,.csv" style="display:none" onchange="vatRecUpload(this,'${slot}')">
                </label>
                <div style="font-size:11px;color:#888;margin-top:8px">Excel أو CSV — يتعرّف النظام على الأعمدة تلقائياً</div>
            </div>`;
        const opt = (field) => {
            const idx = f.cols[field];
            return `<select onchange="vatRecSetCol('${slot}','${field}',this.value)" style="width:100%;padding:5px;border:1px solid #d0d7e0;border-radius:5px;font-family:inherit;font-size:11px">
                <option value="-1" ${idx === -1 ? 'selected' : ''}>— غير محدّد —</option>
                ${(f.headers || []).map((h, i) => `<option value="${i}" ${idx === i ? 'selected' : ''}>${vatRecStr(h) || ('عمود ' + (i + 1))}</option>`).join('')}
            </select>`;
        };
        return `
            <div style="border:2px solid ${color};border-radius:12px;padding:14px;background:#fff">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
                    <div style="font-size:13px;font-weight:900;color:${color}">${lbl} <span style="font-size:11px;font-weight:400;color:#888">${f.records.length} سجل</span></div>
                    <button onclick="vatRecClear('${slot}')" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:12px">✖️ إزالة</button>
                </div>
                <div style="font-size:11px;color:#16a085;background:#e8f8f5;border-radius:5px;padding:4px 8px;margin-bottom:10px">📄 ${f.name}</div>
                <div style="display:grid;grid-template-columns:auto 1fr;gap:6px 8px;align-items:center;font-size:11px">
                    <span style="color:#666">📅 التاريخ</span>${opt('date')}
                    <span style="color:#666">💰 المبلغ</span>${opt('amount')}
                    <span style="color:#666">🧾 الضريبة</span>${opt('tax')}
                    <span style="color:#666">🔢 رقم المستند</span>${opt('doc')}
                    <span style="color:#666">🏢 الجهة</span>${opt('party')}
                </div>
            </div>`;
    };

    let html = `
        <div class="card" style="padding:16px;margin-bottom:14px">
            <div style="font-size:13px;color:#555;margin-bottom:12px;line-height:1.7">💡 ارفع الملفين، وتحقّق من تعيين الأعمدة الذي تعرّف عليه النظام تلقائياً (يمكنك تصحيح أي عمود)، ثم اضغط "تشغيل المطابقة". المحرّك يطابق بالمبلغ + التاريخ + الاسم + رقم المستند معاً مع سماحية قابلة للضبط.</div>
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:14px">
                ${slotCard('A')}
                ${slotCard('B')}
            </div>
            <div style="display:flex;gap:14px;flex-wrap:wrap;align-items:center;margin-top:14px;padding-top:12px;border-top:1px dashed #e0e0e0">
                <label style="font-size:12px;color:#555">سماحية المبلغ المطلقة: <input type="number" step="any" value="${R2.tolAmt}" onchange="vatRecSetTol('tolAmt',this.value)" style="width:70px;padding:5px;border:1px solid #d0d7e0;border-radius:5px"></label>
                <label style="font-size:12px;color:#555">سماحية نسبية %: <input type="number" step="any" value="${R2.tolPct}" onchange="vatRecSetTol('tolPct',this.value)" style="width:60px;padding:5px;border:1px solid #d0d7e0;border-radius:5px"></label>
                <label style="font-size:12px;color:#555">سماحية التاريخ (أيام): <input type="number" value="${R2.tolDays}" onchange="vatRecSetTol('tolDays',this.value)" style="width:60px;padding:5px;border:1px solid #d0d7e0;border-radius:5px"></label>
                <button class="btn" onclick="vatRecRun()" style="background:#0d9488;color:#fff;padding:10px 24px;font-weight:800;margin-right:auto">⚡ تشغيل المطابقة</button>
            </div>
        </div>`;

    const res = R2.result;
    if (!res) return html + `<div class="card" style="text-align:center;padding:40px;color:#888">لم تُشغّل المطابقة بعد — ارفع الملفين ثم اضغط "تشغيل المطابقة".</div>`;

    const card = (label, val, color, sub) => `
        <div class="card" style="padding:12px 14px;text-align:center;border-top:3px solid ${color}">
            <div style="font-size:11px;color:#666">${label}</div>
            <div style="font-size:20px;font-weight:900;color:${color}">${val}</div>
            ${sub ? `<div style="font-size:10px;color:#888;margin-top:2px">${sub}</div>` : ''}
        </div>`;
    html += `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:14px">
        ${card('مطابقة تامة', res.exact.length, '#16a34a', 'سجلات متطابقة')}
        ${card('بفروقات', res.diffs.length, '#f59e0b', 'مبلغ مجموع الفروق: ' + fmt(res.sumDiff))}
        ${card('في (أ) فقط', res.onlyA.length, '#2563eb', 'بمبلغ ' + fmt(res.sumOnlyA))}
        ${card('في (ب) فقط', res.onlyB.length, '#7c3aed', 'بمبلغ ' + fmt(res.sumOnlyB))}
        ${card('فرق الإجماليات', fmt(Math.abs(res.sumA - res.sumB)), '#dc2626', 'أ: ' + fmt(res.sumA) + ' · ب: ' + fmt(res.sumB))}
    </div>`;

    html += `<div class="card" style="padding:14px;margin-bottom:14px"><div style="height:240px"><canvas id="vatRecChart"></canvas></div></div>`;

    // أزرار التصدير + الفلاتر
    const fbtn = (id, label, n) => `<button class="btn ${R2.filter === id ? 'pri' : ''}" onclick="vatRecSetFilter('${id}')" style="${R2.filter === id ? 'background:#0d9488;color:#fff' : ''};padding:7px 14px;font-size:12px;font-weight:700">${label} (${n})</button>`;
    html += `<div class="card" style="padding:12px 14px;margin-bottom:0;border-bottom-left-radius:0;border-bottom-right-radius:0">
        <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
            ${fbtn('all', 'الكل', res.matched.length + res.onlyA.length + res.onlyB.length)}
            ${fbtn('exact', '✅ تامة', res.exact.length)}
            ${fbtn('diff', '⚠️ فروقات', res.diffs.length)}
            ${fbtn('onlyA', '🔵 في (أ) فقط', res.onlyA.length)}
            ${fbtn('onlyB', '🟣 في (ب) فقط', res.onlyB.length)}
            <span style="margin-right:auto;display:flex;gap:8px">
                <button class="btn" onclick="vatRecExport()" style="background:#1e8449;color:#fff;padding:7px 14px;font-size:12px;font-weight:700">📊 تصدير Excel</button>
                <button class="btn" onclick="vatRecPrint()" style="background:#5b2c6f;color:#fff;padding:7px 14px;font-size:12px;font-weight:700">🖨️ طباعة</button>
            </span>
        </div>
    </div>`;

    // بناء صفوف الجدول حسب الفلتر
    const rowsHtml = [];
    const partyCell = r => (r.party || '—') + (r.docNo ? ` <span style="color:#aaa">#${r.docNo}</span>` : '');
    const pairRow = (m, kind) => {
        const a = m.a, b = m.b;
        const bg = kind === 'diff' ? '#fffaf0' : '#fff';
        return `<tr style="background:${bg};border-bottom:1px solid #f0f0f0">
            <td style="padding:6px 8px;font-size:11px">${fmtD(a.date)}</td>
            <td style="padding:6px 8px;font-size:11px">${partyCell(a)}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px">${fmt(a.amount)}</td>
            <td style="padding:6px 8px;font-size:11px">${partyCell(b)}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px">${fmt(b.amount)}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px;font-weight:800;color:${Math.abs(m.amtDiff) > 0.01 ? '#dc2626' : '#16a34a'}">${m.amtDiff === 0 ? '✓' : fmt(m.amtDiff)}</td>
            <td style="padding:6px 8px;text-align:center;font-size:10px;color:#888">${m.manual ? '🔗' : ''}${Math.round(m.score)}%</td>
            <td style="padding:6px 8px;text-align:center"><button onclick="vatRecUnlink('${a.id}','${b.id}')" title="فكّ الارتباط" style="background:none;border:1px solid #e0c0c0;border-radius:5px;color:#c0392b;cursor:pointer;font-size:10px;padding:2px 6px">✂️ فك</button></td>
        </tr>`;
    };
    const singleRow = (r, side) => {
        const isA = side === 'A';
        let action = '<span style="color:#aaa;font-size:10px">—</span>';
        if (isA && r._suggest && r._suggest.length) {
            action = `<select onchange="if(this.value)vatRecLink('${r.id}',this.value)" style="max-width:150px;padding:3px;border:1px solid #2563eb;border-radius:5px;font-family:inherit;font-size:10px">
                <option value="">🔗 ربط بـ…</option>
                ${r._suggest.map(s => `<option value="${s.b.id}">${(s.b.party || '—').slice(0, 18)} · ${fmt(s.b.amount)} (${Math.round(s.s)}%)</option>`).join('')}
            </select>`;
        }
        return `<tr style="background:${isA ? '#f0f6ff' : '#f7f0ff'};border-bottom:1px solid #f0f0f0">
            <td style="padding:6px 8px;font-size:11px">${fmtD(r.date)}</td>
            <td style="padding:6px 8px;font-size:11px">${isA ? partyCell(r) : '—'}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px">${isA ? fmt(r.amount) : '—'}</td>
            <td style="padding:6px 8px;font-size:11px">${isA ? '—' : partyCell(r)}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px">${isA ? '—' : fmt(r.amount)}</td>
            <td style="padding:6px 8px;text-align:left;font-size:11px;font-weight:800;color:${isA ? '#2563eb' : '#7c3aed'}">${isA ? 'في (أ) فقط' : 'في (ب) فقط'}</td>
            <td style="padding:6px 8px;text-align:center;font-size:10px;color:#aaa">—</td>
            <td style="padding:6px 8px;text-align:center">${action}</td>
        </tr>`;
    };

    const fl = R2.filter;
    if (fl === 'all' || fl === 'exact') res.exact.forEach(m => rowsHtml.push(pairRow(m, 'exact')));
    if (fl === 'all' || fl === 'diff') res.diffs.forEach(m => rowsHtml.push(pairRow(m, 'diff')));
    if (fl === 'all' || fl === 'onlyA') res.onlyA.forEach(r => rowsHtml.push(singleRow(r, 'A')));
    if (fl === 'all' || fl === 'onlyB') res.onlyB.forEach(r => rowsHtml.push(singleRow(r, 'B')));

    html += `<div class="card" style="padding:0;border-top-left-radius:0;border-top-right-radius:0">
        <div style="font-size:10px;color:#888;padding:6px 12px">💡 يمكنك ربط سجل "في (أ) فقط" بأقرب تطابق مقترح يدوياً، أو فكّ أي ارتباط خاطئ (✂️). الروابط اليدوية (🔗) لها الأولوية.</div>
        <div id="vatRecTable" style="overflow-x:auto;max-height:520px;overflow-y:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:700px">
                <thead style="position:sticky;top:0;z-index:1"><tr style="background:#0d9488;color:#fff">
                    <th style="padding:8px;text-align:right">التاريخ (أ)</th>
                    <th style="padding:8px;text-align:right">الجهة (أ)</th>
                    <th style="padding:8px;text-align:left">المبلغ (أ)</th>
                    <th style="padding:8px;text-align:right">الجهة (ب)</th>
                    <th style="padding:8px;text-align:left">المبلغ (ب)</th>
                    <th style="padding:8px;text-align:left">الفرق</th>
                    <th style="padding:8px;text-align:center">الثقة</th>
                    <th style="padding:8px;text-align:center">إجراء</th>
                </tr></thead>
                <tbody>${rowsHtml.join('') || '<tr><td colspan="8" style="padding:20px;text-align:center;color:#999">لا توجد سجلات في هذا التصنيف</td></tr>'}</tbody>
            </table>
        </div>
    </div>
    ${renderVatRecAudit()}
    ${renderVatRecCross()}
    ${renderVatRecHistory()}`;
    return html;
}

function vatRecBuildChart() {
    const res = window._vatRec.result; if (!res || typeof Chart === 'undefined') return;
    const c = $('vatRecChart'); if (!c) return;
    window._vatRecChart && (() => { try { window._vatRecChart.destroy(); } catch (e) { } })();
    window._vatRecChart = new Chart(c, {
        type: 'doughnut',
        data: {
            labels: ['مطابقة تامة', 'بفروقات', 'في (أ) فقط', 'في (ب) فقط'],
            datasets: [{ data: [res.exact.length, res.diffs.length, res.onlyA.length, res.onlyB.length], backgroundColor: ['#16a34a', '#f59e0b', '#2563eb', '#7c3aed'] }]
        },
        options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 11 } } }, title: { display: true, text: 'توزيع نتائج المطابقة', font: { size: 13 } } } }
    });
}

// ── تصدير Excel ─────────────────
window.vatRecExport = function () {
    const res = window._vatRec.result; if (!res) { toast('⚠️ شغّل المطابقة أولاً', 'er'); return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة', 'er'); return; }
    const fmtD = d => d ? d.toISOString().slice(0, 10) : '';
    const wb = XLSX.utils.book_new();
    const sum = [
        [(window.gbrCfg && window.gbrCfg.companyAr) || 'بنيان للمقاولات'],
        ['تقرير مطابقة ملفين ضريبيين'],
        ['الملف (أ)', window._vatRec.A ? window._vatRec.A.name : '', 'الملف (ب)', window._vatRec.B ? window._vatRec.B.name : ''],
        [],
        ['البند', 'العدد', 'المبلغ'],
        ['مطابقة تامة', res.exact.length, res.exact.reduce((s, m) => s + m.a.amount, 0)],
        ['مطابقة بفروقات', res.diffs.length, res.sumDiff],
        ['في (أ) فقط', res.onlyA.length, res.sumOnlyA],
        ['في (ب) فقط', res.onlyB.length, res.sumOnlyB],
        ['إجمالي (أ)', window._vatRec.A.records.length, res.sumA],
        ['إجمالي (ب)', window._vatRec.B.records.length, res.sumB],
        ['فرق الإجماليات (أ − ب)', '', Math.round((res.sumA - res.sumB) * 100) / 100]
    ];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(sum), 'الملخص');

    const pairAOA = (arr) => [['تاريخ (أ)', 'جهة (أ)', 'رقم (أ)', 'مبلغ (أ)', 'ضريبة (أ)', 'تاريخ (ب)', 'جهة (ب)', 'رقم (ب)', 'مبلغ (ب)', 'ضريبة (ب)', 'فرق المبلغ', 'فرق الضريبة', 'الثقة %'],
    ...arr.map(m => [fmtD(m.a.date), m.a.party, m.a.docNo, m.a.amount, m.a.tax, fmtD(m.b.date), m.b.party, m.b.docNo, m.b.amount, m.b.tax, m.amtDiff, m.taxDiff, Math.round(m.score)])];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(pairAOA(res.diffs)), 'بفروقات');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(pairAOA(res.exact)), 'مطابقة تامة');
    const singleAOA = (arr) => [['التاريخ', 'الجهة', 'رقم المستند', 'المبلغ', 'الضريبة'], ...arr.map(r => [fmtD(r.date), r.party, r.docNo, r.amount, r.tax])];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(singleAOA(res.onlyA)), 'في أ فقط');
    XLSX.utils.book_append_sheet(wb, XLSX.utils.aoa_to_sheet(singleAOA(res.onlyB)), 'في ب فقط');
    XLSX.writeFile(wb, 'مطابقة_ضريبية.xlsx');
    toast('✅ تم تصدير تقرير المطابقة', 'ok', 4000);
};

// ── طباعة ─────────────────
window.vatRecPrint = function () {
    const res = window._vatRec.result; if (!res) { toast('⚠️ شغّل المطابقة أولاً', 'er'); return; }
    const tbl = $('vatRecTable'); if (!tbl) return;
    const clone = tbl.cloneNode(true);
    const header = (typeof fsBrandHeader === 'function') ? fsBrandHeader('🔍 تقرير مطابقة ملفين ضريبيين', 'أ: ' + (window._vatRec.A ? window._vatRec.A.name : '') + ' · ب: ' + (window._vatRec.B ? window._vatRec.B.name : '')) : '<h1>تقرير مطابقة ضريبية</h1>';
    const summary = `<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
        <div style="border:1px solid #16a34a;border-radius:8px;padding:8px 14px;font-size:12px">تامة: <b>${res.exact.length}</b></div>
        <div style="border:1px solid #f59e0b;border-radius:8px;padding:8px 14px;font-size:12px">بفروقات: <b>${res.diffs.length}</b> (${fmt(res.sumDiff)})</div>
        <div style="border:1px solid #2563eb;border-radius:8px;padding:8px 14px;font-size:12px">في (أ) فقط: <b>${res.onlyA.length}</b></div>
        <div style="border:1px solid #7c3aed;border-radius:8px;padding:8px 14px;font-size:12px">في (ب) فقط: <b>${res.onlyB.length}</b></div>
        <div style="border:1px solid #dc2626;border-radius:8px;padding:8px 14px;font-size:12px">فرق الإجماليات: <b>${fmt(Math.abs(res.sumA - res.sumB))}</b></div>
    </div>`;
    const html = `<!DOCTYPE html><html dir="rtl"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>مطابقة ضريبية</title>
    <style>*{ -webkit-print-color-adjust:exact !important;print-color-adjust:exact !important } body{font-family:'Tajawal',Tahoma;padding:20px;color:#1a3a5c;direction:rtl}
    div{max-height:none !important;overflow:visible !important} table{width:100%;border-collapse:collapse;font-size:11px;page-break-inside:auto} tr{page-break-inside:avoid}
    thead{display:table-header-group;position:static !important} thead tr,thead th{position:static !important} th,td{border:1px solid #eee;padding:4px 6px}
    @page{size:A4 landscape;margin:1.2cm}</style></head><body>${header}${summary}${clone.innerHTML}
    <div style="margin-top:16px;border-top:1px solid #ddd;padding-top:8px;font-size:10px;color:#999;text-align:center">${custCoName()} · ${new Date().toLocaleString('ar-EG')}</div>
    </body></html>`;
    const w = window.open('', '_blank'); w.document.write(html); w.document.close();
    setTimeout(() => { try { w.focus(); w.print(); } catch (e) { } }, 500);
};

// ── فحوصات ضريبية تلقائية (تدقيق ZATCA) ─────────────────
function vatRecAuditFile(f) {
    if (!f || !f.records) return null;
    const rate = [], missing = [], dupMap = {};
    f.records.forEach(r => {
        if (r.tax != null && r.amount > 0) {
            const ir = r.tax / r.amount * 100;
            if (ir > 1 && Math.abs(ir - 15) > 1 && Math.abs(ir - 5) > 1) rate.push({ r, ir });
        }
        const d = vatRecNormDoc(r.docNo); if (d) (dupMap[d] = dupMap[d] || []).push(r);
        if (!r.date || !r.docNo || !r.party) missing.push(r);
    });
    const duplicates = Object.entries(dupMap).filter(([, a]) => a.length > 1).map(([k, a]) => ({ doc: k, items: a }));
    return { rate, duplicates, missing, total: f.records.length };
}
function renderVatRecAudit() {
    const R2 = window._vatRec; if (!R2.A && !R2.B) return '';
    const fmtD = d => d ? d.toISOString().slice(0, 10) : '—';
    const block = (slot) => {
        const f = R2[slot]; if (!f) return '';
        const a = vatRecAuditFile(f); const lbl = slot === 'A' ? '(أ)' : '(ب)';
        const dupItems = a.duplicates.reduce((s, g) => s + g.items.length, 0);
        const chip = (n, txt, color) => `<div style="flex:1;min-width:120px;background:${n ? color + '14' : '#f0f9f4'};border:1px solid ${n ? color : '#cde9d8'};border-radius:8px;padding:8px;text-align:center">
            <div style="font-size:18px;font-weight:900;color:${n ? color : '#16a34a'}">${n}</div><div style="font-size:10px;color:#666">${txt}</div></div>`;
        const det = (title, items, render) => items.length ? `<details style="margin-top:6px"><summary style="cursor:pointer;font-size:11px;color:#0d9488;font-weight:700">${title} (${items.length})</summary>
            <div style="max-height:160px;overflow:auto;margin-top:4px;font-size:10px;color:#555">${items.slice(0, 50).map(render).join('')}</div></details>` : '';
        return `<div style="flex:1;min-width:260px;border:1px solid #e0e0e0;border-radius:10px;padding:12px">
            <div style="font-size:12px;font-weight:800;color:#0d9488;margin-bottom:8px">الملف ${lbl} — ${a.total} سجل</div>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
                ${chip(a.rate.length, 'ضريبة ليست 15%/5%', '#dc2626')}
                ${chip(dupItems, 'فواتير مكررة', '#f59e0b')}
                ${chip(a.missing.length, 'بيانات ناقصة', '#7c3aed')}
            </div>
            ${det('🧾 ضريبة غير قياسية', a.rate, x => `<div>• ${x.r.party || '—'} #${x.r.docNo || '—'} — مبلغ ${fmt(x.r.amount)}، ضريبة ${fmt(x.r.tax)} (${fmt(x.ir)}%)</div>`)}
            ${det('🔁 فواتير مكررة', a.duplicates, g => `<div>• رقم #${g.doc}: ${g.items.length} مرات — ${g.items.map(r => fmt(r.amount)).join(' / ')}</div>`)}
            ${det('⚠️ بيانات ناقصة', a.missing, r => `<div>• ${fmtD(r.date)} — ${r.party || 'بلا جهة'} #${r.docNo || 'بلا رقم'} — ${fmt(r.amount)}</div>`)}
        </div>`;
    };
    const A = block('A'), B = block('B');
    if (!A && !B) return '';
    return `<div class="card" style="padding:14px;margin-top:14px">
        <div style="font-size:14px;font-weight:900;color:#1a3a5c;margin-bottom:10px">🛡️ الفحوصات الضريبية التلقائية (تدقيق)</div>
        <div style="display:flex;gap:12px;flex-wrap:wrap">${A}${B}</div>
    </div>`;
}

// ── المطابقة الثلاثية مع دفتر النظام ─────────────────
function vatRecDateRange() {
    const R2 = window._vatRec; let min = null, max = null;
    [...(R2.A ? R2.A.records : []), ...(R2.B ? R2.B.records : [])].forEach(r => {
        if (!r.dateVal) return; if (min === null || r.dateVal < min) min = r.dateVal; if (max === null || r.dateVal > max) max = r.dateVal;
    });
    const iso = t => t ? new Date(t).toISOString().slice(0, 10) : '';
    return { from: iso(min), to: iso(max) };
}
window.vatRecCrossSet = function (field, val) { window._vatRec[field] = val; };
window.vatRecCrossCheck = function () {
    const R2 = window._vatRec; const dr = vatRecDateRange();
    const from = R2.crossFrom || dr.from, to = R2.crossTo || dr.to;
    if (!from || !to) { toast('⚠️ حدّد الفترة (تعذّر استنتاجها من تواريخ الملفات)', 'er'); return; }
    if (typeof vatCompute !== 'function') { toast('⚠️ تعذّر قراءة بيانات النظام', 'er'); return; }
    let data; try { data = vatCompute(from, to); } catch (e) { toast('❌ خطأ في احتساب ضريبة النظام', 'er'); return; }
    R2.crossFrom = from; R2.crossTo = to;
    R2.cross = { from, to, ledgerOut: data.ledgerOut, ledgerIn: data.ledgerIn, net: data.net };
    renderVatReturn();
};
function renderVatRecCross() {
    const R2 = window._vatRec; if (!R2.result) return '';
    const dr = vatRecDateRange();
    const from = R2.crossFrom || dr.from, to = R2.crossTo || dr.to;
    const c = R2.cross;
    const row = (label, val, color) => `<tr><td style="padding:6px 10px">${label}</td><td style="padding:6px 10px;text-align:left;font-weight:800;color:${color || '#1a3a5c'}">${fmt(val)}</td></tr>`;
    let crossTbl = '';
    if (c) {
        crossTbl = `<table style="width:100%;border-collapse:collapse;font-size:12px;margin-top:10px">
            <tbody>
                ${row('🧾 إجمالي ضريبة الملف (أ)', R2.result.taxA, '#2563eb')}
                ${row('🧾 إجمالي ضريبة الملف (ب)', R2.result.taxB, '#7c3aed')}
                ${row('🏦 ضريبة المخرجات في النظام (مبيعات)', c.ledgerOut, '#0d9488')}
                ${row('🏦 ضريبة المدخلات في النظام (مشتريات)', c.ledgerIn, '#0d9488')}
                <tr style="background:#fef9e7"><td style="padding:6px 10px;font-weight:700">فرق ضريبة الملف (أ) عن مخرجات النظام</td><td style="padding:6px 10px;text-align:left;font-weight:800;color:#dc2626">${fmt(Math.abs(R2.result.taxA - c.ledgerOut))}</td></tr>
                <tr style="background:#fef9e7"><td style="padding:6px 10px;font-weight:700">فرق ضريبة الملف (ب) عن مدخلات النظام</td><td style="padding:6px 10px;text-align:left;font-weight:800;color:#dc2626">${fmt(Math.abs(R2.result.taxB - c.ledgerIn))}</td></tr>
            </tbody></table>
            <div style="font-size:10px;color:#888;margin-top:6px">💡 الافتراض أعلاه أن الملف (أ) للمبيعات والملف (ب) للمشتريات — راجع حسب طبيعة ملفاتك. أرقام النظام محسوبة من القيود المرحّلة في الفترة ${c.from} → ${c.to}.</div>`;
    }
    return `<div class="card" style="padding:14px;margin-top:14px">
        <div style="font-size:14px;font-weight:900;color:#1a3a5c;margin-bottom:8px">⚖️ مطابقة ثلاثية مع دفتر النظام</div>
        <div style="display:flex;gap:10px;flex-wrap:wrap;align-items:center">
            <label style="font-size:12px;color:#555">من: <input type="date" value="${from}" onchange="vatRecCrossSet('crossFrom',this.value)" style="padding:5px;border:1px solid #d0d7e0;border-radius:5px"></label>
            <label style="font-size:12px;color:#555">إلى: <input type="date" value="${to}" onchange="vatRecCrossSet('crossTo',this.value)" style="padding:5px;border:1px solid #d0d7e0;border-radius:5px"></label>
            <button class="btn" onclick="vatRecCrossCheck()" style="background:#0d9488;color:#fff;padding:7px 16px;font-weight:800;font-size:12px">⚖️ قارن مع النظام</button>
        </div>
        ${crossTbl}
    </div>`;
}

// ── حفظ جلسات المطابقة + السجل ─────────────────
window.vatRecSaveSession = function () {
    const R2 = window._vatRec, res = R2.result;
    if (!res) { toast('⚠️ شغّل المطابقة أولاً', 'er'); return; }
    if (!window.R || !window.push || !R.vatRecSessions) { toast('⚠️ تعذّر الحفظ — لا اتصال', 'er'); return; }
    const snap = {
        savedAt: Date.now(), date: new Date().toISOString().slice(0, 10),
        fileA: R2.A ? R2.A.name : '', fileB: R2.B ? R2.B.name : '',
        exact: res.exact.length, diffs: res.diffs.length, onlyA: res.onlyA.length, onlyB: res.onlyB.length,
        sumA: Math.round(res.sumA * 100) / 100, sumB: Math.round(res.sumB * 100) / 100,
        sumDiff: Math.round(res.sumDiff * 100) / 100, sumOnlyA: Math.round(res.sumOnlyA * 100) / 100, sumOnlyB: Math.round(res.sumOnlyB * 100) / 100,
        savedBy: (typeof curU !== 'undefined' && curU && curU.uid) ? curU.uid : 'system'
    };
    push(R.vatRecSessions, snap).then(() => toast('✅ تم حفظ جلسة المطابقة', 'ok', 4000))
        .catch(e => toast('❌ خطأ: ' + (e.message || e), 'er'));
};
window.vatRecDeleteSession = function (key) {
    if (!confirm('حذف هذه الجلسة من السجل؟')) return;
    remove(ref(db, 'ledger/vatRecSessions/' + key)).then(() => toast('🗑️ تم الحذف', 'ok')).catch(e => toast('❌ خطأ: ' + (e.message || e), 'er'));
};
function renderVatRecHistory() {
    const all = window._vatRecSessions || {};
    const entries = Object.entries(all).map(([k, v]) => ({ k, ...v })).sort((a, b) => (b.savedAt || 0) - (a.savedAt || 0));
    const saveBtn = `<button class="btn" onclick="vatRecSaveSession()" style="background:#2563eb;color:#fff;padding:7px 16px;font-weight:800;font-size:12px">💾 حفظ هذه الجلسة</button>`;
    if (!entries.length) return `<div class="card" style="padding:14px;margin-top:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
            <div style="font-size:13px;font-weight:900;color:#1a3a5c">🗂️ سجل جلسات المطابقة</div>${window._vatRec.result ? saveBtn : ''}
        </div>
        <div style="font-size:11px;color:#888;margin-top:8px">لا توجد جلسات محفوظة بعد.</div>
    </div>`;
    return `<div class="card" style="padding:14px;margin-top:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:10px">
            <div style="font-size:13px;font-weight:900;color:#1a3a5c">🗂️ سجل جلسات المطابقة (${entries.length})</div>${window._vatRec.result ? saveBtn : ''}
        </div>
        <div style="overflow-x:auto;max-height:260px;overflow-y:auto;border:1px solid #eef2f6;border-radius:8px">
            <table style="width:100%;border-collapse:collapse;font-size:11px">
                <thead style="position:sticky;top:0"><tr style="background:#eaf2fa;color:#1a3a5c">
                    <th style="padding:7px;text-align:right">التاريخ</th><th style="padding:7px;text-align:right">الملفات</th>
                    <th style="padding:7px;text-align:center">تامة</th><th style="padding:7px;text-align:center">فروقات</th>
                    <th style="padding:7px;text-align:center">أ فقط</th><th style="padding:7px;text-align:center">ب فقط</th>
                    <th style="padding:7px;text-align:left">فرق الإجماليات</th><th style="padding:7px;text-align:left">—</th>
                </tr></thead>
                <tbody>${entries.map(e => `<tr style="border-bottom:1px solid #f3f3f3">
                    <td style="padding:6px 8px">${e.date || '—'}</td>
                    <td style="padding:6px 8px">${(e.fileA || '—')} ⇄ ${(e.fileB || '—')}</td>
                    <td style="padding:6px 8px;text-align:center;color:#16a34a;font-weight:700">${e.exact}</td>
                    <td style="padding:6px 8px;text-align:center;color:#f59e0b;font-weight:700">${e.diffs}</td>
                    <td style="padding:6px 8px;text-align:center;color:#2563eb;font-weight:700">${e.onlyA}</td>
                    <td style="padding:6px 8px;text-align:center;color:#7c3aed;font-weight:700">${e.onlyB}</td>
                    <td style="padding:6px 8px;text-align:left">${fmt(Math.abs((e.sumA || 0) - (e.sumB || 0)))}</td>
                    <td style="padding:6px 8px;text-align:left"><button onclick="vatRecDeleteSession('${e.k}')" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:13px">🗑️</button></td>
                </tr>`).join('')}</tbody>
            </table>
        </div>
    </div>`;
}

console.log('✅ VAT File Reconciliation module [ACC-VAT-REC] loaded — smart two-file matching');

// ============================================================
// [ACC-ITAX] Income Tax Report (ضريبة الدخل على حصة المستثمر الأجنبي)
// ============================================================
const ITAX_EXPENSE_ACC = '5380';
const ITAX_PAYABLE_ACC = '2170';
const ITAX_RATE = 20;

window._itaxState = window._itaxState || {
    year: new Date().getFullYear(),
    foreignPct: (typeof cfg !== 'undefined' && cfg && cfg.foreignOwnershipPct != null) ? cfg.foreignOwnershipPct : 100,
    adjustments: []
};

function itaxComputeNetIncome(year) {
    const fromDate = `${year}-01-01`;
    const toDate = `${year}-12-31`;
    const { balances } = calcFSBalances(fromDate, toDate, ['posted'], '', '');
    const income = buildIncomeStatement(balances);
    return income.netIncome;
}

// 🔎 قائمة الدخل الكاملة لسنة الإقرار — لعرض تفاصيل الحسابات المكوّنة لصافي الربح المحاسبي
function itaxComputeIncome(year) {
    const { balances } = calcFSBalances(`${year}-01-01`, `${year}-12-31`, ['posted'], '', '');
    return buildIncomeStatement(balances);
}

// 📐 المنهجية الضريبية: الوعاء = الربح المحاسبي + بنود غير مقبولة ضريبياً (Add Back) − بنود مسموح بخصمها (Less)
// البنود الشائعة وفق نظام ضريبة الدخل السعودي — تُضاف بنقرة ويُدخل المبلغ
const ITAX_ADD_PRESETS = [
    'الغرامات والجزاءات (مخالفات مرور / بلدية / حكومية)',
    'الزكاة وضريبة الدخل المسجلة كمصروف',
    'مصروفات شخصية للملاك أو الشركاء',
    'تبرعات غير مقبولة نظاماً (لأفراد أو جهات غير معتمدة)',
    'مصروفات غير مؤيدة بمستندات',
    'الجزء غير المقبول من مصروف الضيافة والترفيه',
    'مخصصات غير مقبولة (دعاوى / خسائر مستقبلية / صيانة)',
    'الإهلاك المحاسبي الزائد عن الإهلاك الضريبي',
    'مصروفات أو خسائر تخص سنوات سابقة غير مقبولة',
    'رواتب ومكافآت غير نظامية (مكافأة شريك بدون عمل)'
];
const ITAX_LESS_PRESETS = [
    'فرق الإهلاك الضريبي الزائد عن المحاسبي',
    'خسائر ضريبية مرحّلة من سنوات سابقة (وفق الضوابط)',
    'إيرادات معفاة نظاماً',
    'أرباح سبق إخضاعها للضريبة (منع الازدواج)',
    'تبرعات مقبولة نظاماً (ضمن الحدود والشروط)'
];

// توحيد بنود التعديل: kind = 'add' (يُضاف) أو 'less' (يُخصم) والمبالغ موجبة دائماً
// البيانات القديمة (مبالغ مُوقّعة بلا kind): الموجب إضافة والسالب خصم — للتوافق الخلفي
function itaxNormAdj(list) {
    const arr = Array.isArray(list) ? list : Object.values(list || {});
    return arr.map(a => ({
        desc: a.desc || '',
        amount: Math.abs(parseFloat(a.amount) || 0),
        kind: a.kind === 'less' ? 'less' : (a.kind === 'add' ? 'add' : ((parseFloat(a.amount) || 0) < 0 ? 'less' : 'add'))
    }));
}

window.renderIncomeTax = function () {
    const pg = $('pg-incometax');
    if (!pg) return;
    const st = window._itaxState;
    const byCode = brByCode ? brByCode() : {};
    const hasExpAcc = !!byCode[ITAX_EXPENSE_ACC];
    const hasPayAcc = !!byCode[ITAX_PAYABLE_ACC];

    const itxIncome = itaxComputeIncome(st.year);
    const netIncome = itxIncome.netIncome;
    // 💾 تحميل التعديلات المحفوظة للسنة (المصدر الموحّد) عند فتح السنة أول مرة
    if (st.loadedYear !== st.year && !st.loadedKey) {
        const rec = (window.incomeTaxAdjustments || {})[st.year];
        if (rec) { st.adjustments = itaxNormAdj(rec.adjustments || []); if (rec.foreignPct != null) st.foreignPct = rec.foreignPct; }
        st.loadedYear = st.year;
    }
    st.adjustments = itaxNormAdj(st.adjustments);
    const addTotal = Math.round(st.adjustments.filter(a => a.kind === 'add').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const lessTotal = Math.round(st.adjustments.filter(a => a.kind === 'less').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const adjTotal = Math.round((addTotal - lessTotal) * 100) / 100;
    const taxableIncome = Math.round((netIncome + addTotal - lessTotal) * 100) / 100;
    const foreignShare = Math.round((taxableIncome * (parseFloat(st.foreignPct) || 0) / 100) * 100) / 100;
    const tax = foreignShare > 0 ? Math.round(foreignShare * ITAX_RATE / 100 * 100) / 100 : 0;

    const years = [];
    const curY = new Date().getFullYear();
    for (let y = curY; y >= curY - 5; y--) years.push(y);

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#7c2d12,#9a3412);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">💰 ضريبة الدخل — المستثمر الأجنبي</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">احتساب ضريبة الدخل (${ITAX_RATE}%) على حصة المستثمر الأجنبي من صافي الربح المحاسبي بعد التعديلات الضريبية — سنوياً</div>
    </div>`;

    if (!hasExpAcc || !hasPayAcc) {
        html += `<div class="card" style="background:#fef3c7;border:1px solid #f59e0b;padding:12px 16px;border-radius:8px;margin-bottom:14px;color:#92400e">
            ⚠️ تنبيه: ${!hasExpAcc ? `حساب مصروف ضريبة الدخل (${ITAX_EXPENSE_ACC}) غير موجود في شجرة الحسابات. ` : ''}${!hasPayAcc ? `حساب ضريبة الدخل المستحقة (${ITAX_PAYABLE_ACC}) غير موجود في شجرة الحسابات.` : ''}
            <button class="btn sm" style="margin-right:8px" onclick="itaxCreateAccounts()">إنشاء الحسابات المطلوبة</button>
        </div>`;
    }

    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px">
        <div style="display:flex;gap:14px;flex-wrap:wrap;align-items:center">
            <label>السنة: <select onchange="itaxSetField('year', this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
                ${years.map(y => `<option value="${y}" ${st.year === y ? 'selected' : ''}>${y}</option>`).join('')}
            </select></label>
            <label>نسبة الملكية الأجنبية %: <input type="number" min="0" max="100" step="0.01" value="${st.foreignPct}" onchange="itaxSetForeignPct(this.value)" style="width:90px;padding:6px 10px;border-radius:6px;border:1px solid #ddd"></label>
            <span style="color:#666;font-size:12px">(تُحفظ كإعداد عام للنظام)</span>
        </div>
    </div>`;

    html += `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin-bottom:14px">
        <div class="card" style="padding:14px 16px;text-align:center">
            <div style="color:#666;font-size:13px">صافي الربح المحاسبي (${st.year})</div>
            <div style="font-size:22px;font-weight:800;color:${netIncome >= 0 ? '#0d9488' : '#dc2626'}">${fmt(netIncome)}</div>
        </div>
        <div class="card" style="padding:14px 16px;text-align:center">
            <div style="color:#666;font-size:13px">الربح الخاضع للضريبة (الوعاء)</div>
            <div style="font-size:22px;font-weight:800;color:${taxableIncome >= 0 ? '#0d9488' : '#dc2626'}">${fmt(taxableIncome)}</div>
            <div style="font-size:10.5px;color:#999;margin-top:3px">+ إضافات ${fmt(addTotal)} · − خصومات ${fmt(lessTotal)}</div>
        </div>
        <div class="card" style="padding:14px 16px;text-align:center">
            <div style="color:#666;font-size:13px">حصة المستثمر الأجنبي (${st.foreignPct}%)</div>
            <div style="font-size:22px;font-weight:800;color:#7c3aed">${fmt(foreignShare)}</div>
        </div>
        <div class="card" style="padding:14px 16px;text-align:center;border:2px solid #dc2626">
            <div style="color:#666;font-size:13px">ضريبة الدخل المستحقة (${ITAX_RATE}%)</div>
            <div style="font-size:22px;font-weight:800;color:#dc2626">${fmt(tax)}</div>
        </div>
    </div>`;

    // 📐 قسما التعديلات الضريبية: يُضاف (Add Back) / يُخصم (Less) — مع بنود شائعة جاهزة
    const adjSection = (kind, icon, title, subtitle, color, bgLight, presets, total) => {
        const items = st.adjustments.map((a, i) => ({ a, i })).filter(x => x.a.kind === kind);
        const rows = items.map(x => `<tr style="border-bottom:1px solid #f1f5f9">
            <td style="padding:5px"><input type="text" value="${(x.a.desc || '').replace(/"/g, '&quot;')}" onchange="itaxSetAdj(${x.i},'desc',this.value)" style="width:100%;padding:7px;border:1px solid #e2e8f0;border-radius:6px;font-size:12.5px" placeholder="بيان البند"></td>
            <td style="padding:5px;width:160px"><input type="number" step="0.01" min="0" value="${x.a.amount || 0}" onchange="itaxSetAdj(${x.i},'amount',this.value)" style="width:150px;padding:7px;border:1px solid #e2e8f0;border-radius:6px;text-align:left;font-weight:700"></td>
            <td style="padding:5px;width:40px;text-align:center"><button onclick="itaxRemoveAdj(${x.i})" title="حذف البند" style="background:none;border:none;color:#dc2626;cursor:pointer;font-size:15px">🗑️</button></td>
        </tr>`).join('');
        return `<div style="border:1.5px solid ${color}33;border-radius:12px;margin-bottom:12px;overflow:hidden">
            <div style="background:${bgLight};padding:10px 14px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
                <div>
                    <span style="font-weight:900;color:${color};font-size:14px">${icon} ${title}</span>
                    <div style="font-size:11px;color:#888;margin-top:2px">${subtitle}</div>
                </div>
                <div style="font-weight:900;color:${color};font-size:16px">${kind === 'add' ? '+' : '−'} ${fmt(total)}</div>
            </div>
            <div style="padding:10px 14px">
                ${items.length ? `<table style="width:100%;border-collapse:collapse"><tbody>${rows}</tbody></table>` : `<div style="text-align:center;color:#bbb;font-size:12px;padding:8px">لا توجد بنود — أضف من القائمة الشائعة أو بنداً حراً</div>`}
                <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px;align-items:center">
                    <select onchange="if(this.value){itaxAddAdjPreset('${kind}',this.value);this.selectedIndex=0}" style="padding:7px 10px;border:1.5px solid ${color}55;border-radius:8px;font-size:12px;color:${color};max-width:340px">
                        <option value="">➕ إضافة بند شائع…</option>
                        ${presets.map(p => `<option value="${p.replace(/"/g, '&quot;')}">${p}</option>`).join('')}
                    </select>
                    <button class="btn sm" onclick="itaxAddAdj('${kind}')" style="border:1.5px solid #cbd5e1">✏️ بند آخر (حر)</button>
                </div>
            </div>
        </div>`;
    };
    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
            <h3 style="margin:0">التعديلات الضريبية على الربح المحاسبي</h3>
            <button class="btn sm" onclick="itaxSuggestAuto()" style="background:#eef2ff;border:1.5px solid #6366f1;color:#4338ca;font-weight:700">🤖 اقتراح البنود التلقائية</button>
        </div>
        <div style="font-size:11px;color:#888;margin:4px 0 10px">💡 «اقتراح البنود التلقائية» يضيف مخصص نهاية الخدمة والزكاة/الضريبة المسجلة كمصروف كبنود Add Back جاهزة — يمكنك تعديل مبالغها أو حذفها. هذه التعديلات تُحفظ وتُغذّي ضريبة قائمة الدخل وإيضاح مخصص الضريبة تلقائياً.</div>
        <div style="font-size:11.5px;color:#555;background:#f8fafc;border-radius:8px;padding:9px 12px;margin-bottom:12px;line-height:1.8">
            📐 <strong>المعادلة:</strong> الربح المحاسبي قبل الضريبة <strong style="color:#b45309">+ البنود غير المقبولة ضريبياً (Add Back)</strong> <strong style="color:#0d9488">− البنود المسموح بخصمها أو المعفاة (Less)</strong> = <strong>الربح الخاضع للضريبة (الوعاء الضريبي)</strong>
        </div>
        ${adjSection('add', '➕', 'يُضاف: بنود غير مقبولة ضريبياً (Add Back)', 'مصروفات اعترفت بها المحاسبة لكن النظام الضريبي لا يسمح بخصمها — غرامات، زكاة وضريبة مسجلة كمصروف، مخصصات، فرق إهلاك…', '#b45309', '#fff7ed', ITAX_ADD_PRESETS, addTotal)}
        ${adjSection('less', '➖', 'يُخصم: بنود مسموح بخصمها أو معفاة (Less)', 'بنود تُخصم من الربح المحاسبي — إهلاك ضريبي زائد، خسائر مرحّلة، إيرادات معفاة، أرباح سبق إخضاعها…', '#0d9488', '#f0fdfa', ITAX_LESS_PRESETS, lessTotal)}
        <div style="background:#1a3a5c;color:white;border-radius:10px;padding:11px 16px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;font-size:13px">
            <span style="font-weight:800">الربح الخاضع للضريبة = ${fmt(netIncome)} + ${fmt(addTotal)} − ${fmt(lessTotal)}</span>
            <span style="font-weight:900;font-size:17px">${fmt(taxableIncome)}</span>
        </div>
    </div>`;

    // 🔎 تفاصيل الحسابات المكوّنة لصافي الربح المحاسبي (مثل تفصيل قائمة التدفق النقدي)
    const itxDrillOpts = `{fromDate:'${st.year}-01-01',toDate:'${st.year}-12-31',statuses:['posted']}`;
    const itxAccRow = (b, color) => `<tr class="cfdet itxDet_ni" style="display:none;background:#fdfefe">
        <td style="text-align:right;padding:5px 10px;padding-right:44px;cursor:pointer" onclick="showFSDrilldown('${b.account.code}',${itxDrillOpts})" title="🔍 اعرض القيود التفصيلية لهذا الحساب">
            <span style="font-family:monospace;color:#aaa;font-size:11px;margin-left:6px">${b.account.code}</span>
            <span style="text-decoration:underline dotted;color:#2d6a9f;font-size:12px">${b.account.nameAr || ''}</span>
        </td>
        <td style="font-size:12px;font-weight:700;color:${color}">${fmt(b.naturalMovement)}</td>
    </tr>`;
    const itxRevs = itxIncome.revenues.filter(b => Math.abs(b.naturalMovement) >= 0.01);
    const itxExps = itxIncome.expenses.filter(b => Math.abs(b.naturalMovement) >= 0.01);
    const itxNiDetail = `
        <tr class="cfdet itxDet_ni" style="display:none;background:#f0faf5">
            <td style="text-align:right;padding:6px 10px;padding-right:28px;font-weight:800;color:#1e8449;font-size:12px">💰 إجمالي الإيرادات (${itxRevs.length} حساب)</td>
            <td style="font-weight:800;color:#1e8449;font-size:12px">${fmt(itxIncome.totalRevenue)}</td>
        </tr>
        ${itxRevs.map(b => itxAccRow(b, '#27ae60')).join('')}
        <tr class="cfdet itxDet_ni" style="display:none;background:#fdf5ec">
            <td style="text-align:right;padding:6px 10px;padding-right:28px;font-weight:800;color:#af601a;font-size:12px">💸 إجمالي المصروفات والتكاليف (${itxExps.length} حساب)</td>
            <td style="font-weight:800;color:#af601a;font-size:12px">(${fmt(itxIncome.totalExpense)})</td>
        </tr>
        ${itxExps.map(b => itxAccRow(b, '#e67e22')).join('')}`;
    const itxAdjRows = (kind, cls, color) => st.adjustments.filter(a => a.kind === kind && a.amount).map(a => `
        <tr class="cfdet ${cls}" style="display:none;background:#fdfefe">
            <td style="text-align:right;padding:5px 10px;padding-right:44px;font-size:12px;color:#555">${(a.desc || 'بند بدون بيان')}</td>
            <td style="font-size:12px;font-weight:700;color:${color}">${kind === 'less' ? '(' + fmt(a.amount) + ')' : fmt(a.amount)}</td>
        </tr>`).join('');
    const itxAddDetail = itxAdjRows('add', 'itxDet_add', '#b45309');
    const itxLessDetail = itxAdjRows('less', 'itxDet_less', '#0d9488');
    // صف مجموعة تعديلات قابل للفرد في ملخص الإقرار
    const itxAdjSummaryRow = (cls, label, total, detail, sign) => `
        <tr style="cursor:${detail ? 'pointer' : 'default'}" ${detail ? `onclick="toggleCFDetail('${cls}')" title="انقر لعرض البنود"` : ''}>
            <td style="text-align:right;font-weight:600">
                ${detail ? `<span id="${cls}_i" style="display:inline-block;width:14px;color:#2d6a9f;font-weight:900">▸</span>` : '<span style="display:inline-block;width:14px"></span>'}
                ${label}
            </td>
            <td style="font-weight:700">${sign === '-' && total ? '(' + fmt(total) + ')' : fmt(total)}</td>
        </tr>${detail}`;
    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px;overflow:auto">
        <h3 style="margin-top:0">ملخص الإقرار</h3>
        <div style="font-size:10.5px;color:#2d6a9f;background:#eef5fb;border-radius:6px;padding:7px 10px;margin-bottom:8px">🔎 انقر «صافي الربح المحاسبي» أو «التعديلات الضريبية» لعرض التفاصيل المكوّنة للرقم، ثم انقر أي حساب لعرض قيوده.</div>
        <table class="tbl" style="width:100%;text-align:center">
            <tbody>
                <tr style="cursor:pointer" onclick="toggleCFDetail('itxDet_ni')" title="انقر لعرض الحسابات المكوّنة">
                    <td style="text-align:right;font-weight:600">
                        <span id="itxDet_ni_i" style="display:inline-block;width:14px;color:#2d6a9f;font-weight:900">▸</span>
                        صافي الربح المحاسبي (قبل الضريبة)
                        <span style="font-size:10px;color:#999;margin-right:5px">(${itxRevs.length + itxExps.length} حساب — انقر للتفصيل)</span>
                    </td>
                    <td>${fmt(netIncome)}</td>
                </tr>
                ${itxNiDetail}
                ${itxAdjSummaryRow('itxDet_add', 'يُضاف: بنود غير مقبولة ضريبياً (Add Back)', addTotal, itxAddDetail, '+')}
                ${itxAdjSummaryRow('itxDet_less', 'يُخصم: بنود مسموح بخصمها أو معفاة (Less)', lessTotal, itxLessDetail, '-')}
                <tr style="font-weight:700;background:#f0fdfa"><td style="text-align:right">الربح الخاضع للضريبة (الوعاء الضريبي)</td><td>${fmt(taxableIncome)}</td></tr>
                <tr><td style="text-align:right;font-weight:600">نسبة الملكية الأجنبية</td><td>${st.foreignPct}%</td></tr>
                <tr style="font-weight:700;background:#faf5ff"><td style="text-align:right">حصة المستثمر الأجنبي من الوعاء الضريبي</td><td>${fmt(foreignShare)}</td></tr>
                <tr style="font-weight:800;background:#fef2f2;color:#dc2626"><td style="text-align:right">ضريبة الدخل المستحقة (${ITAX_RATE}%)</td><td>${fmt(tax)}</td></tr>
            </tbody>
        </table>
    </div>`;

    // 🔒 حالة إقرار السنة المختارة: إن كان معتمداً تُقفل أزرار الحفظ ويُوجَّه المستخدم لإعادة الفتح
    const savedAll = window.incomeTaxReturns || {};
    const curSavedEntry = Object.entries(savedAll).find(([k, r]) => r.year === st.year);
    const curFiled = curSavedEntry && curSavedEntry[1].status === 'filed';
    if (curFiled) {
        html += `<div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-bottom:14px">
            <div style="background:#fef3c7;border:1px solid #f59e0b;color:#92400e;border-radius:8px;padding:9px 14px;font-size:13px;font-weight:700">🔒 إقرار سنة ${st.year} معتمد ولا يمكن تعديله — استخدم «إعادة فتح» من الجدول أدناه لتعديله</div>
            <button class="btn" onclick="itaxPrint()">🖨️ طباعة</button>
        </div>`;
    } else {
        html += `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
            <button class="btn pri" onclick="itaxSaveReturn('draft')">💾 حفظ كمسودة</button>
            <button class="btn" style="background:#16a34a;color:#fff" onclick="itaxSaveReturn('filed')">✅ اعتماد وإنشاء قيد الالتزام</button>
            <button class="btn" onclick="itaxPrint()">🖨️ طباعة</button>
            ${st.loadedKey ? `<span style="align-self:center;font-size:12px;color:#2d6a9f;background:#eef5fb;border-radius:8px;padding:7px 12px;font-weight:700">✏️ تعمل الآن على الإقرار المحفوظ لسنة ${st.year} — الحفظ سيُحدّثه</span>` : ''}
        </div>`;
    }

    const savedRows = Object.entries(savedAll).sort((a, b) => (b[1].year || 0) - (a[1].year || 0));
    const filedTaxTotal = savedRows.filter(([k, r]) => r.status === 'filed').reduce((s, [k, r]) => s + (r.tax || 0), 0);
    const statusBadge = s => s === 'filed'
        ? '<span style="background:#dcfce7;color:#15803d;border:1px solid #86efac;border-radius:20px;padding:3px 12px;font-size:11px;font-weight:800">✅ معتمد</span>'
        : '<span style="background:#fef9c3;color:#a16207;border:1px solid #fde047;border-radius:20px;padding:3px 12px;font-size:11px;font-weight:800">📝 مسودة</span>';
    const actBtn = (label, icon, onclick, color, tip) => `<button onclick="${onclick}" title="${tip}" style="background:white;border:1.5px solid ${color};color:${color};border-radius:7px;padding:4px 10px;cursor:pointer;font-size:11px;font-weight:700;margin:1px">${icon} ${label}</button>`;
    html += `<div class="card" style="padding:14px 16px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:10px">
            <h3 style="margin:0">📋 إقرارات ضريبة الدخل المحفوظة${savedRows.length ? ` <span style="font-size:12px;color:#888;font-weight:600">(${savedRows.length})</span>` : ''}</h3>
            ${filedTaxTotal ? `<div style="font-size:12px;color:#7c2d12;background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:6px 12px;font-weight:800">Σ إجمالي الضرائب المعتمدة: ${fmt(Math.round(filedTaxTotal * 100) / 100)}</div>` : ''}
        </div>`;
    if (!savedRows.length) {
        html += `<div style="text-align:center;color:#999;padding:24px">
            <div style="font-size:30px;margin-bottom:6px">🗂️</div>
            لا توجد إقرارات محفوظة بعد — أعدّ الإقرار أعلاه ثم احفظه كمسودة أو اعتمده
        </div>`;
    } else {
        html += `<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12.5px;min-width:880px">
            <thead><tr style="background:#1a3a5c;color:white">
                <th style="padding:9px 10px;text-align:right">السنة</th>
                <th style="padding:9px 10px;text-align:left">صافي الربح</th>
                <th style="padding:9px 10px;text-align:left">التعديلات</th>
                <th style="padding:9px 10px;text-align:left">الوعاء الضريبي</th>
                <th style="padding:9px 10px;text-align:left">حصة الأجنبي</th>
                <th style="padding:9px 10px;text-align:left">الضريبة المستحقة</th>
                <th style="padding:9px 10px;text-align:center">الحالة</th>
                <th style="padding:9px 10px;text-align:center">آخر تحديث</th>
                <th style="padding:9px 10px;text-align:center">إجراءات</th>
            </tr></thead>
            <tbody>`;
        savedRows.forEach(([key, r], idx) => {
            const isLoaded = st.loadedKey === key;
            const filed = r.status === 'filed';
            html += `<tr style="background:${isLoaded ? '#eef5fb' : (idx % 2 ? '#fafcfe' : 'white')};border-bottom:1px solid #eef2f6">
                <td style="padding:8px 10px;font-weight:900;color:#1a3a5c">${r.year || ''}${isLoaded ? ' <span style="font-size:10px;color:#2d6a9f">(محمّل)</span>' : ''}</td>
                <td style="padding:8px 10px;text-align:left">${fmt(r.netIncome || 0)}</td>
                <td style="padding:8px 10px;text-align:left;color:${(r.adjTotal || 0) ? '#1a3a5c' : '#bbb'}">${fmt(r.adjTotal || 0)}${(r.addTotal || r.lessTotal) ? `<div style="font-size:10px;color:#999">+${fmt(r.addTotal || 0)} · −${fmt(r.lessTotal || 0)}</div>` : ''}</td>
                <td style="padding:8px 10px;text-align:left;font-weight:700">${fmt(r.taxableIncome || 0)}</td>
                <td style="padding:8px 10px;text-align:left">${fmt(r.foreignShare || 0)} <span style="font-size:10px;color:#999">(${r.foreignPct ?? 0}%)</span></td>
                <td style="padding:8px 10px;text-align:left;color:#dc2626;font-weight:900">${fmt(r.tax || 0)}</td>
                <td style="padding:8px 10px;text-align:center">${statusBadge(r.status)}</td>
                <td style="padding:8px 10px;text-align:center;font-size:11px;color:#888">${r.updatedAt ? new Date(r.updatedAt).toLocaleDateString('ar') : '—'}${r.updatedBy ? `<div style="font-size:10px;color:#aaa">${r.updatedBy}</div>` : ''}</td>
                <td style="padding:8px 10px;text-align:center;white-space:nowrap">
                    ${filed
                    ? actBtn('عرض', '👁️', `itaxOpenSaved('${key}')`, '#2d6a9f', 'عرض الإقرار (للقراءة — معتمد)')
                    + (r.journalEntryKey ? actBtn('القيد', '📖', `jrnRowMenu('${r.journalEntryKey}',event)`, '#8e44ad', 'عرض قيد الالتزام المرتبط') : '')
                    + actBtn('إعادة فتح', '🔓', `itaxReopenSaved('${key}')`, '#b9770e', 'إعادة فتح الإقرار للتعديل (يُلغي قيد الالتزام)')
                    : actBtn('تعديل', '✏️', `itaxOpenSaved('${key}')`, '#2d6a9f', 'تحميل الإقرار في المحرر أعلاه للتعديل')
                    + actBtn('حذف', '🗑️', `itaxDeleteSaved('${key}')`, '#dc2626', 'حذف المسودة نهائياً')}
                    ${actBtn('طباعة', '🖨️', `itaxPrintSaved('${key}')`, '#555', 'طباعة الإقرار المحفوظ كما هو')}
                </td>
            </tr>`;
        });
        html += `</tbody></table></div>
        <div style="margin-top:8px;font-size:11px;color:#888">💡 «تعديل» يحمّل المسودة في المحرر أعلاه ويحدّثها عند الحفظ · «إعادة فتح» يعيد الإقرار المعتمد مسودةً ويلغي قيد الالتزام المرتبط (بصلاحية المحاسبة المالية) مع تسجيل ذلك في سجل التدقيق.</div>`;
    }
    html += `</div>`;

    pg.innerHTML = html;
};

// 💾 حفظ التعديلات الضريبية للسنة كمصدر واحد يُغذّي القوائم والإيضاح (تلقائي عند أي تغيير)
function itaxPersistAdj() {
    const st = window._itaxState; st.loadedYear = st.year;
    const payload = { foreignPct: parseFloat(st.foreignPct) || 0, adjustments: itaxNormAdj(st.adjustments || []), updatedAt: Date.now() };
    try { update(ref(db, 'ledger/incomeTaxAdjustments/' + st.year), payload).catch(() => { }); } catch (e) { }
}

window.itaxSetField = function (field, value) {
    window._itaxState[field] = field === 'year' ? parseInt(value) : value;
    if (field === 'year') { delete window._itaxState.loadedKey; window._itaxState.loadedYear = null; } // تغيير السنة يحمّل تعديلاتها المحفوظة
    renderIncomeTax();
};

window.itaxSetForeignPct = async function (value) {
    const pct = parseFloat(value) || 0;
    window._itaxState.foreignPct = pct;
    try { await update(R.cfg, { foreignOwnershipPct: pct }); if (typeof cfg !== 'undefined') cfg.foreignOwnershipPct = pct; } catch (e) {}
    itaxPersistAdj();
    renderIncomeTax();
};

window.itaxAddAdj = function (kind) {
    window._itaxState.adjustments.push({ desc: '', amount: 0, kind: kind === 'less' ? 'less' : 'add' });
    itaxPersistAdj(); renderIncomeTax();
};

// إضافة بند شائع جاهز من القائمة المنسدلة (يبقى المبلغ صفراً حتى يُدخله المستخدم)
window.itaxAddAdjPreset = function (kind, desc) {
    window._itaxState.adjustments.push({ desc, amount: 0, kind: kind === 'less' ? 'less' : 'add' });
    itaxPersistAdj(); renderIncomeTax();
};

window.itaxRemoveAdj = function (i) {
    window._itaxState.adjustments.splice(i, 1);
    itaxPersistAdj(); renderIncomeTax();
};

window.itaxSetAdj = function (i, field, value) {
    window._itaxState.adjustments[i][field] = field === 'amount' ? Math.abs(parseFloat(value) || 0) : value;
    itaxPersistAdj(); renderIncomeTax();
};

// 🤖 اقتراح البنود التلقائية (مخصص نهاية الخدمة والمخصصات المكوّنة خلال السنة) كبنود Add Back قابلة للتعديل/الحذف
window.itaxSuggestAuto = function () {
    const st = window._itaxState; const year = st.year;
    const { balances } = calcFSBalances(`${year}-01-01`, `${year}-12-31`, ['posted'], '', '');
    // مخصص نهاية الخدمة/منافع الموظفين المكوّن خلال السنة (حركة الالتزام الدائنة)
    const eosb = Object.values(balances).filter(b => /نهاية الخدمة|منافع.*موظف|مكافأة.*خدمة/.test(b.account.nameAr || '') || String(b.account.code).startsWith('222'))
        .reduce((s, b) => s + Math.max(0, b.naturalMovement), 0);
    const suggestions = [];
    if (eosb > 0.5) suggestions.push({ desc: 'مخصص نهاية الخدمة المكوّن خلال السنة (غير مقبول ضريبياً حتى الصرف الفعلي)', amount: Math.round(eosb * 100) / 100, kind: 'add' });
    // الزكاة/ضريبة الدخل المسجلة كمصروف
    const zt = Object.values(balances).filter(b => /زكاة|ضريبة الدخل/.test(b.account.nameAr || '')).reduce((s, b) => s + Math.max(0, b.naturalMovement), 0);
    if (zt > 0.5) suggestions.push({ desc: 'الزكاة/ضريبة الدخل المسجلة كمصروف', amount: Math.round(zt * 100) / 100, kind: 'add' });
    if (!suggestions.length) { toast('لا توجد بنود تلقائية مقترحة لهذه السنة', 'wn'); return; }
    // تفادي التكرار: لا تُضِف بنداً موجوداً بنفس البيان
    const existing = new Set((st.adjustments || []).map(a => a.desc));
    let added = 0;
    suggestions.forEach(s => { if (!existing.has(s.desc)) { st.adjustments.push(s); added++; } });
    itaxPersistAdj();
    toast(added ? `أُضيفت ${added} بند مقترح — يمكنك تعديلها أو حذفها` : 'البنود المقترحة مضافة مسبقاً', added ? 'ok' : 'wn');
    renderIncomeTax();
};

window.itaxCreateAccounts = async function () {
    const byCode = brByCode ? brByCode() : {};
    if (!byCode[ITAX_EXPENSE_ACC]) {
        await push(R.coa, { code: ITAX_EXPENSE_ACC, nameAr: 'مصروف ضريبة الدخل', nameEn: 'Income Tax Expense', type: 'expense', nature: 'detail', parent: '5300' });
    }
    if (!byCode[ITAX_PAYABLE_ACC]) {
        await push(R.coa, { code: ITAX_PAYABLE_ACC, nameAr: 'ضريبة الدخل المستحقة', nameEn: 'Income Tax Payable', type: 'liability', nature: 'detail', parent: '2100' });
    }
    toast('✅ تم إنشاء الحسابات المطلوبة', 'ok');
};

window.itaxSaveReturn = async function (status) {
    const st = window._itaxState;
    const netIncome = itaxComputeNetIncome(st.year);
    st.adjustments = itaxNormAdj(st.adjustments);
    const addTotal = Math.round(st.adjustments.filter(a => a.kind === 'add').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const lessTotal = Math.round(st.adjustments.filter(a => a.kind === 'less').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const adjTotal = Math.round((addTotal - lessTotal) * 100) / 100;
    const taxableIncome = Math.round((netIncome + addTotal - lessTotal) * 100) / 100;
    const foreignShare = Math.round((taxableIncome * (parseFloat(st.foreignPct) || 0) / 100) * 100) / 100;
    const tax = foreignShare > 0 ? Math.round(foreignShare * ITAX_RATE / 100 * 100) / 100 : 0;

    if (status === 'filed' && !brIsFinance()) {
        toast('🚫 اعتماد الإقرار يتطلب صلاحية المحاسبة المالية', 'er');
        return;
    }

    const saved = window.incomeTaxReturns || {};
    const existing = Object.entries(saved).find(([k, r]) => r.year === st.year);

    if (existing && existing[1].status === 'filed') {
        toast('🔒 إقرار هذه السنة مُعتمد بالفعل ولا يمكن تعديله', 'er');
        return;
    }

    const byCode = brByCode ? brByCode() : {};
    if (status === 'filed' && (!byCode[ITAX_EXPENSE_ACC] || !byCode[ITAX_PAYABLE_ACC])) {
        toast('⚠️ يرجى إنشاء حسابات ضريبة الدخل في شجرة الحسابات أولاً', 'er');
        return;
    }

    const payload = {
        year: st.year, foreignPct: st.foreignPct,
        netIncome, adjustments: st.adjustments, adjTotal, addTotal, lessTotal, taxableIncome, foreignShare, tax,
        status, updatedAt: Date.now(), updatedBy: brUser()
    };

    let returnKey;
    if (existing) {
        returnKey = existing[0];
        await update(ref(db, `ledger/incomeTaxReturns/${returnKey}`), payload);
    } else {
        payload.createdAt = Date.now();
        payload.createdBy = brUser();
        const newRef = await push(R.incomeTaxReturns, payload);
        returnKey = newRef.key;
    }

    if (status === 'filed' && tax > 0) {
        const entryData = {
            date: `${st.year}-12-31`,
            description: `قيد استحقاق ضريبة الدخل لسنة ${st.year} — حصة المستثمر الأجنبي`,
            status: 'posted',
            lines: [
                { accountCode: ITAX_EXPENSE_ACC, accountName: byCode[ITAX_EXPENSE_ACC]?.nameAr || 'مصروف ضريبة الدخل', description: `ضريبة دخل ${st.year}`, date: '', costCenter: '', projectId: '', debit: tax, credit: 0 },
                { accountCode: ITAX_PAYABLE_ACC, accountName: byCode[ITAX_PAYABLE_ACC]?.nameAr || 'ضريبة الدخل المستحقة', description: `ضريبة دخل ${st.year}`, date: '', costCenter: '', projectId: '', debit: 0, credit: tax }
            ],
            createdAt: Date.now(), createdBy: brUser(), source: 'incomeTax', sourceKey: returnKey
        };
        const jeRef = await push(R.jrn, entryData);
        await update(ref(db, `ledger/incomeTaxReturns/${returnKey}`), { journalEntryKey: jeRef.key });
    }

    if (status === 'filed') logAudit('اعتماد إقرار ضريبة دخل', 'المحاسبة', `اعتماد إقرار ضريبة الدخل لسنة ${st.year}`);
    toast(status === 'filed' ? '✅ تم اعتماد الإقرار وإنشاء قيد الالتزام' : '💾 تم حفظ المسودة', 'ok');
};

window.itaxOpenSaved = function (key) {
    const r = (window.incomeTaxReturns || {})[key];
    if (!r) return;
    window._itaxState = { year: r.year, foreignPct: r.foreignPct, adjustments: itaxNormAdj(r.adjustments), loadedKey: key };
    renderIncomeTax();
    const pg = $('pg-incometax');
    if (pg) pg.scrollIntoView({ behavior: 'smooth', block: 'start' });
    toast(r.status === 'filed' ? `👁️ تم تحميل إقرار سنة ${r.year} للعرض (معتمد — أعد فتحه للتعديل)` : `✏️ تم تحميل مسودة إقرار سنة ${r.year} للتعديل`, 'ok');
};

// 🔓 إعادة فتح إقرار معتمد: يُلغي قيد الالتزام المرتبط ويعيد الإقرار مسودةً قابلة للتعديل (بصلاحية مالية + تدقيق)
window.itaxReopenSaved = async function (key) {
    const r = (window.incomeTaxReturns || {})[key];
    if (!r || r.status !== 'filed') return;
    if (!brIsFinance()) { toast('🚫 إعادة فتح الإقرار تتطلب صلاحية المحاسبة المالية', 'er'); return; }
    const ok = await cf2(`هل تريد إعادة فتح إقرار سنة ${r.year} للتعديل؟\nسيُلغى قيد الالتزام المرتبط (إن وجد) ويعود الإقرار مسودة.`);
    if (!ok) return;
    const upd = {};
    if (r.journalEntryKey && (window.journalEntries || {})[r.journalEntryKey]) {
        upd[`ledger/journalEntries/${r.journalEntryKey}/status`] = 'cancelled';
        upd[`ledger/journalEntries/${r.journalEntryKey}/cancelledAt`] = Date.now();
        upd[`ledger/journalEntries/${r.journalEntryKey}/cancelledBy`] = brUser();
        upd[`ledger/journalEntries/${r.journalEntryKey}/cancelReason`] = `إعادة فتح إقرار ضريبة الدخل لسنة ${r.year}`;
    }
    upd[`ledger/incomeTaxReturns/${key}/status`] = 'draft';
    upd[`ledger/incomeTaxReturns/${key}/reopenedAt`] = Date.now();
    upd[`ledger/incomeTaxReturns/${key}/reopenedBy`] = brUser();
    upd[`ledger/incomeTaxReturns/${key}/journalEntryKey`] = null;
    await update(ref(db), upd);
    logAudit('إعادة فتح إقرار ضريبة دخل', 'المحاسبة', `إعادة فتح إقرار سنة ${r.year} وإلغاء قيد الالتزام المرتبط`);
    toast('🔓 أُعيد فتح الإقرار كمسودة — عدّله ثم اعتمده من جديد', 'ok');
    window.itaxOpenSaved(key);
};

window.itaxDeleteSaved = async function (key) {
    const r = (window.incomeTaxReturns || {})[key];
    if (!r) return;
    if (r.status === 'filed') { toast('🔒 لا يمكن حذف إقرار معتمد — أعد فتحه أولاً', 'er'); return; }
    const ok = await cf2(`هل تريد حذف مسودة إقرار سنة ${r.year} نهائياً؟`);
    if (!ok) return;
    await remove(ref(db, `ledger/incomeTaxReturns/${key}`));
    if (window._itaxState.loadedKey === key) delete window._itaxState.loadedKey;
    toast('🗑️ تم الحذف', 'ok');
};

// 🖨️ مستند الإقرار الاحترافي — يُستخدم للإقرار الجاري وللإقرارات المحفوظة كما هي (دون إعادة احتساب)
function itaxPrintDoc(d) {
    const adjList = itaxNormAdj(d.adjustments);
    const addItems = adjList.filter(a => a.kind === 'add' && (a.desc || a.amount));
    const lessItems = adjList.filter(a => a.kind === 'less' && (a.desc || a.amount));
    const addTotal = d.addTotal != null ? d.addTotal : Math.round(addItems.reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const lessTotal = d.lessTotal != null ? d.lessTotal : Math.round(lessItems.reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const adjTable = (title, items, total, color) => items.length ? `<table><thead><tr><th style="color:${color}">${title}</th><th>القيمة</th></tr></thead><tbody>
        ${items.map(a => `<tr><td style="text-align:right">${a.desc || '—'}</td><td>${fmt(a.amount)}</td></tr>`).join('')}
        <tr style="font-weight:700;background:#f8fafc"><td style="text-align:right">الإجمالي</td><td>${fmt(total)}</td></tr>
    </tbody></table>` : '';
    const stamp = d.status === 'filed'
        ? '<span style="border:2px solid #16a34a;color:#16a34a;border-radius:8px;padding:4px 18px;font-weight:800">✔ إقرار معتمد</span>'
        : '<span style="border:2px dashed #b45309;color:#b45309;border-radius:8px;padding:4px 18px;font-weight:800">مسودة — غير معتمد</span>';
    const html = `<!DOCTYPE html><html lang="ar" dir="rtl"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="utf-8"><title>إقرار ضريبة الدخل ${d.year}</title>
    <style>
        body{font-family:'Tajawal',Tahoma,Arial;padding:26px;color:#1f2937}
        table{width:100%;border-collapse:collapse;margin-top:14px}
        th,td{border:1px solid #cbd5e1;padding:8px;text-align:center;font-size:13px}
        th{background:#f1f5f9}
        h2{text-align:center;margin-bottom:2px}
        .sub{text-align:center;color:#666;font-size:12px;margin-top:0}
        .sig{display:flex;justify-content:space-between;gap:20px;margin-top:60px;font-size:13px}
        .sig div{flex:1;text-align:center;border-top:1.5px solid #94a3b8;padding-top:8px}
        @media print{button{display:none}}
    </style></head><body>
    <h2>إقرار ضريبة الدخل — المستثمر الأجنبي</h2>
    <p class="sub">السنة المالية ${d.year} · (المبالغ بالريال السعودي ما لم يذكر غير ذلك)</p>
    <div style="text-align:center;margin:12px 0">${stamp}</div>
    <table>
        <tbody>
            <tr><td style="text-align:right;font-weight:700">صافي الربح المحاسبي (قبل الضريبة)</td><td>${fmt(d.netIncome)}</td></tr>
        </tbody>
    </table>
    ${adjTable('يُضاف: بنود غير مقبولة ضريبياً (Add Back)', addItems, addTotal, '#b45309')}
    ${adjTable('يُخصم: بنود مسموح بخصمها أو معفاة (Less)', lessItems, lessTotal, '#0d9488')}
    <table>
        <tbody>
            <tr><td style="text-align:right;font-weight:700">الربح المعدّل (الربح المحاسبي + الإضافات)</td><td>${fmt(Math.round((d.netIncome + addTotal) * 100) / 100)}</td></tr>
            <tr style="font-weight:700;background:#f0fdfa"><td style="text-align:right">الربح الخاضع للضريبة (الوعاء الضريبي)</td><td>${fmt(d.taxableIncome)}</td></tr>
            <tr><td style="text-align:right">نسبة الملكية الأجنبية</td><td>${d.foreignPct}%</td></tr>
            <tr style="font-weight:700"><td style="text-align:right">حصة المستثمر الأجنبي من الوعاء الضريبي</td><td>${fmt(d.foreignShare)}</td></tr>
            <tr style="font-weight:800;background:#fef2f2;color:#b91c1c"><td style="text-align:right">ضريبة الدخل المستحقة (${ITAX_RATE}%)</td><td>${fmt(d.tax)}</td></tr>
        </tbody>
    </table>
    <div class="sig">
        <div>المحاسب</div>
        <div>المدير المالي</div>
        <div>المدير العام</div>
    </div>
    <p style="font-size:10.5px;color:#94a3b8;margin-top:30px">طُبع بتاريخ ${new Date().toLocaleDateString('ar')} ${d.updatedAt ? `· آخر تحديث للإقرار: ${new Date(d.updatedAt).toLocaleDateString('ar')}` : ''} ${d.updatedBy ? `· بواسطة: ${d.updatedBy}` : ''} — وثيقة داخلية للمراجعة، ولا تُعد إقراراً ضريبياً رسمياً.</p>
    </body></html>`;
    const w = window.open('', '_blank');
    if (!w) { toast('⚠️ يرجى السماح بالنوافذ المنبثقة', 'er'); return; }
    w.document.write(html); w.document.close();
    setTimeout(() => w.print(), 300);
}

window.itaxPrint = function () {
    const st = window._itaxState;
    const netIncome = itaxComputeNetIncome(st.year);
    st.adjustments = itaxNormAdj(st.adjustments);
    const addTotal = Math.round(st.adjustments.filter(a => a.kind === 'add').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const lessTotal = Math.round(st.adjustments.filter(a => a.kind === 'less').reduce((s, a) => s + a.amount, 0) * 100) / 100;
    const taxableIncome = Math.round((netIncome + addTotal - lessTotal) * 100) / 100;
    const foreignShare = Math.round((taxableIncome * (parseFloat(st.foreignPct) || 0) / 100) * 100) / 100;
    const tax = foreignShare > 0 ? Math.round(foreignShare * ITAX_RATE / 100 * 100) / 100 : 0;
    const saved = st.loadedKey ? (window.incomeTaxReturns || {})[st.loadedKey] : null;
    itaxPrintDoc({ year: st.year, foreignPct: st.foreignPct, adjustments: st.adjustments, netIncome, addTotal, lessTotal, adjTotal: Math.round((addTotal - lessTotal) * 100) / 100, taxableIncome, foreignShare, tax, status: saved ? saved.status : 'draft', updatedAt: saved?.updatedAt, updatedBy: saved?.updatedBy });
};

// 🖨️ طباعة إقرار محفوظ كما اعتُمد/حُفظ (من اللقطة المخزنة — دون إعادة احتساب من الدفاتر)
window.itaxPrintSaved = function (key) {
    const r = (window.incomeTaxReturns || {})[key];
    if (!r) return;
    itaxPrintDoc(r);
};

console.log('✅ Income Tax module [ACC-ITAX] loaded — annual report for foreign investor share');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🕌  [ACC-ZAKAT]   الزكاة الشرعية — احتساب وعاء الزكاة والإقرار السنوي       ║
// ║   وعاء الزكاة = (الإضافات − الحسميات)، ولا يقل عن الربح المعدّل × 2.5%        ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const ZAKAT_RATE = 2.5;
const ZAKAT_EXPENSE_ACC = '5390';
const ZAKAT_PAYABLE_ACC = '2175';
const ZAKAT_ADD_FIELDS = [
    ['capital', 'رأس المال المدفوع'],
    ['retained', 'الأرباح المُبقاة أول المدة'],
    ['reserves', 'الاحتياطيات'],
    ['provisions', 'المخصصات (نهاية الخدمة، ديون مشكوك فيها...)'],
    ['ltLoans', 'القروض والتمويل طويلة الأجل'],
    ['otherAdd', 'إضافات أخرى للوعاء']
];
const ZAKAT_DED_FIELDS = [
    ['fixedAssets', 'صافي الأصول الثابتة'],
    ['investments', 'الاستثمارات طويلة الأجل'],
    ['deferred', 'مصروفات مؤجلة / تأسيس'],
    ['losses', 'الخسائر المتراكمة'],
    ['otherDed', 'حسميات أخرى']
];
window._zakatState = window._zakatState || { year: new Date().getFullYear(), add: {}, ded: {}, profitOverride: null };

function zakatCompute() {
    const st = window._zakatState;
    const addTotal = ZAKAT_ADD_FIELDS.reduce((s, [k]) => s + (parseFloat(st.add[k]) || 0), 0);
    const dedTotal = ZAKAT_DED_FIELDS.reduce((s, [k]) => s + (parseFloat(st.ded[k]) || 0), 0);
    const baseRaw = Math.round((addTotal - dedTotal) * 100) / 100;
    let profit = 0;
    if (st.profitOverride != null && st.profitOverride !== '') profit = parseFloat(st.profitOverride) || 0;
    else { try { profit = Math.round((itaxComputeNetIncome(st.year) || 0) * 100) / 100; } catch (e) { profit = 0; } }
    const base = Math.max(baseRaw, profit > 0 ? profit : 0);
    const zakat = base > 0 ? Math.round(base * ZAKAT_RATE / 100 * 100) / 100 : 0;
    return { addTotal, dedTotal, baseRaw, profit, base, zakat, floorApplied: profit > 0 && profit > baseRaw };
}
window.zakatSetField = function (group, key, value) { window._zakatState[group][key] = value; renderZakat(); };
window.zakatSetYear = function (v) { window._zakatState.year = parseInt(v) || new Date().getFullYear(); window._zakatState.profitOverride = null; renderZakat(); };
window.zakatSetProfit = function (v) { window._zakatState.profitOverride = v; renderZakat(); };
window.zakatResetProfit = function () { window._zakatState.profitOverride = null; renderZakat(); };
window.zakatCreateAccounts = async function () {
    const byCode = brByCode ? brByCode() : {};
    if (!byCode[ZAKAT_EXPENSE_ACC]) await push(R.coa, { code: ZAKAT_EXPENSE_ACC, nameAr: 'مصروف الزكاة', nameEn: 'Zakat Expense', type: 'expense', nature: 'detail', parent: '5300' });
    if (!byCode[ZAKAT_PAYABLE_ACC]) await push(R.coa, { code: ZAKAT_PAYABLE_ACC, nameAr: 'الزكاة المستحقة', nameEn: 'Zakat Payable', type: 'liability', nature: 'detail', parent: '2100' });
    toast('✅ تم إنشاء حسابات الزكاة في شجرة الحسابات', 'ok');
};
window.renderZakat = function () {
    const pg = $('pg-zakat'); if (!pg) return;
    const st = window._zakatState;
    const c = zakatCompute();
    const byCode = brByCode ? brByCode() : {};
    const hasAccts = !!byCode[ZAKAT_EXPENSE_ACC] && !!byCode[ZAKAT_PAYABLE_ACC];
    const saved = window.zakatReturns || {};
    const thisYear = Object.entries(saved).find(([, r]) => r.year === st.year);
    const filed = thisYear && thisYear[1].status === 'filed';
    const fld = (g, k, label) => `<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;padding:7px 2px;border-bottom:1px solid #f3f3f3"><label style="font-size:12.5px;color:#444;flex:1">${label}</label><input type="number" step="any" value="${st[g][k] != null ? st[g][k] : ''}" onchange="zakatSetField('${g}','${k}',this.value)" ${filed ? 'disabled' : ''} style="width:150px;padding:7px;border:1.5px solid #d0d7e0;border-radius:7px;font-family:inherit;font-size:13px;text-align:left" placeholder="0"></div>`;
    const savedRows = Object.entries(saved).sort((a, b) => (b[1].year || 0) - (a[1].year || 0)).map(([k, r]) => `<tr style="border-bottom:1px solid #f0f0f0">
        <td style="padding:8px">${r.year}</td><td style="text-align:left;padding:8px">${fmt(r.base)}</td><td style="text-align:left;padding:8px;font-weight:700;color:#0e6655">${fmt(r.zakat)}</td>
        <td style="text-align:center"><span style="background:${r.status === 'filed' ? '#27ae60' : '#f39c12'};color:#fff;padding:2px 9px;border-radius:10px;font-size:11px">${r.status === 'filed' ? 'معتمد' : 'مسودة'}</span></td>
        <td style="text-align:center;white-space:nowrap"><button onclick="zakatOpenSaved('${k}')" style="background:none;border:none;color:#2563eb;cursor:pointer;font-size:13px" title="فتح">📂</button>${r.status !== 'filed' ? `<button onclick="zakatDeleteSaved('${k}')" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:13px" title="حذف">🗑️</button>` : ''}</td></tr>`).join('');

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#0e6655,#16a085);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div><h2 style="margin:0">🕌 الزكاة الشرعية</h2><div style="opacity:.9;margin-top:4px;font-size:13px">احتساب وعاء الزكاة والإقرار السنوي (2.5% من الوعاء الزكوي)</div></div>
            <div style="display:flex;align-items:center;gap:8px;background:rgba(255,255,255,.12);border-radius:10px;padding:8px 12px"><span style="font-size:13px">السنة:</span><input type="number" value="${st.year}" onchange="zakatSetYear(this.value)" style="width:90px;padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:14px;font-weight:700;text-align:center"></div>
        </div>
    </div>
    ${filed ? `<div class="card" style="background:#eafaf1;border:1px solid #abebc6;padding:10px 14px;margin-bottom:14px;font-size:13px;color:#1e8449">🔒 إقرار زكاة سنة ${st.year} <strong>معتمد</strong> — للعرض فقط.</div>` : ''}
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(320px,1fr));gap:14px;margin-bottom:14px">
        <div class="card" style="padding:16px"><div style="font-size:14px;font-weight:900;color:#16a085;margin-bottom:8px">➕ الإضافات للوعاء (مصادر التمويل)</div>${ZAKAT_ADD_FIELDS.map(([k, l]) => fld('add', k, l)).join('')}<div style="display:flex;justify-content:space-between;padding-top:10px;font-weight:800;color:#0e6655"><span>إجمالي الإضافات</span><span>${fmt(c.addTotal)}</span></div></div>
        <div class="card" style="padding:16px"><div style="font-size:14px;font-weight:900;color:#c0392b;margin-bottom:8px">➖ الحسميات من الوعاء</div>${ZAKAT_DED_FIELDS.map(([k, l]) => fld('ded', k, l)).join('')}<div style="display:flex;justify-content:space-between;padding-top:10px;font-weight:800;color:#c0392b"><span>إجمالي الحسميات</span><span>${fmt(c.dedTotal)}</span></div></div>
    </div>
    <div class="card" style="padding:16px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;gap:10px;flex-wrap:wrap">
            <div style="flex:1;min-width:240px"><div style="font-size:13px;font-weight:700;color:#1a3a5c">💰 صافي الربح المعدّل للسنة (حدّ أدنى للوعاء)</div><div style="font-size:11px;color:#888;margin-top:2px">يُسحب تلقائياً من قائمة الدخل — يمكنك تعديله يدوياً</div></div>
            <div style="display:flex;align-items:center;gap:6px"><input type="number" step="any" value="${st.profitOverride != null && st.profitOverride !== '' ? st.profitOverride : c.profit}" onchange="zakatSetProfit(this.value)" ${filed ? 'disabled' : ''} style="width:160px;padding:8px;border:1.5px solid #d0d7e0;border-radius:7px;font-family:inherit;font-size:13px;text-align:left">${st.profitOverride != null && st.profitOverride !== '' ? '<button onclick="zakatResetProfit()" style="background:#f0f0f0;border:none;border-radius:6px;padding:7px 10px;cursor:pointer;font-size:12px" title="استعادة التلقائي">↺</button>' : ''}</div>
        </div>
    </div>
    <div class="card" style="padding:18px;margin-bottom:14px;background:linear-gradient(135deg,#f8fdfb,#eafaf1);border:1.5px solid #abebc6">
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;text-align:center">
            <div><div style="font-size:11px;color:#666">الوعاء قبل الحدّ الأدنى</div><div style="font-size:18px;font-weight:800;color:#1a3a5c">${fmt(c.baseRaw)}</div></div>
            <div><div style="font-size:11px;color:#666">${c.floorApplied ? '⬆️ طُبّق حدّ الربح' : 'الوعاء الزكوي'}</div><div style="font-size:22px;font-weight:900;color:#16a085">${fmt(c.base)}</div></div>
            <div><div style="font-size:11px;color:#666">النسبة</div><div style="font-size:18px;font-weight:800;color:#1a3a5c">${ZAKAT_RATE}%</div></div>
            <div style="background:#0e6655;color:#fff;border-radius:12px;padding:8px"><div style="font-size:11px;opacity:.9">الزكاة المستحقة</div><div style="font-size:24px;font-weight:900">${fmt(c.zakat)}</div></div>
        </div>
        ${c.floorApplied ? '<div style="font-size:11px;color:#b9770e;margin-top:10px;text-align:center">ℹ️ الوعاء أقل من الربح المعدّل — فاعتُمد الربح كحدّ أدنى للوعاء وفق قواعد الهيئة.</div>' : ''}
    </div>
    ${!filed ? `<div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px">
        ${!hasAccts ? `<button class="btn" onclick="zakatCreateAccounts()" style="background:#f39c12;color:#fff;padding:9px 16px;font-weight:800">⚙️ إنشاء حسابات الزكاة</button>` : ''}
        <button class="btn" onclick="zakatSaveReturn('draft')" style="background:#2d6a9f;color:#fff;padding:9px 18px;font-weight:800">💾 حفظ مسودة</button>
        <button class="btn" onclick="zakatSaveReturn('filed')" style="background:#16a085;color:#fff;padding:9px 18px;font-weight:800" ${(!hasAccts && c.zakat > 0) ? 'disabled title="أنشئ الحسابات أولاً"' : ''}>✅ اعتماد وإنشاء القيد</button>
    </div>` : ''}
    <div style="font-size:11px;color:#888;margin-bottom:14px;line-height:1.7">⚠️ هذا احتساب إرشادي مبسّط لوعاء الزكاة. النموذج الرسمي لهيئة الزكاة قد يتضمّن بنوداً إضافية — راجع مستشارك الضريبي قبل التقديم النهائي.</div>
    ${savedRows ? `<div class="card" style="padding:0;overflow:hidden"><div style="padding:12px 16px;font-weight:800;color:#1a3a5c">📋 سجل إقرارات الزكاة</div><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12.5px"><thead><tr style="background:#0e6655;color:#fff"><th style="padding:8px;text-align:right">السنة</th><th style="text-align:left;padding:8px">الوعاء</th><th style="text-align:left;padding:8px">الزكاة</th><th>الحالة</th><th>إجراءات</th></tr></thead><tbody>${savedRows}</tbody></table></div></div>` : ''}`;
};
window.zakatSaveReturn = async function (status) {
    const st = window._zakatState; const c = zakatCompute();
    if (status === 'filed' && typeof brIsFinance === 'function' && !brIsFinance()) { toast('🚫 اعتماد الإقرار يتطلب صلاحية المحاسبة المالية', 'er'); return; }
    const saved = window.zakatReturns || {};
    const existing = Object.entries(saved).find(([, r]) => r.year === st.year);
    if (existing && existing[1].status === 'filed') { toast('🔒 إقرار زكاة هذه السنة معتمد ولا يمكن تعديله', 'er'); return; }
    const byCode = brByCode ? brByCode() : {};
    if (status === 'filed' && c.zakat > 0 && (!byCode[ZAKAT_EXPENSE_ACC] || !byCode[ZAKAT_PAYABLE_ACC])) { toast('⚠️ أنشئ حسابات الزكاة أولاً', 'er'); return; }
    const usr = (typeof brUser === 'function') ? brUser() : 'system';
    const payload = { year: st.year, additions: st.add, deductions: st.ded, addTotal: c.addTotal, dedTotal: c.dedTotal, baseRaw: c.baseRaw, profit: c.profit, base: c.base, rate: ZAKAT_RATE, zakat: c.zakat, status, updatedAt: Date.now(), updatedBy: usr };
    let key;
    if (existing) { key = existing[0]; await update(ref(db, 'ledger/zakatReturns/' + key), payload); }
    else { payload.createdAt = Date.now(); payload.createdBy = usr; const r = await push(R.zakatReturns, payload); key = r.key; }
    if (status === 'filed' && c.zakat > 0) {
        const je = { date: st.year + '-12-31', description: 'قيد استحقاق الزكاة لسنة ' + st.year, status: 'posted', lines: [
            { accountCode: ZAKAT_EXPENSE_ACC, accountName: byCode[ZAKAT_EXPENSE_ACC] ? byCode[ZAKAT_EXPENSE_ACC].nameAr : 'مصروف الزكاة', description: 'زكاة ' + st.year, date: '', costCenter: '', projectId: '', debit: c.zakat, credit: 0 },
            { accountCode: ZAKAT_PAYABLE_ACC, accountName: byCode[ZAKAT_PAYABLE_ACC] ? byCode[ZAKAT_PAYABLE_ACC].nameAr : 'الزكاة المستحقة', description: 'زكاة ' + st.year, date: '', costCenter: '', projectId: '', debit: 0, credit: c.zakat }
        ], createdAt: Date.now(), createdBy: usr, source: 'zakat', sourceKey: key };
        const jeRef = await push(R.jrn, je);
        await update(ref(db, 'ledger/zakatReturns/' + key), { journalEntryKey: jeRef.key });
    }
    if (status === 'filed' && typeof logAudit === 'function') logAudit('اعتماد إقرار زكاة', 'المحاسبة', 'اعتماد إقرار الزكاة لسنة ' + st.year);
    toast(status === 'filed' ? '✅ تم اعتماد الإقرار وإنشاء قيد الزكاة' : '💾 تم حفظ المسودة', 'ok');
    renderZakat();
};
window.zakatOpenSaved = function (key) { const r = (window.zakatReturns || {})[key]; if (!r) return; window._zakatState = { year: r.year, add: r.additions || {}, ded: r.deductions || {}, profitOverride: r.profit }; renderZakat(); };
window.zakatDeleteSaved = async function (key) { const r = (window.zakatReturns || {})[key]; if (!r) return; if (r.status === 'filed') { toast('🔒 لا يمكن حذف إقرار معتمد', 'er'); return; } if (!(await cf2('حذف إقرار الزكاة؟'))) return; await remove(ref(db, 'ledger/zakatReturns/' + key)).then(() => toast('🗑️ تم الحذف', 'ok')); };
console.log('✅ Zakat module [ACC-ZAKAT] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🌐  [ACC-WHT]   ضريبة الاستقطاع (Withholding Tax) على غير المقيمين         ║
// ║   سجلّ المبالغ المستقطعة + التقرير الشهري للهيئة + متابعة التوريد             ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const WHT_TYPES = [
    { id: 'services', label: 'خدمات فنية/استشارية', rate: 5 },
    { id: 'rent', label: 'إيجار', rate: 5 },
    { id: 'royalty', label: 'إتاوات', rate: 15 },
    { id: 'mgmt', label: 'أتعاب إدارة', rate: 20 },
    { id: 'dividends', label: 'أرباح أسهم/توزيعات', rate: 5 },
    { id: 'interest', label: 'فوائد/أعباء قروض', rate: 5 },
    { id: 'insurance', label: 'تأمين/إعادة تأمين', rate: 5 },
    { id: 'tickets', label: 'تذاكر/شحن/نقل دولي', rate: 5 },
    { id: 'telecom', label: 'اتصالات دولية', rate: 5 },
    { id: 'other', label: 'مدفوعات أخرى', rate: 15 }
];
function whtTypeLabel(id) { const t = WHT_TYPES.find(x => x.id === id); return t ? t.label : (id || '—'); }
function whtTypeRate(id) { const t = WHT_TYPES.find(x => x.id === id); return t ? t.rate : 5; }
window._whtState = window._whtState || { adding: false, editing: null, filterMonth: '' };

window.renderWHT = function () {
    const pg = $('pg-wht'); if (!pg) return;
    const st = window._whtState;
    const all = Object.entries(window.whtRecords || {}).map(([k, r]) => ({ k, ...r }));
    const rows = all.filter(r => !st.filterMonth || (r.date || '').slice(0, 7) === st.filterMonth).sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    const totGross = rows.reduce((s, r) => s + (parseFloat(r.gross) || 0), 0);
    const totWht = rows.reduce((s, r) => s + (parseFloat(r.wht) || 0), 0);
    const remitted = rows.filter(r => r.status === 'remitted').reduce((s, r) => s + (parseFloat(r.wht) || 0), 0);
    const due = totWht - remitted;
    const kpi = (icon, label, val, col) => `<div class="card" style="padding:12px 14px;text-align:center;border-top:3px solid ${col}"><div style="font-size:11px;color:#666">${icon} ${label}</div><div style="font-size:19px;font-weight:900;color:${col};margin-top:3px">${val}</div></div>`;

    const cur = (st.editing && (window.whtRecords || {})[st.editing]) ? (window.whtRecords || {})[st.editing] : {};
    const typeOpts = WHT_TYPES.map(t => `<option value="${t.id}" ${cur.type === t.id ? 'selected' : ''}>${t.label} (${t.rate}%)</option>`).join('');
    const inS = 'width:100%;padding:8px;border:1.5px solid #d0d7e0;border-radius:7px;font-family:inherit;font-size:13px';

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#1f618d,#2980b9);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0">🌐 ضريبة الاستقطاع (WHT)</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">المبالغ المستقطعة من المدفوعات لغير المقيمين — مع التقرير الشهري للهيئة ومتابعة التوريد</div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:14px">
        ${kpi('🧾', 'عدد العمليات', rows.length, '#2980b9')}
        ${kpi('💵', 'إجمالي المبالغ', fmt(totGross), '#16a085')}
        ${kpi('🌐', 'إجمالي الاستقطاع', fmt(totWht), '#8e44ad')}
        ${kpi('⚠️', 'مستحق للتوريد', fmt(due), due > 0.01 ? '#c0392b' : '#27ae60')}
    </div>
    <div style="display:flex;gap:10px;margin-bottom:12px;flex-wrap:wrap;align-items:center">
        <button class="btn" onclick="whtAdd()" style="background:#1f618d;color:#fff;padding:9px 16px;font-weight:800">➕ إضافة استقطاع</button>
        <button class="btn" onclick="whtExport()" style="background:#1e8449;color:#fff;padding:9px 16px;font-weight:800">📊 تصدير Excel</button>
        <button class="btn" onclick="whtPrint()" style="background:#34495e;color:#fff;padding:9px 16px;font-weight:800">🖨️ التقرير الشهري</button>
        <div style="margin-inline-start:auto;display:flex;align-items:center;gap:6px"><label style="font-size:12px;color:#888">الشهر:</label><input type="month" value="${st.filterMonth}" onchange="whtSetFilter(this.value)" style="padding:7px;border:1.5px solid #d0d7e0;border-radius:7px;font-family:inherit;font-size:13px">${st.filterMonth ? `<button onclick="whtSetFilter('')" style="background:#f0f0f0;border:none;border-radius:6px;padding:7px 9px;cursor:pointer">✕</button>` : ''}</div>
    </div>
    ${st.adding ? `<div class="card" style="padding:16px;margin-bottom:14px;border:2px solid #1f618d">
        <div style="font-size:14px;font-weight:900;color:#1f618d;margin-bottom:12px">${st.editing ? '✏️ تعديل' : '➕ إضافة'} استقطاع</div>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px">
            <div><label style="font-size:11px;color:#666;font-weight:700">التاريخ</label><input id="wht_date" type="date" value="${cur.date || new Date().toISOString().slice(0, 10)}" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">المستفيد (غير مقيم)</label><input id="wht_benef" type="text" value="${(cur.beneficiary || '').replace(/"/g, '&quot;')}" placeholder="اسم المورد/الجهة" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">الدولة</label><input id="wht_country" type="text" value="${(cur.country || '').replace(/"/g, '&quot;')}" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">نوع الدفعة</label><select id="wht_type" onchange="whtOnType()" style="${inS}">${typeOpts}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">المبلغ الإجمالي</label><input id="wht_gross" type="number" step="any" value="${cur.gross != null ? cur.gross : ''}" oninput="whtPreview()" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">النسبة %</label><input id="wht_rate" type="number" step="any" value="${cur.rate != null ? cur.rate : whtTypeRate(cur.type || 'services')}" oninput="whtPreview()" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">مرجع الفاتورة</label><input id="wht_ref" type="text" value="${(cur.invoiceRef || '').replace(/"/g, '&quot;')}" style="${inS}"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">الحالة</label><select id="wht_status" style="${inS}"><option value="recorded" ${cur.status !== 'remitted' ? 'selected' : ''}>مُسجّل</option><option value="remitted" ${cur.status === 'remitted' ? 'selected' : ''}>مورّد للهيئة</option></select></div>
        </div>
        <div id="whtPrev" style="margin-top:12px;background:#eaf4fb;border-radius:8px;padding:10px 14px;font-size:13px;color:#1f618d">${whtPreviewText(cur)}</div>
        <div style="display:flex;gap:10px;margin-top:12px"><button class="btn" onclick="whtSave()" style="background:#1f618d;color:#fff;padding:9px 22px;font-weight:800">💾 حفظ</button><button class="btn" onclick="whtCancel()" style="background:#f0f0f0;color:#555;padding:9px 22px;font-weight:700">إلغاء</button></div>
    </div>` : ''}
    <div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:780px">
        <thead><tr style="background:#1f618d;color:#fff"><th style="padding:8px;text-align:right">التاريخ</th><th style="text-align:right">المستفيد</th><th style="text-align:right">النوع</th><th>المبلغ</th><th>%</th><th>الاستقطاع</th><th>الصافي</th><th>الحالة</th><th>إجراءات</th></tr></thead>
        <tbody>${rows.length ? rows.map(r => `<tr style="border-bottom:1px solid #f0f0f0;background:${r.status === 'remitted' ? '#fff' : '#fffaf0'}">
            <td style="padding:7px 8px;white-space:nowrap">${r.date || '—'}</td><td>${(r.beneficiary || '—').replace(/</g, '&lt;')}${r.country ? `<div style="font-size:10px;color:#888">${r.country}</div>` : ''}</td>
            <td style="font-size:11px">${whtTypeLabel(r.type)}</td><td style="text-align:left">${fmt(r.gross)}</td><td style="text-align:center">${r.rate}%</td>
            <td style="text-align:left;font-weight:700;color:#8e44ad">${fmt(r.wht)}</td><td style="text-align:left">${fmt(r.net)}</td>
            <td style="text-align:center"><span style="background:${r.status === 'remitted' ? '#27ae60' : '#f39c12'};color:#fff;padding:2px 8px;border-radius:10px;font-size:10px">${r.status === 'remitted' ? 'مورّد' : 'مُسجّل'}</span></td>
            <td style="text-align:center;white-space:nowrap">${r.status !== 'remitted' ? `<button onclick="whtMarkRemitted('${r.k}')" style="background:none;border:none;color:#27ae60;cursor:pointer;font-size:13px" title="تأشير كمورّد">✅</button>` : ''}<button onclick="whtEdit('${r.k}')" style="background:none;border:none;color:#2563eb;cursor:pointer;font-size:13px" title="تعديل">✏️</button><button onclick="whtDelete('${r.k}')" style="background:none;border:none;color:#c0392b;cursor:pointer;font-size:13px" title="حذف">🗑️</button></td>
        </tr>`).join('') : '<tr><td colspan="9" style="text-align:center;color:#999;padding:24px">لا توجد عمليات استقطاع — اضغط "➕ إضافة"</td></tr>'}</tbody>
    </table></div></div>
    <div style="font-size:11px;color:#888;margin-top:12px;line-height:1.7">💡 يُورَّد الاستقطاع للهيئة خلال أول 10 أيام من الشهر التالي. القيد المحاسبي يُسجَّل ضمن سند الصرف للمورد (إجمالي − استقطاع = المدفوع نقداً).</div>`;
};
function whtPreviewText(cur) {
    const g = parseFloat(cur.gross) || 0, rt = cur.rate != null ? (parseFloat(cur.rate) || 0) : whtTypeRate(cur.type || 'services');
    const w = Math.round(g * rt / 100 * 100) / 100;
    return `الاستقطاع: <strong>${fmt(w)}</strong> · المدفوع للمستفيد (الصافي): <strong>${fmt(g - w)}</strong>`;
}
window.whtPreview = function () { const el = $('whtPrev'); if (el) el.innerHTML = whtPreviewText({ gross: $('wht_gross')?.value, rate: $('wht_rate')?.value }); };
window.whtOnType = function () { const t = $('wht_type')?.value; if ($('wht_rate')) $('wht_rate').value = whtTypeRate(t); whtPreview(); };
window.whtAdd = function () { window._whtState.adding = true; window._whtState.editing = null; renderWHT(); };
window.whtEdit = function (k) { window._whtState.adding = true; window._whtState.editing = k; renderWHT(); };
window.whtCancel = function () { window._whtState.adding = false; window._whtState.editing = null; renderWHT(); };
window.whtSetFilter = function (v) { window._whtState.filterMonth = v; renderWHT(); };
window.whtSave = async function () {
    const gross = parseFloat($('wht_gross')?.value) || 0;
    const beneficiary = ($('wht_benef')?.value || '').trim();
    if (!beneficiary || gross <= 0) { toast('⚠️ أدخل المستفيد والمبلغ', 'er'); return; }
    const rate = parseFloat($('wht_rate')?.value) || 0;
    const wht = Math.round(gross * rate / 100 * 100) / 100;
    const usr = (typeof brUser === 'function') ? brUser() : 'system';
    const data = { date: $('wht_date')?.value || new Date().toISOString().slice(0, 10), beneficiary, country: ($('wht_country')?.value || '').trim(), type: $('wht_type')?.value || 'services', gross, rate, wht, net: Math.round((gross - wht) * 100) / 100, invoiceRef: ($('wht_ref')?.value || '').trim(), status: $('wht_status')?.value || 'recorded', notes: '', updatedAt: Date.now(), updatedBy: usr };
    const k = window._whtState.editing;
    try {
        if (k) { await update(ref(db, 'ledger/whtRecords/' + k), data); }
        else { data.createdAt = Date.now(); data.createdBy = usr; await push(R.whtRecords, data); }
        window._whtState.adding = false; window._whtState.editing = null; toast('✅ تم الحفظ', 'ok'); renderWHT();
    } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.whtMarkRemitted = async function (k) { try { await update(ref(db, 'ledger/whtRecords/' + k), { status: 'remitted', remitDate: new Date().toISOString().slice(0, 10) }); toast('✅ تم تأشيرها كمورّدة', 'ok'); } catch (e) { toast('❌ ' + (e.message || e), 'er'); } };
window.whtDelete = async function (k) { if (!(await cf2('حذف عملية الاستقطاع؟'))) return; try { await remove(ref(db, 'ledger/whtRecords/' + k)); toast('🗑️ تم الحذف', 'ok'); } catch (e) { toast('❌ ' + (e.message || e), 'er'); } };
window.whtExport = function () {
    const st = window._whtState;
    const rows = Object.values(window.whtRecords || {}).filter(r => !st.filterMonth || (r.date || '').slice(0, 7) === st.filterMonth).sort((a, b) => (a.date || '').localeCompare(b.date || ''));
    if (!rows.length) { toast('⚠️ لا بيانات للتصدير', 'er'); return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة', 'er'); return; }
    const data = rows.map(r => ({ 'التاريخ': r.date || '', 'المستفيد': r.beneficiary || '', 'الدولة': r.country || '', 'نوع الدفعة': whtTypeLabel(r.type), 'المبلغ الإجمالي': r.gross || 0, 'النسبة %': r.rate || 0, 'الاستقطاع': r.wht || 0, 'الصافي المدفوع': r.net || 0, 'مرجع الفاتورة': r.invoiceRef || '', 'الحالة': r.status === 'remitted' ? 'مورّد' : 'مسجّل' }));
    const ws = XLSX.utils.json_to_sheet(data); const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'ضريبة الاستقطاع'); XLSX.writeFile(wb, 'WHT_' + (st.filterMonth || 'الكل') + '.xlsx');
    toast('✅ تم التصدير', 'ok');
};
window.whtPrint = function () {
    const st = window._whtState;
    const rows = Object.values(window.whtRecords || {}).filter(r => !st.filterMonth || (r.date || '').slice(0, 7) === st.filterMonth).sort((a, b) => (a.date || '').localeCompare(b.date || ''));
    if (!rows.length) { toast('⚠️ لا بيانات للطباعة', 'er'); return; }
    const company = (window.gbrCfg && window.gbrCfg.companyAr) || 'الشركة';
    const totG = rows.reduce((s, r) => s + (+r.gross || 0), 0), totW = rows.reduce((s, r) => s + (+r.wht || 0), 0);
    const html = `<!DOCTYPE html><html dir="rtl" lang="ar"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>تقرير ضريبة الاستقطاع</title>
    <style>*{box-sizing:border-box;-webkit-print-color-adjust:exact!important;font-family:'Tajawal',Tahoma,Arial}body{padding:20px;color:#1a3a5c;direction:rtl}h2{margin:0;color:#1f618d}table{width:100%;border-collapse:collapse;font-size:12px;margin-top:14px}th{background:#1f618d;color:#fff;padding:8px;text-align:right}td{padding:7px 8px;border:1px solid #e0e0e0}tfoot td{font-weight:800;background:#f4f6f8}@page{size:A4 landscape;margin:1cm}</style></head><body>
    <div style="display:flex;justify-content:space-between;align-items:center;border-bottom:3px solid #1f618d;padding-bottom:10px"><div><h2>🌐 تقرير ضريبة الاستقطاع</h2><div style="font-size:12px;color:#666;margin-top:4px">${company}</div></div><div style="text-align:left;font-size:12px;color:#666">الفترة: ${st.filterMonth || 'الكل'}<br>عدد العمليات: ${rows.length}</div></div>
    <table><thead><tr><th>التاريخ</th><th>المستفيد</th><th>الدولة</th><th>النوع</th><th>المبلغ</th><th>%</th><th>الاستقطاع</th></tr></thead>
    <tbody>${rows.map(r => `<tr><td>${r.date || ''}</td><td>${r.beneficiary || ''}</td><td>${r.country || ''}</td><td>${whtTypeLabel(r.type)}</td><td style="text-align:left">${fmt(r.gross)}</td><td style="text-align:center">${r.rate}%</td><td style="text-align:left">${fmt(r.wht)}</td></tr>`).join('')}</tbody>
    <tfoot><tr><td colspan="4">الإجمالي</td><td style="text-align:left">${fmt(totG)}</td><td></td><td style="text-align:left">${fmt(totW)}</td></tr></tfoot></table>
    <div style="margin-top:24px;font-size:12px">المبلغ المستحق توريده للهيئة: <strong>${fmt(totW)}</strong></div></body></html>`;
    const w = window.open('', '_blank'); w.document.write(html); w.document.close(); setTimeout(() => { try { w.print(); } catch (e) { } }, 400);
};
console.log('✅ Withholding Tax module [ACC-WHT] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ✅  [ACC-CLOSE]   قائمة الإقفال الشهري/السنوي — خطوات إغلاق الفترة          ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const CLOSE_STEPS_MONTH = [
    { id: 'post_all', label: 'ترحيل جميع القيود (لا توجد مسودات)', nav: 'journalentries', auto: 'drafts' },
    { id: 'bank_rec', label: 'إنجاز التسوية البنكية لكل الحسابات', nav: 'bankrec' },
    { id: 'ar_recon', label: 'مطابقة أرصدة العملاء (الذمم المدينة)', nav: 'aging' },
    { id: 'ap_recon', label: 'مطابقة أرصدة الموردين (الذمم الدائنة)', nav: 'aging' },
    { id: 'inventory', label: 'جرد وتقييم المخزون', nav: 'inventoryreports' },
    { id: 'depreciation', label: 'إثبات إهلاك الأصول الثابتة', nav: 'assets' },
    { id: 'amortization', label: 'إثبات إطفاء المصروفات المؤجلة', nav: 'amortization' },
    { id: 'accruals', label: 'إثبات المخصصات والاستحقاقات والقيود المتكررة', nav: 'recurringjournals' },
    { id: 'fx', label: 'إعادة تقييم أرصدة العملات الأجنبية', nav: 'fxrevaluation' },
    { id: 'vat', label: 'إعداد ومراجعة الإقرار الضريبي (VAT)', nav: 'vatreturn' },
    { id: 'wht', label: 'مراجعة ضريبة الاستقطاع وتوريدها للهيئة', nav: 'wht' },
    { id: 'tb', label: 'مراجعة ميزان المراجعة (متوازن)', nav: 'trialbalance', auto: 'balance' },
    { id: 'fs_review', label: 'مراجعة القوائم المالية الأولية', nav: 'finstatements' },
    { id: 'lock', label: 'إقفال الفترة المحاسبية (قفل القيود)', nav: 'periodlock', auto: 'locked' }
];
const CLOSE_STEPS_YEAR_EXTRA = [
    { id: 'rev_rec', label: 'إثبات الإيراد بنسبة الإنجاز للمشاريع', nav: 'revrecognition' },
    { id: 'zakat', label: 'احتساب واعتماد إقرار الزكاة', nav: 'zakat' },
    { id: 'income_tax', label: 'احتساب ضريبة الدخل (إن وُجد شريك أجنبي)', nav: 'incometax' },
    { id: 'year_close', label: 'إقفال السنة وترحيل الأرباح المحتجزة', nav: 'yearclosing' }
];
window._closingState = window._closingState || { type: 'month', period: new Date().toISOString().slice(0, 7) };
function closingSteps() { return window._closingState.type === 'year' ? CLOSE_STEPS_MONTH.concat(CLOSE_STEPS_YEAR_EXTRA) : CLOSE_STEPS_MONTH.slice(); }
function closingPeriodKey() { return window._closingState.type + ':' + window._closingState.period; }
function closingAuto() {
    const p = window._closingState.period; let drafts = 0, unbalanced = 0;
    Object.values(window.journalEntries || {}).forEach(j => {
        if (!(j.date || '').startsWith(p)) return;
        if (j.status === 'draft') drafts++;
        const td = (j.lines || []).reduce((s, l) => s + (parseFloat(l.debit) || 0), 0);
        const tc = (j.lines || []).reduce((s, l) => s + (parseFloat(l.credit) || 0), 0);
        if (j.status === 'posted' && Math.abs(td - tc) >= 0.01) unbalanced++;
    });
    let locked = null;
    try { if (typeof isPeriodLocked === 'function') locked = isPeriodLocked(window._closingState.type === 'year' ? (p + '-12-31') : (p + '-15')); } catch (e) { locked = null; }
    return { drafts, unbalanced, locked };
}
window.closingSetType = function (t) { window._closingState.type = t; window._closingState.period = (t === 'year') ? String(new Date().getFullYear()) : new Date().toISOString().slice(0, 7); renderClosing(); };
window.closingSetPeriod = function (v) { window._closingState.period = v; renderClosing(); };
window.closingToggle = async function (id) {
    const pk = closingPeriodKey(); const st = window._closingState;
    const cur = !!(window.closingData?.[pk]?.items?.[id]?.done);
    const usr = (typeof brUser === 'function') ? brUser() : 'system';
    try {
        await update(ref(db, 'ledger/closingChecklists/' + pk), { period: st.period, type: st.type, updatedAt: Date.now() });
        await update(ref(db, 'ledger/closingChecklists/' + pk + '/items/' + id), cur ? { done: false, undoneBy: usr, undoneAt: Date.now() } : { done: true, doneBy: usr, doneAt: Date.now() });
    } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.closingNote = async function (id, val) {
    const pk = closingPeriodKey();
    try { await update(ref(db, 'ledger/closingChecklists/' + pk + '/items/' + id), { note: (val || '').slice(0, 300) }); } catch (e) { }
};
window.closingFinalize = async function () {
    const steps = closingSteps(); const pk = closingPeriodKey(); const items = window.closingData?.[pk]?.items || {};
    const undone = steps.filter(s => !items[s.id]?.done);
    if (undone.length && !(await cf2(`يتبقّى ${undone.length} خطوة غير مكتملة. تأكيد إقفال الفترة كمكتملة رغم ذلك؟`))) return;
    if (!undone.length && !(await cf2('تأكيد وضع علامة "الفترة مُقفلة ومراجَعة"؟'))) return;
    const usr = (typeof brUser === 'function') ? brUser() : 'system';
    try {
        await update(ref(db, 'ledger/closingChecklists/' + pk), { period: window._closingState.period, type: window._closingState.type, status: 'closed', closedBy: usr, closedAt: Date.now() });
        if (typeof logAudit === 'function') logAudit('إقفال فترة', 'المحاسبة', 'إغلاق قائمة الإقفال للفترة ' + pk);
        toast('🔒 تم وضع علامة الإقفال للفترة', 'ok'); renderClosing();
    } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.closingReopen = async function () {
    const pk = closingPeriodKey();
    if (!(await cf2('إعادة فتح الفترة للتعديل على القائمة؟'))) return;
    try { await update(ref(db, 'ledger/closingChecklists/' + pk), { status: 'open', reopenedAt: Date.now() }); toast('🔓 أُعيد فتح الفترة', 'ok'); renderClosing(); } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.renderClosing = function () {
    const pg = $('pg-closing'); if (!pg) return;
    const st = window._closingState; const steps = closingSteps();
    const rec = window.closingData?.[closingPeriodKey()] || {}; const items = rec.items || {};
    const closed = rec.status === 'closed';
    const a = closingAuto();
    const doneCount = steps.filter(s => items[s.id]?.done).length;
    const pct = steps.length ? Math.round(doneCount / steps.length * 100) : 0;
    const autoBadge = (s) => {
        if (s.auto === 'drafts') return a.drafts > 0 ? `<span title="يوجد ${a.drafts} قيد مسودة في الفترة" style="background:#fdebd0;color:#b9770e;font-size:10px;padding:2px 7px;border-radius:9px">⚠️ ${a.drafts} مسودة</span>` : `<span style="background:#eafaf1;color:#1e8449;font-size:10px;padding:2px 7px;border-radius:9px">✓ لا مسودات</span>`;
        if (s.auto === 'balance') return a.unbalanced > 0 ? `<span title="${a.unbalanced} قيد غير متوازن" style="background:#fdecea;color:#c0392b;font-size:10px;padding:2px 7px;border-radius:9px">⚠️ ${a.unbalanced} غير متوازن</span>` : `<span style="background:#eafaf1;color:#1e8449;font-size:10px;padding:2px 7px;border-radius:9px">✓ متوازن</span>`;
        if (s.auto === 'locked') return a.locked === true ? `<span style="background:#eafaf1;color:#1e8449;font-size:10px;padding:2px 7px;border-radius:9px">🔒 مُقفلة</span>` : (a.locked === false ? `<span style="background:#fef9e7;color:#b9770e;font-size:10px;padding:2px 7px;border-radius:9px">🔓 غير مقفلة</span>` : '');
        return '';
    };
    const rows = steps.map((s, i) => {
        const it = items[s.id] || {}; const done = !!it.done;
        return `<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border-bottom:1px solid #f2f2f2;background:${done ? '#f7fcf9' : '#fff'}">
            <input type="checkbox" ${done ? 'checked' : ''} ${closed ? 'disabled' : ''} onchange="closingToggle('${s.id}')" style="width:19px;height:19px;margin-top:2px;cursor:pointer;accent-color:#16a085">
            <div style="flex:1;min-width:0">
                <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap"><span style="font-size:11px;color:#aaa;font-weight:700">${i + 1}.</span><span style="font-size:13px;font-weight:600;color:#1a3a5c;${done ? 'text-decoration:line-through;opacity:.6' : ''}">${s.label}</span>${autoBadge(s)}</div>
                ${done && it.doneAt ? `<div style="font-size:10px;color:#27ae60;margin-top:2px">✓ ${new Date(it.doneAt).toLocaleString('ar-EG')}</div>` : ''}
                <input type="text" value="${(it.note || '').replace(/"/g, '&quot;')}" ${closed ? 'disabled' : ''} onchange="closingNote('${s.id}',this.value)" placeholder="ملاحظة (اختياري)..." style="width:100%;margin-top:5px;padding:5px 8px;border:1px solid #eee;border-radius:6px;font-family:inherit;font-size:11.5px;background:#fafafa">
            </div>
            <button onclick="nav('${s.nav}')" style="background:#eef4fb;color:#2563eb;border:none;border-radius:7px;padding:7px 11px;cursor:pointer;font-size:12px;font-weight:700;white-space:nowrap" title="افتح الوحدة">↗ فتح</button>
        </div>`;
    }).join('');

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#16a085,#117a65);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div><h2 style="margin:0">✅ قائمة الإقفال ${st.type === 'year' ? 'السنوي' : 'الشهري'}</h2><div style="opacity:.9;margin-top:4px;font-size:13px">خطوات منظّمة لإغلاق الفترة المحاسبية بثقة — لا تنسَ أي إجراء</div></div>
            <div style="display:flex;gap:8px;align-items:center;background:rgba(255,255,255,.12);border-radius:10px;padding:8px 12px">
                <select onchange="closingSetType(this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:13px;font-weight:700"><option value="month" ${st.type === 'month' ? 'selected' : ''}>شهري</option><option value="year" ${st.type === 'year' ? 'selected' : ''}>سنوي</option></select>
                ${st.type === 'year' ? `<input type="number" value="${st.period}" min="2000" max="2100" onchange="closingSetPeriod(this.value)" style="width:90px;padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:14px;font-weight:700;text-align:center">` : `<input type="month" value="${st.period}" onchange="closingSetPeriod(this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:13px;font-weight:700">`}
            </div>
        </div>
    </div>
    ${closed ? `<div class="card" style="background:#eafaf1;border:1px solid #abebc6;padding:10px 14px;margin-bottom:14px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px"><span style="font-size:13px;color:#1e8449">🔒 هذه الفترة مُؤشّرة <strong>كمُقفلة ومراجَعة</strong>${rec.closedAt ? ' — ' + new Date(rec.closedAt).toLocaleDateString('ar-EG') : ''}.</span><button class="btn" onclick="closingReopen()" style="background:#e67e22;color:#fff;padding:7px 14px;font-weight:700">🔓 إعادة فتح</button></div>` : ''}
    <div class="card" style="padding:14px 18px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px"><span style="font-size:13px;font-weight:800;color:#1a3a5c">نسبة الإنجاز: ${doneCount}/${steps.length}</span><span style="font-size:18px;font-weight:900;color:${pct === 100 ? '#16a085' : '#e67e22'}">${pct}%</span></div>
        <div style="background:#eee;border-radius:20px;height:12px;overflow:hidden"><div style="width:${pct}%;height:100%;background:linear-gradient(90deg,#16a085,#1abc9c);transition:width .3s"></div></div>
    </div>
    <div class="card" style="padding:0;overflow:hidden;margin-bottom:14px">${rows}</div>
    ${!closed ? `<div style="display:flex;justify-content:flex-end"><button class="btn" onclick="closingFinalize()" style="background:#16a085;color:#fff;padding:10px 22px;font-weight:800">🔒 وضع علامة: الفترة مُقفلة ومراجَعة</button></div>` : ''}
    <div style="font-size:11px;color:#888;margin-top:12px;line-height:1.7">💡 هذه قائمة إرشادية لمتابعة خطوات الإقفال. القفل الفعلي للقيود يتم من «إقفال الفترات المحاسبية»، والإقفال السنوي من «إقفال السنة المالية».</div>`;
};
console.log('✅ Closing Checklist module [ACC-CLOSE] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧮  [ACC-TAXC]   مركز الضرائب والامتثال — لوحة موحّدة + تقويم مواعيد الهيئة   ║
// ║   يقرأ بيانات: vatReturns · whtRecords · zakatReturns · incomeTaxReturns      ║
// ╚══════════════════════════════════════════════════════════════════════════╝
function taxCenterData() {
    const now = new Date();
    const curYear = now.getFullYear();
    const curMonth = now.toISOString().slice(0, 7);
    const vatArr = Object.values(window.vatReturns || {}).sort((a, b) => (b.to || '').localeCompare(a.to || ''));
    const vatLatest = vatArr[0] || null;
    const vatNet = vatLatest ? (vatLatest.figures?.net || 0) : 0;
    let whtUnremitted = 0, whtMonth = 0, whtCount = 0;
    Object.values(window.whtRecords || {}).forEach(r => { const w = parseFloat(r.wht) || 0; if (r.status !== 'remitted') { whtUnremitted += w; whtCount++; } if ((r.date || '').startsWith(curMonth)) whtMonth += w; });
    const zList = Object.values(window.zakatReturns || {});
    const zk = zList.find(r => r.year === curYear) || zList.sort((a, b) => (b.year || 0) - (a.year || 0))[0] || null;
    const iList = Object.values(window.incomeTaxReturns || {});
    const it = iList.find(r => r.year === curYear) || iList.sort((a, b) => (b.year || 0) - (a.year || 0))[0] || null;
    return { vatLatest, vatNet, whtUnremitted, whtMonth, whtCount, zk, it, curYear };
}
function taxDeadlines() {
    const today = new Date(); today.setHours(0, 0, 0, 0); const list = [];
    const mk = (title, dt, kind) => { const d = new Date(dt); const days = Math.round((d - today) / 86400000); list.push({ title, date: dt, days, kind }); };
    const nm = new Date(today.getFullYear(), today.getMonth() + 1, 10);
    mk('توريد ضريبة الاستقطاع عن الشهر السابق', nm.toISOString().slice(0, 10), 'wht');
    const vatDue = new Date(today.getFullYear(), today.getMonth() + 2, 0);
    mk('تقديم إقرار ضريبة القيمة المضافة', vatDue.toISOString().slice(0, 10), 'vat');
    let apr = new Date(today.getFullYear(), 3, 30); if (apr < today) apr = new Date(today.getFullYear() + 1, 3, 30);
    mk('تقديم إقرار الزكاة وضريبة الدخل السنوي', apr.toISOString().slice(0, 10), 'annual');
    return list.sort((a, b) => a.days - b.days);
}
window.renderTaxCenter = function () {
    const pg = $('pg-taxcenter'); if (!pg) return;
    const d = taxCenterData();
    const totalDue = Math.max(0, d.vatNet) + d.whtUnremitted + (d.zk && d.zk.status === 'filed' ? (d.zk.zakat || 0) : 0) + (d.it && d.it.status === 'filed' ? (d.it.tax || 0) : 0);
    const stPill = (filed) => filed ? '<span style="background:#27ae60;color:#fff;padding:2px 9px;border-radius:10px;font-size:11px">معتمد</span>' : '<span style="background:#f39c12;color:#fff;padding:2px 9px;border-radius:10px;font-size:11px">مسودة</span>';
    const card = (icon, title, big, sub, statusHtml, navId, col) => `
        <div class="card" style="padding:0;overflow:hidden;border-top:4px solid ${col}">
            <div style="padding:14px 16px">
                <div style="display:flex;justify-content:space-between;align-items:flex-start"><div style="font-size:13px;font-weight:800;color:#1a3a5c">${icon} ${title}</div>${statusHtml || ''}</div>
                <div style="font-size:24px;font-weight:900;color:${col};margin:8px 0 2px">${big}</div>
                <div style="font-size:11.5px;color:#777">${sub}</div>
            </div>
            <button onclick="nav('${navId}')" style="width:100%;border:none;border-top:1px solid #f0f0f0;background:#fafbfc;color:#2563eb;padding:9px;cursor:pointer;font-size:12px;font-weight:700">فتح الوحدة ↗</button>
        </div>`;

    const vatCard = card('🧾', 'ضريبة القيمة المضافة', d.vatLatest ? fmt(Math.abs(d.vatNet)) : '—',
        d.vatLatest ? (d.vatNet >= 0 ? 'مستحقة للهيئة · ' : 'قابلة للاسترداد · ') + (d.vatLatest.label || (d.vatLatest.from + ' → ' + d.vatLatest.to)) : 'لا يوجد إقرار محفوظ',
        d.vatLatest ? stPill(d.vatLatest.status === 'filed') : '', 'vatreturn', '#2980b9');
    const whtCard = card('🌐', 'ضريبة الاستقطاع', fmt(d.whtUnremitted),
        d.whtCount ? `${d.whtCount} عملية بانتظار التوريد · هذا الشهر ${fmt(d.whtMonth)}` : 'لا مبالغ مستحقة للتوريد', '', 'wht', '#8e44ad');
    const zkCard = card('🕌', 'الزكاة', d.zk ? fmt(d.zk.zakat || 0) : '—',
        d.zk ? `سنة ${d.zk.year} · الوعاء ${fmt(d.zk.base || 0)}` : 'لم تُحتسب بعد', d.zk ? stPill(d.zk.status === 'filed') : '', 'zakat', '#16a085');
    const itCard = card('💰', 'ضريبة الدخل', d.it ? fmt(d.it.tax || 0) : '—',
        d.it ? `سنة ${d.it.year} · حصة أجنبية ${d.it.foreignPct != null ? d.it.foreignPct + '%' : '—'}` : 'لم تُحتسب بعد', d.it ? stPill(d.it.status === 'filed') : '', 'incometax', '#c0392b');

    const dls = taxDeadlines().map(x => {
        const col = x.days < 0 ? '#c0392b' : x.days <= 14 ? '#e67e22' : '#16a085';
        const lbl = x.days < 0 ? `متأخر ${Math.abs(x.days)} يوم` : x.days === 0 ? 'اليوم' : `بعد ${x.days} يوم`;
        return `<div style="display:flex;justify-content:space-between;align-items:center;gap:10px;padding:11px 14px;border-bottom:1px solid #f2f2f2">
            <div><div style="font-size:13px;font-weight:600;color:#1a3a5c">${x.title}</div><div style="font-size:11px;color:#999;margin-top:2px">📅 ${x.date}</div></div>
            <span style="background:${col};color:#fff;padding:4px 12px;border-radius:10px;font-size:12px;font-weight:800;white-space:nowrap">${lbl}</span>
        </div>`;
    }).join('');

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#2c3e50,#34495e);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:12px">
            <div><h2 style="margin:0">🧮 مركز الضرائب والامتثال</h2><div style="opacity:.9;margin-top:4px;font-size:13px">كل التزاماتك الضريبية ومواعيد الهيئة في شاشة واحدة</div></div>
            <div style="display:flex;align-items:center;gap:12px;flex-wrap:wrap">
                <div style="text-align:center;background:rgba(255,255,255,.12);border-radius:12px;padding:10px 18px"><div style="font-size:11px;opacity:.9">إجمالي الالتزامات المعتمدة المستحقة</div><div style="font-size:26px;font-weight:900">${fmt(totalDue)}</div></div>
                <button onclick="${typeof isEmailJSConfigured === 'function' && isEmailJSConfigured() ? 'sendTaxReminderEmail()' : `nav('settings')`}" style="background:rgba(255,255,255,.2);border:1px solid rgba(255,255,255,.4);color:#fff;border-radius:10px;padding:10px 14px;cursor:pointer;font-family:inherit;font-size:12.5px;font-weight:700" title="${typeof isEmailJSConfigured === 'function' && isEmailJSConfigured() ? 'إرسال تذكير بريدي بالمواعيد' : 'اضبط بيانات EmailJS في الإعدادات'}">📧 ${typeof isEmailJSConfigured === 'function' && isEmailJSConfigured() ? 'أرسِل تذكيراً بريدياً' : 'تفعيل التذكير البريدي'}</button>
            </div>
        </div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:12px;margin-bottom:16px">${vatCard}${whtCard}${zkCard}${itCard}</div>
    <div class="card" style="padding:0;overflow:hidden">
        <div style="background:#2c3e50;color:#fff;padding:11px 16px;font-weight:800;font-size:14px">📆 تقويم المواعيد القادمة للهيئة</div>
        ${dls}
    </div>
    <div style="font-size:11px;color:#888;margin-top:12px;line-height:1.7">💡 الأرقام تُسحب من الإقرارات المحفوظة وسجلّ الاستقطاع. «إجمالي الالتزامات» يحتسب القيمة المضافة المستحقة + الاستقطاع غير المورّد + الزكاة وضريبة الدخل <strong>المعتمدة</strong> فقط. المواعيد إرشادية — قد تختلف دورية القيمة المضافة (شهري/ربع سنوي) حسب إيراد المنشأة؛ راجع بوابة «زاتكا».</div>`;
};
console.log('✅ Tax Command Center [ACC-TAXC] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📊  [ACC-GLBUD]   الموازنة الشهرية الشاملة + الفعلي مقابل الموازنة (Oracle) ║
// ║   موازنة 12 شهراً لكل أنواع الحسابات + تحليل انحراف شهري وتراكمي وسنوي         ║
// ╚══════════════════════════════════════════════════════════════════════════╝
const GLB_MONTHS = ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];
window._glBudgetState = window._glBudgetState || { year: new Date().getFullYear(), tab: 'entry', typeFilter: 'expense' };
function glbBudgetMonths(b) { if (b && Array.isArray(b.months) && b.months.length === 12) return b.months.map(x => parseFloat(x) || 0); const a = (b && parseFloat(b.annual)) || 0; const per = Math.round(a / 12 * 100) / 100; return new Array(12).fill(per); }
function glbActuals(year) {
    const acc = window.chartOfAccounts || {}; const codeType = {};
    Object.values(acc).forEach(a => { if (a.code) codeType[a.code] = a.type; });
    const out = {};
    Object.values(window.journalEntries || {}).forEach(e => {
        if (e.status !== 'posted') return;
        (e.lines || []).forEach(l => {
            const d = l.date || e.date || ''; if (d.slice(0, 4) !== String(year)) return;
            const mi = parseInt(d.slice(5, 7)) - 1; if (mi < 0 || mi > 11) return;
            const code = l.accountCode; if (!code) return;
            const debit = parseFloat(l.debit) || 0, credit = parseFloat(l.credit) || 0;
            const t = codeType[code];
            const nat = (t === 'revenue' || t === 'liability' || t === 'equity') ? (credit - debit) : (debit - credit);
            if (!out[code]) out[code] = new Array(12).fill(0);
            out[code][mi] += nat;
        });
    });
    return out;
}
window.glbSetYear = function (v) { window._glBudgetState.year = parseInt(v) || new Date().getFullYear(); renderGLBudget(); };
window.glbSetTab = function (t) { window._glBudgetState.tab = t; renderGLBudget(); };
window.glbSetType = function (t) { window._glBudgetState.typeFilter = t; renderGLBudget(); };
window.glbSetAnnual = async function (code, val) {
    const y = window._glBudgetState.year; const annual = Math.round((parseFloat(val) || 0) * 100) / 100;
    try {
        await update(ref(db, 'ledger/glBudgets/' + y), { year: y, updatedAt: Date.now(), updatedBy: (typeof brUser === 'function' ? brUser() : 'system') });
        await update(ref(db, 'ledger/glBudgets/' + y + '/accounts/' + code), { annual, months: null });
    } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.glbOpenMonthly = function (code) {
    const y = window._glBudgetState.year;
    const acc = Object.values(window.chartOfAccounts || {}).find(a => a.code === code) || { code, nameAr: code };
    const months = glbBudgetMonths((window.glBudgets?.[y]?.accounts || {})[code] || {});
    document.getElementById('taskEditorOverlay')?.remove();
    const ov = document.createElement('div'); ov.id = 'taskEditorOverlay';
    ov.style = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:10003;display:flex;align-items:flex-start;justify-content:center;overflow:auto;padding:20px';
    ov.innerHTML = `<div style="background:#fff;border-radius:14px;max-width:520px;width:100%;box-shadow:0 20px 60px rgba(0,0,0,.3)">
        <div style="background:linear-gradient(135deg,#16527a,#2980b9);color:#fff;padding:14px 18px;border-radius:14px 14px 0 0;display:flex;justify-content:space-between;align-items:center"><div style="font-size:14px;font-weight:900">📅 التوزيع الشهري — ${acc.code} ${acc.nameAr}</div><button onclick="document.getElementById('taskEditorOverlay').remove()" style="background:rgba(255,255,255,.2);border:none;color:#fff;width:28px;height:28px;border-radius:7px;cursor:pointer">✖</button></div>
        <div style="padding:16px;max-height:72vh;overflow:auto">
            <input type="hidden" id="glbMCode" value="${code}">
            <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:8px">
                ${GLB_MONTHS.map((mn, i) => `<div style="display:flex;align-items:center;gap:6px"><label style="font-size:12px;color:#555;width:60px">${mn}</label><input id="glbM${i}" type="number" step="any" value="${months[i] || ''}" oninput="glbMSum()" style="flex:1;padding:6px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;text-align:left"></div>`).join('')}
            </div>
            <div style="display:flex;justify-content:space-between;align-items:center;margin-top:12px;background:#eaf2f8;border-radius:8px;padding:10px;font-weight:800;color:#16527a"><span>الإجمالي السنوي</span><span id="glbMTotal">${fmt(months.reduce((s, x) => s + x, 0))}</span></div>
            <div style="display:flex;gap:10px;margin-top:12px"><button class="btn" onclick="glbSaveMonthly()" style="background:#16527a;color:#fff;padding:9px 22px;font-weight:800">💾 حفظ التوزيع</button><button class="btn" onclick="document.getElementById('taskEditorOverlay').remove()" style="background:#f0f0f0;padding:9px 18px">إلغاء</button></div>
        </div></div>`;
    document.body.appendChild(ov);
};
window.glbMSum = function () { let s = 0; for (let i = 0; i < 12; i++) s += parseFloat($('glbM' + i)?.value) || 0; const el = $('glbMTotal'); if (el) el.textContent = fmt(s); };
window.glbSaveMonthly = async function () {
    const code = $('glbMCode')?.value; if (!code) return;
    const months = []; for (let i = 0; i < 12; i++) months.push(Math.round((parseFloat($('glbM' + i)?.value) || 0) * 100) / 100);
    const annual = Math.round(months.reduce((s, x) => s + x, 0) * 100) / 100;
    const y = window._glBudgetState.year;
    try {
        await update(ref(db, 'ledger/glBudgets/' + y), { year: y, updatedAt: Date.now(), updatedBy: (typeof brUser === 'function' ? brUser() : 'system') });
        await update(ref(db, 'ledger/glBudgets/' + y + '/accounts/' + code), { annual, months });
        document.getElementById('taskEditorOverlay')?.remove(); toast('✅ حُفظ التوزيع الشهري', 'ok'); renderGLBudget();
    } catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.renderGLBudget = function () {
    const pg = $('pg-glbudget'); if (!pg) return;
    const st = window._glBudgetState; const y = st.year;
    const data = window.glBudgets?.[y]?.accounts || {};
    const accounts = Object.values(window.chartOfAccounts || {}).filter(a => a.nature === 'detail' && a.code).sort((a, b) => (a.code || '').localeCompare(b.code || ''));
    const tab = (id, label) => `<button onclick="glbSetTab('${id}')" style="padding:9px 18px;border:none;border-radius:9px;cursor:pointer;font-family:inherit;font-size:13px;font-weight:800;background:${st.tab === id ? '#16527a' : '#eef2f6'};color:${st.tab === id ? '#fff' : '#555'}">${label}</button>`;
    const typeBtns = Object.entries(COA_TYPES).map(([k, t]) => `<button onclick="glbSetType('${k}')" style="padding:6px 12px;border:none;border-radius:8px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:700;background:${st.typeFilter === k ? t.color : '#f0f0f0'};color:${st.typeFilter === k ? '#fff' : '#555'}">${t.ar}</button>`).join('');

    let body = '';
    if (st.tab === 'entry') {
        const rows = accounts.filter(a => a.type === st.typeFilter).map(a => {
            const b = data[a.code] || {}; const isMonthly = Array.isArray(b.months) && b.months.length === 12;
            return `<tr style="border-bottom:1px solid #f2f2f2">
                <td style="padding:8px;font-family:monospace;color:#888">${a.code}</td>
                <td style="padding:8px">${a.nameAr || ''}</td>
                <td style="padding:8px;text-align:left"><input type="number" step="any" value="${b.annual != null ? b.annual : ''}" ${isMonthly ? 'disabled title="مُوزّعة شهرياً — عدّلها من زر 📅"' : ''} onchange="glbSetAnnual('${a.code}',this.value)" style="width:150px;padding:6px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;text-align:left;${isMonthly ? 'background:#f4f4f4' : ''}" placeholder="0"></td>
                <td style="padding:8px;text-align:center"><button onclick="glbOpenMonthly('${a.code}')" style="background:${isMonthly ? '#16527a' : '#eef2f6'};color:${isMonthly ? '#fff' : '#16527a'};border:none;border-radius:7px;padding:6px 10px;cursor:pointer;font-size:12px;font-weight:700" title="توزيع شهري مخصّص">📅 ${isMonthly ? 'شهري' : 'سنوي÷12'}</button></td>
            </tr>`;
        }).join('');
        const total = accounts.filter(a => a.type === st.typeFilter).reduce((s, a) => s + ((parseFloat(data[a.code]?.annual)) || 0), 0);
        body = `<div style="font-size:12px;color:#777;margin-bottom:10px;line-height:1.7">💡 أدخل الموازنة السنوية لكل حساب (تُوزَّع تلقائياً ÷12)، أو اضغط <strong>📅</strong> لتوزيع شهري مخصّص. ثم انتقل لتبويب «الفعلي مقابل الموازنة».</div>
        <div style="display:flex;gap:7px;flex-wrap:wrap;margin-bottom:12px">${typeBtns}</div>
        <div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12.5px;min-width:560px">
            <thead><tr style="background:#16527a;color:#fff"><th style="padding:9px;text-align:right">الكود</th><th style="text-align:right">الحساب</th><th style="text-align:left">الموازنة السنوية</th><th>التوزيع</th></tr></thead>
            <tbody>${rows || '<tr><td colspan="4" style="text-align:center;color:#999;padding:24px">لا توجد حسابات بهذا النوع</td></tr>'}</tbody>
            <tfoot><tr style="background:#eaf2f8;font-weight:900;color:#16527a"><td colspan="2" style="padding:9px">إجمالي ${COA_TYPES[st.typeFilter].ar}</td><td style="text-align:left;padding:9px">${fmt(total)}</td><td></td></tr></tfoot>
        </table></div></div>`;
    } else {
        const actuals = glbActuals(y);
        const isCurYear = y === new Date().getFullYear(); const curMonth = new Date().getMonth(); // 0-based
        const ytdLimit = isCurYear ? curMonth + 1 : 12;
        const budgetedCodes = Object.keys(data).filter(c => (parseFloat(data[c]?.annual) || 0) !== 0 || (Array.isArray(data[c]?.months)));
        const byType = {};
        budgetedCodes.forEach(code => {
            const a = accounts.find(x => x.code === code) || { code, nameAr: code, type: 'expense' };
            const bm = glbBudgetMonths(data[code]); const am = actuals[code] || new Array(12).fill(0);
            const bAnnual = bm.reduce((s, x) => s + x, 0), aAnnual = am.reduce((s, x) => s + x, 0);
            const bYTD = bm.slice(0, ytdLimit).reduce((s, x) => s + x, 0), aYTD = am.slice(0, ytdLimit).reduce((s, x) => s + x, 0);
            (byType[a.type] = byType[a.type] || []).push({ a, bAnnual, aAnnual, bYTD, aYTD });
        });
        const fav = (type, variance) => (type === 'revenue' || type === 'liability' || type === 'equity') ? variance >= 0 : variance <= 0;
        let grandB = 0, grandA = 0;
        const sections = Object.keys(COA_TYPES).filter(t => byType[t]?.length).map(type => {
            const t = COA_TYPES[type]; let sB = 0, sA = 0;
            const rows = byType[type].sort((x, y2) => (x.a.code || '').localeCompare(y2.a.code || '')).map(r => {
                sB += r.bAnnual; sA += r.aAnnual;
                const variance = Math.round((r.aAnnual - r.bAnnual) * 100) / 100;
                const pct = r.bAnnual !== 0 ? Math.round(r.aAnnual / r.bAnnual * 100) : (r.aAnnual ? 999 : 0);
                const good = fav(type, variance);
                return `<tr style="border-bottom:1px solid #f2f2f2">
                    <td style="padding:7px;font-family:monospace;color:#888">${r.a.code}</td>
                    <td style="padding:7px">${r.a.nameAr || ''}</td>
                    <td style="padding:7px;text-align:left">${fmt(r.bAnnual)}</td>
                    <td style="padding:7px;text-align:left">${fmt(r.aYTD)}</td>
                    <td style="padding:7px;text-align:left;font-weight:700">${fmt(r.aAnnual)}</td>
                    <td style="padding:7px;text-align:left;font-weight:800;color:${good ? '#1e8449' : '#c0392b'}">${variance >= 0 ? '+' : ''}${fmt(variance)}</td>
                    <td style="padding:7px;text-align:center"><span style="background:${good ? '#eafaf1' : '#fdecea'};color:${good ? '#1e8449' : '#c0392b'};padding:2px 8px;border-radius:9px;font-size:11px;font-weight:800">${pct}%</span></td>
                </tr>`;
            }).join('');
            grandB += sB; grandA += sA;
            const sVar = Math.round((sA - sB) * 100) / 100; const sGood = fav(type, sVar);
            return `<tr style="background:${t.bg}"><td colspan="7" style="padding:8px 10px;font-weight:900;color:${t.color}">${t.ar}</td></tr>${rows}
                <tr style="background:#f7f9fb;font-weight:800"><td colspan="2" style="padding:7px">إجمالي ${t.en}</td><td style="text-align:left;padding:7px">${fmt(sB)}</td><td></td><td style="text-align:left;padding:7px">${fmt(sA)}</td><td style="text-align:left;padding:7px;color:${sGood ? '#1e8449' : '#c0392b'}">${sVar >= 0 ? '+' : ''}${fmt(sVar)}</td><td></td></tr>`;
        }).join('');
        body = `<div style="font-size:12px;color:#777;margin-bottom:12px;line-height:1.7">📊 مقارنة الموازنة بالأرقام الفعلية من القيود المرحّلة لسنة ${y}. ${isCurYear ? `عمود «الفعلي حتى تاريخه» يشمل حتى ${GLB_MONTHS[curMonth]}.` : ''} الانحراف الأخضر = مُوافِق، الأحمر = غير مُوافِق (حسب طبيعة الحساب).</div>
        ${sections ? `<div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:720px">
            <thead><tr style="background:#16527a;color:#fff"><th style="padding:9px;text-align:right">الكود</th><th style="text-align:right">الحساب</th><th style="text-align:left">الموازنة السنوية</th><th style="text-align:left">الفعلي حتى تاريخه</th><th style="text-align:left">الفعلي السنوي</th><th style="text-align:left">الانحراف</th><th>الإنجاز</th></tr></thead>
            <tbody>${sections}</tbody>
            <tfoot><tr style="background:#16527a;color:#fff;font-weight:900"><td colspan="2" style="padding:9px">الإجمالي العام</td><td style="text-align:left;padding:9px">${fmt(grandB)}</td><td></td><td style="text-align:left;padding:9px">${fmt(grandA)}</td><td style="text-align:left;padding:9px">${(grandA - grandB) >= 0 ? '+' : ''}${fmt(Math.round((grandA - grandB) * 100) / 100)}</td><td></td></tr></tfoot>
        </table></div></div>` : '<div class="card" style="padding:40px;text-align:center;color:#999">لا توجد موازنات مُدخَلة لهذه السنة — ابدأ من تبويب «إدخال الموازنة».</div>'}`;
    }

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#16527a,#2980b9);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div><h2 style="margin:0">📊 الموازنة الشهرية الشاملة</h2><div style="opacity:.9;margin-top:4px;font-size:13px">موازنة 12 شهراً لكل الحسابات + تحليل الانحراف الفعلي مقابل الموازنة</div></div>
            <div style="display:flex;align-items:center;gap:8px;background:rgba(255,255,255,.12);border-radius:10px;padding:8px 12px"><span style="font-size:13px">السنة:</span><input type="number" value="${y}" min="2000" max="2100" onchange="glbSetYear(this.value)" style="width:90px;padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:14px;font-weight:700;text-align:center"></div>
        </div>
    </div>
    <div style="display:flex;gap:9px;margin-bottom:14px">${tab('entry', '✏️ إدخال الموازنة')}${tab('variance', '📈 الفعلي مقابل الموازنة')}</div>
    ${body}`;
};
console.log('✅ GL Budget module [ACC-GLBUD] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧱  [ACC-FSG]   مولّد القوائم المالية المخصّصة (Financial Statement Generator)║
// ║   بناء تقارير مالية بصفوف معرّفة (نطاقات حسابات) وأعمدة فعلي/موازنة/انحراف      ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._fsgState = window._fsgState || { mode: 'list', editId: null, runId: null, from: '', to: '', budgetYear: new Date().getFullYear(), showBudget: false };
window._fsgEdit = window._fsgEdit || null;
function fsgYearDefaults() { const y = new Date().getFullYear(); return { from: y + '-01-01', to: y + '-12-31' }; }
function fsgLineActual(row, balances) {
    let sum = 0;
    Object.values(balances).forEach(b => {
        const c = b.account?.code; if (!c) return;
        if (row.from && c < row.from) return;
        if (row.to && c > row.to) return;
        sum += (row.basis === 'balance' ? (b.naturalClosing || 0) : (b.naturalMovement || 0));
    });
    return Math.round(sum * (row.sign || 1) * 100) / 100;
}
function fsgLineBudget(row, year) {
    const accts = window.glBudgets?.[year]?.accounts || {}; let sum = 0;
    Object.keys(accts).forEach(c => { if (row.from && c < row.from) return; if (row.to && c > row.to) return; sum += parseFloat(accts[c].annual) || 0; });
    return Math.round(sum * (row.sign || 1) * 100) / 100;
}
window.fsgNewReport = function () { window._fsgEdit = { id: null, name: '', rows: [{ type: 'line', label: '', from: '', to: '', sign: 1, basis: 'movement' }] }; window._fsgState.mode = 'edit'; renderFSG(); };
window.fsgEditReport = function (id) { const r = window.fsgReports?.[id]; if (!r) return; window._fsgEdit = { id, name: r.name || '', rows: JSON.parse(JSON.stringify(r.rows || [])) }; window._fsgState.mode = 'edit'; renderFSG(); };
window.fsgCancelEdit = function () { window._fsgEdit = null; window._fsgState.mode = 'list'; renderFSG(); };
window.fsgAddRow = function (type) { window._fsgEdit.rows.push(type === 'line' ? { type: 'line', label: '', from: '', to: '', sign: 1, basis: 'movement' } : { type, label: '' }); renderFSG(); };
window.fsgRemoveRow = function (i) { window._fsgEdit.rows.splice(i, 1); renderFSG(); };
window.fsgMoveRow = function (i, dir) { const r = window._fsgEdit.rows; const j = i + dir; if (j < 0 || j >= r.length) return; [r[i], r[j]] = [r[j], r[i]]; renderFSG(); };
window.fsgUpdateRow = function (i, field, val) { const row = window._fsgEdit.rows[i]; if (!row) return; row[field] = (field === 'sign') ? (parseInt(val) || 1) : val; };
window.fsgSaveReport = async function () {
    const e = window._fsgEdit; if (!e) return;
    e.name = ($('fsgName')?.value || e.name || '').trim();
    if (!e.name) { toast('⚠️ أدخل اسم التقرير', 'er'); return; }
    const payload = { name: e.name, rows: e.rows, updatedAt: Date.now(), updatedBy: (typeof brUser === 'function' ? brUser() : 'system') };
    try {
        if (e.id) { await update(ref(db, 'ledger/fsgReports/' + e.id), payload); }
        else { payload.createdAt = Date.now(); const r = await push(R.fsgReports, payload); e.id = r.key; }
        toast('✅ حُفظ التقرير', 'ok'); window._fsgEdit = null; window._fsgState.mode = 'list'; renderFSG();
    } catch (err) { toast('❌ ' + (err.message || err), 'er'); }
};
window.fsgDeleteReport = async function (id) { const r = window.fsgReports?.[id]; if (!r) return; if (!(await cf2(`حذف تقرير «${r.name}»؟`))) return; try { await remove(ref(db, 'ledger/fsgReports/' + id)); toast('🗑️ حُذف', 'ok'); renderFSG(); } catch (e) { toast('❌ ' + (e.message || e), 'er'); } };
window.fsgRunReport = function (id) { const d = fsgYearDefaults(); const st = window._fsgState; st.runId = id; st.mode = 'run'; if (!st.from) st.from = d.from; if (!st.to) st.to = d.to; renderFSG(); };
window.fsgSetRun = function (field, val) { window._fsgState[field] = (field === 'showBudget') ? val : val; renderFSG(); };
window.fsgBackToList = function () { window._fsgState.mode = 'list'; renderFSG(); };
window.renderFSG = function () {
    const pg = $('pg-fsg'); if (!pg) return;
    const st = window._fsgState;
    const hero = (title, sub) => `<div class="card" style="background:linear-gradient(135deg,#34495e,#5d6d7e);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px"><h2 style="margin:0">🧱 ${title}</h2><div style="opacity:.9;margin-top:4px;font-size:13px">${sub}</div></div>`;

    if (st.mode === 'edit' && window._fsgEdit) {
        const e = window._fsgEdit;
        const rowEditor = e.rows.map((row, i) => {
            const ctrls = `<div style="display:flex;gap:3px"><button onclick="fsgMoveRow(${i},-1)" style="border:none;background:#eef2f6;border-radius:5px;padding:4px 7px;cursor:pointer" title="أعلى">▲</button><button onclick="fsgMoveRow(${i},1)" style="border:none;background:#eef2f6;border-radius:5px;padding:4px 7px;cursor:pointer" title="أسفل">▼</button><button onclick="fsgRemoveRow(${i})" style="border:none;background:#fdecea;color:#c0392b;border-radius:5px;padding:4px 7px;cursor:pointer" title="حذف">🗑️</button></div>`;
            const typeSel = `<select onchange="fsgUpdateRow(${i},'type',this.value);renderFSG()" style="padding:6px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px"><option value="line" ${row.type === 'line' ? 'selected' : ''}>سطر حساب</option><option value="header" ${row.type === 'header' ? 'selected' : ''}>عنوان</option><option value="subtotal" ${row.type === 'subtotal' ? 'selected' : ''}>مجموع فرعي</option><option value="spacer" ${row.type === 'spacer' ? 'selected' : ''}>فراغ</option></select>`;
            const inS = 'padding:6px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px';
            let fields = `<input value="${(row.label || '').replace(/"/g, '&quot;')}" onchange="fsgUpdateRow(${i},'label',this.value)" placeholder="${row.type === 'spacer' ? '(فراغ)' : 'العنوان/الوصف'}" style="${inS};flex:1;min-width:120px" ${row.type === 'spacer' ? 'disabled' : ''}>`;
            if (row.type === 'line') fields += `
                <input value="${row.from || ''}" onchange="fsgUpdateRow(${i},'from',this.value)" placeholder="من كود" style="${inS};width:80px;direction:ltr;text-align:left">
                <input value="${row.to || ''}" onchange="fsgUpdateRow(${i},'to',this.value)" placeholder="إلى كود" style="${inS};width:80px;direction:ltr;text-align:left">
                <select onchange="fsgUpdateRow(${i},'sign',this.value)" style="${inS}"><option value="1" ${row.sign != -1 ? 'selected' : ''}>+ موجب</option><option value="-1" ${row.sign == -1 ? 'selected' : ''}>− سالب</option></select>
                <select onchange="fsgUpdateRow(${i},'basis',this.value)" style="${inS}"><option value="movement" ${row.basis !== 'balance' ? 'selected' : ''}>حركة الفترة</option><option value="balance" ${row.basis === 'balance' ? 'selected' : ''}>الرصيد التراكمي</option></select>`;
            return `<div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap;padding:8px;border-bottom:1px solid #f2f2f2;background:${row.type === 'header' ? '#eaf2f8' : row.type === 'subtotal' ? '#f4f9f4' : '#fff'}">${ctrls}${typeSel}${fields}</div>`;
        }).join('');
        pg.innerHTML = hero(e.id ? 'تعديل تقرير' : 'تقرير جديد', 'عرّف صفوف التقرير: كل سطر حساب يجمع نطاق أكواد، مع إشارة وأساس احتساب') + `
        <div class="card" style="padding:16px;margin-bottom:12px">
            <label style="font-size:12px;font-weight:700;color:#444">📝 اسم التقرير</label>
            <input id="fsgName" value="${(e.name || '').replace(/"/g, '&quot;')}" placeholder="مثال: قائمة الدخل التحليلية" style="width:100%;max-width:420px;padding:9px;border:1.5px solid #d0d7e0;border-radius:7px;font-family:inherit;font-size:13px;margin-top:4px">
        </div>
        <div class="card" style="padding:0;overflow:hidden;margin-bottom:12px"><div style="background:#34495e;color:#fff;padding:9px 14px;font-weight:800;font-size:13px">صفوف التقرير</div>${rowEditor}</div>
        <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
            <button class="btn" onclick="fsgAddRow('line')" style="background:#2980b9;color:#fff;padding:8px 14px;font-weight:700">➕ سطر حساب</button>
            <button class="btn" onclick="fsgAddRow('header')" style="background:#16a085;color:#fff;padding:8px 14px;font-weight:700">➕ عنوان</button>
            <button class="btn" onclick="fsgAddRow('subtotal')" style="background:#8e44ad;color:#fff;padding:8px 14px;font-weight:700">➕ مجموع فرعي</button>
            <button class="btn" onclick="fsgAddRow('spacer')" style="background:#95a5a6;color:#fff;padding:8px 14px;font-weight:700">➕ فراغ</button>
        </div>
        <div style="display:flex;gap:10px"><button class="btn" onclick="fsgSaveReport()" style="background:#27ae60;color:#fff;padding:10px 24px;font-weight:800">💾 حفظ التقرير</button><button class="btn" onclick="fsgCancelEdit()" style="background:#f0f0f0;padding:10px 20px">إلغاء</button></div>`;
        return;
    }

    if (st.mode === 'run' && window.fsgReports?.[st.runId]) {
        const rep = window.fsgReports[st.runId];
        const { balances } = calcFSBalances(st.from, st.to, ['posted'], '', '');
        let acc = 0; const showB = st.showBudget;
        const bodyRows = (rep.rows || []).map(row => {
            if (row.type === 'spacer') { return `<tr><td colspan="${showB ? 4 : 2}" style="height:10px"></td></tr>`; }
            if (row.type === 'header') { return `<tr style="background:#eaf2f8"><td colspan="${showB ? 4 : 2}" style="padding:8px 12px;font-weight:900;color:#1a3a5c">${row.label || ''}</td></tr>`; }
            if (row.type === 'subtotal') {
                const v = acc; acc = 0;
                return `<tr style="background:#f4f9f4;font-weight:900"><td style="padding:8px 12px;color:#1e8449">${row.label || 'مجموع فرعي'}</td><td style="text-align:left;padding:8px 12px;color:#1e8449">${fmt(v)}</td>${showB ? `<td></td><td></td>` : ''}</tr>`;
            }
            const actual = fsgLineActual(row, balances); acc += actual;
            let bCols = '';
            if (showB) { const bud = fsgLineBudget(row, st.budgetYear); const variance = Math.round((actual - bud) * 100) / 100; bCols = `<td style="text-align:left;padding:7px 12px">${fmt(bud)}</td><td style="text-align:left;padding:7px 12px;font-weight:700;color:${variance >= 0 ? '#1e8449' : '#c0392b'}">${variance >= 0 ? '+' : ''}${fmt(variance)}</td>`; }
            return `<tr style="border-bottom:1px solid #f4f4f4"><td style="padding:7px 12px">${row.label || ''}${(row.from || row.to) ? ` <span style="font-size:10px;color:#aaa;font-family:monospace">[${row.from || '…'}–${row.to || '…'}]</span>` : ''}</td><td style="text-align:left;padding:7px 12px;font-weight:600">${fmt(actual)}</td>${bCols}</tr>`;
        }).join('');
        const budYears = Object.keys(window.glBudgets || {}).sort();
        pg.innerHTML = hero(rep.name || 'تقرير', 'عرض التقرير المخصّص') + `
        <div class="card" style="padding:12px 16px;margin-bottom:12px;display:flex;gap:12px;align-items:end;flex-wrap:wrap">
            <button class="btn" onclick="fsgBackToList()" style="background:#eef2f6;color:#555;padding:8px 14px;font-weight:700">← القائمة</button>
            <div><label style="font-size:11px;color:#666;font-weight:700">من</label><input type="date" value="${st.from}" onchange="fsgSetRun('from',this.value)" style="display:block;padding:7px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">إلى</label><input type="date" value="${st.to}" onchange="fsgSetRun('to',this.value)" style="display:block;padding:7px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px"></div>
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;color:#444;cursor:pointer"><input type="checkbox" ${showB ? 'checked' : ''} onchange="fsgSetRun('showBudget',this.checked)"> إظهار عمود الموازنة</label>
            ${showB ? `<div><label style="font-size:11px;color:#666;font-weight:700">سنة الموازنة</label><select onchange="fsgSetRun('budgetYear',parseInt(this.value))" style="display:block;padding:7px;border:1.5px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px;margin-top:3px">${(budYears.length ? budYears : [st.budgetYear]).map(yy => `<option value="${yy}" ${st.budgetYear == yy ? 'selected' : ''}>${yy}</option>`).join('')}</select></div>` : ''}
            <button class="btn" onclick="window.print()" style="background:#34495e;color:#fff;padding:8px 14px;font-weight:700;margin-inline-start:auto">🖨️ طباعة</button>
        </div>
        <div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead><tr style="background:#34495e;color:#fff"><th style="padding:10px;text-align:right">البيان</th><th style="text-align:left;padding:10px">الفعلي</th>${showB ? `<th style="text-align:left;padding:10px">الموازنة</th><th style="text-align:left;padding:10px">الانحراف</th>` : ''}</tr></thead>
            <tbody>${bodyRows || `<tr><td colspan="${showB ? 4 : 2}" style="text-align:center;color:#999;padding:24px">لا صفوف في هذا التقرير</td></tr>`}</tbody>
        </table></div></div>`;
        return;
    }

    // list mode
    const reps = Object.entries(window.fsgReports || {}).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || ''));
    pg.innerHTML = hero('مولّد القوائم المالية المخصّصة', 'صمّم تقاريرك المالية الخاصة بصفوف وأعمدة تحدّدها أنت — كما في Oracle FSG') + `
    <div style="margin-bottom:14px"><button class="btn" onclick="fsgNewReport()" style="background:#27ae60;color:#fff;padding:10px 20px;font-weight:800">➕ تقرير جديد</button></div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px">
        ${reps.length ? reps.map(([id, r]) => `<div class="card" style="padding:14px 16px">
            <div style="font-size:15px;font-weight:900;color:#1a3a5c">🧱 ${r.name || '—'}</div>
            <div style="font-size:11px;color:#888;margin:6px 0 12px">${(r.rows || []).filter(x => x.type === 'line').length} سطر حساب · ${(r.rows || []).length} صف</div>
            <div style="display:flex;gap:6px;flex-wrap:wrap"><button class="btn" onclick="fsgRunReport('${id}')" style="background:#2980b9;color:#fff;padding:7px 14px;font-weight:700">▶️ تشغيل</button><button class="btn" onclick="fsgEditReport('${id}')" style="background:#eef2f6;color:#555;padding:7px 12px">✏️ تعديل</button><button class="btn" onclick="fsgDeleteReport('${id}')" style="background:#fdecea;color:#c0392b;padding:7px 12px">🗑️</button></div>
        </div>`).join('') : '<div class="card" style="padding:40px;text-align:center;color:#999;grid-column:1/-1">لا توجد تقارير مخصّصة بعد — اضغط «➕ تقرير جديد» لتصميم أول تقرير.</div>'}
    </div>`;
};
console.log('✅ Financial Statement Generator [ACC-FSG] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🔎  [ACC-AA]   تحليل الحسابات (Account Analysis) — استعلام نطاق حسابات       ║
// ║   كل الحركات عبر نطاق/نوع حسابات دفعة واحدة + تتبّع لكل سطر + تصدير             ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._aaState = window._aaState || { from: '', to: '', accFrom: '', accTo: '', type: '', costCenter: '', projectId: '', status: 'posted', group: true };
window.aaSet = function (field, val) { window._aaState[field] = val; renderAccountAnalysis(); };
window.aaReset = function () { window._aaState = { from: '', to: '', accFrom: '', accTo: '', type: '', costCenter: '', projectId: '', status: 'posted', group: true }; renderAccountAnalysis(); };
function aaCollect() {
    const st = window._aaState;
    const accounts = window.chartOfAccounts || {}; const codeType = {}; const codeName = {};
    Object.values(accounts).forEach(a => { if (a.code) { codeType[a.code] = a.type; codeName[a.code] = a.nameAr || a.code; } });
    const statuses = st.status === 'all' ? ['posted', 'draft'] : [st.status];
    const rows = [];
    Object.entries(window.journalEntries || {}).forEach(([ekey, e]) => {
        if (!statuses.includes(e.status || 'draft')) return;
        const d = e.date || '';
        if (st.from && d < st.from) return;
        if (st.to && d > st.to) return;
        (e.lines || []).forEach(l => {
            const code = l.accountCode; if (!code) return;
            if (st.accFrom && code < st.accFrom) return;
            if (st.accTo && code > st.accTo) return;
            if (st.type && codeType[code] !== st.type) return;
            if (st.costCenter && (l.costCenter || '') !== st.costCenter) return;
            if (st.projectId && !ccLineMatchesProject(l, st.projectId)) return;
            rows.push({ ekey, code, name: codeName[code] || code, type: codeType[code], date: l.date || d, number: e.number || '', desc: l.description || e.description || '', cc: ccProjLabel(l, e.projectId), debit: parseFloat(l.debit) || 0, credit: parseFloat(l.credit) || 0, status: e.status });
        });
    });
    return rows;
}
window.aaExport = function () {
    const rows = aaCollect().sort((a, b) => (a.code || '').localeCompare(b.code || '') || (a.date || '').localeCompare(b.date || ''));
    if (!rows.length) { toast('⚠️ لا بيانات للتصدير', 'er'); return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة', 'er'); return; }
    const data = rows.map(r => ({ 'الكود': r.code, 'الحساب': r.name, 'التاريخ': r.date, 'القيد': r.number, 'البيان': r.desc, 'المركز/المشروع': r.cc, 'مدين': r.debit, 'دائن': r.credit }));
    const ws = XLSX.utils.json_to_sheet(data); const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'تحليل الحسابات'); XLSX.writeFile(wb, 'AccountAnalysis.xlsx'); toast('✅ تم التصدير', 'ok');
};
window.renderAccountAnalysis = function () {
    const pg = $('pg-acctanalysis'); if (!pg) return;
    const st = window._aaState;
    const rows = aaCollect();
    const totD = rows.reduce((s, r) => s + r.debit, 0), totC = rows.reduce((s, r) => s + r.credit, 0);
    const inS = 'padding:7px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;background:white';
    const kpi = (lbl, val, col) => `<div class="card" style="padding:11px 14px;text-align:center;border-top:3px solid ${col}"><div style="font-size:11px;color:#666">${lbl}</div><div style="font-size:18px;font-weight:900;color:${col}">${val}</div></div>`;

    let resultHtml;
    if (!rows.length) {
        resultHtml = '<div class="card" style="padding:40px;text-align:center;color:#999">لا توجد حركات مطابقة للفلاتر — وسّع النطاق أو غيّر الفترة.</div>';
    } else if (st.group) {
        const byCode = {};
        rows.forEach(r => { (byCode[r.code] = byCode[r.code] || { name: r.name, type: r.type, items: [] }).items.push(r); });
        const sections = Object.keys(byCode).sort().map(code => {
            const g = byCode[code]; const naturallyDebit = ['asset', 'expense'].includes(g.type);
            let run = 0; let sd = 0, sc = 0;
            const items = g.items.sort((a, b) => (a.date || '').localeCompare(b.date || '')).map(r => {
                run += naturallyDebit ? (r.debit - r.credit) : (r.credit - r.debit); sd += r.debit; sc += r.credit;
                return `<tr style="border-bottom:1px solid #f4f4f4;cursor:pointer" onclick="jrnRowMenu('${r.ekey}',event)" title="انقر لعرض القيد والمستند المصدر">
                    <td style="padding:6px 8px">${r.date}</td><td style="padding:6px 8px;font-family:monospace;color:#2980b9">${r.number}</td>
                    <td style="padding:6px 8px">${(r.desc || '').replace(/</g, '&lt;')}</td><td style="padding:6px 8px;font-size:11px;color:#777">${r.cc}</td>
                    <td style="padding:6px 8px;text-align:left;color:#2d6a9f">${r.debit ? fmt(r.debit) : '—'}</td><td style="padding:6px 8px;text-align:left;color:#c0392b">${r.credit ? fmt(r.credit) : '—'}</td>
                    <td style="padding:6px 8px;text-align:left;font-weight:700">${fmt(run)}</td></tr>`;
            }).join('');
            return `<tr style="background:#eef4fb"><td colspan="7" style="padding:8px 10px;font-weight:900;color:#1a3a5c">${code} — ${g.name} <span style="font-size:11px;color:#888;font-weight:400">(${g.items.length} حركة)</span></td></tr>
                ${items}
                <tr style="background:#f7f9fb;font-weight:800"><td colspan="4" style="padding:6px 10px;text-align:left">مجموع الحساب</td><td style="text-align:left;padding:6px 8px;color:#2d6a9f">${fmt(sd)}</td><td style="text-align:left;padding:6px 8px;color:#c0392b">${fmt(sc)}</td><td style="text-align:left;padding:6px 8px">${fmt(naturallyDebit ? sd - sc : sc - sd)}</td></tr>`;
        }).join('');
        resultHtml = `<div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:760px">
            <thead><tr style="background:#1a3a5c;color:#fff"><th style="padding:8px;text-align:right">التاريخ</th><th style="text-align:right">القيد</th><th style="text-align:right">البيان</th><th style="text-align:right">المركز/المشروع</th><th style="text-align:left">مدين</th><th style="text-align:left">دائن</th><th style="text-align:left">الرصيد الجاري</th></tr></thead>
            <tbody>${sections}</tbody></table></div></div>`;
    } else {
        const flat = rows.sort((a, b) => (a.date || '').localeCompare(b.date || '') || (a.code || '').localeCompare(b.code || '')).map(r => `<tr style="border-bottom:1px solid #f4f4f4;cursor:pointer" onclick="jrnRowMenu('${r.ekey}',event)" title="انقر لعرض القيد والمستند المصدر">
            <td style="padding:6px 8px">${r.date}</td><td style="padding:6px 8px;font-family:monospace;color:#888">${r.code}</td><td style="padding:6px 8px">${r.name}</td>
            <td style="padding:6px 8px;font-family:monospace;color:#2980b9">${r.number}</td><td style="padding:6px 8px;font-size:11px">${(r.desc || '').replace(/</g, '&lt;')}</td>
            <td style="padding:6px 8px;text-align:left;color:#2d6a9f">${r.debit ? fmt(r.debit) : '—'}</td><td style="padding:6px 8px;text-align:left;color:#c0392b">${r.credit ? fmt(r.credit) : '—'}</td></tr>`).join('');
        resultHtml = `<div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:760px">
            <thead><tr style="background:#1a3a5c;color:#fff"><th style="padding:8px;text-align:right">التاريخ</th><th style="text-align:right">الكود</th><th style="text-align:right">الحساب</th><th style="text-align:right">القيد</th><th style="text-align:right">البيان</th><th style="text-align:left">مدين</th><th style="text-align:left">دائن</th></tr></thead>
            <tbody>${flat}</tbody></table></div></div>`;
    }

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#1a3a5c,#2d6a9f);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0">🔎 تحليل الحسابات</h2><div style="opacity:.9;margin-top:4px;font-size:13px">استعلام مرن عبر نطاق أو نوع حسابات دفعة واحدة — مع التتبّع لكل حركة</div>
    </div>
    <div class="card" style="padding:14px 16px;margin-bottom:14px">
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;align-items:end">
            <div><label style="font-size:11px;color:#666;font-weight:700">من كود حساب</label><input value="${st.accFrom}" onchange="aaSet('accFrom',this.value)" placeholder="مثال: 5100" style="${inS};width:100%;direction:ltr;text-align:left;display:block;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">إلى كود حساب</label><input value="${st.accTo}" onchange="aaSet('accTo',this.value)" placeholder="مثال: 5999" style="${inS};width:100%;direction:ltr;text-align:left;display:block;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">النوع</label><select onchange="aaSet('type',this.value)" style="${inS};width:100%;display:block;margin-top:3px"><option value="">كل الأنواع</option>${Object.entries(COA_TYPES).map(([k, t]) => `<option value="${k}" ${st.type === k ? 'selected' : ''}>${t.ar}</option>`).join('')}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">من تاريخ</label><input type="date" value="${st.from}" onchange="aaSet('from',this.value)" style="${inS};width:100%;display:block;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">إلى تاريخ</label><input type="date" value="${st.to}" onchange="aaSet('to',this.value)" style="${inS};width:100%;display:block;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">🎯 مركز التكلفة</label><select onchange="aaSet('costCenter',this.value)" style="${inS};width:100%;display:block;margin-top:3px">${ccOnlyOptions(st.costCenter, '-- الكل --')}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">🏗️ المشروع</label><select onchange="aaSet('projectId',this.value)" style="${inS};width:100%;display:block;margin-top:3px">${projOnlyOptions(st.projectId, '-- الكل --')}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">الحالة</label><select onchange="aaSet('status',this.value)" style="${inS};width:100%;display:block;margin-top:3px"><option value="posted" ${st.status === 'posted' ? 'selected' : ''}>المرحّلة فقط</option><option value="all" ${st.status === 'all' ? 'selected' : ''}>الكل (مع المسودات)</option></select></div>
        </div>
        <div style="display:flex;gap:10px;margin-top:12px;flex-wrap:wrap;align-items:center">
            <button class="btn" onclick="aaReset()" style="background:#e74c3c;color:#fff;padding:7px 14px;font-weight:700">↺ إعادة ضبط</button>
            <button class="btn" onclick="aaExport()" style="background:#1e8449;color:#fff;padding:7px 14px;font-weight:700">📊 تصدير Excel</button>
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;color:#444;cursor:pointer;margin-inline-start:auto"><input type="checkbox" ${st.group ? 'checked' : ''} onchange="aaSet('group',this.checked)"> تجميع حسب الحساب</label>
        </div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:14px">
        ${kpi('عدد الحركات', rows.length, '#2980b9')}${kpi('إجمالي المدين', fmt(totD), '#2d6a9f')}${kpi('إجمالي الدائن', fmt(totC), '#c0392b')}${kpi('الفرق', fmt(Math.round((totD - totC) * 100) / 100), Math.abs(totD - totC) < 0.01 ? '#27ae60' : '#e67e22')}
    </div>
    ${resultHtml}`;
};
console.log('✅ Account Analysis [ACC-AA] loaded');

