// ║   💸  [ACC-PRUN]   تشغيل الدفعات المجمّعة (Payment Run) — سداد موردين دفعة واحدة║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._prState = window._prState || { dueBy: '', vendorId: '', cashAccountCode: '', date: new Date().toISOString().slice(0, 10), method: 'transfer', selected: {} };
function prInvRemaining(inv) { return Math.round(((parseFloat(inv.grandTotal) || 0) - (parseFloat(inv.paidAmount) || 0) - (parseFloat(inv.debitedAmount) || 0)) * 100) / 100; }
function prCashAccounts() { return Object.values(window.chartOfAccounts || {}).filter(a => a.code && a.nature === 'detail' && (String(a.code).startsWith('111') || String(a.code).startsWith('112'))).sort((a, b) => (a.code || '').localeCompare(b.code || '')); }
function prCashName(code) { const a = prCashAccounts().find(x => x.code === code); return a ? `${a.code} — ${a.nameAr}` : '—'; }
function prPayables() {
    const st = window._prState;
    return Object.entries(window.purchaseInvoices || {}).map(([k, inv]) => ({ k, inv, rem: prInvRemaining(inv) }))
        .filter(x => x.inv.status === 'posted' && x.rem > 0.01)
        .filter(x => !st.vendorId || x.inv.vendorId === st.vendorId)
        .filter(x => !st.dueBy || ((x.inv.dueDate || x.inv.date || '') <= st.dueBy))
        .sort((a, b) => (a.inv.dueDate || a.inv.date || '').localeCompare(b.inv.dueDate || b.inv.date || ''));
}
window.prSet = function (field, val) { window._prState[field] = val; renderPaymentRun(); };
window.prToggle = function (k, checked) { if (checked) window._prState.selected[k] = true; else delete window._prState.selected[k]; renderPaymentRun(); };
window.prSelectAll = function (checked) { const st = window._prState; if (checked) prPayables().forEach(x => st.selected[x.k] = true); else st.selected = {}; renderPaymentRun(); };
window.renderPaymentRun = function () {
    const pg = $('pg-paymentrun'); if (!pg) return;
    const st = window._prState;
    const list = prPayables();
    const cashAccts = prCashAccounts();
    const vendors = window.vendors || {};
    const today = new Date().toISOString().slice(0, 10);
    const selList = list.filter(x => st.selected[x.k]);
    const selTotal = selList.reduce((s, x) => s + x.rem, 0);
    const vendorSet = new Set(selList.map(x => x.inv.vendorId));
    const inS = 'padding:7px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;background:white';
    const allChecked = list.length && list.every(x => st.selected[x.k]);

    const rows = list.map(x => {
        const v = vendors[x.inv.vendorId]; const overdue = x.inv.dueDate && x.inv.dueDate < today;
        return `<tr style="border-bottom:1px solid #f2f2f2;background:${st.selected[x.k] ? '#eefaf1' : (overdue ? '#fff7f5' : '#fff')}">
            <td style="padding:7px;text-align:center"><input type="checkbox" ${st.selected[x.k] ? 'checked' : ''} onchange="prToggle('${x.k}',this.checked)" style="width:17px;height:17px;cursor:pointer;accent-color:#16a085"></td>
            <td style="padding:7px;font-family:monospace;font-weight:700;color:#1a3a5c">${x.inv.number || '—'}</td>
            <td style="padding:7px">${v?.nameAr || '—'}</td>
            <td style="padding:7px">${x.inv.date || '—'}</td>
            <td style="padding:7px;color:${overdue ? '#c0392b' : '#666'};font-weight:${overdue ? '700' : '400'}">${x.inv.dueDate || '—'}${overdue ? ' ⚠️' : ''}</td>
            <td style="padding:7px;text-align:left">${fmt(x.inv.grandTotal)}</td>
            <td style="padding:7px;text-align:left;color:#27ae60">${fmt(x.inv.paidAmount || 0)}</td>
            <td style="padding:7px;text-align:left;font-weight:800;color:#c0392b">${fmt(x.rem)}${(x.inv.currency && x.inv.currency !== baseCurrencyCode()) ? ` <span style="font-size:9px;color:#888">${x.inv.currency}</span>` : ''}</td>
        </tr>`;
    }).join('');

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#7b241c,#c0392b);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0">💸 تشغيل الدفعات المجمّعة</h2><div style="opacity:.9;margin-top:4px;font-size:13px">اختر فواتير الموردين المستحقة وادفعها دفعة واحدة — تُنشأ سندات الصرف وقيودها تلقائياً</div>
    </div>
    <div class="card" style="padding:14px 16px;margin-bottom:14px">
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:10px;align-items:end">
            <div><label style="font-size:11px;color:#666;font-weight:700">💰 حساب الصرف (صندوق/بنك)</label><select onchange="prSet('cashAccountCode',this.value)" style="${inS};width:100%;display:block;margin-top:3px"><option value="">— اختر —</option>${cashAccts.map(a => `<option value="${a.code}" ${st.cashAccountCode === a.code ? 'selected' : ''}>${a.code} — ${a.nameAr}</option>`).join('')}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">📅 تاريخ الدفع</label><input type="date" value="${st.date}" onchange="prSet('date',this.value)" style="${inS};width:100%;display:block;margin-top:3px"></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">طريقة الدفع</label><select onchange="prSet('method',this.value)" style="${inS};width:100%;display:block;margin-top:3px"><option value="transfer" ${st.method === 'transfer' ? 'selected' : ''}>تحويل بنكي</option><option value="cash" ${st.method === 'cash' ? 'selected' : ''}>نقدي</option><option value="cheque" ${st.method === 'cheque' ? 'selected' : ''}>شيك</option></select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">🏭 المورد</label><select onchange="prSet('vendorId',this.value)" style="${inS};width:100%;display:block;margin-top:3px"><option value="">كل الموردين</option>${Object.entries(vendors).sort((a, b) => (a[1].nameAr || '').localeCompare(b[1].nameAr || '')).map(([k, v]) => `<option value="${k}" ${st.vendorId === k ? 'selected' : ''}>${v.nameAr || k}</option>`).join('')}</select></div>
            <div><label style="font-size:11px;color:#666;font-weight:700">مستحقة حتى تاريخ</label><input type="date" value="${st.dueBy}" onchange="prSet('dueBy',this.value)" style="${inS};width:100%;display:block;margin-top:3px"></div>
        </div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:14px">
        <div class="card" style="padding:11px 14px;text-align:center;border-top:3px solid #c0392b"><div style="font-size:11px;color:#666">فواتير مستحقة</div><div style="font-size:18px;font-weight:900;color:#c0392b">${list.length}</div></div>
        <div class="card" style="padding:11px 14px;text-align:center;border-top:3px solid #16a085"><div style="font-size:11px;color:#666">محدّدة للدفع</div><div style="font-size:18px;font-weight:900;color:#16a085">${selList.length}</div></div>
        <div class="card" style="padding:11px 14px;text-align:center;border-top:3px solid #1a3a5c"><div style="font-size:11px;color:#666">عدد الموردين</div><div style="font-size:18px;font-weight:900;color:#1a3a5c">${vendorSet.size}</div></div>
        <div class="card" style="padding:11px 14px;text-align:center;border-top:3px solid #e67e22"><div style="font-size:11px;color:#666">إجمالي الدفع</div><div style="font-size:18px;font-weight:900;color:#e67e22">${fmt(selTotal)}</div></div>
    </div>
    <div style="display:flex;justify-content:flex-end;margin-bottom:10px"><button class="btn" onclick="prPay()" style="background:#c0392b;color:#fff;padding:10px 24px;font-weight:800" ${selList.length && st.cashAccountCode ? '' : 'disabled title="اختر حساب الصرف وفاتورة واحدة على الأقل"'}>▶️ تنفيذ الدفع (${selList.length})</button></div>
    <div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:720px">
        <thead><tr style="background:#7b241c;color:#fff"><th style="padding:8px;text-align:center"><input type="checkbox" ${allChecked ? 'checked' : ''} onchange="prSelectAll(this.checked)" style="width:16px;height:16px;cursor:pointer" title="تحديد الكل"></th><th style="text-align:right;padding:8px">رقم الفاتورة</th><th style="text-align:right">المورد</th><th style="text-align:right">التاريخ</th><th style="text-align:right">الاستحقاق</th><th style="text-align:left">الإجمالي</th><th style="text-align:left">المدفوع</th><th style="text-align:left">المتبقّي</th></tr></thead>
        <tbody>${rows || '<tr><td colspan="8" style="text-align:center;color:#999;padding:24px">لا توجد فواتير موردين مستحقة الدفع بالفلاتر الحالية 🎉</td></tr>'}</tbody>
    </table></div></div>
    <div style="font-size:11px;color:#888;margin-top:12px;line-height:1.7">💡 لكل مورد يُنشأ سند صرف واحد يجمع فواتيره المحدّدة (بنفس العملة) مع تخصيص تلقائي على كل فاتورة وقيد محاسبي (مدين الموردون / دائن ${st.cashAccountCode ? prCashName(st.cashAccountCode) : 'الصندوق/البنك'}).</div>`;
};
window.prPay = async function () {
    const st = window._prState;
    if (!st.cashAccountCode) { toast('⚠️ اختر حساب الصرف (صندوق/بنك)', 'er'); return; }
    const sel = prPayables().filter(x => st.selected[x.k]);
    if (!sel.length) { toast('⚠️ اختر فاتورة واحدة على الأقل', 'er'); return; }
    const total = Math.round(sel.reduce((s, x) => s + x.rem, 0) * 100) / 100;
    const base = typeof baseCurrencyCode === 'function' ? baseCurrencyCode() : 'SAR';
    // تجميع حسب المورد + العملة + سعر الصرف
    const groups = {};
    sel.forEach(x => { const cur = x.inv.currency || base; const rate = parseFloat(x.inv.exchangeRate) || 1; const gk = x.inv.vendorId + '|' + cur + '|' + rate; (groups[gk] = groups[gk] || { vendorId: x.inv.vendorId, currency: cur, rate, items: [] }).items.push(x); });
    const nGroups = Object.keys(groups).length;
    if (!(await cf2(`تنفيذ دفع ${sel.length} فاتورة (${nGroups} سند صرف) بإجمالي ${fmt(total)} من ${prCashName(st.cashAccountCode)}؟\nستُنشأ سندات الصرف وقيودها وتُحدَّث أرصدة الفواتير تلقائياً.`))) return;
    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system'; const now = new Date().toISOString();
    let vouchers = 0, errors = 0;
    for (const gk of Object.keys(groups)) {
        const g = groups[gk];
        const amount = Math.round(g.items.reduce((s, x) => s + x.rem, 0) * 100) / 100;
        const allocations = {}; g.items.forEach(x => { allocations[x.k] = x.rem; });
        const data = { number: generateVoucherNumber('payment'), date: st.date, type: 'payment', partyId: g.vendorId, method: st.method, cashAccountCode: st.cashAccountCode, amount, currency: g.currency, exchangeRate: g.rate, amountBase: Math.round(amount * g.rate * 100) / 100, projectId: '', description: `دفعة مجمّعة — ${g.items.length} فاتورة`, allocations, notes: 'دفعة مجمّعة (Payment Run)', status: 'posted', createdAt: now, createdBy: userId, postedAt: now, postedBy: userId, source: 'payment_run' };
        try { const r = await push(R.paym, data); await allocateToInvoices(allocations, 'payment', r.key); await createJournalForVoucher(r.key, data); vouchers++; }
        catch (e) { console.error('Payment run error:', e); errors++; }
    }
    if (typeof logAudit === 'function') logAudit('دفعات مجمّعة', 'سندات الصرف', `${vouchers} سند بإجمالي ${fmt(total)}`);
    toast(`✅ نُفّذت الدفعات: ${vouchers} سند صرف${errors ? ` (تعذّر ${errors})` : ''}`, 'ok', 6000);
    st.selected = {}; renderPaymentRun();
};
console.log('✅ Payment Run [ACC-PRUN] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ♻️  [ACC-WC]   لوحة رأس المال العامل — DSO · DPO · DIO · دورة التحويل النقدي  ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._wcState = window._wcState || (function () { const t = new Date(); const from = new Date(t); from.setFullYear(from.getFullYear() - 1); return { from: from.toISOString().slice(0, 10), to: t.toISOString().slice(0, 10) }; })();
function wcDays(from, to) { const a = new Date(from), b = new Date(to); return Math.max(1, Math.round((b - a) / 86400000) + 1); }
function wcCompute(from, to) {
    const { balances } = calcFSBalances(from || '', to, ['posted'], '', '');
    const income = buildIncomeStatement(balances);
    // العملاء/الموردون = الحساب الموحّد + حسابات المجموعات (نمط المجموعات)
    let ar = 0, ap = 0;
    Object.values(balances).forEach(b => {
        const c = String(b.account?.code || '');
        if (b.account?.nature !== 'detail') return;
        if (c === '1130' || c.startsWith('1130-')) ar += (b.naturalClosing || 0);
        else if (c === '2110' || c.startsWith('2110-')) ap += (b.naturalClosing || 0);
    });
    ar = Math.max(0, ar); ap = Math.max(0, ap);
    let inv = 0; Object.values(balances).forEach(b => { const c = String(b.account?.code || ''); if (c.startsWith('115') && b.account.nature === 'detail') inv += (b.naturalClosing || 0); });
    inv = Math.max(0, inv);
    const days = wcDays(from || to, to);
    const sales = income.totalRevenue, cogs = income.directCost || income.totalExpense;
    const dso = sales > 0 ? ar / sales * days : 0;
    const dpo = cogs > 0 ? ap / cogs * days : 0;
    const dio = cogs > 0 ? inv / cogs * days : 0;
    return { ar, ap, inv, sales, cogs, days, dso, dpo, dio, ccc: dso + dio - dpo };
}
window.wcSet = function (field, val) { window._wcState[field] = val; renderWorkingCapital(); };
window.wcQuick = function (range) {
    const t = new Date();
    if (range === 'ytd') { window._wcState = { from: t.getFullYear() + '-01-01', to: t.toISOString().slice(0, 10) }; }
    else { const f = new Date(t); f.setFullYear(f.getFullYear() - 1); window._wcState = { from: f.toISOString().slice(0, 10), to: t.toISOString().slice(0, 10) }; }
    renderWorkingCapital();
};
window.renderWorkingCapital = function () {
    const pg = $('pg-workingcapital'); if (!pg) return;
    const st = window._wcState;
    const m = wcCompute(st.from, st.to);
    const nd = n => (n || n === 0) ? Math.round(n) : '—';
    const card = (icon, title, val, unit, sub, col, hint) => `
        <div class="card" style="padding:14px 16px;border-top:4px solid ${col}">
            <div style="font-size:12px;font-weight:800;color:#1a3a5c">${icon} ${title}</div>
            <div style="font-size:30px;font-weight:900;color:${col};margin:6px 0 2px">${val}<span style="font-size:14px;font-weight:600;color:#888"> ${unit}</span></div>
            <div style="font-size:11px;color:#777">${sub}</div>
            <div style="font-size:10.5px;color:#999;margin-top:6px;line-height:1.5">${hint}</div>
        </div>`;
    // اتجاه 6 أشهر (نافذة متحركة 12 شهراً)
    const now = new Date(); const trend = [];
    for (let i = 5; i >= 0; i--) { const d = new Date(now.getFullYear(), now.getMonth() - i + 1, 0); const to = d.toISOString().slice(0, 10); const f = new Date(d); f.setFullYear(f.getFullYear() - 1); const r = wcCompute(f.toISOString().slice(0, 10), to); trend.push({ label: (d.getMonth() + 1) + '/' + String(d.getFullYear()).slice(2), ...r }); }
    const maxCcc = Math.max(1, ...trend.map(t => Math.abs(t.ccc)));
    const cccCol = m.ccc <= 30 ? '#27ae60' : m.ccc <= 75 ? '#e67e22' : '#c0392b';

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#0e6655,#148f77);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div><h2 style="margin:0">♻️ لوحة رأس المال العامل</h2><div style="opacity:.9;margin-top:4px;font-size:13px">مؤشرات كفاءة التحصيل والسداد والمخزون + دورة التحويل النقدي</div></div>
            <div style="display:flex;gap:6px;align-items:center;background:rgba(255,255,255,.12);border-radius:10px;padding:8px 10px;flex-wrap:wrap">
                <input type="date" value="${st.from}" onchange="wcSet('from',this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:12px">
                <span style="font-size:12px">→</span>
                <input type="date" value="${st.to}" onchange="wcSet('to',this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:12px">
                <button onclick="wcQuick('12m')" style="background:rgba(255,255,255,.2);border:none;color:#fff;border-radius:6px;padding:6px 10px;cursor:pointer;font-size:11px;font-weight:700">12 شهر</button>
                <button onclick="wcQuick('ytd')" style="background:rgba(255,255,255,.2);border:none;color:#fff;border-radius:6px;padding:6px 10px;cursor:pointer;font-size:11px;font-weight:700">السنة</button>
            </div>
        </div>
    </div>
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:12px;margin-bottom:14px">
        ${card('📥', 'فترة التحصيل DSO', nd(m.dso), 'يوم', `العملاء ${fmt(m.ar)} · مبيعات ${fmt(m.sales)}`, '#2980b9', 'كم يوماً يستغرق تحصيل الذمم — الأقل أفضل')}
        ${card('📤', 'فترة السداد DPO', nd(m.dpo), 'يوم', `الموردون ${fmt(m.ap)} · مشتريات ${fmt(m.cogs)}`, '#8e44ad', 'كم يوماً تستغرق قبل سداد الموردين — الأطول يحسّن السيولة')}
        ${card('📦', 'فترة المخزون DIO', nd(m.dio), 'يوم', `المخزون ${fmt(m.inv)}`, '#e67e22', 'كم يوماً يبقى المخزون قبل بيعه — الأقل أفضل')}
        ${card('♻️', 'دورة التحويل النقدي', nd(m.ccc), 'يوم', 'DSO + DIO − DPO', cccCol, m.ccc <= 30 ? 'ممتازة — نقد يعود بسرعة' : m.ccc <= 75 ? 'مقبولة — راقب التحصيل والمخزون' : 'مرتفعة — النقد محتجز طويلاً')}
    </div>
    <div class="card" style="padding:16px;margin-bottom:14px">
        <div style="font-size:13px;font-weight:800;color:#1a3a5c;margin-bottom:12px">📈 اتجاه دورة التحويل النقدي (نافذة 12 شهراً متحركة)</div>
        <div style="display:flex;align-items:flex-end;gap:10px;height:130px;padding-top:10px">
            ${trend.map(t => { const h = Math.round(Math.abs(t.ccc) / maxCcc * 100); const c = t.ccc <= 30 ? '#27ae60' : t.ccc <= 75 ? '#e67e22' : '#c0392b'; return `<div style="flex:1;display:flex;flex-direction:column;align-items:center;justify-content:flex-end;height:100%"><div style="font-size:11px;font-weight:800;color:${c}">${Math.round(t.ccc)}</div><div style="width:100%;max-width:46px;height:${h}%;background:${c};border-radius:6px 6px 0 0;min-height:3px"></div><div style="font-size:10px;color:#888;margin-top:5px">${t.label}</div></div>`; }).join('')}
        </div>
    </div>
    <div class="card" style="padding:0;overflow:hidden;margin-bottom:14px"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:520px">
        <thead><tr style="background:#0e6655;color:#fff"><th style="padding:8px;text-align:right">الشهر</th><th>DSO</th><th>DPO</th><th>DIO</th><th>دورة التحويل</th></tr></thead>
        <tbody>${trend.map(t => `<tr style="border-bottom:1px solid #f2f2f2;text-align:center"><td style="padding:7px;text-align:right;font-weight:700">${t.label}</td><td>${nd(t.dso)}</td><td>${nd(t.dpo)}</td><td>${nd(t.dio)}</td><td style="font-weight:800;color:${t.ccc <= 30 ? '#27ae60' : t.ccc <= 75 ? '#e67e22' : '#c0392b'}">${nd(t.ccc)}</td></tr>`).join('')}</tbody>
    </table></div></div>
    <div style="font-size:11px;color:#888;line-height:1.8">💡 <strong>دورة التحويل النقدي</strong> = عدد الأيام بين دفع المورد وتحصيل النقد من العميل. كلما قلّت تحسّنت السيولة. الحسابات تعتمد أرصدة العملاء (1130) والموردين (2110) والمخزون (115x) مقابل مبيعات ومشتريات الفترة من القيود المرحّلة.</div>`;
};
console.log('✅ Working Capital dashboard [ACC-WC] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   🧭  [ACC-SEG]   قائمة الدخل المقارنة حسب مراكز التكلفة/المشاريع (Segment P&L) ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window._segState = window._segState || { from: new Date().getFullYear() + '-01-01', to: new Date().toISOString().slice(0, 10), dim: 'costCenter' };
function segMembers(dim) {
    if (dim === 'project') return Object.entries(window.projects || {}).map(([id, p]) => ({ id, label: p.name || p.projectName || id }));
    return Object.entries(window.costCenters || {}).filter(([, c]) => c.active !== false).map(([id]) => ({ id, label: (typeof ccDisplayName === 'function' ? ccDisplayName(id) : id) }));
}
function segIncome(from, to, dim, id) { const cc = dim === 'costCenter' ? id : ''; const proj = dim === 'project' ? id : ''; const { balances } = calcFSBalances(from, to, ['posted'], cc, proj); return buildIncomeStatement(balances); }
window.segSet = function (field, val) { window._segState[field] = val; renderSegmentPL(); };
window.renderSegmentPL = function () {
    const pg = $('pg-segmentpl'); if (!pg) return;
    const st = window._segState;
    const members = segMembers(st.dim).map(mem => ({ ...mem, inc: segIncome(st.from, st.to, st.dim, mem.id) })).filter(m => Math.abs(m.inc.totalRevenue) > 0.01 || Math.abs(m.inc.totalExpense) > 0.01);
    const company = buildIncomeStatement(calcFSBalances(st.from, st.to, ['posted'], '', '').balances);
    const pctCell = v => `<span style="font-size:10px;color:#888">${v}</span>`;
    const gm = inc => inc.totalRevenue ? Math.round(inc.grossProfit / inc.totalRevenue * 100) : 0;
    const nm = inc => inc.totalRevenue ? Math.round(inc.netIncome / inc.totalRevenue * 100) : 0;
    const inS = 'padding:7px;border:1.5px solid #c8d8ee;border-radius:6px;font-family:inherit;font-size:12px;background:white';

    const metricRows = [
        { label: '💰 الإيرادات', get: i => i.totalRevenue, bold: false },
        { label: '🏗️ التكاليف المباشرة', get: i => i.directCost, neg: true },
        { label: '📊 مجمل الربح', get: i => i.grossProfit, bold: true, color: true },
        { label: 'هامش مجمل الربح', get: i => gm(i), pct: true },
        { label: '🏢 مصروفات أخرى', get: i => i.adminExpense, neg: true },
        { label: '✅ صافي الربح', get: i => i.netIncome, bold: true, color: true, big: true },
        { label: 'هامش صافي الربح', get: i => nm(i), pct: true }
    ];
    const colHead = members.map(m => `<th style="padding:9px;text-align:left;min-width:120px;border-left:1px solid rgba(255,255,255,.15)">${m.label}</th>`).join('') + `<th style="padding:9px;text-align:left;min-width:120px;background:#0b3d2e">الإجمالي (الشركة)</th>`;
    const bodyRows = metricRows.map(mr => {
        const cells = members.map(m => {
            const v = mr.get(m.inc);
            if (mr.pct) return `<td style="padding:7px 10px;text-align:left;color:${v >= 0 ? '#1e8449' : '#c0392b'};font-weight:700">${v}%</td>`;
            const col = mr.color ? (v >= 0 ? '#1e8449' : '#c0392b') : (mr.neg ? '#c0392b' : '#1a3a5c');
            return `<td style="padding:7px 10px;text-align:left;font-weight:${mr.bold ? '800' : '500'};color:${col};font-size:${mr.big ? '13.5px' : '12px'}">${fmt(v)}</td>`;
        }).join('');
        const cv = mr.get(company);
        const totCell = mr.pct
            ? `<td style="padding:7px 10px;text-align:left;background:#eafaf1;color:${cv >= 0 ? '#1e8449' : '#c0392b'};font-weight:800">${cv}%</td>`
            : `<td style="padding:7px 10px;text-align:left;background:#eafaf1;font-weight:${mr.bold ? '900' : '700'};color:${mr.color ? (cv >= 0 ? '#1e8449' : '#c0392b') : (mr.neg ? '#c0392b' : '#0e6655')}">${fmt(cv)}</td>`;
        return `<tr style="border-bottom:1px solid #f2f2f2;${mr.bold ? 'background:#fafcff' : ''}"><td style="padding:7px 10px;font-weight:${mr.bold ? '800' : '600'};color:#1a3a5c">${mr.label}</td>${cells}${totCell}</tr>`;
    }).join('');

    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#1a5276,#2874a6);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div><h2 style="margin:0">🧭 قائمة الدخل المقارنة</h2><div style="opacity:.9;margin-top:4px;font-size:13px">مقارنة الربحية عبر مراكز التكلفة أو المشاريع جنباً إلى جنب</div></div>
            <div style="display:flex;gap:6px;align-items:center;background:rgba(255,255,255,.12);border-radius:10px;padding:8px 10px;flex-wrap:wrap">
                <select onchange="segSet('dim',this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:12px;font-weight:700"><option value="costCenter" ${st.dim === 'costCenter' ? 'selected' : ''}>🎯 مراكز التكلفة</option><option value="project" ${st.dim === 'project' ? 'selected' : ''}>🏗️ المشاريع</option></select>
                <input type="date" value="${st.from}" onchange="segSet('from',this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:12px">
                <span style="font-size:12px">→</span>
                <input type="date" value="${st.to}" onchange="segSet('to',this.value)" style="padding:6px;border:none;border-radius:6px;font-family:inherit;font-size:12px">
                <button onclick="window.print()" style="background:rgba(255,255,255,.2);border:none;color:#fff;border-radius:6px;padding:6px 10px;cursor:pointer;font-size:11px;font-weight:700">🖨️</button>
            </div>
        </div>
    </div>
    ${members.length ? `<div class="card" style="padding:0;overflow:hidden"><div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:${Math.max(560, 200 + members.length * 130)}px">
        <thead><tr style="background:#1a5276;color:#fff"><th style="padding:9px;text-align:right;min-width:150px">البند</th>${colHead}</tr></thead>
        <tbody>${bodyRows}</tbody>
    </table></div></div>
    <div style="font-size:11px;color:#888;margin-top:12px;line-height:1.8">💡 كل عمود = ${st.dim === 'project' ? 'مشروع' : 'مركز تكلفة'} تُحسب له قائمة دخله من القيود المرحّلة المخصّصة له. عمود «الإجمالي (الشركة)» يشمل كل الحركات (بما فيها غير المخصّصة لأي ${st.dim === 'project' ? 'مشروع' : 'مركز'})، لذا قد لا يساوي مجموع الأعمدة.</div>`
        : '<div class="card" style="padding:40px;text-align:center;color:#999">لا توجد حركات مخصّصة لهذه الأبعاد في الفترة المحددة.</div>'}`;
};
console.log('✅ Segment P&L [ACC-SEG] loaded');

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📋  [ACC-JTMP]   مكتبة قوالب القيود اليدوية (Journal Templates)             ║
// ╚══════════════════════════════════════════════════════════════════════════╝
window.saveJrnAsTemplate = async function () {
    const lines = (jrnEditorState.lines || []).filter(l => l.accountCode).map(l => ({ accountCode: l.accountCode, accountName: l.accountName || '', description: l.description || '', debit: parseFloat(l.debit) || 0, credit: parseFloat(l.credit) || 0 }));
    if (lines.length < 2) { toast('⚠️ أضف سطرين على الأقل بحساباتٍ قبل الحفظ كقالب', 'er'); return; }
    const name = (typeof prompt === 'function' ? (prompt('اسم القالب:', ($('mJrnDescription')?.value || '').slice(0, 40)) || '') : '').trim();
    if (!name) return;
    const payload = { name, description: ($('mJrnDescription')?.value || '').trim(), lines, createdAt: Date.now(), createdBy: (typeof brUser === 'function' ? brUser() : 'system') };
    try { await push(R.jrnTemplates, payload); toast('✅ حُفظ القالب — تجده في «قوالب القيود»', 'ok', 5000); }
    catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.applyJrnTemplate = function (id) {
    const t = window.jrnTemplates?.[id]; if (!t) { toast('⚠️ القالب غير موجود', 'er'); return; }
    if (typeof openJrnEditor !== 'function') return;
    openJrnEditor();
    jrnEditorState.lines = (t.lines || []).map(l => ({ accountCode: l.accountCode || '', accountName: l.accountName || '', description: l.description || '', date: '', costCenter: '', projectId: '', debit: parseFloat(l.debit) || 0, credit: parseFloat(l.credit) || 0 }));
    if (!jrnEditorState.lines.length) jrnEditorState.lines = [{ accountCode: '', accountName: '', description: '', date: '', costCenter: '', projectId: '', debit: 0, credit: 0 }];
    if ($('mJrnDescription') && t.description) $('mJrnDescription').value = t.description;
    if ($('mJrnTitle')) $('mJrnTitle').textContent = '📒 قيد من قالب: ' + (t.name || '');
    if (typeof renderJrnLines === 'function') renderJrnLines();
    toast('📋 طُبّق القالب — عدّل المبالغ والتاريخ ثم رحّل', 'ok', 5000);
};
window.deleteJrnTemplate = async function (id) {
    const t = window.jrnTemplates?.[id]; if (!t) return;
    if (!(await cf2(`حذف القالب «${t.name}»؟`))) return;
    try { await remove(ref(db, 'ledger/jrnTemplates/' + id)); toast('🗑️ حُذف القالب', 'ok'); renderJrnTemplates(); }
    catch (e) { toast('❌ ' + (e.message || e), 'er'); }
};
window.newJrnFromScratch = function () { if (typeof openJrnEditor === 'function') { openJrnEditor(); toast('💡 ابنِ سطور القيد ثم اضغط «📋 حفظ كقالب»', 'ok', 5000); } };
window.renderJrnTemplates = function () {
    const pg = $('pg-jrntemplates'); if (!pg) return;
    const items = Object.entries(window.jrnTemplates || {}).sort((a, b) => (a[1].name || '').localeCompare(b[1].name || ''));
    pg.innerHTML = `
    <div class="card" style="background:linear-gradient(135deg,#5b2c6f,#8e44ad);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0">📋 قوالب القيود اليدوية</h2><div style="opacity:.9;margin-top:4px;font-size:13px">قوالب جاهزة للقيود المتكررة (إهلاك، تسويات، مخصصات) — تُملأ بنقرة</div>
    </div>
    <div style="margin-bottom:14px;font-size:12px;color:#666;line-height:1.7;background:#f8f4fb;border:1px solid #e8d9f0;border-radius:10px;padding:12px 14px">💡 لإنشاء قالب: اضغط «➕ قالب جديد»، ابنِ سطور القيد بالحسابات (والمبالغ النموذجية إن رغبت)، ثم «📋 حفظ كقالب» داخل محرّر القيد. لاستخدام قالب: اضغط «استخدام» فيُفتح المحرّر معبّأً — عدّل المبالغ والتاريخ ثم رحّل.</div>
    <div style="margin-bottom:14px"><button class="btn" onclick="newJrnFromScratch()" style="background:#8e44ad;color:#fff;padding:10px 20px;font-weight:800">➕ قالب جديد (ابدأ ببناء قيد)</button></div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:12px">
        ${items.length ? items.map(([id, t]) => {
        const td = (t.lines || []).reduce((s, l) => s + (parseFloat(l.debit) || 0), 0);
        const balanced = Math.abs(td - (t.lines || []).reduce((s, l) => s + (parseFloat(l.credit) || 0), 0)) < 0.01;
        return `<div class="card" style="padding:14px 16px">
            <div style="font-size:15px;font-weight:900;color:#1a3a5c">📋 ${(t.name || '—').replace(/</g, '&lt;')}</div>
            <div style="font-size:11px;color:#888;margin:5px 0 8px">${(t.lines || []).length} سطر · إجمالي ${fmt(td)} ${balanced ? '' : '<span style="color:#c0392b">⚠️ غير متوازن</span>'}</div>
            <div style="font-size:11px;color:#555;max-height:66px;overflow:hidden;margin-bottom:10px">${(t.lines || []).slice(0, 4).map(l => `${l.accountCode || '—'} ${l.debit ? '<span style="color:#2d6a9f">مدين ' + fmt(l.debit) + '</span>' : '<span style="color:#c0392b">دائن ' + fmt(l.credit) + '</span>'}`).join('<br>')}${(t.lines || []).length > 4 ? '<br>…' : ''}</div>
            <div style="display:flex;gap:6px"><button class="btn" onclick="applyJrnTemplate('${id}')" style="background:#27ae60;color:#fff;padding:7px 16px;font-weight:700">▶️ استخدام</button><button class="btn" onclick="deleteJrnTemplate('${id}')" style="background:#fdecea;color:#c0392b;padding:7px 12px">🗑️</button></div>
        </div>`;
    }).join('') : '<div class="card" style="padding:40px;text-align:center;color:#999;grid-column:1/-1">لا توجد قوالب بعد — اضغط «➕ قالب جديد» لإنشاء أول قالب.</div>'}
    </div>`;
};
console.log('✅ Journal Templates [ACC-JTMP] loaded');

// ============================================================
// [ACC-LOCK] Period Locking (إقفال الفترات المحاسبية)
// ============================================================

// تتحقق مما إذا كان تاريخ معين يقع داخل فترة (شهر) مقفلة، وتعيد بيانات القفل أو null
function pcIsLocked(dateStr) {
    if (!dateStr) return null;
    const period = dateStr.slice(0, 7); // 'YYYY-MM'
    const locks = window.periodLocks || {};
    const lock = locks[period];
    return (lock && lock.locked) ? { period, ...lock } : null;
}

window._pclState = window._pclState || { year: new Date().getFullYear() };

window.renderPeriodLock = function () {
    const pg = $('pg-periodlock');
    if (!pg) return;
    const st = window._pclState;
    const locks = window.periodLocks || {};
    const isFinance = brIsFinance();

    const years = [];
    const curY = new Date().getFullYear();
    for (let y = curY; y >= curY - 5; y--) years.push(y);

    const monthNames = ['يناير', 'فبراير', 'مارس', 'أبريل', 'مايو', 'يونيو', 'يوليو', 'أغسطس', 'سبتمبر', 'أكتوبر', 'نوفمبر', 'ديسمبر'];

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#1e3a8a,#1e40af);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">🔒 إقفال الفترات المحاسبية</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">إقفال أي شهر يمنع إضافة أو تعديل أو ترحيل أو إلغاء أو حذف أي قيد بتاريخ يقع ضمنه (سواء تاريخ القيد أو التاريخ الجانبي للسطر)</div>
    </div>`;

    if (!isFinance) {
        html += `<div class="card" style="background:#fef3c7;border:1px solid #f59e0b;padding:12px 16px;border-radius:8px;margin-bottom:14px;color:#92400e">
            ⚠️ عرض فقط — إقفال/فتح الفترات مخصص للمدير المالي ومدير النظام
        </div>`;
    }

    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px">
        <label>السنة: <select onchange="pclSetYear(this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
            ${years.map(y => `<option value="${y}" ${st.year === y ? 'selected' : ''}>${y}</option>`).join('')}
        </select></label>
    </div>`;

    html += `<div class="card" style="padding:14px 16px;overflow:auto">
        <table class="tbl" style="width:100%;text-align:center">
            <thead><tr style="background:#f8f9fa"><th>الشهر</th><th>الحالة</th><th>تم الإقفال بواسطة</th><th>تاريخ الإقفال</th><th>إجراء</th></tr></thead>
            <tbody>`;
    for (let m = 1; m <= 12; m++) {
        const period = `${st.year}-${String(m).padStart(2, '0')}`;
        const lock = locks[period];
        const locked = lock && lock.locked;
        html += `<tr>
            <td style="font-weight:600">${monthNames[m - 1]} ${st.year}</td>
            <td>${locked ? '<span style="color:#dc2626;font-weight:700">🔒 مقفلة</span>' : '<span style="color:#16a34a">🔓 مفتوحة</span>'}</td>
            <td>${lock?.lockedByName || lock?.lockedBy || '-'}</td>
            <td>${lock?.lockedAt ? new Date(lock.lockedAt).toLocaleString('ar-SA') : '-'}</td>
            <td>${isFinance ? (locked
                ? `<button class="btn sm" style="color:#16a34a" onclick="pclToggle('${period}', false)">🔓 إعادة فتح</button>`
                : `<button class="btn sm" style="color:#dc2626" onclick="pclToggle('${period}', true)">🔒 إقفال</button>`)
                : '-'}</td>
        </tr>`;
    }
    html += `</tbody></table>
    </div>`;

    pg.innerHTML = html;
};

window.pclSetYear = function (value) {
    window._pclState.year = parseInt(value);
    renderPeriodLock();
};

window.pclToggle = async function (period, lock) {
    if (!brIsFinance()) { toast('🚫 إقفال/فتح الفترات مخصص للمدير المالي ومدير النظام', 'er'); return; }
    const msg = lock
        ? `هل تريد إقفال فترة ${period}؟ بعد الإقفال لا يمكن إضافة أو تعديل أو ترحيل أو إلغاء أو حذف أي قيد بتاريخ يقع ضمنها.`
        : `هل تريد إعادة فتح فترة ${period}؟ سيصبح بإمكان المستخدمين تعديل القيود ضمنها مجدداً.`;
    if (!await cf2(msg)) return;
    try {
        if (lock) {
            await update(ref(db, `ledger/periodLocks/${period}`), {
                locked: true,
                lockedAt: Date.now(),
                lockedBy: brUser(),
                lockedByName: (typeof myP !== 'undefined' && myP?.name) || ''
            });
            logAudit('إقفال فترة', 'المحاسبة', `إقفال الفترة المحاسبية ${period}`);
            toast(`🔒 تم إقفال فترة ${period}`, 'ok');
        } else {
            await update(ref(db, `ledger/periodLocks/${period}`), {
                locked: false,
                reopenedAt: Date.now(),
                reopenedBy: brUser()
            });
            logAudit('فتح فترة', 'المحاسبة', `إعادة فتح الفترة المحاسبية ${period}`);
            toast(`🔓 تم إعادة فتح فترة ${period}`, 'ok');
        }
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

console.log('✅ Period Locking module [ACC-LOCK] loaded');

// ============================================================
// [ACC-YEC] Year-End Closing (إقفال السنة المالية)
// ============================================================
const YEC_RETAINED_EARNINGS_ACC = '3200';

window._yecState = window._yecState || { year: new Date().getFullYear() - 1 };

// يحسب أرصدة الحسابات كما هي في نهاية toDate (تراكمي منذ البداية) دون تأثير أي قيود مستقبلية
function yecBalancesAsOf(toDate) {
    const { balances } = calcFSBalances('', toDate, ['posted'], '', '');
    return balances;
}

window.renderYearClosing = function () {
    const pg = $('pg-yearclosing');
    if (!pg) return;
    const st = window._yecState;
    const byCode = brByCode ? brByCode() : {};
    const isFinance = brIsFinance();
    const closings = window.yearClosings || {};
    const existing = closings[st.year];

    const years = [];
    const curY = new Date().getFullYear();
    for (let y = curY; y >= curY - 6; y--) years.push(y);

    // صافي ربح/خسارة السنة المحددة
    const incomeBalances = (() => {
        const { balances } = calcFSBalances(`${st.year}-01-01`, `${st.year}-12-31`, ['posted'], '', '');
        return balances;
    })();
    const income = buildIncomeStatement(incomeBalances);

    // الحسابات التي ستُقفل (إيرادات/مصروفات لها حركة في السنة)
    const revExpToClose = [...income.revenues, ...income.expenses].filter(b => Math.abs(b.naturalMovement) > 0.005);

    // أرصدة نهاية السنة (لبناء القيد الافتتاحي) — أصول/خصوم/حقوق ملكية
    const closingBalances = yecBalancesAsOf(`${st.year}-12-31`);
    const bsAccounts = Object.values(closingBalances).filter(b => ['asset', 'liability', 'equity'].includes(b.account.type) && Math.abs(b.naturalClosing) > 0.005);

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#4c1d95,#6d28d9);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">🗓️ إقفال السنة المالية</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">إقفال حسابات الإيرادات والمصروفات وترحيل صافي الربح/الخسارة إلى الأرباح المحتجزة (${byCode[YEC_RETAINED_EARNINGS_ACC]?.nameAr || YEC_RETAINED_EARNINGS_ACC})، وإنشاء قيد افتتاحي للسنة التالية، وإقفال السنة بالكامل</div>
    </div>`;

    if (!isFinance) {
        html += `<div class="card" style="background:#fef3c7;border:1px solid #f59e0b;padding:12px 16px;border-radius:8px;margin-bottom:14px;color:#92400e">
            ⚠️ عرض فقط — تنفيذ إقفال السنة مخصص للمدير المالي ومدير النظام
        </div>`;
    }

    html += `<div class="card" style="padding:14px 16px;margin-bottom:14px">
        <label>السنة المراد إقفالها: <select onchange="yecSetYear(this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd">
            ${years.map(y => `<option value="${y}" ${st.year === y ? 'selected' : ''}>${y}</option>`).join('')}
        </select></label>
        <span style="margin-right:10px;color:#666;font-size:12px">سيُنشأ قيد إقفال بتاريخ ${st.year}-12-31 وقيد افتتاحي بتاريخ ${st.year + 1}-01-01، ويُقفل عام ${st.year} بالكامل (12 شهر)</span>
    </div>`;

    if (existing) {
        html += `<div class="card" style="background:#dcfce7;border:1px solid #16a34a;padding:12px 16px;border-radius:8px;margin-bottom:14px;color:#166534">
            ✅ تم إقفال سنة ${st.year} بالفعل بتاريخ ${existing.closedAt ? new Date(existing.closedAt).toLocaleString('ar-SA') : ''} بواسطة ${existing.closedByName || existing.closedBy || ''}.
            <br>صافي ${existing.netIncome >= 0 ? 'الربح' : 'الخسارة'}: ${fmt(Math.abs(existing.netIncome || 0))}
            ${isFinance ? `<br><button class="btn sm" style="margin-top:8px;color:#dc2626" onclick="yecUndo(${st.year})">↩️ التراجع عن الإقفال</button>` : ''}
        </div>`;
    } else {
        html += `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;margin-bottom:14px">
            <div class="card" style="padding:14px 16px;text-align:center">
                <div style="color:#666;font-size:13px">إجمالي الإيرادات (${st.year})</div>
                <div style="font-size:20px;font-weight:800;color:#0d9488">${fmt(income.totalRevenue)}</div>
            </div>
            <div class="card" style="padding:14px 16px;text-align:center">
                <div style="color:#666;font-size:13px">إجمالي المصروفات (${st.year})</div>
                <div style="font-size:20px;font-weight:800;color:#7c3aed">${fmt(income.totalExpense)}</div>
            </div>
            <div class="card" style="padding:14px 16px;text-align:center;border:2px solid ${income.netIncome >= 0 ? '#16a34a' : '#dc2626'}">
                <div style="color:#666;font-size:13px">${income.netIncome >= 0 ? 'صافي الربح' : 'صافي الخسارة'} (يُرحَّل إلى الأرباح المحتجزة)</div>
                <div style="font-size:20px;font-weight:800;color:${income.netIncome >= 0 ? '#16a34a' : '#dc2626'}">${fmt(Math.abs(income.netIncome))}</div>
            </div>
        </div>`;

        html += `<div class="card" style="padding:14px 16px;margin-bottom:14px;overflow:auto">
            <h3 style="margin-top:0">قيد الإقفال (${st.year}-12-31) — ${revExpToClose.length + 1} سطر</h3>
            <table class="tbl" style="width:100%;text-align:center">
                <thead><tr style="background:#f8f9fa"><th>الحساب</th><th>مدين</th><th>دائن</th></tr></thead>
                <tbody>`;
        revExpToClose.forEach(b => {
            const isRevenue = b.account.type === 'revenue';
            html += `<tr><td style="text-align:right">${b.account.code} - ${b.account.nameAr}</td>
                <td>${isRevenue ? fmt(b.naturalMovement) : ''}</td>
                <td>${!isRevenue ? fmt(b.naturalMovement) : ''}</td></tr>`;
        });
        html += `<tr style="font-weight:700;background:#f0fdfa">
                <td style="text-align:right">${YEC_RETAINED_EARNINGS_ACC} - ${byCode[YEC_RETAINED_EARNINGS_ACC]?.nameAr || 'الأرباح المحتجزة'}</td>
                <td>${income.netIncome < 0 ? fmt(-income.netIncome) : ''}</td>
                <td>${income.netIncome >= 0 ? fmt(income.netIncome) : ''}</td>
            </tr>
            </tbody></table>
        </div>`;

        html += `<div class="card" style="padding:14px 16px;margin-bottom:14px;overflow:auto">
            <h3 style="margin-top:0">القيد الافتتاحي (${st.year + 1}-01-01) — ${bsAccounts.length} سطر</h3>
            <table class="tbl" style="width:100%;text-align:center">
                <thead><tr style="background:#f8f9fa"><th>الحساب</th><th>مدين</th><th>دائن</th></tr></thead>
                <tbody>`;
        bsAccounts.forEach(b => {
            const isDebitNature = ['asset'].includes(b.account.type);
            let amt = b.naturalClosing;
            if (b.account.code === YEC_RETAINED_EARNINGS_ACC) amt += income.netIncome;
            const debitSide = amt >= 0 ? isDebitNature : !isDebitNature;
            html += `<tr><td style="text-align:right">${b.account.code} - ${b.account.nameAr}</td>
                <td>${debitSide ? fmt(Math.abs(amt)) : ''}</td>
                <td>${!debitSide ? fmt(Math.abs(amt)) : ''}</td></tr>`;
        });
        html += `</tbody></table>
        </div>`;

        if (isFinance) {
            html += `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:14px">
                <button class="btn" style="background:#6d28d9;color:#fff" onclick="yecRunClosing(${st.year})">🗓️ تنفيذ إقفال سنة ${st.year}</button>
            </div>`;
        }
    }

    // سجل الإقفالات السابقة
    const savedRows = Object.entries(closings).sort((a, b) => (b[1].year || 0) - (a[1].year || 0));
    if (savedRows.length) {
        html += `<div class="card" style="padding:14px 16px">
            <h3 style="margin-top:0">📋 سجل إقفالات السنوات</h3>
            <table class="tbl" style="width:100%;text-align:center">
                <thead><tr style="background:#f8f9fa"><th>السنة</th><th>صافي الربح/الخسارة</th><th>تاريخ الإقفال</th><th>بواسطة</th></tr></thead>
                <tbody>`;
        savedRows.forEach(([key, r]) => {
            html += `<tr>
                <td>${r.year}</td>
                <td style="color:${(r.netIncome || 0) >= 0 ? '#16a34a' : '#dc2626'};font-weight:700">${fmt(Math.abs(r.netIncome || 0))}</td>
                <td>${r.closedAt ? new Date(r.closedAt).toLocaleString('ar-SA') : ''}</td>
                <td>${r.closedByName || r.closedBy || ''}</td>
            </tr>`;
        });
        html += `</tbody></table></div>`;
    }

    pg.innerHTML = html;
};

window.yecSetYear = function (value) {
    window._yecState.year = parseInt(value);
    renderYearClosing();
};

window.yecRunClosing = async function (year) {
    if (!brIsFinance()) { toast('🚫 تنفيذ إقفال السنة مخصص للمدير المالي ومدير النظام', 'er'); return; }
    const closings = window.yearClosings || {};
    if (closings[year]) { toast('⚠️ تم إقفال هذه السنة بالفعل', 'er'); return; }

    const byCode = brByCode ? brByCode() : {};
    const { balances: incomeBalances } = calcFSBalances(`${year}-01-01`, `${year}-12-31`, ['posted'], '', '');
    const income = buildIncomeStatement(incomeBalances);
    const revExpToClose = [...income.revenues, ...income.expenses].filter(b => Math.abs(b.naturalMovement) > 0.005);

    if (!revExpToClose.length && Math.abs(income.netIncome) < 0.005) {
        toast('⚠️ لا توجد حركات على حسابات الإيرادات والمصروفات لهذه السنة', 'er');
        return;
    }

    if (!await cf2(`هل تريد تنفيذ إقفال سنة ${year}؟\n\nسيتم:\n• إنشاء قيد إقفال بتاريخ ${year}-12-31 لتصفير حسابات الإيرادات والمصروفات وترحيل ${income.netIncome >= 0 ? 'صافي الربح' : 'صافي الخسارة'} (${fmt(Math.abs(income.netIncome))}) إلى الأرباح المحتجزة\n• إنشاء قيد افتتاحي بتاريخ ${year + 1}-01-01 بالأرصدة الافتتاحية للسنة الجديدة\n• إقفال جميع أشهر سنة ${year} (لا يمكن التعديل عليها بعد ذلك إلا بإعادة فتحها)\n\nهذه العملية يمكن التراجع عنها لاحقاً.`)) return;

    try {
        const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
        const userName = (typeof myP !== 'undefined' && myP?.name) || '';

        // ── قيد الإقفال ─────────────────
        const closingLines = revExpToClose.map(b => ({
            accountCode: b.account.code,
            accountName: b.account.nameAr,
            description: `إقفال حساب ${b.account.nameAr} لسنة ${year}`,
            date: '', costCenter: '', projectId: '',
            debit: b.account.type === 'revenue' ? b.naturalMovement : 0,
            credit: b.account.type === 'expense' ? b.naturalMovement : 0
        }));
        closingLines.push({
            accountCode: YEC_RETAINED_EARNINGS_ACC,
            accountName: byCode[YEC_RETAINED_EARNINGS_ACC]?.nameAr || 'الأرباح المحتجزة',
            description: `ترحيل صافي ${income.netIncome >= 0 ? 'ربح' : 'خسارة'} سنة ${year} إلى الأرباح المحتجزة`,
            date: '', costCenter: '', projectId: '',
            debit: income.netIncome < 0 ? -income.netIncome : 0,
            credit: income.netIncome >= 0 ? income.netIncome : 0
        });
        const closingTotalDebit = closingLines.reduce((s, l) => s + l.debit, 0);
        const closingTotalCredit = closingLines.reduce((s, l) => s + l.credit, 0);

        const closingEntryRef = await push(R.jrn, {
            date: `${year}-12-31`,
            description: `قيد إقفال السنة المالية ${year}`,
            status: 'posted',
            lines: closingLines,
            totalDebit: Math.round(closingTotalDebit * 100) / 100,
            totalCredit: Math.round(closingTotalCredit * 100) / 100,
            notes: `قيد آلي لإقفال حسابات الإيرادات والمصروفات لسنة ${year} وترحيل صافي ${income.netIncome >= 0 ? 'الربح' : 'الخسارة'} إلى الأرباح المحتجزة`,
            source: 'yearEndClosing', sourceType: 'closing', sourceYear: year,
            createdAt: Date.now(), createdBy: userId, updatedAt: new Date().toISOString(), updatedBy: userId
        });

        // ── القيد الافتتاحي ─────────────────
        const closingBalances = yecBalancesAsOf(`${year}-12-31`);
        const bsAccounts = Object.values(closingBalances).filter(b => ['asset', 'liability', 'equity'].includes(b.account.type));
        const openingLines = [];
        bsAccounts.forEach(b => {
            let amt = b.naturalClosing;
            if (b.account.code === YEC_RETAINED_EARNINGS_ACC) amt += income.netIncome;
            if (Math.abs(amt) < 0.005) return;
            const isDebitNature = b.account.type === 'asset';
            const debitSide = amt >= 0 ? isDebitNature : !isDebitNature;
            openingLines.push({
                accountCode: b.account.code,
                accountName: b.account.nameAr,
                description: `رصيد افتتاحي ${year + 1}`,
                date: '', costCenter: '', projectId: '',
                debit: debitSide ? Math.abs(amt) : 0,
                credit: !debitSide ? Math.abs(amt) : 0
            });
        });
        const openingTotalDebit = openingLines.reduce((s, l) => s + l.debit, 0);
        const openingTotalCredit = openingLines.reduce((s, l) => s + l.credit, 0);

        const openingEntryRef = await push(R.jrn, {
            date: `${year + 1}-01-01`,
            description: `قيد افتتاحي لسنة ${year + 1} (مرحّل من إقفال سنة ${year})`,
            status: 'posted',
            lines: openingLines,
            totalDebit: Math.round(openingTotalDebit * 100) / 100,
            totalCredit: Math.round(openingTotalCredit * 100) / 100,
            notes: `قيد آلي بالأرصدة الافتتاحية لسنة ${year + 1} بناءً على أرصدة إقفال سنة ${year}`,
            source: 'yearEndClosing', sourceType: 'opening', sourceYear: year,
            createdAt: Date.now(), createdBy: userId, updatedAt: new Date().toISOString(), updatedBy: userId
        });

        // ── إقفال جميع أشهر السنة ─────────────────
        const lockUpdates = {};
        for (let m = 1; m <= 12; m++) {
            const period = `${year}-${String(m).padStart(2, '0')}`;
            lockUpdates[period] = { locked: true, lockedAt: Date.now(), lockedBy: userId, lockedByName: userName, viaYearClosing: true };
        }
        await update(ref(db, 'ledger/periodLocks'), lockUpdates);

        // ── سجل الإقفال ─────────────────
        await update(ref(db, `ledger/yearClosings/${year}`), {
            year, netIncome: income.netIncome,
            closingEntryKey: closingEntryRef.key, openingEntryKey: openingEntryRef.key,
            closedAt: Date.now(), closedBy: userId, closedByName: userName
        });

        logAudit('إقفال سنة مالية', 'المحاسبة', `إقفال السنة المالية ${year} ونقل صافي الربح/الخسارة للأرباح المحتجزة`);
        toast(`✅ تم إقفال سنة ${year} بنجاح`, 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

window.yecUndo = async function (year) {
    if (!brIsFinance()) { toast('🚫 التراجع عن الإقفال مخصص للمدير المالي ومدير النظام', 'er'); return; }
    const closing = (window.yearClosings || {})[year];
    if (!closing) return;

    if (!await cf2(`هل تريد التراجع عن إقفال سنة ${year}؟\n\nسيتم حذف قيد الإقفال والقيد الافتتاحي وإعادة فتح جميع أشهر سنة ${year}.`)) return;

    try {
        if (closing.closingEntryKey) await remove(ref(db, `ledger/journalEntries/${closing.closingEntryKey}`));
        if (closing.openingEntryKey) await remove(ref(db, `ledger/journalEntries/${closing.openingEntryKey}`));

        const lockUpdates = {};
        for (let m = 1; m <= 12; m++) {
            const period = `${year}-${String(m).padStart(2, '0')}`;
            const lock = (window.periodLocks || {})[period];
            if (lock && lock.viaYearClosing) {
                lockUpdates[period] = { locked: false, reopenedAt: Date.now(), reopenedBy: (typeof curU !== 'undefined' && curU?.uid) || 'system' };
            }
        }
        if (Object.keys(lockUpdates).length) await update(ref(db, 'ledger/periodLocks'), lockUpdates);

        await remove(ref(db, `ledger/yearClosings/${year}`));
        logAudit('تراجع عن إقفال سنة', 'المحاسبة', `التراجع عن إقفال السنة المالية ${year}`);
        toast(`↩️ تم التراجع عن إقفال سنة ${year}`, 'ok');
    } catch (e) {
        toast('❌ خطأ: ' + (e.message || e), 'er');
    }
};

console.log('✅ Year-End Closing module [ACC-YEC] loaded');

// 🗓️ مؤشر السنة المالية المفتوحة في الشريط العلوي
window.updateFYIndicator = function () {
    const pill = $('fyPill'), txt = $('fyT');
    if (!pill || !txt) return;
    const canFn = (typeof can === 'function') ? can : () => true;
    if (!canFn('view_accounting') && (typeof myP === 'undefined' || myP?.role !== 'admin')) { pill.style.display = 'none'; return; }

    const closings = window.yearClosings || {};
    const closedYears = Object.values(closings).map(c => c.year).filter(y => typeof y === 'number');
    const openYear = closedYears.length ? Math.max(...closedYears) + 1 : new Date().getFullYear();

    txt.textContent = `📅 السنة المالية المفتوحة: ${openYear}`;
    pill.style.display = 'flex';
    pill.style.background = '#ecfdf5';
    pill.style.color = '#065f46';
    pill.style.border = '1px solid #6ee7b7';
};

// ============================================================
// [ACC-AGE] Aging Report (أعمار الديون)
// ============================================================
window._ageState = window._ageState || { type: 'ar' };

function ageBuckets(invoices, idField, masterMap) {
    const today = new Date().toISOString().slice(0, 10);
    const rows = {};
    Object.values(invoices || {}).forEach(inv => {
        if (inv.status !== 'posted') return;
        const key = inv[idField];
        if (!key) return;
        const grand = Math.round((parseFloat(inv.grandTotal) || 0) * 100) / 100;
        const paid = Math.round((parseFloat(inv.paidAmount) || 0) * 100) / 100;
        const open = Math.round((grand - paid) * 100) / 100;
        if (open <= 0.005) return;
        const due = inv.dueDate || inv.invoiceDate || today;
        const days = Math.floor((new Date(today) - new Date(due)) / 86400000);
        let bucket;
        if (days <= 0) bucket = 'current';
        else if (days <= 30) bucket = 'b30';
        else if (days <= 60) bucket = 'b60';
        else if (days <= 90) bucket = 'b90';
        else bucket = 'b90p';

        if (!rows[key]) rows[key] = { current: 0, b30: 0, b60: 0, b90: 0, b90p: 0, total: 0 };
        rows[key][bucket] += open;
        rows[key].total += open;
    });
    return Object.entries(rows).map(([key, b]) => ({
        key,
        name: masterMap?.[key]?.name || masterMap?.[key]?.nameAr || key,
        ...b
    })).filter(r => r.total > 0.005).sort((a, b) => b.total - a.total);
}

window.ageSetType = function (type) {
    window._ageState.type = type;
    renderAging();
};

window.renderAging = function () {
    const pg = $('pg-aging');
    if (!pg) return;
    const st = window._ageState;
    const isAR = st.type === 'ar';

    const rows = isAR
        ? ageBuckets(window.salesInvoices, 'customerId', window.customers)
        : ageBuckets(window.purchaseInvoices, 'vendorId', window.vendors);

    const cols = [
        { k: 'current', l: 'لم يحن السداد', c: '#16a34a' },
        { k: 'b30', l: '1-30 يوم', c: '#65a30d' },
        { k: 'b60', l: '31-60 يوم', c: '#d97706' },
        { k: 'b90', l: '61-90 يوم', c: '#ea580c' },
        { k: 'b90p', l: 'أكثر من 90 يوم', c: '#dc2626' }
    ];

    const totals = { current: 0, b30: 0, b60: 0, b90: 0, b90p: 0, total: 0 };
    rows.forEach(r => cols.concat([{ k: 'total' }]).forEach(c => totals[c.k] += r[c.k]));

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#0f766e,#0d9488);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">⏳ أعمار الديون</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">تحليل أرصدة العملاء والموردين غير المسددة حسب فترات التأخر عن تاريخ الاستحقاق</div>
    </div>`;

    html += `<div class="card" style="padding:10px 14px;margin-bottom:14px;display:flex;gap:8px;align-items:center">
        <button class="btn sm ${isAR ? 'primary' : ''}" onclick="ageSetType('ar')">🧑‍💼 أعمار ذمم العملاء (مدينون)</button>
        <button class="btn sm ${!isAR ? 'primary' : ''}" onclick="ageSetType('vendor')">🏭 أعمار ذمم الموردين (دائنون)</button>
        <button class="btn sm" style="margin-right:auto" onclick="window.print()">🖨️ طباعة</button>
        <button class="btn sm" onclick="ageExport()">📤 تصدير Excel</button>
    </div>`;

    html += `<div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:14px">
        ${cols.map(c => `
            <div class="card" style="padding:12px;text-align:center;border-top:3px solid ${c.c}">
                <div style="color:#666;font-size:12px">${c.l}</div>
                <div style="font-size:18px;font-weight:800;color:${c.c}">${fmt(totals[c.k])}</div>
            </div>`).join('')}
        <div class="card" style="padding:12px;text-align:center;border-top:3px solid #4c1d95">
            <div style="color:#666;font-size:12px">الإجمالي</div>
            <div style="font-size:18px;font-weight:800;color:#4c1d95">${fmt(totals.total)}</div>
        </div>
    </div>`;

    html += `<div class="card" style="padding:14px 16px;overflow:auto">
        <table class="tbl" style="width:100%;text-align:center">
            <thead><tr style="background:#f8f9fa">
                <th style="text-align:right">${isAR ? 'العميل' : 'المورد'}</th>
                ${cols.map(c => `<th>${c.l}</th>`).join('')}
                <th>الإجمالي</th>
            </tr></thead>
            <tbody>`;

    if (!rows.length) {
        html += `<tr><td colspan="${cols.length + 2}" style="padding:20px;color:#999">لا توجد أرصدة متأخرة</td></tr>`;
    } else {
        rows.forEach(r => {
            html += `<tr>
                <td style="text-align:right;font-weight:600">${r.name}</td>
                ${cols.map(c => `<td style="${r[c.k] > 0.005 ? `color:${c.c};font-weight:600` : 'color:#ccc'}">${r[c.k] > 0.005 ? fmt(r[c.k]) : '-'}</td>`).join('')}
                <td style="font-weight:800">${fmt(r.total)}</td>
            </tr>`;
        });
    }

    html += `</tbody>
            <tfoot><tr style="background:#f8f9fa;font-weight:800">
                <td style="text-align:right">الإجمالي</td>
                ${cols.map(c => `<td>${fmt(totals[c.k])}</td>`).join('')}
                <td>${fmt(totals.total)}</td>
            </tr></tfoot>
        </table>
    </div>`;

    pg.innerHTML = html;
};

window.ageExport = function () {
    const st = window._ageState;
    const isAR = st.type === 'ar';
    const rows = isAR
        ? ageBuckets(window.salesInvoices, 'customerId', window.customers)
        : ageBuckets(window.purchaseInvoices, 'vendorId', window.vendors);

    const data = rows.map(r => ({
        [isAR ? 'العميل' : 'المورد']: r.name,
        'لم يحن السداد': r.current,
        '1-30 يوم': r.b30,
        '31-60 يوم': r.b60,
        '61-90 يوم': r.b90,
        'أكثر من 90 يوم': r.b90p,
        'الإجمالي': r.total
    }));

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'أعمار الديون');
    XLSX.writeFile(wb, `aging_${isAR ? 'ar' : 'ap'}_${new Date().toISOString().slice(0, 10)}.xlsx`);
};

console.log('✅ Aging Report module [ACC-AGE] loaded');

// ============================================================
// [ACC-AUDIT] Audit Log (سجل التدقيق الشامل)
// ============================================================

// تسجيل عملية في سجل التدقيق — تُستخدم من أي مكان في النظام
window.logAudit = function (action, module, description, extra) {
    try {
        push(R.auditLog, {
            at: Date.now(),
            by: curU?.uid || '',
            byName: myP?.name || curU?.email || '',
            module,
            action,
            description,
            ...(extra || {})
        });
    } catch (e) { console.error('logAudit error', e); }
};

window._auditState = window._auditState || { from: '', to: '', module: '', user: '', q: '' };

window.audSetFilter = function (key, val) {
    window._auditState[key] = val;
    renderAuditLog();
};

window.renderAuditLog = function () {
    const pg = $('pg-auditlog');
    if (!pg) return;
    const st = window._auditState;
    const log = window.auditLog || {};

    let rows = Object.entries(log).map(([key, r]) => ({ key, ...r }));
    rows.sort((a, b) => (b.at || 0) - (a.at || 0));

    const modules = [...new Set(rows.map(r => r.module).filter(Boolean))].sort();
    const users = [...new Set(rows.map(r => r.byName).filter(Boolean))].sort();

    if (st.from) rows = rows.filter(r => r.at >= new Date(st.from).getTime());
    if (st.to) rows = rows.filter(r => r.at <= new Date(st.to).getTime() + 86400000 - 1);
    if (st.module) rows = rows.filter(r => r.module === st.module);
    if (st.user) rows = rows.filter(r => r.byName === st.user);
    if (st.q) {
        const q = st.q.toLowerCase();
        rows = rows.filter(r => (r.description || '').toLowerCase().includes(q) || (r.action || '').toLowerCase().includes(q));
    }

    const shown = rows.slice(0, 300);
    const canManage = (typeof can === 'function' ? can('manage_audit_log') : false) || window.myP?.role === 'admin';

    let html = `
    <div class="card" style="background:linear-gradient(135deg,#374151,#1f2937);color:#fff;padding:18px 22px;border-radius:12px;margin-bottom:14px">
        <h2 style="margin:0;display:flex;align-items:center;gap:8px">🕵️ سجل التدقيق الشامل</h2>
        <div style="opacity:.9;margin-top:4px;font-size:13px">سجل كامل بالعمليات الحساسة في النظام: من قام بها، متى، وتفاصيلها</div>
    </div>`;

    html += `<div class="card" style="padding:12px 16px;margin-bottom:14px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">
        <label>من: <input type="date" value="${st.from}" onchange="audSetFilter('from',this.value)" style="padding:6px;border-radius:6px;border:1px solid #ddd"></label>
        <label>إلى: <input type="date" value="${st.to}" onchange="audSetFilter('to',this.value)" style="padding:6px;border-radius:6px;border:1px solid #ddd"></label>
        <label>القسم: <select onchange="audSetFilter('module',this.value)" style="padding:6px;border-radius:6px;border:1px solid #ddd">
            <option value="">الكل</option>
            ${modules.map(m => `<option value="${m}" ${st.module === m ? 'selected' : ''}>${m}</option>`).join('')}
        </select></label>
        <label>المستخدم: <select onchange="audSetFilter('user',this.value)" style="padding:6px;border-radius:6px;border:1px solid #ddd">
            <option value="">الكل</option>
            ${users.map(u => `<option value="${u}" ${st.user === u ? 'selected' : ''}>${u}</option>`).join('')}
        </select></label>
        <input type="text" placeholder="🔍 بحث في الوصف/الإجراء..." value="${st.q}" oninput="audSetFilter('q',this.value)" style="padding:6px 10px;border-radius:6px;border:1px solid #ddd;flex:1;min-width:200px">
        <span style="color:#666;font-size:12px;margin-right:auto">عرض ${shown.length} من ${rows.length} سجل</span>
    </div>`;

    if (canManage && shown.length) {
        html += `<div class="card" style="padding:10px 16px;margin-bottom:14px;display:flex;gap:10px;align-items:center;flex-wrap:wrap">
            <label style="display:flex;align-items:center;gap:6px;font-size:12px;cursor:pointer"><input type="checkbox" id="aud-selectall" onchange="audToggleAll(this.checked)"> تحديد الكل</label>
            <button class="btn" id="aud-delsel" disabled style="padding:5px 12px;font-size:12px;background:#fdecea;color:#c0392b" onclick="audDeleteSelected()">🗑️ حذف المحدد (<span id="aud-selcount">0</span>)</button>
            <button class="btn" style="padding:5px 12px;font-size:12px;background:#fdecea;color:#c0392b" onclick="audDeleteFiltered()">🗑️ حذف كل السجلات المعروضة (${rows.length})</button>
        </div>`;
    }

    html += `<div class="card" style="padding:14px 16px;overflow:auto">
        <table class="tbl" style="width:100%;text-align:center">
            <thead><tr style="background:#f8f9fa">
                ${canManage ? '<th></th>' : ''}<th>التاريخ والوقت</th><th>المستخدم</th><th>القسم</th><th>الإجراء</th><th style="text-align:right">الوصف</th>${canManage ? '<th></th>' : ''}
            </tr></thead>
            <tbody>`;

    if (!shown.length) {
        html += `<tr><td colspan="${canManage ? 7 : 5}" style="padding:20px;color:#999">لا توجد سجلات مطابقة</td></tr>`;
    } else {
        shown.forEach(r => {
            html += `<tr>
                ${canManage ? `<td><input type="checkbox" class="aud-chk" data-key="${r.key}" onchange="audUpdateBulkBar()"></td>` : ''}
                <td style="white-space:nowrap;font-size:12px">${r.at ? new Date(r.at).toLocaleString('ar-SA') : ''}</td>
                <td>${r.byName || '-'}</td>
                <td>${r.module || '-'}</td>
                <td>${r.action || '-'}</td>
                <td style="text-align:right">${r.description || '-'}</td>
                ${canManage ? `<td><button onclick="audDeleteEntry('${r.key}')" style="border:none;background:none;cursor:pointer;font-size:13px" title="حذف">🗑️</button></td>` : ''}
            </tr>`;
        });
    }

    html += `</tbody></table>
    </div>`;

    pg.innerHTML = html;
};

window.audDeleteEntry = function (key) {
    cf2('هل تريد حذف هذا السجل من سجل التدقيق؟', async () => {
        try {
            await remove(ref(db, `ledger/auditLog/${key}`));
            toast('تم الحذف', 'ok');
            setTimeout(() => renderAuditLog(), 300);
        } catch (e) { toast('خطأ: ' + e.message, 'er'); }
    });
};

window.audToggleAll = function (checked) {
    document.querySelectorAll('.aud-chk').forEach(c => c.checked = checked);
    audUpdateBulkBar();
};

window.audUpdateBulkBar = function () {
    const checked = document.querySelectorAll('.aud-chk:checked');
    const btn = $('aud-delsel'), cnt = $('aud-selcount');
    if (cnt) cnt.textContent = checked.length;
    if (btn) btn.disabled = checked.length === 0;
};

window.audDeleteSelected = function () {
    const keys = [...document.querySelectorAll('.aud-chk:checked')].map(c => c.dataset.key);
    if (!keys.length) return;
    cf2(`هل تريد حذف ${keys.length} سجل محدد من سجل التدقيق؟`, async () => {
        try {
            await Promise.all(keys.map(k => remove(ref(db, `ledger/auditLog/${k}`))));
            toast('تم حذف السجلات المحددة', 'ok');
            setTimeout(() => renderAuditLog(), 300);
        } catch (e) { toast('خطأ: ' + e.message, 'er'); }
    });
};

// حذف كل السجلات المطابقة للفلاتر الحالية (وليس كل السجل بالضرورة)
window.audDeleteFiltered = function () {
    const st = window._auditState;
    let rows = Object.entries(window.auditLog || {}).map(([key, r]) => ({ key, ...r }));
    if (st.from) rows = rows.filter(r => r.at >= new Date(st.from).getTime());
    if (st.to) rows = rows.filter(r => r.at <= new Date(st.to).getTime() + 86400000 - 1);
    if (st.module) rows = rows.filter(r => r.module === st.module);
    if (st.user) rows = rows.filter(r => r.byName === st.user);
    if (st.q) {
        const q = st.q.toLowerCase();
        rows = rows.filter(r => (r.description || '').toLowerCase().includes(q) || (r.action || '').toLowerCase().includes(q));
    }
    if (!rows.length) return;
    cf2(`⚠️ هل تريد حذف ${rows.length} سجل (المطابقة للفلاتر الحالية) من سجل التدقيق؟ لا يمكن التراجع عن هذا الإجراء.`, async () => {
        try {
            await Promise.all(rows.map(r => remove(ref(db, `ledger/auditLog/${r.key}`))));
            toast('تم الحذف', 'ok');
            setTimeout(() => renderAuditLog(), 300);
        } catch (e) { toast('خطأ: ' + e.message, 'er'); }
    });
};

