// 🧮 تقرير: الجرد الدوري (Physical Stock Count)
// ═══════════════════════════════════════════════════════════════════
let stockCountState = { warehouseId: '', counts: {} };

function renderStockCountReport(container) {
    const items = window.inventoryItems || {};
    const whId = stockCountState.warehouseId || mainWarehouseId();
    stockCountState.warehouseId = whId;

    const rows = Object.entries(items)
        .filter(([, it]) => it.active !== false && it.type !== 'service')
        .sort((a, b) => (a[1].code || '').localeCompare(b[1].code || ''))
        .map(([key, it]) => ({ key, it, bal: calcInvItemBalance(key, whId) }));

    container.innerHTML = `
        <div class="card" style="margin-bottom:14px;padding:14px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px">
            <div style="font-size:13px;color:#666">🧮 <strong>الجرد الدوري</strong> — أدخل الكمية الفعلية المعدودة، وسيُولّد النظام حركات تسوية للفروقات</div>
            <div style="display:flex;gap:6px;align-items:center">
                <select id="stockCountWarehouse" onchange="stockCountState.warehouseId=this.value;stockCountState.counts={};renderActiveInvReport()" style="padding:8px;border:1.5px solid #d0d7e0;border-radius:6px;font-size:11px"></select>
                <button class="btn b-g" onclick="applyStockCountAdjustments()" style="padding:8px 14px;font-size:11px">✅ ترحيل الفروقات</button>
            </div>
        </div>
        <div class="card">
            <div style="overflow-x:auto">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:800px">
                    <thead style="background:#16a085;color:white">
                        <tr>
                            <th style="padding:10px;text-align:right">الرمز</th>
                            <th style="padding:10px;text-align:right">الصنف</th>
                            <th style="padding:10px;text-align:center">الوحدة</th>
                            <th style="padding:10px;text-align:center">الرصيد بالنظام</th>
                            <th style="padding:10px;text-align:center;background:#0e6655">الكمية الفعلية (الجرد)</th>
                            <th style="padding:10px;text-align:center">الفرق</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${rows.map((r, i) => {
                            const counted = stockCountState.counts[r.key];
                            const diff = counted === undefined || counted === '' ? null : (parseFloat(counted) - r.bal.balance);
                            return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                                <td style="padding:8px;font-family:monospace;font-weight:800;color:#1a3a5c">${r.it.code || '—'}</td>
                                <td style="padding:8px;font-weight:600">${r.it.nameAr || '—'}</td>
                                <td style="padding:8px;text-align:center;font-size:11px">${INV_UNITS[r.it.unit] || r.it.unit || ''}</td>
                                <td style="padding:8px;text-align:center;font-weight:700">${fmt(r.bal.balance)}</td>
                                <td style="padding:8px;text-align:center">
                                    <input type="number" step="0.001" value="${counted ?? ''}" placeholder="${fmt(r.bal.balance)}"
                                        oninput="stockCountState.counts['${r.key}']=this.value;updateStockCountDiffRow('${r.key}')"
                                        style="width:100px;padding:6px;border:1.5px solid #d0d7e0;border-radius:6px;text-align:center;direction:ltr">
                                </td>
                                <td id="scDiff_${r.key}" style="padding:8px;text-align:center;font-weight:800;color:${diff > 0 ? '#27ae60' : diff < 0 ? '#c0392b' : '#888'}">${diff === null ? '—' : fmt(diff)}</td>
                            </tr>`;
                        }).join('')}
                    </tbody>
                </table>
            </div>
        </div>
    `;
    if ($('stockCountWarehouse')) {
        fillWarehouseSelect($('stockCountWarehouse'));
        $('stockCountWarehouse').value = whId;
    }
}

window.updateStockCountDiffRow = function (key) {
    const items = window.inventoryItems || {};
    const it = items[key]; if (!it) return;
    const bal = calcInvItemBalance(key, stockCountState.warehouseId);
    const counted = stockCountState.counts[key];
    const diff = counted === undefined || counted === '' ? null : (parseFloat(counted) - bal.balance);
    const cell = $('scDiff_' + key);
    if (cell) {
        cell.textContent = diff === null ? '—' : fmt(diff);
        cell.style.color = diff > 0 ? '#27ae60' : diff < 0 ? '#c0392b' : '#888';
    }
};

window.applyStockCountAdjustments = async function () {
    const items = window.inventoryItems || {};
    const whId = stockCountState.warehouseId;
    const diffs = Object.entries(stockCountState.counts)
        .map(([key, counted]) => {
            if (counted === undefined || counted === '') return null;
            const bal = calcInvItemBalance(key, whId);
            const diff = parseFloat(counted) - bal.balance;
            return Math.abs(diff) > 0.0001 ? { key, diff } : null;
        })
        .filter(Boolean);

    if (diffs.length === 0) { toast('⚠️ لا توجد فروقات لترحيلها', 'er'); return; }
    if (!await cf2(`سيتم إنشاء ${diffs.length} حركة تسوية بناءً على الجرد. هل تريد المتابعة؟`)) return;

    const userId = (typeof curU !== 'undefined' && curU?.uid) || 'system';
    const now = new Date().toISOString();
    const dateStr = now.slice(0, 10);

    try {
        for (const { key, diff } of diffs) {
            const it = items[key];
            await push(R.invmov, {
                number: 'JRD-' + Date.now() + '-' + key.slice(0, 4),
                date: dateStr,
                type: diff > 0 ? 'in' : 'out',
                itemId: key,
                warehouseId: whId,
                qty: Math.abs(diff),
                unitPrice: parseFloat(it?.costPrice) || 0,
                projectId: '',
                reason: diff > 0 ? 'adjustment_in' : 'adjustment_out',
                description: '🧮 تسوية جرد دوري',
                notes: '',
                createdAt: now,
                createdBy: userId
            });
        }
        toast(`✅ تم ترحيل ${diffs.length} حركة تسوية`, 'ok');
        stockCountState.counts = {};
        renderActiveInvReport();
    } catch (e) {
        console.error('Stock count adjustment error:', e);
        toast('❌ حدث خطأ أثناء ترحيل الفروقات', 'er');
    }
};


// ═══════════════════════════════════════════════════════════════════
// 🕒 تقرير: الأصناف الراكدة (Inventory Aging)
// ═══════════════════════════════════════════════════════════════════
function renderInvAgingReport(container) {
    const items = window.inventoryItems || {};
    const movs = window.inventoryMovements || {};
    const today = new Date();

    const lastMoveByItem = {};
    Object.values(movs).forEach(m => {
        if (!m.itemId || !m.date) return;
        const d = new Date(m.date);
        if (!lastMoveByItem[m.itemId] || d > lastMoveByItem[m.itemId]) lastMoveByItem[m.itemId] = d;
    });

    const rows = Object.entries(items)
        .filter(([, it]) => it.active !== false && it.type !== 'service')
        .map(([key, it]) => {
            const bal = calcInvItemBalance(key);
            const lastMove = lastMoveByItem[key];
            const days = lastMove ? Math.floor((today - lastMove) / (1000 * 60 * 60 * 24)) : null;
            return { key, it, bal, lastMove, days };
        })
        .filter(r => r.bal.balance > 0.0001)
        .sort((a, b) => (b.days ?? Infinity) - (a.days ?? Infinity));

    const bucket = (days) => {
        if (days === null) return { label: 'لا توجد حركة', color: '#7f8c8d' };
        if (days > 180) return { label: '🔴 أكثر من 180 يوم', color: '#c0392b' };
        if (days > 90) return { label: '🟠 90-180 يوم', color: '#e67e22' };
        if (days > 30) return { label: '🟡 30-90 يوم', color: '#f39c12' };
        return { label: '🟢 أقل من 30 يوم', color: '#27ae60' };
    };

    const totals = {
        over180: rows.filter(r => r.days !== null && r.days > 180).length,
        over90: rows.filter(r => r.days !== null && r.days > 90 && r.days <= 180).length,
        noMove: rows.filter(r => r.days === null).length,
        stuckValue: rows.filter(r => r.days === null || r.days > 90).reduce((s, r) => s + r.bal.balance * (parseFloat(r.it.costPrice) || 0), 0)
    };

    container.innerHTML = `
        <div class="card" style="margin-bottom:14px;padding:14px">
            <div style="font-size:13px;color:#666">🕒 <strong>تقرير الأصناف الراكدة</strong> — الأصناف التي لم تتحرك منذ فترة طويلة</div>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:#fadbd8;border-radius:12px;padding:12px;border-right:4px solid #c0392b">
                <div style="font-size:11px;color:#641e16">🔴 راكدة أكثر من 180 يوم</div>
                <div style="font-size:24px;font-weight:900;color:#c0392b">${totals.over180}</div>
            </div>
            <div style="background:#fef5e7;border-radius:12px;padding:12px;border-right:4px solid #e67e22">
                <div style="font-size:11px;color:#7d4e00">🟠 راكدة 90-180 يوم</div>
                <div style="font-size:24px;font-weight:900;color:#e67e22">${totals.over90}</div>
            </div>
            <div style="background:#eaecee;border-radius:12px;padding:12px;border-right:4px solid #7f8c8d">
                <div style="font-size:11px;color:#444">⚪ بدون حركة على الإطلاق</div>
                <div style="font-size:24px;font-weight:900;color:#7f8c8d">${totals.noMove}</div>
            </div>
            <div style="background:#e8f4fd;border-radius:12px;padding:12px;border-right:4px solid #2d6a9f">
                <div style="font-size:11px;color:#0d4f7c">💰 قيمة المخزون الراكد</div>
                <div style="font-size:18px;font-weight:900;color:#2d6a9f">${fmt(totals.stuckValue)}</div>
            </div>
        </div>
        <div class="card">
            <div style="overflow-x:auto">
                <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:900px">
                    <thead style="background:#7f8c8d;color:white">
                        <tr>
                            <th style="padding:10px;text-align:right">الرمز</th>
                            <th style="padding:10px;text-align:right">الصنف</th>
                            <th style="padding:10px;text-align:center">الرصيد</th>
                            <th style="padding:10px;text-align:center">قيمة الرصيد</th>
                            <th style="padding:10px;text-align:center">آخر حركة</th>
                            <th style="padding:10px;text-align:center">عدد الأيام</th>
                            <th style="padding:10px;text-align:center">الحالة</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${rows.map((r, i) => {
                            const b = bucket(r.days);
                            const val = r.bal.balance * (parseFloat(r.it.costPrice) || 0);
                            return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                                <td style="padding:8px;font-family:monospace;font-weight:800;color:#1a3a5c">${r.it.code || '—'}</td>
                                <td style="padding:8px;font-weight:600">${r.it.nameAr || '—'}</td>
                                <td style="padding:8px;text-align:center;font-weight:700">${fmt(r.bal.balance)}</td>
                                <td style="padding:8px;text-align:center;color:#e67e22;font-weight:700">${fmt(val)}</td>
                                <td style="padding:8px;text-align:center;font-size:11px">${r.lastMove ? r.lastMove.toISOString().slice(0, 10) : '—'}</td>
                                <td style="padding:8px;text-align:center;font-weight:800">${r.days ?? '—'}</td>
                                <td style="padding:8px;text-align:center"><span style="background:${b.color};color:white;padding:3px 8px;border-radius:4px;font-size:10px;font-weight:700">${b.label}</span></td>
                            </tr>`;
                        }).join('')}
                    </tbody>
                </table>
            </div>
        </div>
    `;
}


// ═══════════════════════════════════════════════════════════════════
// 🖨️ طباعة سند حركة مخزون (تحويل/إخراج/إدخال) كـ PDF
// ═══════════════════════════════════════════════════════════════════
window.printInvMovementVoucher = function (key) {
    const movs = window.inventoryMovements || {};
    const m = movs[key]; if (!m) { toast('⚠️ الحركة غير موجودة', 'er'); return; }
    const item = window.inventoryItems?.[m.itemId] || {};
    const reasons = { ...INV_MOV_REASONS_IN, ...INV_MOV_REASONS_OUT };
    const reasonLabel = reasons[m.reason] || m.reason || '—';
    const isIn = m.type === 'in';
    const whId = whIdOfMovement(m);
    const wh = window.warehouses?.[whId];
    const whLabel = wh ? wh.name : '—';

    let title = isIn ? '📥 سند إدخال مخزني' : '📤 سند إخراج مخزني';
    let otherWhRow = '';
    if (m.transferGroupId) {
        title = '🔁 سند تحويل مخزني';
        const pair = Object.values(movs).find(x => x.transferGroupId === m.transferGroupId && x.itemId === m.itemId && x.type !== m.type);
        const otherWhId = pair ? whIdOfMovement(pair) : '';
        const otherWh = window.warehouses?.[otherWhId];
        if (m.type === 'out') {
            otherWhRow = `<tr><td>من مخزن</td><td>${whLabel}</td></tr><tr><td>إلى مخزن</td><td>${otherWh?.name || '—'}</td></tr>`;
        } else {
            otherWhRow = `<tr><td>من مخزن</td><td>${otherWh?.name || '—'}</td></tr><tr><td>إلى مخزن</td><td>${whLabel}</td></tr>`;
        }
    }

    const projName = m.projectId && window.projects?.[m.projectId] ? window.projects[m.projectId].name : '—';

    const html = `<!DOCTYPE html><html dir="rtl"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>سند حركة مخزون</title>
    <style>* { -webkit-print-color-adjust: exact !important; } body { font-family: 'Tajawal', Tahoma; padding: 30px; color: #1a3a5c; direction: rtl; }
    h1 { text-align: center; border-bottom: 3px solid #1a5276; padding-bottom: 10px; }
    table { width: 100%; border-collapse: collapse; font-size: 13px; margin-top: 20px; }
    td, th { padding: 10px; border: 1px solid #ddd; }
    td:first-child { background: #f4f6f7; font-weight: 700; width: 200px; }
    .sign { margin-top: 60px; display: flex; justify-content: space-between; font-size: 13px; }
    .sign div { border-top: 1px solid #888; padding-top: 6px; width: 200px; text-align: center; }
    @page { size: A4; margin: 2cm; }</style></head><body>
    <h1>${title}</h1>
    <div style="text-align:center;font-size:12px;margin:10px 0">📅 ${new Date().toLocaleDateString('ar-SA')}</div>
    <table>
        <tr><td>رقم السند</td><td>${m.number || '—'}</td></tr>
        <tr><td>التاريخ</td><td>${m.date || '—'}</td></tr>
        <tr><td>الصنف</td><td>${item.nameAr || '—'} (${item.code || ''})</td></tr>
        <tr><td>الكمية</td><td>${fmt(m.qty || 0)} ${INV_UNITS[item.unit] || ''}</td></tr>
        ${otherWhRow || `<tr><td>المخزن</td><td>${whLabel}</td></tr>`}
        <tr><td>السبب</td><td>${reasonLabel}</td></tr>
        <tr><td>المشروع</td><td>${projName}</td></tr>
        <tr><td>البيان</td><td>${m.description || '—'}</td></tr>
        ${m.batchNo ? `<tr><td>رقم التشغيلة</td><td>${m.batchNo}</td></tr>` : ''}
        ${m.expiryDate ? `<tr><td>تاريخ الانتهاء</td><td>${m.expiryDate}</td></tr>` : ''}
        ${m.notes ? `<tr><td>ملاحظات</td><td>${m.notes}</td></tr>` : ''}
    </table>
    <div class="sign">
        <div>المستلم</div>
        <div>المُسلِّم</div>
        <div>أمين المخزن</div>
    </div>
    </body></html>`;
    const w = window.open('', '_blank'); w.document.write(html); w.document.close();
    setTimeout(() => { try { w.print(); } catch (e) { } }, 500);
};


// ═══════════════════════════════════════════════════════════════════
// 📟 تقرير: لوحة تحكم المخزون (Dashboard)
// ═══════════════════════════════════════════════════════════════════
function renderInvDashboardReport(container) {
    const items = window.inventoryItems || {};
    const movs = Object.values(window.inventoryMovements || {});
    const warehouses = window.warehouses || {};

    const materialItems = Object.entries(items).filter(([, it]) => it.active !== false && it.type !== 'service');

    // قيمة المخزون لكل مخزن
    const whStats = Object.entries(warehouses).filter(([, w]) => w.active !== false).map(([whKey, w]) => {
        let value = 0, count = 0;
        materialItems.forEach(([key, it]) => {
            const bal = calcInvItemBalance(key, whKey).balance;
            if (bal > 0.0001) { value += bal * (parseFloat(it.costPrice) || 0); count++; }
        });
        return { whKey, name: w.name, type: w.type, value, count };
    }).sort((a, b) => b.value - a.value);

    // إجمالي القيمة والأصناف
    const totalValue = materialItems.reduce((s, [key, it]) => s + calcInvItemBalance(key).balance * (parseFloat(it.costPrice) || 0), 0);

    // الأصناف الأكثر استهلاكاً (خروج) آخر 90 يوم
    const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 90);
    const consumption = {};
    movs.forEach(m => {
        if (m.type !== 'out' || !m.date || !m.itemId) return;
        if (new Date(m.date) < cutoff) return;
        consumption[m.itemId] = (consumption[m.itemId] || 0) + (parseFloat(m.qty) || 0);
    });
    const topConsumed = Object.entries(consumption)
        .map(([key, qty]) => ({ key, it: items[key], qty }))
        .filter(r => r.it)
        .sort((a, b) => b.qty - a.qty)
        .slice(0, 8);

    // تنبيهات الحد الأدنى
    const lowStockCount = materialItems.filter(([key, it]) => (parseFloat(it.minQty) || 0) > 0 && calcInvItemBalance(key).balance < (parseFloat(it.minQty) || 0)).length;

    // تنبيهات انتهاء الصلاحية (خلال 30 يوم أو منتهية)
    const soon = new Date(); soon.setDate(soon.getDate() + 30);
    const expiryAlerts = movs.filter(m => m.expiryDate && new Date(m.expiryDate) <= soon)
        .map(m => ({ m, it: items[m.itemId] }))
        .filter(r => r.it)
        .sort((a, b) => new Date(a.m.expiryDate) - new Date(b.m.expiryDate));

    container.innerHTML = `
        <div style="background:linear-gradient(135deg,#2c3e50 0%,#34495e 100%);border-radius:16px;padding:20px;margin-bottom:18px;color:white;box-shadow:0 6px 20px rgba(44,62,80,.25)">
            <div style="font-size:11px;opacity:.85;letter-spacing:1px">INVENTORY DASHBOARD</div>
            <h1 style="margin:4px 0 0;font-size:24px;font-weight:900">📟 لوحة تحكم المخزون</h1>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(170px,1fr));gap:10px;margin-bottom:18px">
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #2d6a9f">
                <div style="font-size:11px;color:#666">💰 القيمة الإجمالية</div>
                <div style="font-size:20px;font-weight:900;color:#2d6a9f">${fmt(totalValue)}</div>
            </div>
            <div style="background:white;border-radius:12px;padding:12px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid #27ae60">
                <div style="font-size:11px;color:#666">📦 عدد الأصناف</div>
                <div style="font-size:24px;font-weight:900;color:#27ae60">${materialItems.length}</div>
            </div>
            <div style="background:#fadbd8;border-radius:12px;padding:12px;border-right:4px solid #c0392b">
                <div style="font-size:11px;color:#641e16">⚠️ تحت الحد الأدنى</div>
                <div style="font-size:24px;font-weight:900;color:#c0392b">${lowStockCount}</div>
            </div>
            <div style="background:#fef5e7;border-radius:12px;padding:12px;border-right:4px solid #e67e22">
                <div style="font-size:11px;color:#7d4e00">⏳ تنبيهات انتهاء صلاحية</div>
                <div style="font-size:24px;font-weight:900;color:#e67e22">${expiryAlerts.length}</div>
            </div>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:18px">
            <div class="card">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">🏬 قيمة المخزون لكل مخزن</div>
                ${whStats.length === 0 ? '<div style="text-align:center;padding:20px;color:#888">لا توجد مخازن</div>' : `
                <table style="width:100%;border-collapse:collapse;font-size:12px">
                    <thead style="background:#34495e;color:white"><tr><th style="padding:8px;text-align:right">المخزن</th><th style="padding:8px;text-align:center">عدد الأصناف</th><th style="padding:8px;text-align:center">القيمة</th></tr></thead>
                    <tbody>${whStats.map((w, i) => `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                        <td style="padding:8px">${w.type === 'main' ? '🏢' : '📦'} ${w.name}</td>
                        <td style="padding:8px;text-align:center">${w.count}</td>
                        <td style="padding:8px;text-align:center;font-weight:700;color:#2d6a9f">${fmt(w.value)}</td>
                    </tr>`).join('')}</tbody>
                </table>`}
            </div>
            <div class="card">
                <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">🔥 الأكثر استهلاكاً (آخر 90 يوم)</div>
                ${topConsumed.length === 0 ? '<div style="text-align:center;padding:20px;color:#888">لا توجد بيانات</div>' : `
                <table style="width:100%;border-collapse:collapse;font-size:12px">
                    <thead style="background:#34495e;color:white"><tr><th style="padding:8px;text-align:right">الصنف</th><th style="padding:8px;text-align:center">الكمية المستهلكة</th></tr></thead>
                    <tbody>${topConsumed.map((r, i) => `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                        <td style="padding:8px">${r.it.nameAr || '—'}</td>
                        <td style="padding:8px;text-align:center;font-weight:700;color:#c0392b">${fmt(r.qty)} ${INV_UNITS[r.it.unit] || ''}</td>
                    </tr>`).join('')}</tbody>
                </table>`}
            </div>
        </div>
        <div class="card">
            <div style="font-size:14px;font-weight:800;color:#1a3a5c;margin-bottom:12px">⏳ تنبيهات انتهاء الصلاحية (30 يوم القادمة أو منتهية)</div>
            ${expiryAlerts.length === 0 ? `<div style="text-align:center;padding:20px;color:#27ae60">✅ لا توجد تنبيهات</div>` : `
            <table style="width:100%;border-collapse:collapse;font-size:12px">
                <thead style="background:#e67e22;color:white"><tr><th style="padding:8px;text-align:right">الصنف</th><th style="padding:8px;text-align:center">رقم التشغيلة</th><th style="padding:8px;text-align:center">تاريخ الانتهاء</th></tr></thead>
                <tbody>${expiryAlerts.map((r, i) => {
                    const expired = new Date(r.m.expiryDate) < new Date();
                    return `<tr style="${i % 2 ? 'background:#fafbfc' : ''}">
                        <td style="padding:8px">${r.it.nameAr || '—'}</td>
                        <td style="padding:8px;text-align:center;font-family:monospace">${r.m.batchNo || '—'}</td>
                        <td style="padding:8px;text-align:center;font-weight:700;color:${expired ? '#c0392b' : '#e67e22'}">${expired ? '🔴' : '🟠'} ${r.m.expiryDate}</td>
                    </tr>`;
                }).join('')}</tbody>
            </table>`}
        </div>
    `;
}


// ═══════════════════════════════════════════════════════════════════
// ⚡ ربط طلبات المواد المعتمدة بحركات المخزون (إنشاء سريع)
// ═══════════════════════════════════════════════════════════════════
window.quickCreateInvMovementFromMatRequest = function (rk) {
    const r = window.matRequests?.[rk]; if (!r) return;
    const reqItems = r.items ? Object.entries(r.items) : [];
    const first = reqItems[0]?.[1] || (r.materialName ? { matName: r.materialName, qty: r.qty, unit: r.unit, estPrice: r.estPrice } : null);
    if (!first) { toast('⚠️ لا توجد مواد في هذا الطلب', 'er'); return; }

    openInvMovementEditor();
    setTimeout(() => {
        $('mInvMovTypeIn').checked = true;
        onInvMovTypeChange();
        $('mInvMovQty').value = first.qty || '';
        $('mInvMovUnitPrice').value = first.estPrice || 0;
        if (r.projectId) $('mInvMovProject').value = r.projectId;
        $('mInvMovDescription').value = `استلام من طلب مواد ${r.reqNumber || ''} — ${first.matName || ''}`;
        $('mInvMovReason').value = 'purchase';
        toast(`⚡ تم تعبئة الحركة بمادة "${first.matName}" — يرجى اختيار الصنف المطابق من قائمة الأصناف${reqItems.length > 1 ? ` (الطلب يحتوي ${reqItems.length} مواد، كرر العملية لكل مادة)` : ''}`, 'ok', 6000);
    }, 150);
};


// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   📂  [ACC-FS-EXT]   ━━━━   EXTERNAL FILE ANALYSIS   ━━━━                   ║
// ║   رفع قوائم مالية خارجية (Excel/CSV) + نموذج للتحميل والتعبئة                  ║
// ║   ثم تحليل مالي شامل (نفس محرّك النسب والتنبيهات) + رسوم + توجيهات إدارية      ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// ── مخطط حقول النموذج (مصدر واحد لتوليد النموذج وقراءته) ─────────────────
const FS_EXT_FIELDS = [
    { key: 'entityName', label: 'اسم المنشأة', section: 'meta', type: 'text', hint: 'اختياري — يظهر في رأس التقرير', kw: ['اسم المنشأة', 'الشركة', 'company', 'entity'] },
    { key: 'period', label: 'الفترة المالية', section: 'meta', type: 'text', hint: 'اختياري — مثال: 2025 أو 01/2025–12/2025', kw: ['الفترة', 'period', 'year', 'السنة'] },
    { key: 'taxRate', label: 'نسبة ضريبة الدخل التقديرية %', section: 'meta', type: 'num', def: 20, hint: 'الافتراضي 20% على صافي الربح', kw: ['ضريبة', 'tax'] },

    { key: 'revenue', label: 'الإيرادات / المبيعات', section: 'income', type: 'num', hint: 'إجمالي إيرادات الفترة', kw: ['إيراد', 'مبيعات', 'revenue', 'sales'] },
    { key: 'directCost', label: 'تكلفة الإيرادات المباشرة', section: 'income', type: 'num', hint: 'تكلفة المبيعات / تكاليف المشاريع المباشرة', kw: ['تكلفة المبيعات', 'تكلفة الإيراد', 'تكاليف مباشرة', 'cogs', 'cost of'] },
    { key: 'opex', label: 'المصروفات التشغيلية والإدارية', section: 'income', type: 'num', hint: 'رواتب إدارية، إيجارات، مصاريف عمومية', kw: ['تشغيلية', 'إدارية', 'عمومية', 'operating', 'admin', 'g&a', 'sg&a'] },
    { key: 'otherExp', label: 'مصروفات أخرى وفوائد التمويل', section: 'income', type: 'num', hint: 'فوائد القروض ومصروفات أخرى غير تشغيلية', kw: ['فوائد', 'تمويل', 'مصروفات أخرى', 'interest', 'finance cost', 'other exp'] },

    { key: 'cash', label: 'النقدية وما يعادلها', section: 'assets', type: 'num', hint: 'الصندوق + البنوك', kw: ['نقد', 'صندوق', 'بنك', 'cash', 'bank'] },
    { key: 'receivables', label: 'الذمم المدينة (العملاء)', section: 'assets', type: 'num', hint: 'أرصدة العملاء المدينة', kw: ['مدين', 'عملاء', 'receivable', 'debtor'] },
    { key: 'inventory', label: 'المخزون', section: 'assets', type: 'num', hint: 'بضاعة / مواد بالمخازن', kw: ['مخزون', 'بضاعة', 'inventory', 'stock'] },
    { key: 'otherCA', label: 'أصول متداولة أخرى', section: 'assets', type: 'num', hint: 'مصروفات مدفوعة مقدماً، إيرادات مستحقة...', kw: ['أصول متداولة أخرى', 'other current asset'] },
    { key: 'nonCA', label: 'الأصول غير المتداولة (الثابتة)', section: 'assets', type: 'num', hint: 'الأصول الثابتة بالصافي + استثمارات طويلة الأجل', kw: ['غير المتداول', 'ثابت', 'non-current asset', 'fixed asset'] },

    { key: 'payables', label: 'الذمم الدائنة (الموردون)', section: 'liab', type: 'num', hint: 'أرصدة الموردين الدائنة', kw: ['دائن', 'موردون', 'موردين', 'payable', 'creditor'] },
    { key: 'otherCL', label: 'خصوم متداولة أخرى', section: 'liab', type: 'num', hint: 'مصروفات مستحقة، ضرائب مستحقة، جزء متداول من القروض...', kw: ['خصوم متداولة أخرى', 'مستحقات', 'other current liab', 'accrued'] },
    { key: 'nonCL', label: 'الخصوم غير المتداولة (طويلة الأجل)', section: 'liab', type: 'num', hint: 'القروض طويلة الأجل، مكافأة نهاية الخدمة', kw: ['غير المتداولة', 'طويلة الأجل', 'non-current liab', 'long term', 'long-term'] },
    { key: 'equity', label: 'حقوق الملكية', section: 'liab', type: 'num', hint: 'رأس المال + الاحتياطيات + الأرباح المحتجزة (صافي)', kw: ['حقوق الملكية', 'حقوق المساهمين', 'equity', 'رأس المال'] },

    { key: 'interest', label: 'منها: فوائد التمويل (لتحليل التغطية)', section: 'extra', type: 'num', hint: 'مبلغ الفوائد ضمن المصروفات — يُستخدم لنسبة تغطية الفوائد فقط (لا يُضاف للمصروفات)', kw: ['فوائد', 'interest', 'finance cost'] },
    { key: 'depreciation', label: 'منها: الإهلاك والاستهلاك', section: 'extra', type: 'num', hint: 'مبلغ الإهلاك ضمن المصروفات — يُستخدم لاحتساب EBITDA فقط', kw: ['إهلاك', 'استهلاك', 'depreciation', 'amortization'] },
    { key: 'ocf', label: 'التدفق النقدي التشغيلي (إن توفّر)', section: 'extra', type: 'num', hint: 'صافي النقد من الأنشطة التشغيلية — لنسبة تغطية الالتزامات نقداً', kw: ['تدفق نقدي تشغيلي', 'operating cash', 'ocf'] }
];

const FS_EXT_SECTIONS = {
    meta: '⚙️ بيانات عامة وإعدادات',
    income: '📈 قائمة الدخل (Income Statement)',
    assets: '🏦 المركز المالي — الأصول (Assets)',
    liab: '⚖️ المركز المالي — الخصوم وحقوق الملكية (Liabilities & Equity)',
    extra: '🛡️ بيانات تحليلية إضافية (اختياري — لنسب التغطية)'
};

// state: آخر مجموعة بيانات تم رفعها وتحليلها + ملف المقارنة الاختياري
window._fsExt = window._fsExt || { loaded: false, vals: null, income: null, balance: null, analysis: null, alerts: null, report: null, fileName: '' };
window._fsExtCompare = window._fsExtCompare || null;

// ── أداة: تحويل أي قيمة خلية إلى رقم ─────────────────
function fsExtNum(v) {
    if (typeof v === 'number') return isFinite(v) ? v : 0;
    if (v === null || v === undefined || v === '') return 0;
    const n = parseFloat(String(v).replace(/[٬,،\s]/g, '').replace(/[^\d.\-]/g, ''));
    return isNaN(n) ? 0 : n;
}
function fsExtNorm(s) { return String(s == null ? '' : s).replace(/\s+/g, ' ').trim(); }

// ── 1) تنزيل النموذج (Excel أو CSV) ─────────────────
window.downloadFSExtTemplate = function (type) {
    const aoa = [
        ['نموذج التحليل المالي — بنيان للمقاولات', '', ''],
        ['تعليمات: املأ عمود "القيمة" بالأرقام فقط (بدون فواصل أو رموز عملة)، ثم احفظ الملف وارفعه في التبويب. لا تُعدّل عمود "البند".', '', ''],
        ['البند', 'القيمة', 'ملاحظات / تعليمات']
    ];
    let lastSection = null;
    FS_EXT_FIELDS.forEach(f => {
        if (f.section !== lastSection) {
            aoa.push([FS_EXT_SECTIONS[f.section], '', '']);
            lastSection = f.section;
        }
        aoa.push([f.label, (f.def !== undefined ? f.def : ''), f.hint || '']);
    });
    aoa.push(['', '', '']);
    aoa.push(['💡 المعادلات المحسوبة تلقائياً: مجمل الربح = الإيرادات − التكلفة المباشرة | صافي الربح = الإيرادات − (التكلفة + التشغيلية + الأخرى)', '', '']);
    aoa.push(['💡 للتأكد من توازن المركز المالي: إجمالي الأصول يجب أن يساوي (إجمالي الخصوم + حقوق الملكية)', '', '']);

    if (type === 'csv') {
        const csv = '﻿' + aoa.map(r => r.map(c => {
            const s = String(c == null ? '' : c);
            return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
        }).join(',')).join('\r\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'نموذج_التحليل_المالي.csv';
        a.click();
        setTimeout(() => URL.revokeObjectURL(a.href), 1000);
        toast('✅ تم تنزيل نموذج CSV — افتحه، املأ القيم، ثم ارفعه', 'ok', 5000);
        return;
    }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة — جرّب تنزيل CSV', 'er'); return; }
    const ws = XLSX.utils.aoa_to_sheet(aoa);
    ws['!cols'] = [{ wch: 42 }, { wch: 16 }, { wch: 55 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'النموذج');
    XLSX.writeFile(wb, 'نموذج_التحليل_المالي.xlsx');
    toast('✅ تم تنزيل نموذج Excel — افتحه، املأ عمود "القيمة"، ثم ارفعه', 'ok', 5000);
};

// ── 2) معالجة الملف المرفوع ─────────────────
window.handleFSExtUpload = function (input, target) {
    target = target || 'primary';
    const file = input.files && input.files[0];
    if (!file) return;
    if (target === 'compare' && !(window._fsExt && window._fsExt.loaded)) { toast('⚠️ ارفع الملف الأساسي أولاً قبل ملف المقارنة', 'er'); input.value = ''; return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة قراءة الملفات غير محمّلة', 'er'); return; }
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const wb = XLSX.read(e.target.result, { type: 'array' });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false });

            // خريطة: نص البند (عمود 0) → قيمة (عمود 1)
            const labelToVal = {};
            const usedRows = new Set();
            rows.forEach((r, i) => {
                const lbl = fsExtNorm(r[0]);
                if (lbl) labelToVal[lbl] = { v: r[1], i };
            });

            const vals = {};
            // أ) مطابقة مباشرة بالاسم (مسار النموذج)
            FS_EXT_FIELDS.forEach(f => {
                const m = labelToVal[fsExtNorm(f.label)];
                if (m) { vals[f.key] = f.type === 'num' ? fsExtNum(m.v) : fsExtNorm(m.v); usedRows.add(m.i); }
            });
            // ب) مطابقة احتياطية بالكلمات المفتاحية للملفات الخارجية غير المطابقة للنموذج
            FS_EXT_FIELDS.forEach(f => {
                if (vals[f.key] !== undefined && vals[f.key] !== '' && vals[f.key] !== 0) return;
                if (!f.kw) return;
                for (const [lbl, m] of Object.entries(labelToVal)) {
                    if (usedRows.has(m.i)) continue;
                    const low = lbl.toLowerCase();
                    if (f.kw.some(k => low.includes(k.toLowerCase()))) {
                        const num = fsExtNum(m.v);
                        if (f.type === 'num' && num === 0) continue; // تجنّب التقاط صفوف فارغة
                        vals[f.key] = f.type === 'num' ? num : fsExtNorm(m.v);
                        usedRows.add(m.i);
                        break;
                    }
                }
            });

            const hasData = ['revenue', 'cash', 'receivables', 'inventory', 'nonCA', 'payables', 'equity']
                .some(k => fsExtNum(vals[k]) !== 0);
            if (!hasData) {
                toast('⚠️ لم يتم العثور على أرقام صالحة في الملف — تأكد من استخدام النموذج وتعبئة عمود "القيمة"', 'er', 8000);
                input.value = '';
                return;
            }

            fsExtAnalyze(vals, file.name, target);
            toast(target === 'compare' ? '✅ تم تحميل ملف المقارنة' : '✅ تم تحليل الملف بنجاح', 'ok', 4000);
        } catch (err) {
            toast('❌ تعذّر قراءة الملف: ' + (err.message || err), 'er', 8000);
        }
        input.value = '';
    };
    reader.onerror = () => { toast('❌ خطأ في قراءة الملف', 'er'); input.value = ''; };
    reader.readAsArrayBuffer(file);
};

// ── 3) بناء كائنات القوائم + تشغيل محرّك التحليل والتنبيهات ─────────────────
function fsExtAnalyze(vals, fileName, target) {
    const v = k => fsExtNum(vals[k]);
    const taxRate = (vals.taxRate !== undefined && vals.taxRate !== '') ? fsExtNum(vals.taxRate) : 20;

    const revenue = v('revenue');
    const directCost = v('directCost');
    const opex = v('opex');
    const otherExp = v('otherExp');
    const totalExpense = Math.round((directCost + opex + otherExp) * 100) / 100;
    const grossProfit = Math.round((revenue - directCost) * 100) / 100;
    const netIncome = Math.round((revenue - totalExpense) * 100) / 100;
    const incomeTax = netIncome > 0 ? Math.round(netIncome * taxRate / 100 * 100) / 100 : 0;
    const netIncomeAfterTax = Math.round((netIncome - incomeTax) * 100) / 100;

    const cash = v('cash'), receivables = v('receivables'), inventory = v('inventory'), otherCA = v('otherCA'), nonCA = v('nonCA');
    const payables = v('payables'), otherCL = v('otherCL'), nonCL = v('nonCL'), equity = v('equity');
    const currentAssets = Math.round((cash + receivables + inventory + otherCA) * 100) / 100;
    const totalAssets = Math.round((currentAssets + nonCA) * 100) / 100;
    const currentLiabilities = Math.round((payables + otherCL) * 100) / 100;
    const totalLiabilities = Math.round((currentLiabilities + nonCL) * 100) / 100;
    const diff = Math.abs(totalAssets - (totalLiabilities + equity));
    const isBalanced = diff < Math.max(1, totalAssets * 0.01);

    // كائن قائمة الدخل (متوافق مع buildFinancialAnalysis / buildFSAlerts / التصدير)
    const income = {
        totalRevenue: revenue, directCost, opex, otherExp, totalExpense,
        adminExpense: Math.round((opex + otherExp) * 100) / 100,
        grossProfit, netIncome, incomeTaxRate: taxRate, incomeTax, netIncomeAfterTax,
        revenues: [{ account: { code: '4000', nameAr: 'الإيرادات / المبيعات' }, naturalMovement: revenue }],
        expenses: [
            { account: { code: '5100', nameAr: 'تكلفة الإيرادات المباشرة' }, naturalMovement: directCost },
            { account: { code: '5300', nameAr: 'المصروفات التشغيلية والإدارية' }, naturalMovement: opex },
            { account: { code: '5400', nameAr: 'مصروفات أخرى وفوائد' }, naturalMovement: otherExp }
        ].filter(e => e.naturalMovement)
    };

    // كائن المركز المالي — أكواد الحسابات مختارة لتطابق منطق buildFinancialAnalysis
    // (المخزون 115x، المدينون 113x، الدائنون 211x)
    const balance = {
        assets: [
            { account: { code: '1110', nameAr: 'النقدية وما يعادلها' }, naturalClosing: cash },
            { account: { code: '1130', nameAr: 'الذمم المدينة (العملاء)' }, naturalClosing: receivables },
            { account: { code: '1150', nameAr: 'المخزون' }, naturalClosing: inventory },
            { account: { code: '1190', nameAr: 'أصول متداولة أخرى' }, naturalClosing: otherCA },
            { account: { code: '1200', nameAr: 'الأصول غير المتداولة' }, naturalClosing: nonCA }
        ].filter(a => a.naturalClosing),
        liabilities: [
            { account: { code: '2110', nameAr: 'الذمم الدائنة (الموردون)' }, naturalClosing: payables },
            { account: { code: '2190', nameAr: 'خصوم متداولة أخرى' }, naturalClosing: otherCL },
            { account: { code: '2200', nameAr: 'خصوم غير متداولة' }, naturalClosing: nonCL }
        ].filter(l => l.naturalClosing),
        equities: [{ account: { code: '3000', nameAr: 'حقوق الملكية' }, naturalClosing: equity }],
        currentAssets, totalAssets, currentLiabilities, totalLiabilities,
        adjustedEquity: equity, totalEquityLedger: equity,
        fixedAssets: nonCA, longTermLiabilities: nonCL,
        balanceDiff: Math.round(diff * 100) / 100, isBalanced
    };

    const extra = { interest: v('interest'), depreciation: v('depreciation'), ocf: (vals.ocf !== undefined && vals.ocf !== '' && fsExtNum(vals.ocf) !== 0) ? v('ocf') : null };
    const analysis = buildFinancialAnalysis(income, balance, extra);

    if (target === 'compare') {
        window._fsExtCompare = { loaded: true, mode: 'form', income, balance, analysis, label: fileName || 'نموذج مختصر' };
        renderFinancialStatements();
        return;
    }

    const alerts = buildFSAlerts(income, balance, analysis, null);
    const report = buildFSExtReport(income, balance, analysis);

    window._fsExt = { loaded: true, vals, income, balance, analysis, alerts, report, fileName: fileName || '' };
    if (fsState.activeTab !== 'external') fsState.activeTab = 'external';
    renderFinancialStatements();
}

// ── 4) محرّك التقرير الذكي والتوجيهات الإدارية (قاعدي — بدون AI خارجي) ─────────────────
function buildFSExtReport(income, balance, analysis) {
    const strengths = [], weaknesses = [], directives = [];
    const ratingScore = { 'ممتاز': 2, 'مقبول': 1, 'ضعيف': 0 };
    let scoreSum = 0, scoreCount = 0;
    const allRatios = [...analysis.liquidity, ...analysis.profitability, ...analysis.activity, ...analysis.leverage];
    allRatios.forEach(r => {
        if (r.value === null || isNaN(r.value)) return;
        const sc = ratingScore[r.rating.label];
        if (sc === undefined) return;
        scoreSum += sc; scoreCount++;
        if (r.rating.label === 'ممتاز') strengths.push(`${r.label}: ${fmt(r.value)}${r.suffix || ''} — أداء قوي يتجاوز المعدل الآمن.`);
        else if (r.rating.label === 'ضعيف') weaknesses.push(`${r.label}: ${fmt(r.value)}${r.suffix || ''} — أقل من الحد المرجعي ويستدعي معالجة.`);
    });
    const healthPct = scoreCount ? Math.round((scoreSum / (scoreCount * 2)) * 100) : null;
    let healthLabel = '—', healthColor = '#888';
    if (healthPct !== null) {
        if (healthPct >= 75) { healthLabel = 'مركز مالي قوي'; healthColor = '#27ae60'; }
        else if (healthPct >= 50) { healthLabel = 'مركز مالي مقبول'; healthColor = '#f39c12'; }
        else { healthLabel = 'مركز مالي يحتاج معالجة'; healthColor = '#c0392b'; }
    }

    // الملخص التنفيذي
    const nm = income.totalRevenue ? (income.netIncome / income.totalRevenue) * 100 : null;
    let summary = `حقّقت المنشأة إيرادات بقيمة ${fmt(income.totalRevenue)} خلال الفترة، `;
    summary += income.netIncome >= 0
        ? `وصافي ربح قدره ${fmt(income.netIncome)}${nm !== null ? ` بهامش ربح صافٍ ${fmt(nm)}%` : ''}. `
        : `وصافي خسارة قدرها ${fmt(Math.abs(income.netIncome))}، ما يستدعي مراجعة عاجلة لهيكل التكاليف والإيرادات. `;
    summary += `يبلغ إجمالي الأصول ${fmt(balance.totalAssets)} مقابل التزامات ${fmt(balance.totalLiabilities)} وحقوق ملكية ${fmt(balance.adjustedEquity)}. `;
    if (!balance.isBalanced) summary += `⚠️ ملاحظة: المركز المالي غير متوازن (فرق ${fmt(balance.balanceDiff)}) — راجع دقة البيانات المُدخلة. `;
    if (healthPct !== null) summary += `وبتقييم آلي شامل للنسب المالية، يُصنّف الوضع بأنه "${healthLabel}" بمؤشر صحة مالية ${healthPct}%.`;

    // توجيهات إدارية مشتقة من النسب
    const findR = (g, l) => (analysis[g] || []).find(r => r.label.includes(l));
    const cr = findR('liquidity', 'النسبة الجارية');
    if (cr && cr.value !== null && cr.value < 1.5) directives.push('تعزيز السيولة: تسريع تحصيل الذمم المدينة وإعادة جدولة بعض الالتزامات قصيرة الأجل لرفع النسبة الجارية إلى النطاق الآمن (1.5–3).');
    const gm = findR('profitability', 'هامش الربح الإجمالي');
    if (gm && gm.value !== null && gm.value < 20) directives.push('تحسين هامش الربح الإجمالي: مراجعة التسعير والتفاوض على تكاليف المواد والمقاولين من الباطن، والتركيز على المشاريع الأعلى ربحية.');
    const dr = findR('leverage', 'الديون إلى الأصول');
    if (dr && dr.value !== null && dr.value > 50) directives.push('ضبط المديونية: الحد من الاستدانة الجديدة وتعزيز حقوق الملكية عبر احتجاز الأرباح، مع متابعة جدول استحقاقات القروض.');
    const it = findR('activity', 'دوران المخزون');
    if (it && it.value !== null && it.value < 4) directives.push('تحسين كفاءة المخزون: تقليل المخزون الراكد وربط المشتريات باحتياجات المشاريع الفعلية لتسريع الدوران.');
    const roe = findR('profitability', 'العائد على حقوق الملكية');
    if (roe && roe.value !== null && roe.value < 15) directives.push('رفع العائد على حقوق الملكية: استخدم تحليل DuPont لتحديد المحرك الأضعف (الهامش/كفاءة الأصول/الرافعة) وتوجيه التحسين إليه.');
    if (income.netIncome < 0) directives.push('وقف النزيف: إجراء مراجعة فورية لبنود التكاليف الكبرى وإيقاف الأنشطة الخاسرة، ووضع خطة استرداد ربحية بجدول زمني محدد.');
    const cccR = findR('cashCycle', 'دورة التحويل النقدي');
    if (cccR && cccR.value !== null && cccR.value > 100) directives.push(`تقصير دورة التحويل النقدي (${fmt(cccR.value)} يوم): سرّع التحصيل، قلّل ركود المخزون، وفاوض على آجال سداد أطول لتحرير سيولة محتجزة في التشغيل.`);
    if (analysis.zModel && analysis.zModel.score !== null && analysis.zModel.score < 1.1) directives.unshift('⚠️ إنذار تعثّر (مؤشر Z في منطقة الخطر): ضع خطة إنقاذ مالي عاجلة — إعادة هيكلة الديون، ضخ سيولة، وخفض التكاليف الثابتة — وتابع المؤشر شهرياً.');
    if (!directives.length) directives.push('الحفاظ على الأداء الحالي ومراقبة المؤشرات دورياً، مع البحث عن فرص نمو مدروسة دون الإخلال بالتوازن المالي.');

    return { summary, strengths, weaknesses, directives, healthPct, healthLabel, healthColor };
}

// ── 5) عرض التبويب ─────────────────
function renderFSExternalTab() {
    const ext = window._fsExt;
    const uploader = `
        <div class="card" style="margin-bottom:14px">
            <div style="background:linear-gradient(135deg,#16a085,#1abc9c);color:white;border-radius:12px;padding:16px;margin-bottom:14px">
                <div style="font-size:15px;font-weight:900">📂 تحليل قوائم مالية خارجية</div>
                <div style="font-size:11px;opacity:.95;margin-top:5px;line-height:1.7">حلّل بيانات من خارج النظام بنفس محرّك النسب والتنبيهات الاحترافي. الطريقة الأفضل: ارفع <strong>ميزان مراجعة كامل</strong> والنظام يتعرّف تلقائياً على الحسابات الرئيسية والفرعية ويصنّفها (أصول/خصوم/حقوق/إيرادات/مصروفات) ثم يحلّلها — مع رسوم بيانية وتوجيهات إدارية.</div>
            </div>

            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:14px">
                <div style="border:2px solid #16a085;border-radius:12px;padding:14px;background:#f4fdfb">
                    <div style="font-size:13px;font-weight:900;color:#0e6655;margin-bottom:4px">⚖️ الطريقة الأولى — رفع ميزان المراجعة <span style="background:#16a085;color:#fff;font-size:9px;padding:1px 7px;border-radius:5px">موصى به</span></div>
                    <div style="font-size:11px;color:#555;line-height:1.7;margin-bottom:10px">ارفع ميزان المراجعة بأعمدة: <strong>رمز الحساب · اسم الحساب · مدين · دائن</strong>. يتعرّف النظام على المستويات الرئيسية/الفرعية تلقائياً ويصنّف كل حساب.</div>
                    <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
                        <button class="btn" onclick="downloadFSExtTBTemplate('xlsx')" style="background:#1e8449;color:white;padding:9px 14px;font-weight:800;font-size:12px">📥 نموذج الميزان (Excel)</button>
                        <button class="btn" onclick="downloadFSExtTBTemplate('csv')" style="background:#2d6a9f;color:white;padding:9px 14px;font-weight:800;font-size:12px">📥 (CSV)</button>
                        <label class="btn" style="background:#16a085;color:white;padding:9px 14px;font-weight:800;font-size:12px;cursor:pointer">
                            📤 رفع ميزان مراجعة
                            <input type="file" accept=".xlsx,.xls,.csv" style="display:none" onchange="handleFSExtTBUpload(this)">
                        </label>
                    </div>
                </div>

                <div style="border:1.5px solid #d0d7e0;border-radius:12px;padding:14px;background:#fafbfc">
                    <div style="font-size:13px;font-weight:900;color:#5b2c6f;margin-bottom:4px">📝 الطريقة الثانية — نموذج مختصر</div>
                    <div style="font-size:11px;color:#555;line-height:1.7;margin-bottom:10px">إن لم يتوفّر ميزان مراجعة، استخدم النموذج المختصر (إجماليات قائمة الدخل والمركز المالي مباشرة).</div>
                    <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
                        <button class="btn" onclick="downloadFSExtTemplate('xlsx')" style="background:#1e8449;color:white;padding:9px 14px;font-weight:800;font-size:12px">📥 النموذج المختصر (Excel)</button>
                        <button class="btn" onclick="downloadFSExtTemplate('csv')" style="background:#2d6a9f;color:white;padding:9px 14px;font-weight:800;font-size:12px">📥 (CSV)</button>
                        <label class="btn" style="background:#8e44ad;color:white;padding:9px 14px;font-weight:800;font-size:12px;cursor:pointer">
                            📤 رفع النموذج المختصر
                            <input type="file" accept=".xlsx,.xls,.csv" style="display:none" onchange="handleFSExtUpload(this)">
                        </label>
                    </div>
                </div>
            </div>

            ${ext.loaded ? `<div style="margin-top:12px;padding-top:12px;border-top:1px dashed #d0d7e0;display:flex;gap:10px;flex-wrap:wrap;align-items:center">
                <div style="font-size:12px;font-weight:800;color:#1a3a5c">🆚 المقارنة:</div>
                <label class="btn" style="background:#34495e;color:white;padding:8px 14px;font-weight:800;font-size:12px;cursor:pointer">
                    📎 رفع ميزان للمقارنة
                    <input type="file" accept=".xlsx,.xls,.csv" style="display:none" onchange="handleFSExtTBUpload(this,'compare')">
                </label>
                <label class="btn" style="background:#7f8c8d;color:white;padding:8px 14px;font-weight:800;font-size:12px;cursor:pointer">
                    📎 رفع نموذج مختصر للمقارنة
                    <input type="file" accept=".xlsx,.xls,.csv" style="display:none" onchange="handleFSExtUpload(this,'compare')">
                </label>
                ${window._fsExtCompare && window._fsExtCompare.loaded ? `<button class="btn" onclick="clearFSExtCompare()" style="background:#fdecea;color:#c0392b;padding:8px 14px;font-weight:800;font-size:12px">✖️ إزالة المقارنة</button>` : '<span style="font-size:11px;color:#888">ارفع ملفاً ثانياً (سنة سابقة / شركة أخرى) لعرضه جنباً إلى جنب</span>'}
            </div>
            <div style="margin-top:10px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">
                <button class="btn" onclick="clearFSExt()" style="background:#fdecea;color:#c0392b;padding:8px 16px;font-weight:800;font-size:12px">🗑️ مسح التحليل الحالي</button>
                ${ext.fileName ? `<span style="font-size:11px;color:#16a085;background:#e8f8f5;border-radius:6px;padding:6px 10px">📄 ${ext.mode === 'tb' ? 'ميزان مراجعة' : 'نموذج مختصر'}: <strong>${ext.fileName}</strong>${ext.tbAccounts ? ` · ${ext.tbAccounts.length} حساب مُصنَّف` : ''}</span>` : ''}
            </div>` : ''}
        </div>`;

    if (!ext.loaded) {
        return uploader + `
        <div class="card" style="text-align:center;padding:48px 20px">
            <div style="font-size:64px;margin-bottom:14px">⚖️</div>
            <div style="font-size:16px;font-weight:800;color:#1a3a5c;margin-bottom:6px">لم يتم رفع أي ملف بعد</div>
            <div style="font-size:12px;color:#666;line-height:1.8;max-width:560px;margin:0 auto">
                نزّل نموذج ميزان المراجعة، الصِق فيه ميزان مراجعتك (رمز · اسم · مدين · دائن)، ثم ارفعه.
                سيتعرّف النظام على الحسابات الرئيسية والفرعية ويصنّفها تلقائياً، ثم يُنتج: كل النسب المالية (السيولة، الربحية، النشاط، المديونية)،
                تحليل DuPont، رسوماً بيانية، تنبيهات ذكية، وتقريراً تنفيذياً بتوجيهات إدارية قابلاً للطباعة والتصدير.
            </div>
        </div>`;
    }

    const { income, balance, analysis, alerts, report } = ext;
    const card = (label, val, color, sub) => `
        <div style="background:white;border-radius:12px;padding:16px;box-shadow:0 2px 8px rgba(0,0,0,.06);border-right:4px solid ${color}">
            <div style="font-size:12px;color:#666">${label}</div>
            <div style="font-size:22px;font-weight:900;color:${color}">${fmt(val)}</div>
            ${sub ? `<div style="font-size:11px;color:#888;margin-top:4px">${sub}</div>` : ''}
        </div>`;

    const health = report.healthPct;
    const healthCard = health === null ? '' : `
        <div style="background:linear-gradient(135deg,${report.healthColor},#1a3a5c);border-radius:12px;padding:18px;color:white;display:flex;align-items:center;gap:18px;flex-wrap:wrap;margin-bottom:14px">
            <div style="text-align:center;min-width:120px">
                <div style="font-size:42px;font-weight:900;line-height:1">${health}%</div>
                <div style="font-size:11px;opacity:.9;margin-top:4px">مؤشر الصحة المالية</div>
            </div>
            <div style="flex:1;min-width:200px">
                <div style="font-size:16px;font-weight:900">${report.healthLabel}</div>
                <div style="font-size:11px;opacity:.92;margin-top:6px;line-height:1.8">${report.summary}</div>
            </div>
        </div>`;

    const listBlock = (title, icon, color, items, emptyMsg) => `
        <div class="card" style="margin-bottom:14px">
            <div style="font-size:13px;font-weight:900;color:${color};margin-bottom:8px">${icon} ${title}</div>
            ${items.length ? `<ul style="margin:0;padding-inline-start:20px;font-size:12px;color:#444;line-height:1.9">${items.map(t => `<li>${t}</li>`).join('')}</ul>`
            : `<div style="font-size:11px;color:#999">${emptyMsg}</div>`}
        </div>`;

    const reportBlock = `
        <div id="fsExtPrintArea">
            ${healthCard}
            <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px;margin-bottom:14px">
                ${card('إجمالي الإيرادات', income.totalRevenue, '#2d6a9f')}
                ${card('مجمل الربح', income.grossProfit, '#8e44ad', income.totalRevenue ? `${fmt(income.grossProfit / income.totalRevenue * 100)}% من الإيرادات` : '')}
                ${card(income.netIncome >= 0 ? 'صافي الربح قبل الضريبة' : 'صافي الخسارة قبل الضريبة', income.netIncome, income.netIncome >= 0 ? '#27ae60' : '#c0392b')}
                ${card('إجمالي الأصول', balance.totalAssets, '#16a085', balance.isBalanced ? '✅ المركز متوازن' : `⚠️ فرق ${fmt(balance.balanceDiff)}`)}
                ${card('حقوق الملكية', balance.adjustedEquity, '#e67e22')}
            </div>

            ${ext.mode === 'tb' ? renderFSTbRecognition(ext.tbAccounts) : ''}

            <div class="card" style="margin-bottom:14px">
                <div style="font-size:14px;font-weight:900;color:#1a3a5c;margin-bottom:12px">📊 الرسوم البيانية</div>
                <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(260px,1fr));gap:16px">
                    <div><div style="font-size:11px;color:#666;text-align:center;margin-bottom:6px">هوامش الربحية (%)</div><div style="height:240px"><canvas id="extChartProfit"></canvas></div></div>
                    <div><div style="font-size:11px;color:#666;text-align:center;margin-bottom:6px">هيكل التمويل (الأصول مقابل مصادر التمويل)</div><div style="height:240px"><canvas id="extChartStructure"></canvas></div></div>
                    <div><div style="font-size:11px;color:#666;text-align:center;margin-bottom:6px">نسب السيولة مقابل المعدل الآمن</div><div style="height:240px"><canvas id="extChartLiquidity"></canvas></div></div>
                </div>
            </div>

            ${renderFSAnalysisTab(analysis, income, balance)}

            ${renderFSExtCompareBlock()}

            ${renderFSAlertsPanel(alerts)}

            ${listBlock('نقاط القوة', '✅', '#27ae60', report.strengths, 'لا توجد نسب بتقييم "ممتاز" في هذه البيانات.')}
            ${listBlock('نقاط الضعف والمخاطر', '⚠️', '#c0392b', report.weaknesses, 'لا توجد نسب بتقييم "ضعيف" — أداء جيد عموماً.')}

            <div class="card" style="margin-bottom:14px;background:linear-gradient(135deg,#fef9e7,#fff);border:1px solid #f0c419">
                <div style="font-size:14px;font-weight:900;color:#7d4e00;margin-bottom:10px">🎯 أهم التوجيهات والملاحظات الإدارية</div>
                <ol style="margin:0;padding-inline-start:22px;font-size:12.5px;color:#5c3d00;line-height:2">${report.directives.map(t => `<li>${t}</li>`).join('')}</ol>
            </div>
        </div>`;

    const actions = `
        <div class="card" style="margin-bottom:14px;display:flex;gap:10px;flex-wrap:wrap;align-items:center">
            <div style="font-size:12px;font-weight:800;color:#1a3a5c">تصدير التحليل:</div>
            <button class="btn" onclick="printFSExtReport()" style="background:#5b2c6f;color:white;padding:9px 16px;font-weight:800">🖨️ طباعة / PDF (يتضمن الرسوم)</button>
            <button class="btn" onclick="exportFSExtExcel()" style="background:#1e8449;color:white;padding:9px 16px;font-weight:800">📊 تصدير Excel (بيانات كاملة)</button>
            <button class="btn" onclick="fsSaveExtAnalysis()" style="background:#2d6a9f;color:white;padding:9px 16px;font-weight:800">💾 حفظ في السجل التاريخي</button>
        </div>`;

    return uploader + actions + reportBlock + renderFSHistoryBlock();
}

window.clearFSExt = function () {
    window._fsExt = { loaded: false, vals: null, income: null, balance: null, analysis: null, alerts: null, report: null, fileName: '', mode: '', tbAccounts: null };
    window._fsExtCompare = null;
    renderFinancialStatements();
};
window.clearFSExtCompare = function () {
    window._fsExtCompare = null;
    renderFinancialStatements();
};

// ── كتلة المقارنة جنباً إلى جنب (ملف أساسي مقابل ملف ثانٍ) ─────────────────
function renderFSExtCompareBlock() {
    const a = window._fsExt, b = window._fsExtCompare;
    if (!a || !a.loaded || !b || !b.loaded) return '';
    const rt = (an, grp, i) => { const r = an && an[grp] && an[grp][i]; return (r && r.value !== null && !isNaN(r.value)) ? r.value : null; };
    const metrics = [
        { l: 'إجمالي الإيرادات', av: a.income.totalRevenue, bv: b.income.totalRevenue, pct: false, hb: true },
        { l: 'مجمل الربح', av: a.income.grossProfit, bv: b.income.grossProfit, pct: false, hb: true },
        { l: 'صافي الربح قبل الضريبة', av: a.income.netIncome, bv: b.income.netIncome, pct: false, hb: true },
        { l: 'إجمالي الأصول', av: a.balance.totalAssets, bv: b.balance.totalAssets, pct: false, hb: null },
        { l: 'حقوق الملكية', av: a.balance.adjustedEquity, bv: b.balance.adjustedEquity, pct: false, hb: true },
        { l: 'هامش الربح الإجمالي %', av: rt(a.analysis, 'profitability', 0), bv: rt(b.analysis, 'profitability', 0), pct: true, hb: true },
        { l: 'هامش الربح الصافي %', av: rt(a.analysis, 'profitability', 1), bv: rt(b.analysis, 'profitability', 1), pct: true, hb: true },
        { l: 'العائد على الأصول ROA %', av: rt(a.analysis, 'profitability', 2), bv: rt(b.analysis, 'profitability', 2), pct: true, hb: true },
        { l: 'العائد على حقوق الملكية ROE %', av: rt(a.analysis, 'profitability', 3), bv: rt(b.analysis, 'profitability', 3), pct: true, hb: true },
        { l: 'النسبة الجارية', av: rt(a.analysis, 'liquidity', 0), bv: rt(b.analysis, 'liquidity', 0), pct: false, suf: 'x', hb: true },
        { l: 'النسبة السريعة', av: rt(a.analysis, 'liquidity', 1), bv: rt(b.analysis, 'liquidity', 1), pct: false, suf: 'x', hb: true },
        { l: 'نسبة الديون إلى الأصول %', av: rt(a.analysis, 'leverage', 0), bv: rt(b.analysis, 'leverage', 0), pct: true, hb: false },
        { l: 'دورة التحويل النقدي (يوم)', av: rt(a.analysis, 'cashCycle', 3), bv: rt(b.analysis, 'cashCycle', 3), pct: false, suf: ' يوم', hb: false },
        { l: 'مؤشر ألتمان Z″', av: a.analysis.zModel ? a.analysis.zModel.score : null, bv: b.analysis.zModel ? b.analysis.zModel.score : null, pct: false, hb: true }
    ];
    const cell = (v, m) => (v === null || isNaN(v)) ? '—' : fmt(v) + (m.pct ? '%' : (m.suf || ''));
    const delta = (m) => {
        if (m.av === null || m.bv === null || isNaN(m.av) || isNaN(m.bv)) return '<span style="color:#999">—</span>';
        const d = m.bv - m.av;
        if (Math.abs(d) < 0.005) return '<span style="color:#999">بدون تغيير</span>';
        const up = d > 0;
        const good = m.hb === null ? null : (up === m.hb);
        const color = good === null ? '#555' : (good ? '#27ae60' : '#c0392b');
        const pctChg = m.av !== 0 ? ` (${fmt(Math.abs(d / m.av * 100))}%)` : '';
        return `<span style="color:${color};font-weight:800">${up ? '▲' : '▼'} ${fmt(Math.abs(d))}${m.pct ? '%' : (m.suf || '')}${pctChg}</span>`;
    };
    return `
        <div class="card" style="margin-bottom:14px">
            <div style="font-size:14px;font-weight:900;color:#34495e;margin-bottom:4px">🆚 مقارنة جنباً إلى جنب</div>
            <div style="font-size:11px;color:#666;margin-bottom:12px">الملف الأساسي: <strong>${a.fileName || '—'}</strong> · ملف المقارنة: <strong>${b.label || '—'}</strong> — عمود "الفرق" يقارن الثاني بالأساسي (الأخضر = تحسّن، الأحمر = تراجع)</div>
            <div style="overflow-x:auto">
            <table style="width:100%;border-collapse:collapse;font-size:12px;min-width:520px">
                <thead><tr style="background:#eaeef2;color:#34495e">
                    <th style="padding:8px;text-align:right">المؤشر</th>
                    <th style="padding:8px;text-align:left">الأساسي</th>
                    <th style="padding:8px;text-align:left">المقارنة</th>
                    <th style="padding:8px;text-align:left">الفرق</th>
                </tr></thead>
                <tbody>
                    ${metrics.map(m => `<tr style="border-bottom:1px solid #f0f0f0">
                        <td style="padding:7px 8px">${m.l}</td>
                        <td style="padding:7px 8px;text-align:left;font-weight:700;color:#1a3a5c">${cell(m.av, m)}</td>
                        <td style="padding:7px 8px;text-align:left;font-weight:700;color:#1a3a5c">${cell(m.bv, m)}</td>
                        <td style="padding:7px 8px;text-align:left">${delta(m)}</td>
                    </tr>`).join('')}
                </tbody>
            </table>
            </div>
        </div>`;
}

// ── 6) الرسوم البيانية ─────────────────
function buildFSExtCharts() {
    const ext = window._fsExt;
    if (!ext || !ext.loaded || typeof Chart === 'undefined') return;
    const { income, balance } = ext;
    window._fsExtCharts = window._fsExtCharts || {};
    const destroy = id => { if (window._fsExtCharts[id]) { try { window._fsExtCharts[id].destroy(); } catch (e) { } delete window._fsExtCharts[id]; } };

    // هوامش الربحية
    const c1 = $('extChartProfit');
    if (c1) {
        destroy('extChartProfit');
        const gm = income.totalRevenue ? income.grossProfit / income.totalRevenue * 100 : 0;
        const nm = income.totalRevenue ? income.netIncome / income.totalRevenue * 100 : 0;
        const nmt = income.totalRevenue ? income.netIncomeAfterTax / income.totalRevenue * 100 : 0;
        window._fsExtCharts['extChartProfit'] = new Chart(c1, {
            type: 'bar',
            data: {
                labels: ['هامش إجمالي', 'هامش صافٍ', 'صافٍ بعد الضريبة'],
                datasets: [{ data: [+gm.toFixed(1), +nm.toFixed(1), +nmt.toFixed(1)], backgroundColor: ['#8e44ad', '#27ae60', '#1e8449'] }]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { y: { ticks: { callback: v => v + '%' } } } }
        });
    }

    // هيكل التمويل
    const c2 = $('extChartStructure');
    if (c2) {
        destroy('extChartStructure');
        window._fsExtCharts['extChartStructure'] = new Chart(c2, {
            type: 'doughnut',
            data: {
                labels: ['الخصوم المتداولة', 'الخصوم غير المتداولة', 'حقوق الملكية'],
                datasets: [{ data: [balance.currentLiabilities, balance.longTermLiabilities, balance.adjustedEquity], backgroundColor: ['#e67e22', '#c0392b', '#27ae60'] }]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 10 } } } } }
        });
    }

    // السيولة مقابل المعدل الآمن
    const c3 = $('extChartLiquidity');
    if (c3) {
        destroy('extChartLiquidity');
        const cr = balance.currentLiabilities ? balance.currentAssets / balance.currentLiabilities : 0;
        const inv = balance.assets.filter(b => b.account.code.startsWith('115')).reduce((s, b) => s + b.naturalClosing, 0);
        const qr = balance.currentLiabilities ? (balance.currentAssets - inv) / balance.currentLiabilities : 0;
        window._fsExtCharts['extChartLiquidity'] = new Chart(c3, {
            type: 'bar',
            data: {
                labels: ['النسبة الجارية', 'النسبة السريعة'],
                datasets: [
                    { label: 'الفعلي', data: [+cr.toFixed(2), +qr.toFixed(2)], backgroundColor: ['#2d6a9f', '#16a085'] },
                    { label: 'المعدل الآمن', data: [1.5, 1], type: 'line', borderColor: '#c0392b', borderDash: [6, 4], pointRadius: 4, pointBackgroundColor: '#c0392b', fill: false }
                ]
            },
            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position: 'bottom', labels: { font: { size: 10 } } } }, scales: { y: { beginAtZero: true, ticks: { callback: v => v + 'x' } } } }
        });
    }
}

// ── 7) الطباعة / PDF (يتضمن الرسوم البيانية كصور) ─────────────────
window.printFSExtReport = function () {
    const ext = window._fsExt;
    if (!ext || !ext.loaded) { toast('⚠️ لا يوجد تحليل للطباعة', 'er'); return; }
    const area = $('fsExtPrintArea');
    if (!area) return;
    const clone = area.cloneNode(true);
    // فتح كل الأقسام القابلة للطي (التعرّف على الحسابات + التنبيهات) لتُطبع كاملة
    clone.querySelectorAll('details').forEach(d => d.setAttribute('open', ''));
    // استبدال الـ canvas بصور من الرسوم الحية
    const live = area.querySelectorAll('canvas');
    const cloned = clone.querySelectorAll('canvas');
    live.forEach((c, i) => {
        if (!cloned[i]) return;
        try {
            const img = document.createElement('img');
            img.src = c.toDataURL('image/png');
            img.style.maxWidth = '100%';
            cloned[i].replaceWith(img);
        } catch (e) { }
    });
    const title = ext.vals.entityName ? `التحليل المالي — ${ext.vals.entityName}` : 'التحليل المالي لملف خارجي';
    const period = ext.vals.period ? ` · الفترة: ${ext.vals.period}` : '';
    const html = `<!DOCTYPE html><html dir="rtl"><head><link href="https://fonts.googleapis.com/css2?family=Tajawal:wght@400;500;700;800&display=swap" rel="stylesheet"><meta charset="UTF-8"><title>${title}</title>
    <style>* { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
    body { font-family: 'Tajawal', Tahoma; padding: 20px; color: #1a3a5c; direction: rtl; }
    h1 { text-align:center; border-bottom: 3px solid #16a085; padding-bottom: 10px; font-size:20px; }
    .card { background:#fff; border:1px solid #eee; border-radius:10px; padding:14px; margin-bottom:12px; }
    ul,ol { margin:0; padding-inline-start:22px; line-height:1.9; }
    img { display:block; margin:6px auto; }
    /* إلغاء قيود التمرير/الارتفاع حتى تُطبع كل صفوف الجداول كاملة */
    div { max-height:none !important; overflow:visible !important; }
    table { width:100%; border-collapse:collapse; page-break-inside:auto; }
    tr { page-break-inside:avoid; }
    thead { display:table-header-group; position:static !important; }
    thead tr, thead th { position:static !important; }
    details { page-break-inside:auto; }
    details > summary { display:block; }
    @page { size: A4; margin: 1.4cm; }</style></head><body>
    ${fsBrandHeader('📂 ' + title, 'التحليل المالي' + (ext.vals && ext.vals.period ? ' · الفترة: ' + ext.vals.period : ''))}
    ${clone.innerHTML}
    <div style="margin-top:18px;border-top:1px solid #ddd;padding-top:8px;font-size:10px;color:#999;text-align:center">أُنشئ بواسطة ${custCoName()} · ${new Date().toLocaleString('ar-EG')}</div>
    </body></html>`;
    const w = window.open('', '_blank'); w.document.write(html); w.document.close();
    setTimeout(() => { try { w.focus(); w.print(); } catch (e) { } }, 600);
};

// ── 8) تصدير Excel متعدد الأوراق ─────────────────
window.exportFSExtExcel = function () {
    const ext = window._fsExt;
    if (!ext || !ext.loaded) { toast('⚠️ لا يوجد تحليل للتصدير', 'er'); return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة', 'er'); return; }
    const { income, balance, analysis, report } = ext;
    const wb = XLSX.utils.book_new();

    // ورقة 1: القوائم المالية
    const stmtAOA = [
        [(window.gbrCfg && window.gbrCfg.companyAr) || 'شركة جي بي آر للمقاولات'],
        ['التحليل المالي لملف خارجي'],
        [ext.vals.entityName ? `المنشأة: ${ext.vals.entityName}` : '', ext.vals.period ? `الفترة: ${ext.vals.period}` : ''],
        [],
        ['📈 قائمة الدخل', ''],
        ['الإيرادات / المبيعات', income.totalRevenue],
        ['تكلفة الإيرادات المباشرة', income.directCost],
        ['مجمل الربح', income.grossProfit],
        ['المصروفات الإدارية والعمومية وأخرى', income.adminExpense],
        ['إجمالي المصروفات والتكاليف', income.totalExpense],
        ['صافي الربح/الخسارة قبل الضريبة', income.netIncome],
        [`ضريبة الدخل التقديرية (${income.incomeTaxRate}%)`, -income.incomeTax],
        ['صافي الربح/الخسارة بعد الضريبة', income.netIncomeAfterTax],
        [],
        ['🏦 المركز المالي — الأصول', ''],
        ...balance.assets.map(a => [a.account.nameAr, a.naturalClosing]),
        ['إجمالي الأصول المتداولة', balance.currentAssets],
        ['إجمالي الأصول', balance.totalAssets],
        [],
        ['⚖️ الخصوم وحقوق الملكية', ''],
        ...balance.liabilities.map(l => [l.account.nameAr, l.naturalClosing]),
        ['إجمالي الخصوم المتداولة', balance.currentLiabilities],
        ['إجمالي الخصوم', balance.totalLiabilities],
        ['حقوق الملكية', balance.adjustedEquity],
        ['إجمالي الخصوم وحقوق الملكية', Math.round((balance.totalLiabilities + (balance.partnerTotal||0) + balance.adjustedEquity) * 100) / 100],
        [balance.isBalanced ? '✅ المركز المالي متوازن' : `⚠️ فرق عدم التوازن: ${balance.balanceDiff}`, '']
    ];
    const ws1 = XLSX.utils.aoa_to_sheet(stmtAOA); ws1['!cols'] = [{ wch: 42 }, { wch: 18 }];
    XLSX.utils.book_append_sheet(wb, ws1, 'القوائم المالية');

    // ورقة 2: النسب والتحليل
    const ratioAOA = [['النسب المالية والتحليل'], [], ['المجموعة', 'النسبة', 'القيمة', 'التقييم', 'المعيار', 'متوسط القطاع']];
    const pushGroup = (name, arr) => arr.forEach(r => ratioAOA.push([name, r.label, (r.value === null || isNaN(r.value)) ? '—' : Math.round(r.value * 100) / 100, r.rating.label, r.benchmark, r.industryAvg == null ? '—' : r.industryAvg]));
    pushGroup('السيولة', analysis.liquidity);
    pushGroup('الربحية', analysis.profitability);
    pushGroup('النشاط', analysis.activity);
    if (analysis.cashCycle) pushGroup('دورة التحويل النقدي', analysis.cashCycle);
    pushGroup('المديونية', analysis.leverage);
    if (analysis.zModel) {
        ratioAOA.push([]);
        ratioAOA.push(['ألتمان Z″', 'قيمة المؤشر', analysis.zModel.score == null ? '—' : Math.round(analysis.zModel.score * 100) / 100, analysis.zModel.zone.label, analysis.zModel.zone.note, '']);
    }
    ratioAOA.push([]);
    ratioAOA.push(['تحليل DuPont', 'هامش الربح %', analysis.dupont.margin == null ? '—' : Math.round(analysis.dupont.margin * 100) / 100]);
    ratioAOA.push(['تحليل DuPont', 'دوران الأصول', analysis.dupont.turnover == null ? '—' : Math.round(analysis.dupont.turnover * 100) / 100]);
    ratioAOA.push(['تحليل DuPont', 'الرافعة المالية', analysis.dupont.leverage == null ? '—' : Math.round(analysis.dupont.leverage * 100) / 100]);
    ratioAOA.push(['تحليل DuPont', 'العائد على حقوق الملكية %', analysis.dupont.roe == null ? '—' : Math.round(analysis.dupont.roe * 100) / 100]);
    const ws2 = XLSX.utils.aoa_to_sheet(ratioAOA); ws2['!cols'] = [{ wch: 14 }, { wch: 36 }, { wch: 12 }, { wch: 10 }, { wch: 30 }, { wch: 12 }];
    XLSX.utils.book_append_sheet(wb, ws2, 'النسب والتحليل');

    // ورقة 3: التقرير والتوجيهات
    const repAOA = [
        ['التقرير التنفيذي والتوجيهات الإدارية'], [],
        ['مؤشر الصحة المالية', report.healthPct == null ? '—' : report.healthPct + '%', report.healthLabel], [],
        ['الملخص التنفيذي'], [report.summary], [],
        ['✅ نقاط القوة'], ...(report.strengths.length ? report.strengths.map(s => [s]) : [['لا يوجد']]), [],
        ['⚠️ نقاط الضعف والمخاطر'], ...(report.weaknesses.length ? report.weaknesses.map(s => [s]) : [['لا يوجد']]), [],
        ['🎯 التوجيهات الإدارية'], ...report.directives.map((d, i) => [`${i + 1}. ${d}`])
    ];
    const ws3 = XLSX.utils.aoa_to_sheet(repAOA); ws3['!cols'] = [{ wch: 90 }, { wch: 14 }, { wch: 24 }];
    XLSX.utils.book_append_sheet(wb, ws3, 'التقرير والتوجيهات');

    // ورقة 4 (لنمط الميزان فقط): تصنيف الحسابات كما تعرّف عليها النظام
    if (ext.mode === 'tb' && ext.tbAccounts && ext.tbAccounts.length) {
        const recAOA = [['تصنيف الحسابات (التعرّف التلقائي)'], [],
            ['الرمز', 'اسم الحساب', 'النوع', 'التصنيف', 'المستوى', 'محتسب؟', 'القيمة'],
            ...ext.tbAccounts.map(a => [a.code, a.name, FS_TB_TYPE_AR[a.type], a.bucketLabel, a.level, a.summable ? 'نعم' : 'مستبعد (ازدواج)', a.value])
        ];
        const ws4 = XLSX.utils.aoa_to_sheet(recAOA); ws4['!cols'] = [{ wch: 14 }, { wch: 38 }, { wch: 12 }, { wch: 26 }, { wch: 10 }, { wch: 16 }, { wch: 16 }];
        XLSX.utils.book_append_sheet(wb, ws4, 'تصنيف الحسابات');
    }

    const fn = `تحليل_مالي_${(ext.vals.entityName || 'ملف_خارجي').replace(/\s+/g, '_')}.xlsx`;
    XLSX.writeFile(wb, fn);
    toast('✅ تم تصدير ملف Excel كامل (قوائم + نسب + تقرير)', 'ok', 5000);
};

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║   ⚖️  [ACC-FS-EXT-TB]   رفع ميزان مراجعة كامل + تعرّف تلقائي على الحسابات     ║
// ╚══════════════════════════════════════════════════════════════════════════╝

// تسميات الفئات (Buckets) القياسية — كل حساب يُسنَد لكود قانوني يطابق منطق بُناة القوائم
const FS_TB_BUCKETS = {
    '1110': 'النقدية والبنوك', '1130': 'الذمم المدينة (العملاء)', '1150': 'المخزون',
    '1190': 'أصول متداولة أخرى', '1200': 'أصول غير متداولة (ثابتة)',
    '2110': 'الذمم الدائنة (الموردون)', '2190': 'خصوم متداولة أخرى', '2200': 'خصوم غير متداولة (طويلة الأجل)',
    '3000': 'حقوق الملكية', '4000': 'الإيرادات', '5100': 'تكاليف مباشرة', '5300': 'مصروفات تشغيلية وإدارية'
};
const FS_TB_TYPE_AR = { asset: 'أصل', liability: 'خصم', equity: 'حقوق ملكية', revenue: 'إيراد', expense: 'مصروف' };

// ── تصنيف حساب: تحديد النوع + الكود القانوني (Bucket) ─────────────────
// الأولوية: شجرة حسابات النظام (إن وُجد الكود) ← بادئة الكود القياسية ← الكلمات المفتاحية في الاسم
function fsTbBucket(realCode, name) {
    const code = String(realCode == null ? '' : realCode).trim();
    const n = String(name == null ? '' : name).toLowerCase();
    const coa = window.chartOfAccounts || {};
    const found = Object.values(coa).find(a => a.code === code);

    // النوع الأساسي
    let type;
    if (found && found.type) type = found.type;
    else {
        const d = code.replace(/[^\d]/g, '')[0];
        if (d === '1') type = 'asset';
        else if (d === '2') type = 'liability';
        else if (d === '3') type = 'equity';
        else if (d === '4') type = 'revenue';
        else if (d === '5' || d === '6') type = 'expense';
        else if (/إيراد|مبيعات|revenue|sales/.test(n)) type = 'revenue';
        else if (/تكلفة|مصروف|مشتريات|أجور|رواتب|expense|cost|purchas|salary|wage/.test(n)) type = 'expense';
        else if (/رأس ?المال|حقوق|احتياطي|محتجز|equity|capital|reserve|retained/.test(n)) type = 'equity';
        else if (/دائن|مورد|قرض|مستحق|payable|creditor|loan|accrued|liab/.test(n)) type = 'liability';
        else type = 'asset';
    }

    const cd = code.replace(/[^\d]/g, '');
    let bucket;
    if (type === 'asset') {
        if (cd.startsWith('111') || cd.startsWith('112') || /نقد|صندوق|بنك|cash|bank/.test(n)) bucket = '1110';
        else if (cd.startsWith('113') || cd.startsWith('114') || /عملاء|مدين|ذمم مدينة|أوراق قبض|receivable|debtor/.test(n)) bucket = '1130';
        else if (cd.startsWith('115') || cd.startsWith('116') || /مخزون|بضاعة|مواد|أعمال تحت التنفيذ|inventory|stock|wip/.test(n)) bucket = '1150';
        else if ((cd && !cd.startsWith('11')) || /ثابت|غير متداول|سيارات|معدات|آلات|مبان|أراض|أثاث|عقار|fixed|non.?current|equipment|property|vehicle|machinery/.test(n)) bucket = '1200';
        else bucket = '1190';
    } else if (type === 'liability') {
        if (cd.startsWith('211') || /مورد|دائن|ذمم دائنة|أوراق دفع|payable|creditor|supplier/.test(n)) bucket = '2110';
        else if ((cd && !cd.startsWith('21')) || /طويل|غير متداول|نهاية الخدمة|قرض طويل|long.?term|non.?current|end of service/.test(n)) bucket = '2200';
        else bucket = '2190';
    } else if (type === 'equity') bucket = '3000';
    else if (type === 'revenue') bucket = '4000';
    else { // expense
        if (cd.startsWith('51') || cd.startsWith('52') || /تكلفة المبيعات|تكلفة الإيراد|تكاليف مباشرة|مشتريات|مواد|مقاول|أجور مباشرة|cogs|cost of|direct|subcontract|material/.test(n)) bucket = '5100';
        else bucket = '5300';
    }
    return { type, bucket, bucketLabel: FS_TB_BUCKETS[bucket] };
}

// ── تنزيل نموذج ميزان المراجعة ─────────────────
window.downloadFSExtTBTemplate = function (type) {
    const aoa = [
        ['نموذج ميزان المراجعة — بنيان للمقاولات'],
        ['تعليمات: الصِق ميزان مراجعتك أسفل صف العناوين. أعمدة: رمز الحساب · اسم الحساب · مدين · دائن. يمكن ترك الرئيسية أو الفرعية — النظام يتعرّف على المستويات تلقائياً ولا يحتسب الإجماليات مرتين.'],
        [],
        ['رمز الحساب', 'اسم الحساب', 'مدين', 'دائن'],
        ['1110', 'النقدية والبنوك', 250000, 0],
        ['1130', 'العملاء (ذمم مدينة)', 480000, 0],
        ['1150', 'المخزون', 320000, 0],
        ['1200', 'الأصول الثابتة (بالصافي)', 950000, 0],
        ['2110', 'الموردون (ذمم دائنة)', 0, 410000],
        ['2200', 'قروض طويلة الأجل', 0, 300000],
        ['3100', 'رأس المال', 0, 1000000],
        ['3200', 'الأرباح المحتجزة', 0, 90000],
        ['4100', 'إيرادات العقود', 0, 1800000],
        ['5100', 'تكلفة العقود المباشرة', 1250000, 0],
        ['5300', 'مصروفات إدارية وعمومية', 350000, 0]
    ];
    if (type === 'csv') {
        const csv = '﻿' + aoa.map(r => r.map(c => {
            const s = String(c == null ? '' : c);
            return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s;
        }).join(',')).join('\r\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const a = document.createElement('a');
        a.href = URL.createObjectURL(blob);
        a.download = 'نموذج_ميزان_المراجعة.csv';
        a.click();
        setTimeout(() => URL.revokeObjectURL(a.href), 1000);
        toast('✅ تم تنزيل نموذج الميزان (CSV) — الصِق ميزانك ثم ارفعه', 'ok', 5000);
        return;
    }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة Excel غير محمّلة — جرّب CSV', 'er'); return; }
    const ws = XLSX.utils.aoa_to_sheet(aoa);
    ws['!cols'] = [{ wch: 14 }, { wch: 38 }, { wch: 16 }, { wch: 16 }];
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'ميزان المراجعة');
    XLSX.writeFile(wb, 'نموذج_ميزان_المراجعة.xlsx');
    toast('✅ تم تنزيل نموذج الميزان (Excel) — الصِق ميزانك (الأمثلة استرشادية) ثم ارفعه', 'ok', 6000);
};

// ── رفع ميزان المراجعة ─────────────────
window.handleFSExtTBUpload = function (input, target) {
    target = target || 'primary';
    const file = input.files && input.files[0];
    if (!file) return;
    if (target === 'compare' && !(window._fsExt && window._fsExt.loaded)) { toast('⚠️ ارفع الملف الأساسي أولاً قبل ملف المقارنة', 'er'); input.value = ''; return; }
    if (typeof XLSX === 'undefined') { toast('⚠️ مكتبة قراءة الملفات غير محمّلة', 'er'); return; }
    const reader = new FileReader();
    reader.onload = (e) => {
        try {
            const wb = XLSX.read(e.target.result, { type: 'array' });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const rows = XLSX.utils.sheet_to_json(ws, { header: 1, blankrows: false });
            if (!rows.length) { toast('⚠️ الملف فارغ', 'er'); input.value = ''; return; }

            // تحديد صف العناوين وأعمدته
            let headerIdx = -1, cCode = 0, cName = 1, cDebit = -1, cCredit = -1, cBal = -1;
            for (let i = 0; i < Math.min(rows.length, 15); i++) {
                const r = rows[i].map(x => String(x == null ? '' : x).toLowerCase().trim());
                const codeC = r.findIndex(x => /رمز|كود|رقم الحساب|code|acc/.test(x));
                const nameC = r.findIndex(x => /اسم|بيان|حساب|name|desc/.test(x));
                const debC = r.findIndex(x => /مدين|debit|dr/.test(x));
                const creC = r.findIndex(x => /دائن|credit|cr/.test(x));
                const balC = r.findIndex(x => /رصيد|صافي|balance|net/.test(x));
                if (codeC > -1 && (debC > -1 || creC > -1 || balC > -1 || nameC > -1)) {
                    headerIdx = i;
                    cCode = codeC > -1 ? codeC : 0;
                    cName = nameC > -1 ? nameC : (cCode === 0 ? 1 : 0);
                    cDebit = debC; cCredit = creC; cBal = balC;
                    break;
                }
            }
            // إن لم نجد عناوين، نفترض الترتيب القياسي: رمز/اسم/مدين/دائن
            if (headerIdx === -1) { headerIdx = -1; cCode = 0; cName = 1; cDebit = 2; cCredit = 3; }

            const accounts = [];
            for (let i = headerIdx + 1; i < rows.length; i++) {
                const r = rows[i]; if (!r) continue;
                const code = String(r[cCode] == null ? '' : r[cCode]).trim();
                const name = String(r[cName] == null ? '' : r[cName]).trim();
                if (!code && !name) continue;
                if (!code) continue; // لا يمكن التصنيف بدون رمز
                let debit = 0, credit = 0;
                if (cDebit > -1 || cCredit > -1) {
                    debit = fsExtNum(r[cDebit]); credit = fsExtNum(r[cCredit]);
                } else if (cBal > -1) {
                    const net = fsExtNum(r[cBal]); // رصيد بإشارة (مدين موجب)
                    if (net >= 0) debit = net; else credit = -net;
                } else {
                    debit = fsExtNum(r[cDebit > -1 ? cDebit : 2]); credit = fsExtNum(r[cCredit > -1 ? cCredit : 3]);
                }
                accounts.push({ code, name, debit, credit });
            }

            if (!accounts.length) { toast('⚠️ لم يتم العثور على حسابات في الملف — تأكد من الأعمدة (رمز/اسم/مدين/دائن)', 'er', 8000); input.value = ''; return; }
            const n = fsExtAnalyzeTB(accounts, file.name, target);
            toast(target === 'compare' ? `✅ تم تحميل ميزان المقارنة (${n} حساب)` : `✅ تم التعرّف على ${n} حساباً وتحليل الميزان بنجاح`, 'ok', 5000);
        } catch (err) {
            toast('❌ تعذّر قراءة الميزان: ' + (err.message || err), 'er', 8000);
        }
        input.value = '';
    };
    reader.onerror = () => { toast('❌ خطأ في قراءة الملف', 'er'); input.value = ''; };
    reader.readAsArrayBuffer(file);
};

// ── تحليل الميزان: تعرّف على المستويات + تصنيف + بناء balances ثم القوائم ─────────────────
function fsExtAnalyzeTB(accounts, fileName, target) {
    // حساب "قابل للجمع" = ليس له فرع آخر يحمل قيمة (يتجنّب ازدواج احتساب الرئيسي مع الفرعي)
    const nonzero = a => (Math.abs(a.debit) + Math.abs(a.credit)) > 0;
    const hasValuedChild = (code) => accounts.some(o => o.code !== code && o.code.startsWith(code) && o.code.length > code.length && nonzero(o));

    const balances = {};
    const tbAccounts = [];
    accounts.forEach(a => {
        const isParent = hasValuedChild(a.code);
        const { type, bucket, bucketLabel } = fsTbBucket(a.code, a.name);
        const summable = !isParent && nonzero(a);
        const net = Math.round((a.debit - a.credit) * 100) / 100; // مدين موجب
        const naturallyDebit = (type === 'asset' || type === 'expense');
        const naturalVal = Math.round((naturallyDebit ? net : -net) * 100) / 100;
        tbAccounts.push({ code: a.code, name: a.name, type, bucket, bucketLabel, level: isParent ? 'رئيسي' : 'فرعي', summable, value: naturalVal });
        if (!summable) return;
        // مفتاح فريد بالكود الحقيقي، لكن account.code = الكود القانوني (Bucket) ليطابق منطق البُناة
        balances[a.code] = {
            key: a.code,
            account: { code: bucket, nameAr: a.name, realCode: a.code, type, nature: 'detail' },
            opening: 0, beforeDebit: 0, beforeCredit: 0, periodDebit: 0, periodCredit: 0, count: 0,
            periodOpening: 0, closing: net,
            naturalOpening: 0, naturalClosing: naturalVal, naturalMovement: naturalVal
        };
    });

    const income = buildIncomeStatement(balances);
    const balanceSheet = buildBalanceSheet(balances, income.netIncome);
    balanceSheet.balanceDiff = Math.round(Math.abs(balanceSheet.totalAssets - (balanceSheet.totalLiabilities + (balanceSheet.partnerTotal||0) + balanceSheet.adjustedEquity)) * 100) / 100;
    balanceSheet.isBalanced = balanceSheet.balanceDiff < Math.max(1, balanceSheet.totalAssets * 0.01);

    // التقاط الفوائد والإهلاك من أسماء الحسابات المحتسبة (لنسب التغطية)
    let exInterest = 0, exDeprec = 0;
    tbAccounts.forEach(a => {
        if (!a.summable || a.type !== 'expense') return;
        const nm = String(a.name || '').toLowerCase();
        if (/فوائد|فائدة|interest|finance cost/.test(nm)) exInterest += Math.abs(a.value);
        if (/إهلاك|اهلاك|استهلاك|depreciation|amortization/.test(nm)) exDeprec += Math.abs(a.value);
    });
    const extra = { interest: exInterest, depreciation: exDeprec, ocf: null };
    const analysis = buildFinancialAnalysis(income, balanceSheet, extra);

    if (target === 'compare') {
        window._fsExtCompare = { loaded: true, mode: 'tb', income, balance: balanceSheet, analysis, label: fileName || 'ميزان مراجعة' };
        renderFinancialStatements();
        return tbAccounts.length;
    }

    const alerts = buildFSAlerts(income, balanceSheet, analysis, null);
    const report = buildFSExtReport(income, balanceSheet, analysis);

    // ترتيب جدول التعرّف: حسب الكود
    tbAccounts.sort((a, b) => String(a.code).localeCompare(String(b.code), undefined, { numeric: true }));

    window._fsExt = {
        loaded: true, mode: 'tb', fileName: fileName || '',
        vals: { entityName: '', period: '', taxRate: income.incomeTaxRate },
        income, balance: balanceSheet, analysis, alerts, report, tbAccounts
    };
    if (fsState.activeTab !== 'external') fsState.activeTab = 'external';
    renderFinancialStatements();
    return tbAccounts.length;
}

// ── جدول التعرّف على الحسابات (كيف صنّف النظام كل حساب) ─────────────────
function renderFSTbRecognition(tbAccounts) {
    if (!tbAccounts || !tbAccounts.length) return '';
    const typeColor = { asset: '#16a085', liability: '#e67e22', equity: '#8e44ad', revenue: '#27ae60', expense: '#c0392b' };
    const summary = {};
    tbAccounts.forEach(a => { if (a.summable) summary[a.type] = (summary[a.type] || 0) + a.value; });
    const summaryChips = Object.entries(summary).map(([t, v]) =>
        `<span style="background:${typeColor[t]}22;color:${typeColor[t]};font-size:11px;font-weight:800;padding:4px 10px;border-radius:8px">${FS_TB_TYPE_AR[t]}: ${fmt(v)}</span>`).join('');
    const summedCount = tbAccounts.filter(a => a.summable).length;
    const parentCount = tbAccounts.filter(a => a.level === 'رئيسي').length;

    const rows = tbAccounts.map(a => `
        <tr style="${a.summable ? '' : 'opacity:.5'}">
            <td style="padding:6px 8px;font-family:monospace;font-size:11px">${a.code}</td>
            <td style="padding:6px 8px;font-size:12px">${a.name || '—'}</td>
            <td style="padding:6px 8px"><span style="background:${typeColor[a.type]};color:#fff;font-size:10px;font-weight:700;padding:1px 7px;border-radius:5px">${FS_TB_TYPE_AR[a.type]}</span></td>
            <td style="padding:6px 8px;font-size:11px;color:#555">${a.bucketLabel}</td>
            <td style="padding:6px 8px;font-size:10px;color:#888">${a.level}${a.summable ? '' : ' <span title="مستبعد من الجمع لتفادي الازدواج (له فروع بقيم)">⊘</span>'}</td>
            <td style="padding:6px 8px;text-align:left;font-weight:700;font-size:12px">${fmt(a.value)}</td>
        </tr>`).join('');

    return `
        <details class="card" style="margin-bottom:14px;padding:0" open>
            <summary style="cursor:pointer;padding:14px;font-size:14px;font-weight:900;color:#0e6655;list-style:none;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
                <span>🔎 التعرّف على الحسابات وتصنيفها</span>
                <span style="font-size:11px;font-weight:400;color:#888">— ${tbAccounts.length} حساب (${summedCount} فرعي محتسب · ${parentCount} رئيسي مستبعد من الجمع)</span>
                <span style="margin-inline-start:auto;display:flex;gap:6px;flex-wrap:wrap">${summaryChips}</span>
            </summary>
            <div style="padding:0 14px 14px">
                <div style="font-size:11px;color:#666;margin-bottom:8px;line-height:1.7">صنّف النظام كل حساب تلقائياً (عبر شجرة حسابات النظام إن وُجد الكود، وإلا ببادئة الكود أو الكلمات المفتاحية). الحسابات الرئيسية التي لها فروع بقيم تُستبعد من الجمع لتفادي الازدواج (⊘).</div>
                <div style="overflow-x:auto;max-height:380px;overflow-y:auto;border:1px solid #eef2f6;border-radius:8px">
                    <table style="width:100%;border-collapse:collapse;font-size:12px">
                        <thead style="position:sticky;top:0"><tr style="background:#e8f8f5;color:#0e6655">
                            <th style="padding:8px;text-align:right">الرمز</th><th style="padding:8px;text-align:right">اسم الحساب</th>
                            <th style="padding:8px;text-align:right">النوع</th><th style="padding:8px;text-align:right">التصنيف</th>
                            <th style="padding:8px;text-align:right">المستوى</th><th style="padding:8px;text-align:left">القيمة</th>
                        </tr></thead>
                        <tbody>${rows}</tbody>
                    </table>
                </div>
            </div>
        </details>`;
}

