function fsBrandHeader(title, subtitle) {
    const c = window.gbrCfg || {};
    const cA = c.companyAr || 'شركة جي بي آر للمقاولات';
    const cE = c.companyEn || 'GBR';
    const initials = (cE.split(/\s+/).map(w => w[0]).join('').slice(0, 3) || 'GBR').toUpperCase();
    const meta = [c.address, c.phone ? 'هاتف: ' + c.phone : '', c.vat ? 'ر.ضريبي: ' + c.vat : '', c.reg ? 'س.تجاري: ' + c.reg : ''].filter(Boolean).join(' · ');
    return `
    <div style="display:flex;align-items:center;gap:14px;border-bottom:3px solid #16a085;padding-bottom:12px;margin-bottom:14px">
        <div style="width:58px;height:58px;border-radius:12px;background:linear-gradient(135deg,#16a085,#1a3a5c);color:#fff;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:900;letter-spacing:1px">${initials}</div>
        <div style="flex:1">
            <div style="font-size:19px;font-weight:900;color:#1a3a5c">${cA}</div>
            <div style="font-size:11px;color:#666">${cE}${meta ? ' · ' + meta : ''}</div>
        </div>
        <div style="text-align:left">
            <div style="font-size:15px;font-weight:800;color:#16a085">${title}</div>
            <div style="font-size:10px;color:#888">${subtitle || ''} · ${new Date().toLocaleDateString('ar-EG')}</div>
        </div>
    </div>`;
}

