window.pinvOcrPick = function (input) {
    const f = input.files && input.files[0];
    window._pinvOcr.file = f || null;
    $('pinvOcrFileName').textContent = f ? f.name : '';
    const btn = $('pinvOcrRunBtn');
    if (btn) { btn.disabled = !f; btn.style.opacity = f ? '1' : '.5'; }
};

function pinvNormDate(s) {
    s = ocrToLatinDigits(String(s || ''));
    let m = s.match(/(\d{4})[\/.\-](\d{1,2})[\/.\-](\d{1,2})/);
    if (m) return `${m[1]}-${String(m[2]).padStart(2, '0')}-${String(m[3]).padStart(2, '0')}`;
    m = s.match(/(\d{1,2})[\/.\-](\d{1,2})[\/.\-](\d{2,4})/);
    if (m) { let y = +m[3]; if (y < 100) y += 2000; return `${y}-${String(m[2]).padStart(2, '0')}-${String(m[1]).padStart(2, '0')}`; }
    return '';
}

// تحويل PDF لصورة (للملفات الممسوحة بلا طبقة نص)
async function pinvPdfToCanvas(file) {
    try { pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js'; } catch (e) { }
    const data = new Uint8Array(await file.arrayBuffer());
    const pdf = await pdfjsLib.getDocument({ data }).promise;
    const page = await pdf.getPage(1);
    const viewport = page.getViewport({ scale: 2.6 });
    const canvas = document.createElement('canvas');
    canvas.width = viewport.width; canvas.height = viewport.height;
    await page.render({ canvasContext: canvas.getContext('2d'), viewport }).promise;
    return canvas;
}

// معالجة مسبقة للصورة (تكبير + تدرّج رمادي + عتبة) لتحسين دقة OCR
function pinvImagePreprocess(file) {
    return new Promise((resolve, reject) => {
        const img = new Image();
        img.onload = () => {
            const scale = Math.min(2.5, Math.max(1, 1600 / img.width));
            const c = document.createElement('canvas');
            c.width = img.width * scale; c.height = img.height * scale;
            const ctx = c.getContext('2d');
            ctx.drawImage(img, 0, 0, c.width, c.height);
            try {
                const d = ctx.getImageData(0, 0, c.width, c.height); const a = d.data;
                for (let i = 0; i < a.length; i += 4) {
                    const g = 0.299 * a[i] + 0.587 * a[i + 1] + 0.114 * a[i + 2];
                    const v = g > 165 ? 255 : (g < 110 ? 0 : g);
                    a[i] = a[i + 1] = a[i + 2] = v;
                }
                ctx.putImageData(d, 0, 0);
            } catch (e) { /* تجاهل عند تعذّر المعالجة */ }
            URL.revokeObjectURL(img.src);
            resolve(c);
        };
        img.onerror = () => reject(new Error('تعذّر تحميل الصورة'));
        img.src = URL.createObjectURL(file);
    });
}

// استخراج طبقة النص من PDF بإحداثياتها وإعادة بنائها صفوفاً (RTL)
async function pinvExtractPdf(file) {
    if (typeof pdfjsLib === 'undefined') throw new Error('مكتبة قراءة PDF غير محمّلة');
    try { pdfjsLib.GlobalWorkerOptions.workerSrc = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js'; } catch (e) { }
    const data = new Uint8Array(await file.arrayBuffer());
    const pdf = await pdfjsLib.getDocument({ data }).promise;
    let items = [];
    const pages = Math.min(pdf.numPages, 2);
    for (let pn = 1; pn <= pages; pn++) {
        const page = await pdf.getPage(pn);
        const tc = await page.getTextContent();
        tc.items.forEach(it => {
            const s = (it.str || '').trim(); if (!s) return;
            items.push({ x: it.transform[4], y: it.transform[5] - (pn - 1) * 100000, str: s });
        });
    }
    items.sort((a, b) => (b.y - a.y) || (b.x - a.x));
    const rows = []; let cur = null;
    items.forEach(it => { if (!cur || Math.abs(cur.y - it.y) > 4) { cur = { y: it.y, items: [it] }; rows.push(cur); } else cur.items.push(it); });
    rows.forEach(r => r.items.sort((a, b) => b.x - a.x)); // RTL: يمين → يسار
    const text = rows.map(r => r.items.map(i => i.str).join(' ')).join('\n');
    return { rows, text, count: items.length };
}

// تحليل مُهيكَل من صفوف PDF: حقول الرأس + بنود الجدول بالإحداثيات
function pinvParseInvoice(rows, text) {
    const T = ocrToLatinDigits(text);
    const grab = (re) => { const m = T.match(re); return m ? m[1].trim() : ''; };
    const number = grab(/رقم\s*الفاتورة\D{0,8}?(\d{2,})/) || grab(/invoice\s*(?:no|#|number)?\D{0,6}?([A-Za-z0-9\-\/]{2,})/i);
    const date = pinvNormDate(grab(/تاريخ\s*(?:الإصدار|الاصدار|الفاتورة)\D{0,8}?(\d[\d\/.\-]{6,12})/) || grab(/(\d{4}[\/.\-]\d{1,2}[\/.\-]\d{1,2})/) || grab(/(\d{1,2}[\/.\-]\d{1,2}[\/.\-]\d{2,4})/));
    const vatNo = grab(/الرقم\s*الضريبي\s*للمنشأة\D{0,8}?(\d{15})/) || grab(/\b(\d{15})\b/);
    const custVatNo = grab(/ضريبي\s*(?:ال)?عميل\D{0,8}?(\d{15})/);
    // الإجماليات: أكبر رقم في الصف الذي يحوي التسمية (يدعم قوالب مختلفة)
    const rowTxt = rows.map(r => ocrToLatinDigits(r.items.map(i => i.str).join(' ')));
    const rowMax = (re) => { for (const t of rowTxt) { if (re.test(t)) { const ms = t.match(/[\d][\d.,]*\d|\d/g); if (ms) { const v = ms.map(ocrNum).filter(x => x != null && x >= 1); if (v.length) return Math.max(...v); } } } return null; };
    let net = rowMax(/الإجمالي\s*قبل\s*الضريبة|الصافي\s*قبل\s*الضريبة|المجموع\s*الخاضع|المجموع\s*الفرعي|(?:^|\s)المجموع(?:\s|$)/);
    let vat = rowMax(/ضريبة\s*القيمة\s*المضافة|القيمة\s*المضافة|[قف]يمة\s*الضريبة|مبلغ\s*الضريبة|VAT/i);
    let total = rowMax(/الإجمالي\s*شامل|الإجمالي\s*\(شامل|صافي\s*القيمة|المبلغ\s*المطلوب|الإجمالي\s*النهائي|(?:^|\s)الإجمالي(?:\s|$)/);

    // ── بنود الجدول بالإحداثيات ── (كشف مرن لتسميات الأعمدة)
    const norm = s => s.replace(/\s/g, '');
    let hi = -1;
    for (let i = 0; i < rows.length; i++) {
        const t = norm(rows[i].items.map(x => x.str).join(''));
        const hasQty = /الكمية/.test(t);
        const hasTotal = /المجموع|الإجمالي|الاجمالي/.test(t);
        const hasPriceOrDesc = /سعرالوحدة|سعرالوحده|السعر|سعر|الوصف|تفاصيل|السلع|البيان/.test(t);
        if (hasQty && hasTotal && hasPriceOrDesc) { hi = i; break; }
    }
    const lineItems = [];
    if (hi > -1) {
        const hcells = rows[hi].items.map(c => ({ x: c.x, s: norm(c.str) }));
        const findX = (...kws) => { for (const kw of kws) { const c = hcells.find(h => h.s.includes(kw)); if (c) return c.x; } return null; };
        const colPrice = findX('سعرالوحدة', 'سعرالوحده', 'السعر', 'سعر');
        let colUnit = null; hcells.forEach(h => { if (h.s === 'الوحدة' && h.x !== colPrice) colUnit = h.x; });
        const heads = [
            ['total', findX('المجموع', 'الإجمالي', 'الاجمالي')], ['vatAmt', findX('يمةالضريبة', 'مبلغالضريبة', 'مبلغالضريبه')],
            ['vatPct', findX('نسبةالضريبة', 'نسبةالضريبه', 'نسبة')], ['net', findX('المبلغالخاضع', 'الخاضع')],
            ['price', colPrice], ['qty', findX('الكمية')], ['unit', colUnit],
            ['desc', findX('الوصف', 'تفاصيل', 'السلع', 'البيان')], ['code', findX('البند', 'رقمالصنف', 'الصنف')]
        ].filter(h => h[1] != null).sort((a, b) => a[1] - b[1]);
        const bounds = heads.map((h, i) => [h[0], i === 0 ? -Infinity : (heads[i - 1][1] + h[1]) / 2, i === heads.length - 1 ? Infinity : (h[1] + heads[i + 1][1]) / 2]);
        const colOf = x => { for (const b of bounds) { if (x >= b[1] && x < b[2]) return b[0]; } return null; };
        for (let i = hi + 1; i < rows.length; i++) {
            const r = rows[i]; const t = norm(r.items.map(x => x.str).join(''));
            if (/المطلوب|شاملالضريبة|صافيالقيمة|المبلغالمدفوع|القيمةالمضافة|^المجموع|^الإجمالي/.test(t)) break;
            const cell = {};
            r.items.forEach(it => { const c = colOf(it.x); if (!c) return; cell[c] = (cell[c] ? cell[c] + ' ' : '') + it.str; });
            const qty = ocrNum(cell.qty), price = ocrNum(cell.price), tot = ocrNum(cell.total), lnet = ocrNum(cell.net), vatA = ocrNum(cell.vatAmt);
            if (qty != null && price != null && (tot != null || lnet != null)) {
                lineItems.push({ code: (cell.code || '').trim(), description: (cell.desc || '').trim(), unit: (cell.unit || '').trim(), qty, unitPrice: price, net: lnet != null ? lnet : Math.round(qty * price * 100) / 100, vatAmt: vatA, total: tot });
            } else if (lineItems.length && cell.desc && qty == null && price == null && tot == null) {
                // سطر امتداد للوصف (وصف متعدد الأسطر) — يُلحق بالبند السابق
                const last = lineItems[lineItems.length - 1];
                const extra = cell.desc.trim(); if (extra && !/^\d/.test(extra)) last.description = (last.description + ' ' + extra).trim();
            }
        }
    }

    // تجميع/تعويض الإجماليات من البنود
    if (lineItems.length) {
        const sNet = lineItems.reduce((s, l) => s + (l.net || 0), 0);
        const sVat = lineItems.reduce((s, l) => s + (l.vatAmt || 0), 0);
        if (net == null) net = Math.round(sNet * 100) / 100;
        if (vat == null && sVat) vat = Math.round(sVat * 100) / 100;
    }
    if (net == null && total != null && vat != null) net = Math.round((total - vat) * 100) / 100;
    if (vat == null && net != null) vat = Math.round(net * 0.15 * 100) / 100;
    if (total == null && net != null) total = Math.round((net + (vat || 0)) * 100) / 100;
    const rate = (net && vat != null) ? Math.round(vat / net * 100) : 15;

    // مطابقة المورد
    let vendorKey = '', vendorName = '', bestSim = 0;
    const vendors = window.vendors || {};
    const topRows = rows.slice(0, 14).map(r => r.items.map(i => i.str).join(' '));
    Object.entries(vendors).forEach(([k, v]) => { const nm = v.nameAr || v.nameEn || ''; if (!nm) return; topRows.forEach(l => { const s = (typeof vatRecNameSim === 'function') ? vatRecNameSim(l, nm) : 0; if (s > bestSim) { bestSim = s; vendorKey = k; vendorName = nm; } }); });
    if (bestSim < 0.34) vendorKey = '';

    return { number: ocrToLatinDigits(number), date, vatNo, custVatNo, net, vat, total, rate, vendorKey, vendorName, lineItems, _mode: 'pdf-text' };
}

window.pinvOcrRun = async function () {
    const st = window._pinvOcr;
    if (!st.file || st.busy) return;
    st.busy = true;
    const prog = $('pinvOcrProgress'), bar = $('pinvOcrBar'), status = $('pinvOcrStatus'), btn = $('pinvOcrRunBtn');
    if (prog) prog.style.display = 'block';
    if (btn) { btn.disabled = true; btn.style.opacity = '.5'; }
    const setP = (txt, p) => { if (status) status.textContent = txt; if (bar && p != null) bar.style.width = Math.round(p * 100) + '%'; };
    const showPreviewCanvas = (canvas) => { const prev = $('pinvOcrPreview'); if (!prev) return; prev.style.display = 'block'; prev.innerHTML = ''; const c2 = document.createElement('canvas'); c2.width = canvas.width; c2.height = canvas.height; c2.getContext('2d').drawImage(canvas, 0, 0); c2.style.maxWidth = '260px'; c2.style.border = '1px solid #eee'; c2.style.borderRadius = '6px'; prev.appendChild(c2); };
    const isPDF = st.file.type === 'application/pdf' || /\.pdf$/i.test(st.file.name);
    const useAi = $('pinvUseAi') && $('pinvUseAi').checked && pinvAiGetKey();
    const runOcr = async (img) => Tesseract.recognize(img, 'ara+eng', { logger: m => { if (m.status === 'recognizing text') setP('جارٍ قراءة النص (OCR)… ' + Math.round(m.progress * 100) + '%', 0.15 + m.progress * 0.85); else if (m.status) setP(m.status, null); } });
    try {
        let text = '', parsed = null;
        if (useAi) {
            // معاينة سريعة (للصور)
            if (!isPDF) { const prev = $('pinvOcrPreview'); if (prev) { prev.style.display = 'block'; prev.innerHTML = `<img src="${URL.createObjectURL(st.file)}" style="max-width:260px;border:1px solid #eee;border-radius:6px">`; } }
            parsed = await pinvAiRead(st.file, setP);
            text = '(قراءة بالذكاء الاصطناعي)';
        } else if (isPDF) {
            setP('جارٍ قراءة طبقة نص PDF…', 0.2);
            const ext = await pinvExtractPdf(st.file);
            if (ext && ext.count > 25) { // PDF رقمي بطبقة نص — استخراج دقيق بلا OCR
                text = ext.text; parsed = pinvParseInvoice(ext.rows, ext.text);
            } else { // PDF ممسوح — تحويل لصورة و OCR
                setP('PDF ممسوح — تحويل لصورة ثم OCR…', 0.15);
                const canvas = await pinvPdfToCanvas(st.file); showPreviewCanvas(canvas);
                const res = await runOcr(canvas); text = (res.data && res.data.text) || ''; parsed = pinvOcrParse(text); parsed._mode = 'pdf-ocr';
            }
        } else {
            setP('جارٍ معالجة الصورة…', 0.1);
            const canvas = await pinvImagePreprocess(st.file); showPreviewCanvas(canvas);
            const res = await runOcr(canvas); text = (res.data && res.data.text) || ''; parsed = pinvOcrParse(text); parsed._mode = 'image-ocr';
        }
        st.text = text; st.parsed = parsed;
        setP('اكتملت القراءة ✓', 1);
        pinvOcrShowResult();
    } catch (e) {
        setP('❌ تعذّرت القراءة: ' + (e.message || e), null);
        toast('❌ خطأ في القراءة: ' + (e.message || e), 'er', 7000);
    }
    st.busy = false;
    if (btn) { btn.disabled = false; btn.style.opacity = '1'; }
};

// تحليل نص OCR (للصور والملفات الممسوحة) — حقول أساسية بلا جدول دقيق
function pinvOcrParse(text) {
    const raw = text || '';
    const lines = raw.split(/\n+/).map(l => l.trim()).filter(Boolean);
    const allNums = [];
    raw.replace(/[\d٠-٩۰-۹][\d٠-٩۰-۹.,]{1,}/g, m => { const n = ocrNum(m); if (n != null) allNums.push(n); return m; });
    const lineNum = (re) => { for (const l of lines) { if (re.test(l)) { const ms = l.match(/[\d٠-٩۰-۹][\d٠-٩۰-۹.,]{1,}/g); if (ms && ms.length) { const vals = ms.map(ocrNum).filter(v => v != null); if (vals.length) return Math.max(...vals); } } } return null; };
    let total = lineNum(/الإجمالي شامل|صافي القيمة|المبلغ المطلوب|grand\s*total|total\s*due/i);
    let vat = lineNum(/ضريبة القيمة المضافة|قيمة الضريبة|مبلغ الضريبة|vat\s*tax/i);
    let net = lineNum(/الإجمالي قبل الضريبة|قبل الضريبة|sub\s*total|المجموع الخاضع/i);
    if (total == null && allNums.length) total = Math.max(...allNums);
    if (net == null && total != null && vat != null) net = Math.round((total - vat) * 100) / 100;
    if (net == null && total != null) net = Math.round((total / 1.15) * 100) / 100;
    if (vat == null && total != null && net != null) vat = Math.round((total - net) * 100) / 100;
    const rate = (net && vat != null) ? Math.round(vat / net * 100) : 15;
    let date = '';
    const dm = ocrToLatinDigits(raw).match(/(\d{4})[-/.](\d{1,2})[-/.](\d{1,2})/) || ocrToLatinDigits(raw).match(/(\d{1,2})[-/.](\d{1,2})[-/.](\d{2,4})/);
    if (dm) date = pinvNormDate(dm[0]);
    let number = '';
    for (const l of lines) { const m = l.match(/(?:رقم\s*الفاتورة|فاتورة\s*رقم|invoice\s*(?:no|#|number)?)[:\s#]*([A-Za-z0-9\-\/]{2,})/i); if (m) { number = ocrToLatinDigits(m[1]); break; } }
    let vatNo = ''; const vm = ocrToLatinDigits(raw).match(/\b(\d{15})\b/); if (vm) vatNo = vm[1];
    let vendorKey = '', vendorName = '', bestSim = 0; const vendors = window.vendors || {};
    Object.entries(vendors).forEach(([k, v]) => { const nm = v.nameAr || v.nameEn || ''; if (!nm) return; lines.slice(0, 12).forEach(l => { const s = (typeof vatRecNameSim === 'function') ? vatRecNameSim(l, nm) : 0; if (s > bestSim) { bestSim = s; vendorKey = k; vendorName = nm; } }); });
    if (bestSim < 0.34) vendorKey = '';
    return { number, date, vatNo, custVatNo: '', total, vat, net, rate, vendorKey, vendorName, lineItems: [], _mode: 'ocr' };
}

function pinvOcrShowResult() {
    const p = window._pinvOcr.parsed; if (!p) return;
    const box = $('pinvOcrResult'); if (!box) return;
    const vendors = window.vendors || {};
    const vOpts = '<option value="">— لم يُتعرّف (اختر يدوياً) —</option>' + Object.entries(vendors).map(([k, v]) => `<option value="${k}" ${p.vendorKey === k ? 'selected' : ''}>${v.nameAr || v.nameEn || k}</option>`).join('');
    const fld = (id, label, val, type) => `<div><label style="font-size:11px;color:#666;font-weight:700">${label}</label>
        <input id="${id}" type="${type || 'text'}" value="${val == null ? '' : String(val).replace(/"/g, '&quot;')}" style="width:100%;padding:7px;border:1px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px"></div>`;
    const modeBadge = p._mode === 'ai' ? '<span style="background:#8e44ad;color:#fff;font-size:10px;padding:2px 8px;border-radius:5px">🤖 ذكاء اصطناعي (Claude)</span>'
        : p._mode === 'pdf-text' ? '<span style="background:#16a34a;color:#fff;font-size:10px;padding:2px 8px;border-radius:5px">📄 نص PDF دقيق</span>'
            : '<span style="background:#f59e0b;color:#fff;font-size:10px;padding:2px 8px;border-radius:5px">🔎 OCR (قد يحتاج تصحيحاً)</span>';
    const items = p.lineItems || [];
    const itemsTable = items.length ? `
        <div style="margin-bottom:12px">
            <div style="font-size:12px;font-weight:800;color:#1a3a5c;margin-bottom:6px">📦 البنود المُستخرجة (${items.length})</div>
            <div style="overflow-x:auto;border:1px solid #eee;border-radius:8px;max-height:220px;overflow-y:auto">
                <table style="width:100%;border-collapse:collapse;font-size:11px">
                    <thead><tr style="background:#ecf3fb;color:#1a3a5c"><th style="padding:5px">الصنف</th><th style="padding:5px">الوصف</th><th style="padding:5px">الوحدة</th><th style="padding:5px">الكمية</th><th style="padding:5px">سعر الوحدة</th><th style="padding:5px">الخاضع للضريبة</th><th style="padding:5px">الضريبة</th><th style="padding:5px">المجموع</th></tr></thead>
                    <tbody>${items.map(l => `<tr style="border-bottom:1px solid #f3f3f3">
                        <td style="padding:5px;font-family:monospace">${l.code || ''}</td>
                        <td style="padding:5px">${l.description || ''}</td>
                        <td style="padding:5px;text-align:center">${l.unit || ''}</td>
                        <td style="padding:5px;text-align:center">${l.qty != null ? fmt(l.qty) : ''}</td>
                        <td style="padding:5px;text-align:left">${l.unitPrice != null ? fmt(l.unitPrice) : ''}</td>
                        <td style="padding:5px;text-align:left">${l.net != null ? fmt(l.net) : ''}</td>
                        <td style="padding:5px;text-align:left">${l.vatAmt != null ? fmt(l.vatAmt) : ''}</td>
                        <td style="padding:5px;text-align:left;font-weight:700">${l.total != null ? fmt(l.total) : ''}</td>
                    </tr>`).join('')}</tbody>
                </table>
            </div>
        </div>` : '';
    box.innerHTML = `
        <div style="background:#f4ecf7;border-radius:8px;padding:10px 12px;font-size:12px;color:#5b2c6f;margin-bottom:12px;line-height:1.7;display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap">
            <span>✅ تمت القراءة. راجع الحقول والبنود ثم اضغط "تعبئة فاتورة جديدة" — تحقّق من المبالغ دائماً.</span>${modeBadge}
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:10px;margin-bottom:12px">
            <div><label style="font-size:11px;color:#666;font-weight:700">المورد (مُطابق)</label>
                <select id="ocrVendor" style="width:100%;padding:7px;border:1px solid #d0d7e0;border-radius:6px;font-family:inherit;font-size:12px">${vOpts}</select></div>
            ${fld('ocrNumber', 'رقم الفاتورة', p.number)}
            ${fld('ocrDate', 'التاريخ', p.date, 'date')}
            ${fld('ocrVatNo', 'الرقم الضريبي للمورد', p.vatNo)}
            ${fld('ocrNet', 'الإجمالي قبل الضريبة', p.net != null ? p.net : '', 'number')}
            ${fld('ocrRate', 'نسبة الضريبة %', p.rate != null ? p.rate : 15, 'number')}
            ${fld('ocrVat', 'قيمة الضريبة', p.vat != null ? p.vat : '', 'number')}
            ${fld('ocrTotal', 'الإجمالي شامل الضريبة', p.total != null ? p.total : '', 'number')}
        </div>
        ${itemsTable}
        <details style="margin-bottom:12px"><summary style="cursor:pointer;font-size:11px;color:#8e44ad;font-weight:700">📄 النص المُستخرج كاملاً</summary>
            <pre style="max-height:160px;overflow:auto;background:#fafafa;border:1px solid #eee;border-radius:6px;padding:8px;font-size:10px;white-space:pre-wrap;direction:rtl">${(window._pinvOcr.text || '').replace(/</g, '&lt;')}</pre></details>
        <div style="display:flex;gap:10px;flex-wrap:wrap">
            <button class="btn" onclick="pinvOcrApply()" style="background:#1e8449;color:#fff;padding:10px 22px;font-weight:800">📝 تعبئة فاتورة جديدة${items.length ? ' (' + items.length + ' بند)' : ''}</button>
            <button class="btn" onclick="document.getElementById('pinvOcrOverlay').remove()" style="background:#f0f0f0;color:#555;padding:10px 22px;font-weight:700">إلغاء</button>
        </div>`;
}

window.pinvOcrApply = function () {
    const p = window._pinvOcr.parsed || {};
    const get = id => { const e = $(id); return e ? e.value : ''; };
    const vendorKey = get('ocrVendor');
    const number = get('ocrNumber');
    const date = get('ocrDate');
    const net = parseFloat(get('ocrNet')) || 0;
    let rate = parseFloat(get('ocrRate')); if (isNaN(rate)) rate = 15;
    const items = p.lineItems || [];
    const rawText = window._pinvOcr.text || '';
    document.getElementById('pinvOcrOverlay')?.remove();

    if (typeof openPInvEditor !== 'function') { toast('⚠️ تعذّر فتح نموذج الفاتورة', 'er'); return; }
    openPInvEditor();
    setTimeout(() => {
        try {
            if (date && $('mPInvDate')) $('mPInvDate').value = date;
            if (number && $('mPInvVendorRef')) $('mPInvVendorRef').value = number;
            if ($('mPInvSubject')) $('mPInvSubject').value = 'فاتورة مقروءة آلياً — يرجى المراجعة';
            if (vendorKey && $('mPInvVendor')) { $('mPInvVendor').value = vendorKey; if (typeof onPInvVendorChange === 'function') onPInvVendorChange(); }
            if ($('mPInvNotes')) $('mPInvNotes').value = '📷 أُنشئت عبر القراءة الآلية' + (number ? ' — فاتورة رقم ' + number : '') + '.';
            if (typeof pInvEditorState !== 'undefined') {
                if (items.length) {
                    pInvEditorState.lines = items.map(l => {
                        const lnet = (l.net != null) ? l.net : (l.qty || 0) * (l.unitPrice || 0);
                        const vr = (lnet && l.vatAmt != null) ? Math.round(l.vatAmt / lnet * 100) : rate;
                        return { code: l.code || '', description: (l.description || l.code || 'بند'), qty: l.qty || 1, unit: l.unit || '', unitPrice: l.unitPrice || 0, vatRate: vr, total: (l.qty || 0) * (l.unitPrice || 0) };
                    });
                } else {
                    pInvEditorState.lines = [{ description: 'إجمالي الفاتورة (قراءة آلية — فصّل البنود إن لزم)', qty: 1, unit: '', unitPrice: net, vatRate: rate, total: net }];
                }
                if (typeof renderPInvLines === 'function') renderPInvLines();
                if (typeof updatePInvTotals === 'function') updatePInvTotals();
            }
            toast(`✅ تم تعبئة الفاتورة${items.length ? ' بـ ' + items.length + ' بند' : ''} — راجع البيانات قبل الحفظ`, 'ok', 6000);
        } catch (e) { toast('⚠️ تعذّر تعبئة بعض الحقول: ' + (e.message || e), 'er'); }
    }, 250);
};

console.log('✅ Purchase Invoice OCR module [ACC-OCR] loaded — Tesseract + pdf.js');
